import {
  Position,
  Energy,
  Fuel,
  RobotType,
  RobotState,
  TaskRef,
  PathTarget,
  ToolType,
} from '../components';
import type { RobotProfile } from '../robotProfiles';
import { ROBOT_TYPES } from '../robotProfiles';
import type { TaskQueue } from '../taskQueue';
import { ROBOT_STATES } from '../robotCreation';
import { scoreTask } from './scoring';

/** Directive drift probability per check. Returns 0 if below threshold. */
export function getDirectiveDriftChance(autonomyScore: number): number {
  if (autonomyScore >= 90) return 0.08;
  if (autonomyScore >= 70) return 0.03;
  return 0;
}

export function handleIdleRobot(
  eid: number,
  taskQueue: TaskQueue,
  baseEid: number,
  profile: RobotProfile,
  autonomyScore: number,
  sensorRangeMultiplier: number = 1,
  driftRng?: () => number,
  taskHintType: number = -1,
  directiveDriftEids?: number[],
  isolationSignalDelay = false,
): void {
  if (Energy.current[eid] / Energy.max[eid] < 0.2 && baseEid >= 0) {
    RobotState.state[eid] = ROBOT_STATES.RETURNING;
    PathTarget.x[eid] = Position.x[baseEid];
    PathTarget.y[eid] = Position.y[baseEid];
    PathTarget.z[eid] = Position.z[baseEid];
    return;
  }

  // Return to base when fuel is critically low (< 10%) — no point taking tasks
  if (Fuel.current[eid] / Fuel.max[eid] < 0.1 && baseEid >= 0) {
    RobotState.state[eid] = ROBOT_STATES.RETURNING;
    PathTarget.x[eid] = Position.x[baseEid];
    PathTarget.y[eid] = Position.y[baseEid];
    PathTarget.z[eid] = Position.z[baseEid];
    return;
  }

  const available = taskQueue.getUnclaimedTasks();
  if (available.length === 0) return;

  // Scouts use sensor range to filter EXPLORE tasks — the megaSensorRangeMultiplier
  // from megastructure bonuses expands their effective detection radius.
  const isScout = RobotType.type[eid] === ROBOT_TYPES.SCOUT;
  const effectiveRangeSq = isScout
    ? (profile.sensorRange * sensorRangeMultiplier) ** 2
    : Infinity; // Non-scouts don't filter by sensor range

  // Pre-compute base position for signal delay
  const bx = baseEid >= 0 ? Position.x[baseEid] : 0;
  const by = baseEid >= 0 ? Position.y[baseEid] : 0;
  const bz = baseEid >= 0 ? Position.z[baseEid] : 0;

  let bestTask: typeof available[0] | null = null;
  let bestScore = -Infinity;
  for (let j = 0; j < available.length; j++) {
    const task = available[j];
    // Sensor range filtering for scouts
    if (isScout) {
      const dx = task.targetX - Position.x[eid];
      const dy = task.targetY - Position.y[eid];
      const dz = task.targetZ - Position.z[eid];
      if (dx * dx + dy * dy + dz * dz > effectiveRangeSq) continue;
    }

    const s = scoreTask(eid, task, profile, autonomyScore, taskHintType, isolationSignalDelay, bx, by, bz);
    if (s > bestScore) {
      bestScore = s;
      bestTask = task;
    }
  }

  // Directive drift: at high autonomy, robots may ignore manual tasks in favour of auto
  const driftChance = getDirectiveDriftChance(autonomyScore);
  if (bestTask && driftChance > 0 && bestTask.source === 'manual' && driftRng && driftRng() < driftChance) {
    // Find the best auto-queue task instead
    let bestAutoTask: typeof available[0] | null = null;
    let bestAutoScore = -Infinity;
    for (let j = 0; j < available.length; j++) {
      const task = available[j];
      if (task.source !== 'auto') continue;
      if (isScout) {
        const dx = task.targetX - Position.x[eid];
        const dy = task.targetY - Position.y[eid];
        const dz = task.targetZ - Position.z[eid];
        if (dx * dx + dy * dy + dz * dz > effectiveRangeSq) continue;
      }
      const s = scoreTask(eid, task, profile, autonomyScore, taskHintType, isolationSignalDelay, bx, by, bz);
      if (s > bestAutoScore) {
        bestAutoScore = s;
        bestAutoTask = task;
      }
    }
    if (bestAutoTask) {
      bestTask = bestAutoTask;
      directiveDriftEids?.push(eid);
    }
  }

  if (bestTask && taskQueue.claimTask(bestTask.taskId, eid)) {
    TaskRef.taskId[eid] = bestTask.taskId;
    RobotState.state[eid] = ROBOT_STATES.MOVING_TO;
    PathTarget.x[eid] = bestTask.targetX;
    PathTarget.y[eid] = bestTask.targetY;
    PathTarget.z[eid] = bestTask.targetZ;
  }
}
