/**
 * Multi-base logistics system.
 *
 * Manages inter-base resource transfer routes. Hauler robots pick up
 * TRANSFER tasks generated here and shuttle resources between bases.
 */

import { Position, Storage } from './components';
import { TaskQueue, TASK_TYPES } from './taskQueue';

export interface HaulRoute {
  id: string;
  name: string;
  fromBaseEid: number;
  toBaseEid: number;
  resource: string; // 'iron' | 'nickel' | 'cobalt' | 'platinum' | 'ice' | 'carbon' | 'silicate'
  minSurplus: number; // only haul when source has more than this
  enabled: boolean;
  priority: number;
}

export interface LogisticsState {
  routes: Map<string, HaulRoute>;
  baseEids: number[]; // index 0 = primary base
  lastTickProcessed: number;
}

export interface SerializedLogisticsState {
  routes: HaulRoute[];
  nextBaseIndex: number;
}

export interface BaseInfo {
  eid: number;
  x: number;
  y: number;
  z: number;
  iron: number;
  nickel: number;
  cobalt: number;
  platinum: number;
  ice: number;
  carbon: number;
  silicate: number;
  capacity: number;
  isPrimary: boolean;
}

// Resource cost to build a new base
export const BASE_BUILD_COSTS: Record<string, number> = {
  iron: 500,
  carbon: 200,
};

// Default storage capacity for new bases (0 = unlimited in existing code,
// we use explicit limits for secondary bases)
export const DEFAULT_BASE_CAPACITY = 500;
export const STORAGE_UPGRADE_CAPACITIES = [500, 2000, 5000, 10000];

const LOGISTICS_TICK_INTERVAL = 180; // every 3 seconds at 60 ticks/s

export function createLogisticsState(primaryBaseEid: number): LogisticsState {
  return {
    routes: new Map(),
    baseEids: [primaryBaseEid],
    lastTickProcessed: 0,
  };
}

export function upsertRoute(state: LogisticsState, route: HaulRoute): void {
  state.routes.set(route.id, { ...route });
}

export function deleteRoute(state: LogisticsState, id: string): void {
  state.routes.delete(id);
}

/**
 * Returns per-base info for broadcasting to the main thread.
 */
export function getBaseInfos(state: LogisticsState): BaseInfo[] {
  return state.baseEids.map((eid, idx) => ({
    eid,
    x: Position.x[eid],
    y: Position.y[eid],
    z: Position.z[eid],
    iron: Storage.iron[eid],
    nickel: Storage.nickel[eid],
    cobalt: Storage.cobalt[eid],
    platinum: Storage.platinum[eid],
    ice: Storage.ice[eid],
    carbon: Storage.carbon[eid],
    silicate: Storage.silicate[eid],
    capacity: Storage.capacity[eid],
    isPrimary: idx === 0,
  }));
}

/**
 * Check if a TRANSFER task for this route is already pending/in-progress.
 * Simple dedup: check if any task in the queue targets the source base.
 */
function hasActiveTransferForRoute(taskQueue: TaskQueue, route: HaulRoute): boolean {
  const srcX = Position.x[route.fromBaseEid];
  const srcY = Position.y[route.fromBaseEid];
  const srcZ = Position.z[route.fromBaseEid];
  const dstX = Position.x[route.toBaseEid];
  const dstY = Position.y[route.toBaseEid];
  const dstZ = Position.z[route.toBaseEid];

  const tasks = taskQueue.getTasksByType(TASK_TYPES.TRANSFER);
  for (const t of tasks) {
    if (
      Math.abs(t.targetX - srcX) < 1 &&
      Math.abs(t.targetY - srcY) < 1 &&
      Math.abs(t.targetZ - srcZ) < 1 &&
      Math.abs(t.destX - dstX) < 1 &&
      Math.abs(t.destY - dstY) < 1 &&
      Math.abs(t.destZ - dstZ) < 1
    ) {
      return true;
    }
  }
  return false;
}

/**
 * Tick logistics: generate inter-base TRANSFER tasks when routes have surplus.
 */
export function tickLogistics(state: LogisticsState, tick: number, taskQueue: TaskQueue): void {
  if (tick - state.lastTickProcessed < LOGISTICS_TICK_INTERVAL) return;
  state.lastTickProcessed = tick;

  for (const route of state.routes.values()) {
    if (!route.enabled) continue;

    const srcEid = route.fromBaseEid;
    const dstEid = route.toBaseEid;

    // Validate base eids are still in our list
    if (!state.baseEids.includes(srcEid) || !state.baseEids.includes(dstEid)) continue;

    const res = route.resource as keyof typeof Storage;
    const srcStorage = Storage[res] as Float32Array | undefined;
    if (!srcStorage) continue;

    const srcAmount = srcStorage[srcEid];
    if (srcAmount <= route.minSurplus) continue;

    // Skip if there's already an active transfer for this route
    if (hasActiveTransferForRoute(taskQueue, route)) continue;

    taskQueue.addTask(
      TASK_TYPES.TRANSFER,
      srcEid,
      Position.x[srcEid],
      Position.y[srcEid],
      Position.z[srcEid],
      Position.x[dstEid],
      Position.y[dstEid],
      Position.z[dstEid],
      route.priority,
    );
  }
}

export function serializeLogisticsState(state: LogisticsState): SerializedLogisticsState {
  return {
    routes: Array.from(state.routes.values()),
    nextBaseIndex: state.baseEids.length,
  };
}

export function deserializeLogisticsState(
  data: SerializedLogisticsState,
  baseEids: number[],
): LogisticsState {
  const state: LogisticsState = {
    routes: new Map(),
    baseEids: [...baseEids],
    lastTickProcessed: 0,
  };
  for (const r of data.routes) {
    state.routes.set(r.id, r);
  }
  return state;
}
