import { addComponent, addEntity, query } from 'bitecs';
import type { World } from '../core/ecs';
import {
  Position,
  Velocity,
  Rotation,
  RobotTag,
  RobotType,
  RobotState,
  Energy,
  Fuel,
  Inventory,
  ToolType,
  ToolTier,
  ResearchOutput,
  TaskRef,
  PathTarget,
  Thrust,
  BaseStationTag,
  Storage,
} from './components';
import { ROBOT_PROFILES } from './robotProfiles';
import { SpatialGrid } from './spatialGrid';

// Proximity threshold for arrival detection (shared with robotAI)
export const ARRIVAL_RADIUS = 20;

// Robot states
export const ROBOT_STATES = {
  IDLE: 0,
  MOVING_TO: 1,
  MINING: 2,
  HAULING: 3,
  RETURNING: 4,
  CHARGING: 5,
  BROKEN: 6,
  STUDYING: 7, // Researcher: studying an asteroid
  TRANSFERRING: 8, // Hauler: inter-base resource transfer
  CONSTRUCTING: 9, // Engineer: building a structure
} as const;

/** Canonical display names for robot states, indexed by ROBOT_STATES value. */
export const ROBOT_STATE_NAMES: string[] = [
  'Idle',
  'Moving',
  'Mining',
  'Hauling',
  'Returning',
  'Charging',
  'Broken',
  'Studying',
  'Transferring',
  'Constructing',
];

export function createRobot(
  world: World,
  robotType: number,
  x: number,
  y: number,
  z: number,
  grid: SpatialGrid,
): number {
  const profile = ROBOT_PROFILES[robotType];
  if (!profile) return -1;

  const eid = addEntity(world);

  // bitECS v0.4: addComponent(world, eid, component)
  addComponent(world, eid, RobotTag);
  addComponent(world, eid, Position);
  addComponent(world, eid, Velocity);
  addComponent(world, eid, Rotation);
  addComponent(world, eid, RobotType);
  addComponent(world, eid, RobotState);
  addComponent(world, eid, Energy);
  addComponent(world, eid, Fuel);
  addComponent(world, eid, Inventory);
  addComponent(world, eid, ToolType);
  addComponent(world, eid, ToolTier);
  addComponent(world, eid, ResearchOutput);
  addComponent(world, eid, TaskRef);
  addComponent(world, eid, PathTarget);
  addComponent(world, eid, Thrust);

  Position.x[eid] = x;
  Position.y[eid] = y;
  Position.z[eid] = z;

  Velocity.x[eid] = 0;
  Velocity.y[eid] = 0;
  Velocity.z[eid] = 0;

  RobotType.type[eid] = robotType;
  RobotState.state[eid] = ROBOT_STATES.IDLE;

  Energy.current[eid] = profile.energyCapacity;
  Energy.max[eid] = profile.energyCapacity;

  Fuel.current[eid] = profile.fuelCapacity;
  Fuel.max[eid] = profile.fuelCapacity;

  Inventory.capacity[eid] = profile.inventoryCapacity;
  Inventory.used[eid] = 0;

  ToolType.type[eid] = profile.toolType;
  ToolTier.tier[eid] = 1; // default tier 1 (Drill)
  ResearchOutput.pointsPerSecond[eid] = profile.researchRate ?? 0;
  ResearchOutput.isStudying[eid] = 0;
  TaskRef.taskId[eid] = -1;

  Thrust.maxThrust[eid] = profile.maxThrust;
  Thrust.maxSpeed[eid] = profile.maxSpeed;
  Thrust.mass[eid] = profile.mass;

  PathTarget.x[eid] = 0;
  PathTarget.y[eid] = 0;
  PathTarget.z[eid] = 0;
  PathTarget.arrivalRadius[eid] = ARRIVAL_RADIUS;

  grid.insert(eid, x, y, z);
  return eid;
}

export function createBaseStation(
  world: World,
  x: number,
  y: number,
  z: number,
  grid: SpatialGrid,
): number {
  const eid = addEntity(world);
  addComponent(world, eid, BaseStationTag);
  addComponent(world, eid, Position);
  addComponent(world, eid, Storage);

  Position.x[eid] = x;
  Position.y[eid] = y;
  Position.z[eid] = z;

  Storage.iron[eid] = 0;
  Storage.nickel[eid] = 0;
  Storage.cobalt[eid] = 0;
  Storage.platinum[eid] = 0;
  Storage.ice[eid] = 0;
  Storage.carbon[eid] = 0;
  Storage.silicate[eid] = 0;

  grid.insert(eid, x, y, z);
  return eid;
}

/**
 * Find the nearest base station to position (x, y, z).
 * Returns -1 if no bases exist.
 */
export function findNearestBase(world: World, x: number = 0, y: number = 0, z: number = 0): number {
  const bases = query(world, [BaseStationTag, Position]);
  if (bases.length === 0) return -1;
  if (bases.length === 1) return bases[0];
  let nearest = bases[0];
  let nearestDist2 =
    (Position.x[nearest] - x) ** 2 +
    (Position.y[nearest] - y) ** 2 +
    (Position.z[nearest] - z) ** 2;
  for (let i = 1; i < bases.length; i++) {
    const b = bases[i];
    const d2 = (Position.x[b] - x) ** 2 + (Position.y[b] - y) ** 2 + (Position.z[b] - z) ** 2;
    if (d2 < nearestDist2) {
      nearestDist2 = d2;
      nearest = b;
    }
  }
  return nearest;
}
