/**
 * Threat System — Kinetic Threat Model
 *
 * Replaces the old HP-based faction ship combat with positional/economic
 * threats: trajectory interjection, claim jumping, mass driver threats,
 * and signal jamming.
 *
 * Threats are generated based on faction hostility and territorialness,
 * advance over time, and resolve based on player response or arrival.
 */

import type { FactionSystemState, FactionId } from './factions/factionSystem';
import { FACTION_DEFS } from './factions/factionSystem';

// ── Types ─────────────────────────────────────────────────────────────────────

export type ThreatType =
  | 'trajectory_interjection'
  | 'claim_jump'
  | 'mass_driver_threat'
  | 'signal_jam';

export type ThreatResponseType =
  | 'deflect'
  | 'reroute'
  | 'evacuate'
  | 'negotiate'
  | 'contest'
  | 'ignore';

export interface ThreatEvent {
  id: number;
  type: ThreatType;
  factionId: FactionId;
  originX: number;
  originY: number;
  originZ: number;
  targetX: number;
  targetY: number;
  targetZ: number;
  /** Tick when threat was detected */
  detectedTick: number;
  /** Tick when threat arrives/resolves if unresponded */
  arrivalTick: number;
  /** Whether this threat has been resolved */
  resolved: boolean;
  /** How the player responded (set on resolution) */
  responseType?: ThreatResponseType;
}

// ── Constants ─────────────────────────────────────────────────────────────────

/** Minimum disposition to be considered hostile (below this → threats may spawn) */
const HOSTILE_DISPOSITION_THRESHOLD = -40;

/** Ticks between threat generation attempts per faction (90 seconds at 60 tps) */
const THREAT_INTERVAL_TICKS = 60 * 90;

/** Max concurrent active threats per faction */
const MAX_THREATS_PER_FACTION = 2;

/** Max total active threats across all factions */
const MAX_TOTAL_THREATS = 8;

/**
 * Threat type weights by faction territorialness.
 * Higher territorialness → more kinetic threats.
 * Lower territorialness → more economic/diplomatic threats.
 */
function pickThreatType(territorialness: number, rng: () => number): ThreatType {
  const roll = rng();
  if (territorialness > 0.7) {
    // Aggressive factions: more trajectory interjection and mass driver
    if (roll < 0.35) return 'trajectory_interjection';
    if (roll < 0.55) return 'mass_driver_threat';
    if (roll < 0.80) return 'claim_jump';
    return 'signal_jam';
  } else if (territorialness > 0.4) {
    // Moderate factions: balanced threats
    if (roll < 0.30) return 'trajectory_interjection';
    if (roll < 0.50) return 'claim_jump';
    if (roll < 0.75) return 'signal_jam';
    return 'mass_driver_threat';
  } else {
    // Peaceful factions: mostly economic/diplomatic
    if (roll < 0.15) return 'trajectory_interjection';
    if (roll < 0.45) return 'claim_jump';
    if (roll < 0.80) return 'signal_jam';
    return 'mass_driver_threat';
  }
}

/** Duration in ticks from detection to arrival, by threat type */
function threatDuration(type: ThreatType, rng: () => number): number {
  const base: Record<ThreatType, number> = {
    trajectory_interjection: 60 * 120,  // 2 minutes
    claim_jump: 60 * 60,               // 1 minute (diplomatic, fast)
    mass_driver_threat: 60 * 300,       // 5 minutes (slow-moving rock)
    signal_jam: 60 * 180,              // 3 minutes
  };
  // Add ±20% variance
  const variance = 0.8 + rng() * 0.4;
  return Math.round(base[type] * variance);
}

// ── State ─────────────────────────────────────────────────────────────────────

export interface ThreatState {
  /** Active and recently resolved threat events */
  threats: ThreatEvent[];
  /** Per-faction generation cooldown timers */
  generationTimers: number[];
  /** Next threat ID counter */
  nextId: number;
}

export function createThreatState(): ThreatState {
  return {
    threats: [],
    generationTimers: FACTION_DEFS.map(() => 0),
    nextId: 1,
  };
}

// ── Threat Generation ─────────────────────────────────────────────────────────

export type ThreatGeneratedCallback = (threat: ThreatEvent) => void;

/**
 * Generate new threat events based on faction hostility.
 * Threats originate from hostile faction bases and target player positions.
 */
export function tickThreatGeneration(
  tick: number,
  factionState: FactionSystemState,
  threatState: ThreatState,
  playerBaseX: number,
  playerBaseY: number,
  playerBaseZ: number,
  rng: () => number,
  onGenerated?: ThreatGeneratedCallback,
): void {
  // Count active threats per faction
  const activeCounts: number[] = FACTION_DEFS.map(() => 0);
  let totalActive = 0;
  for (const t of threatState.threats) {
    if (!t.resolved) {
      activeCounts[t.factionId]++;
      totalActive++;
    }
  }

  for (const faction of factionState.factions) {
    // Only generate threats for hostile factions
    if (faction.disposition >= HOSTILE_DISPOSITION_THRESHOLD) continue;
    if (activeCounts[faction.id] >= MAX_THREATS_PER_FACTION) continue;
    if (totalActive >= MAX_TOTAL_THREATS) break;

    threatState.generationTimers[faction.id]++;
    if (threatState.generationTimers[faction.id] < THREAT_INTERVAL_TICKS) continue;

    threatState.generationTimers[faction.id] = 0;

    const factionDef = FACTION_DEFS[faction.id];
    const type = pickThreatType(factionDef.territorialness, rng);
    const duration = threatDuration(type, rng);

    // Target is near player base with some offset for variety
    const offsetRange = 3000;
    const targetX = playerBaseX + (rng() - 0.5) * offsetRange;
    const targetY = playerBaseY;
    const targetZ = playerBaseZ + (rng() - 0.5) * offsetRange;

    const threat: ThreatEvent = {
      id: threatState.nextId++,
      type,
      factionId: faction.id,
      originX: faction.base.x,
      originY: faction.base.y,
      originZ: faction.base.z,
      targetX,
      targetY,
      targetZ,
      detectedTick: tick,
      arrivalTick: tick + duration,
      resolved: false,
    };

    threatState.threats.push(threat);
    totalActive++;
    activeCounts[faction.id]++;

    onGenerated?.(threat);
  }
}

// ── Threat Resolution ─────────────────────────────────────────────────────────

export type ThreatArrivedCallback = (threat: ThreatEvent) => void;

/**
 * Advance active threats. Threats that reach their arrival tick without
 * player response are automatically resolved as 'ignore'.
 * Cleaned-up resolved threats older than 5 minutes.
 */
export function tickThreatResolution(
  tick: number,
  threatState: ThreatState,
  onArrived?: ThreatArrivedCallback,
): void {
  for (const threat of threatState.threats) {
    if (threat.resolved) continue;

    if (tick >= threat.arrivalTick) {
      // Threat arrived unaddressed — resolved as ignored
      threat.resolved = true;
      threat.responseType = 'ignore';
      onArrived?.(threat);
    }
  }

  // Prune old resolved threats (keep for 5 minutes after resolution = 18000 ticks)
  const pruneThreshold = tick - 60 * 300;
  threatState.threats = threatState.threats.filter(
    (t) => !t.resolved || t.arrivalTick > pruneThreshold,
  );
}

// ── Player Response ───────────────────────────────────────────────────────────

/**
 * Resolve a threat with a player response. Returns true if the threat
 * was found and resolved, false if not found or already resolved.
 */
export function respondToThreat(
  threatState: ThreatState,
  threatId: number,
  response: ThreatResponseType,
): boolean {
  const threat = threatState.threats.find((t) => t.id === threatId);
  if (!threat || threat.resolved) return false;

  threat.resolved = true;
  threat.responseType = response;
  return true;
}

/**
 * Get all active (unresolved) threats.
 */
export function getActiveThreats(threatState: ThreatState): readonly ThreatEvent[] {
  return threatState.threats.filter((t) => !t.resolved);
}

/**
 * Get active threats for a specific faction.
 */
export function getActiveThreatsByFaction(
  threatState: ThreatState,
  factionId: FactionId,
): readonly ThreatEvent[] {
  return threatState.threats.filter((t) => !t.resolved && t.factionId === factionId);
}

// ── Signal Jam Query ─────────────────────────────────────────────────────────

/**
 * Check if any signal jam is currently active (unresolved).
 * While active, Earth communication is cut: no market orders, no Aria updates.
 */
export function isSignalJamActive(threatState: ThreatState): boolean {
  return threatState.threats.some((t) => !t.resolved && t.type === 'signal_jam');
}

/**
 * Get all active signal jam threats (for UI display / duration info).
 */
export function getActiveSignalJams(threatState: ThreatState): readonly ThreatEvent[] {
  return threatState.threats.filter((t) => !t.resolved && t.type === 'signal_jam');
}

// ── Threat Arrival Effects ───────────────────────────────────────────────────

/** Disposition penalty when a claim jump arrives uncontested */
const CLAIM_JUMP_IGNORE_PENALTY = -15;

/** Disposition cost to negotiate away a claim jump (smaller penalty) */
const CLAIM_JUMP_NEGOTIATE_COST = -5;

/** Disposition cost to contest a claim jump (moderate penalty, but keeps territory) */
const CLAIM_JUMP_CONTEST_COST = -10;

/** Disposition cost to negotiate end of signal jamming */
const SIGNAL_JAM_NEGOTIATE_COST = -8;

export interface ThreatEffectResult {
  dispositionDelta: number;
  factionId: FactionId;
  description: string;
}

/**
 * Compute the gameplay effect when a claim_jump threat arrives unresolved.
 * The faction successfully claims contested territory — disposition worsens.
 */
export function claimJumpArrivalEffect(threat: ThreatEvent): ThreatEffectResult {
  return {
    dispositionDelta: CLAIM_JUMP_IGNORE_PENALTY,
    factionId: threat.factionId,
    description: 'Claim jump succeeded — faction seized contested asteroid territory',
  };
}

/**
 * Compute the gameplay effect when a player responds to a threat.
 * Returns null if no disposition effect applies.
 */
export function threatResponseEffect(
  threat: ThreatEvent,
  response: ThreatResponseType,
): ThreatEffectResult | null {
  if (threat.type === 'claim_jump') {
    if (response === 'negotiate') {
      return {
        dispositionDelta: CLAIM_JUMP_NEGOTIATE_COST,
        factionId: threat.factionId,
        description: 'Negotiated claim jump withdrawal — minor diplomatic cost',
      };
    }
    if (response === 'contest') {
      return {
        dispositionDelta: CLAIM_JUMP_CONTEST_COST,
        factionId: threat.factionId,
        description: 'Contested claim jump — territory retained but relations damaged',
      };
    }
  }

  if (threat.type === 'signal_jam') {
    if (response === 'negotiate') {
      return {
        dispositionDelta: SIGNAL_JAM_NEGOTIATE_COST,
        factionId: threat.factionId,
        description: 'Negotiated signal jam ceasefire — communications restored',
      };
    }
  }

  if (threat.type === 'trajectory_interjection') {
    if (response === 'reroute') {
      return {
        dispositionDelta: -3,
        factionId: threat.factionId,
        description: 'Rerouted mining robots — minimal disruption, slight diplomatic cost',
      };
    }
    if (response === 'evacuate') {
      return {
        dispositionDelta: 0,
        factionId: threat.factionId,
        description: 'Evacuated mining zone — no casualties, operations paused briefly',
      };
    }
  }

  return null;
}

// ── Mass Driver Threat Mechanics ─────────────────────────────────────────────

/**
 * Base kinetic damage dealt by a mass driver impact.
 * Each turret (defenseScore point) reduces damage by this amount.
 */
const MASS_DRIVER_BASE_DAMAGE = 200;

/** Damage reduction per defenseScore point (from turrets) */
const DEFENSE_SCORE_REDUCTION = 30;

/** Minimum damage even with maximum defense (you can't fully block a rock) */
const MASS_DRIVER_MIN_DAMAGE = 50;

/** Fraction of base storage destroyed on unmitigated impact (0.0 – 1.0) */
const STORAGE_LOSS_FRACTION = 0.15;

/** Fraction of base storage destroyed when deflected (much lower) */
const STORAGE_LOSS_DEFLECTED = 0.03;

export interface MassDriverImpactResult {
  /** Effective damage after defense mitigation */
  damage: number;
  /** Was the threat partially deflected by defenseScore? */
  deflected: boolean;
  /** Fraction of storage to destroy */
  storageLossFraction: number;
  /** Description for ARIA notification */
  description: string;
}

/**
 * Calculate the impact of a mass driver threat arriving at a base.
 * DefenseScore from turrets reduces damage. A deflect response
 * requires at least 1 defenseScore and reduces damage further.
 */
export function massDriverImpact(
  defenseScore: number,
  responseType: ThreatResponseType | undefined,
): MassDriverImpactResult {
  const isDeflect = responseType === 'deflect';

  if (isDeflect && defenseScore <= 0) {
    // Can't deflect without turrets — treated as ignore
    return {
      damage: MASS_DRIVER_BASE_DAMAGE,
      deflected: false,
      storageLossFraction: STORAGE_LOSS_FRACTION,
      description: 'Mass driver impact — no turrets available to deflect. Full damage sustained.',
    };
  }

  if (isDeflect) {
    // Successful deflection — greatly reduced damage
    const mitigated = Math.max(
      MASS_DRIVER_MIN_DAMAGE * 0.5,
      MASS_DRIVER_BASE_DAMAGE - defenseScore * DEFENSE_SCORE_REDUCTION * 2,
    );
    return {
      damage: Math.round(mitigated),
      deflected: true,
      storageLossFraction: STORAGE_LOSS_DEFLECTED,
      description: `Mass driver deflected by turret defense (score ${defenseScore}). Impact reduced.`,
    };
  }

  // No deflection — standard defenseScore passive mitigation
  const mitigated = Math.max(
    MASS_DRIVER_MIN_DAMAGE,
    MASS_DRIVER_BASE_DAMAGE - defenseScore * DEFENSE_SCORE_REDUCTION,
  );
  const ignored = responseType === 'ignore' || responseType === undefined;

  return {
    damage: Math.round(mitigated),
    deflected: false,
    storageLossFraction: ignored ? STORAGE_LOSS_FRACTION : STORAGE_LOSS_FRACTION * 0.5,
    description: defenseScore > 0
      ? `Mass driver impact — turret defense absorbed some damage (score ${defenseScore}).`
      : 'Mass driver impact — no turret defense. Full damage sustained.',
  };
}

// ── Serialization ─────────────────────────────────────────────────────────────

export interface SerializedThreatState {
  threats: ThreatEvent[];
  generationTimers: number[];
  nextId: number;
}

export function serializeThreatState(state: ThreatState): SerializedThreatState {
  return {
    threats: state.threats.map((t) => ({ ...t })),
    generationTimers: [...state.generationTimers],
    nextId: state.nextId,
  };
}

export function deserializeThreatState(data: SerializedThreatState): ThreatState {
  const timers = [...data.generationTimers];
  while (timers.length < FACTION_DEFS.length) timers.push(0);
  return {
    threats: data.threats.map((t) => ({ ...t })),
    generationTimers: timers,
    nextId: data.nextId,
  };
}
