/**
 * Material priority weights: player-configurable per-mineral utility weights.
 *
 * Each mineral has a weight (default 1.0). Higher weight = fleet prefers
 * asteroids rich in that mineral. Weight of 0 = ignore that mineral.
 *
 * Used in:
 * - taskGenerationSystem(): weighted candidate scoring for auto-mining
 * - scoreTask(): material utility factor when robots pick from task queue
 */

import { MINERAL_FIELDS, type MineralField } from './minerals';
import { MineralComposition } from './components';

// ── Data structure ───────────────────────────────────────────────────────────

export type MaterialWeights = Record<MineralField, number>;

export function createDefaultWeights(): MaterialWeights {
  return Object.fromEntries(MINERAL_FIELDS.map((f) => [f, 1.0])) as MaterialWeights;
}

// ── Asteroid utility scoring ─────────────────────────────────────────────────

/**
 * Score an asteroid entity based on its mineral composition and the player's
 * material priority weights. Returns a multiplier >= 0.
 *
 * Formula: sum(composition[mineral] * weight[mineral]) / sum(composition[mineral])
 * This gives the weighted-average priority of the asteroid's minerals.
 * If the asteroid has no minerals or all weights are 0, returns 1.0 (neutral).
 */
export function asteroidMaterialScore(eid: number, weights: MaterialWeights): number {
  let weightedSum = 0;
  let totalComp = 0;
  for (const mineral of MINERAL_FIELDS) {
    const comp = MineralComposition[mineral][eid];
    if (comp > 0) {
      weightedSum += comp * weights[mineral];
      totalComp += comp;
    }
  }
  if (totalComp <= 0) return 1.0;
  return weightedSum / totalComp;
}

// ── Serialization ────────────────────────────────────────────────────────────

export type SerializedMaterialWeights = MaterialWeights;
