/**
 * Tech/economy message handlers: research, recipes, builds, buildings.
 */
import { workerState, sendMessage } from '../state';
import { getRawStorage, writeRawStorage } from '../phases/helpers';
import { startResearch, serializeTechState } from '../../techTree';
import { enqueueRecipe } from '../../refining';
import { enqueueBuild } from '../../robotFactory';
import {
  buildBuilding,
  computeRobotCap,
  serializeBuildingState,
  BUILDING_TYPES,
} from '../../buildings';
import type { BuildingType } from '../../buildings';
import type { SimBuildBuildingMessage } from '../../messages';
import { Position } from '../../components';

export function handleStartResearch(payload: { nodeId: string }): void {
  const s = workerState;
  const raw = getRawStorage();
  const result = startResearch(s.techState, payload.nodeId, raw);
  writeRawStorage(raw);
  if (!result.ok) {
    sendMessage({
      type: 'sim:research_error',
      payload: { nodeId: payload.nodeId, error: result.error ?? 'Unknown error' },
    });
  } else {
    sendMessage({
      type: 'sim:tech_state',
      payload: {
        techState: serializeTechState(s.techState),
        refined: { ...s.refineryState.refined },
        justUnlocked: null,
        factoryQueueLength: s.factoryState.queue.length,
        factoryProgress: s.factoryState.activeBuild
          ? s.factoryState.activeBuild.progress / s.factoryState.activeBuild.duration
          : null,
        factoryRemainingSeconds: s.factoryState.activeBuild
          ? s.factoryState.activeBuild.duration - s.factoryState.activeBuild.progress
          : null,
        tick: s.tick,
      },
    });
  }
}

export function handleEnqueueRecipe(payload: { recipeId: string }): void {
  enqueueRecipe(workerState.refineryState, payload.recipeId);
}

export function handleEnqueueBuild(payload: { robotType: number }): void {
  const s = workerState;
  enqueueBuild(s.factoryState, payload.robotType);
  sendMessage({
    type: 'sim:tech_state',
    payload: {
      techState: serializeTechState(s.techState),
      refined: { ...s.refineryState.refined },
      justUnlocked: null,
      factoryQueueLength: s.factoryState.queue.length,
      factoryProgress: s.factoryState.activeBuild
        ? s.factoryState.activeBuild.progress / s.factoryState.activeBuild.duration
        : null,
      factoryRemainingSeconds: s.factoryState.activeBuild
        ? s.factoryState.activeBuild.duration - s.factoryState.activeBuild.progress
        : null,
      tick: s.tick,
    },
  });
}

export function handleBuildBuilding(payload: SimBuildBuildingMessage['payload']): void {
  const s = workerState;
  if (!s.world) return;
  const rawStorage = getRawStorage();
  const baseX = s.baseEidGlobal >= 0 ? Position.x[s.baseEidGlobal] : 0;
  const baseY = s.baseEidGlobal >= 0 ? Position.y[s.baseEidGlobal] : 0;
  const baseZ = s.baseEidGlobal >= 0 ? Position.z[s.baseEidGlobal] : 0;
  const instance = buildBuilding(
    s.buildingState,
    payload.buildingType as BuildingType,
    s.baseEidGlobal,
    rawStorage,
    s._unlockedTechIds,
    baseX,
    baseY,
    baseZ,
  );
  writeRawStorage(rawStorage);
  // Side effects now deferred to when construction completes (see activateBuilding).
  // Factory built flag is set immediately so the build queue is unlocked.
  if (instance && payload.buildingType === BUILDING_TYPES.FACTORY) {
    s.factoryState.built = true;
  }
  sendMessage({
    type: 'sim:building_built',
    payload: {
      success: instance !== null,
      buildingType: payload.buildingType,
      buildings: serializeBuildingState(s.buildingState),
      robotCap: computeRobotCap(s.buildingState),
    },
  });
}
