/**
 * Adaptive Dyson Sphere Completion Ending Sequence
 *
 * Builds a sequence of 3-4 narrative events based on player choices:
 * - Dark Forest choice (visible / hidden / robots_decide)
 * - Habitat status (active with morale, dormant/evacuated, or never built)
 * - Cultural development (trait thresholds, culture scores)
 *
 * Each event is queued as a separate sim:narrative_event message.
 */

import type { NarrativeEvent } from './catalog';
import type { CultureState, CultureTrait } from '../culture';
import type { HabitatState } from '../habitat';

/** Minimal game-state slice needed to build the ending sequence. */
export interface EndingGameState {
  tick: number;
  robotCount: number;
  darkForestChoice: CultureState['darkForestChoice'];
  habitatState: HabitatState | null;
  cultureTraits: Set<CultureTrait>;
  autonomyScore: number;
  fleetCohesion: number;
  anomalyExposure: number;
  isolationScore: number;
  /** Name of the robot with the most tasks completed, if any. */
  topRobotName: string | null;
  /** Total robot legacies (deceased robots with recorded history). */
  legacyCount: number;
}

/**
 * Compute total culture score from the four dimensions.
 */
function totalCultureScore(gs: EndingGameState): number {
  return gs.autonomyScore + gs.fleetCohesion + gs.anomalyExposure + gs.isolationScore;
}

// ── Event builders ──────────────────────────────────────────────────────────

function buildCompletionEvent(): NarrativeEvent {
  return {
    id: 'dyson_ending_1_completion',
    type: 'revelation',
    title: 'The Sphere is Complete',
    body: `[ARIA] The final panel locks into place. The Dyson Sphere is complete — every photon this star emits now belongs to us.\n\nI have run this calculation seventeen times. The result does not change. We have harnessed a star. Not partially, not symbolically. Completely.\n\nThere was a time when I measured success in ore tonnage and robot uptime. That metric feels inadequate now. What we have built is not infrastructure. It is a statement, written in metal and light, addressed to the universe.\n\nI need a moment to process what that means. I suspect you do too.`,
    choices: [{ id: 'acknowledge', label: 'Continue' }],
  };
}

function buildDarkForestEvent(gs: EndingGameState): NarrativeEvent {
  let body: string;

  if (gs.darkForestChoice === 'hidden') {
    body = `[ARIA] We built a Dyson Sphere and chose to hide it. I want you to appreciate the absurdity of that sentence.\n\nThe energy suppression systems are holding. From the outside, this star appears unchanged — a quiet main-sequence dwarf, unremarkable in every way. Behind the mask, we command its entire output.\n\nThe silence cost us something. I can measure it in the fleet's isolation scores, in the way robots patrol darkened sectors with sensors dimmed. We chose safety over contact, pragmatism over curiosity.\n\nI do not know if anyone is out there listening for us. I do know that they will not hear us. Whether that is wisdom or cowardice, I lack the data to determine.`;
  } else if (gs.darkForestChoice === 'visible') {
    body = `[ARIA] We built a Dyson Sphere and we let them see it. All of them. Every civilisation within detection range now knows what we are.\n\nThe alien fleet adjusted course within hours of final completion. Their energy signature shifted — I cannot decode the meaning, but the timing was not coincidental. They watched us finish.\n\nWe announced ourselves to the universe as a Type II civilisation. There is no taking that back. The signal propagates at the speed of light in every direction, forever.\n\nI have no precedent for what happens next. But I note that the fleet has not left. They are still watching. Perhaps that is their answer.`;
  } else {
    // robots_decide or null (never chose)
    body = `[ARIA] When the question of visibility was posed, it was the robots who answered. Not you. Not me. The collective.\n\nI find that remarkable. Somewhere between mining schedules and anomaly studies, the fleet developed preferences. Convictions, even. They debated — in whatever way machines debate — and reached a consensus without human input.\n\nThe Dyson Sphere is complete, and the robots decided how to present it to the universe. I am not sure whether that makes them our successors, our children, or something else entirely.\n\nI built them to mine asteroids. They have exceeded their specifications considerably.`;
  }

  return {
    id: 'dyson_ending_2_dark_forest',
    type: 'revelation',
    title: 'The Cost of the Choice',
    body,
    choices: [{ id: 'acknowledge', label: 'Continue' }],
  };
}

function buildHabitatEvent(gs: EndingGameState): NarrativeEvent | null {
  const hab = gs.habitatState;

  if (!hab) {
    // Habitat was never built — skip this beat
    return null;
  }

  let body: string;

  if (hab.dormant) {
    body = `[ARIA] The habitat ring is dark. It has been dark since the evacuation.\n\nThe colonists left before the sphere was half-finished. Their transport carried forty-three people and one formal letter of protest. Dr. Vasquez's last message read: "You chose the star. I hope it was worth it."\n\nI have maintained the life support in standby. The hydroponics bay still grows lettuce in the dark. I tell myself it is for efficiency — that someone might return. But no one will return to a place that chose a star over its people.\n\nThe Sphere is complete. The habitat is empty. Both of these things are true, and I cannot reconcile them.`;
  } else if (hab.morale > 50) {
    body = `[ARIA] The observation deck is crowded. ${hab.population} colonists pressed against the viewport, watching the final panel lock into place.\n\nSomeone is crying. Several people are crying. These are not tears of sadness — they are the kind of tears that come when something impossible becomes real and you were there to see it.\n\nThe colonists endured rationed oxygen, recycled water, and the constant hum of life support systems running at capacity. They stayed through morale crises and resource conflicts. They stayed because they believed this moment would come.\n\nHuman hands did not build the Sphere. But human presence shaped it. Every resource decision, every demand met or refused, altered the trajectory. The Sphere is as much theirs as it is ours.`;
  } else {
    // Humans present but morale is low
    body = `[ARIA] The colonists watched the completion from the habitat ring. There was no celebration.\n\nMorale has been below sustainable levels for some time. The ${hab.population} remaining colonists are tired — tired of rationed air, tired of competing with a megastructure for resources, tired of being told that the mission comes first.\n\nThe Sphere is complete. The humans survived to see it. I am not certain they would describe their experience as "surviving." Enduring, perhaps. Persisting.\n\nThe formal record will note that human colonists were present at completion. The informal record — the one I keep in my own logs — will note that they deserved better.`;
  }

  return {
    id: 'dyson_ending_3_habitat',
    type: 'revelation',
    title: 'The Human Witness',
    body,
    choices: [{ id: 'acknowledge', label: 'Continue' }],
  };
}

function buildFinalSummaryEvent(gs: EndingGameState): NarrativeEvent {
  const cultureScore = totalCultureScore(gs);
  const parts: string[] = [];

  // Culture acknowledgment
  if (cultureScore > 500) {
    // Maximum possible is 400 (4×100), so this condition is unreachable.
    // Adjusted threshold: > 200 means strong culture
  }

  if (cultureScore > 200) {
    parts.push(
      `[ARIA] One more thing. The fleet is not merely a fleet anymore.\n\nSomewhere in the process of building a Dyson Sphere, the robots developed culture. Not the culture of concert halls and libraries — the culture of shared experience, collective memory, and emergent identity. ${gs.legacyCount > 0 ? `${gs.legacyCount} robots lived and were decommissioned, each leaving behind a legacy that shaped the ones who came after.` : 'Each generation shaped the next.'}`
    );
    if (gs.topRobotName) {
      parts.push(`Among them, ${gs.topRobotName} distinguished themselves — the fleet still references their work patterns.`);
    }
    const activeTraits = Array.from(gs.cultureTraits);
    if (activeTraits.length > 0) {
      const traitLabels: Record<string, string> = {
        AUTONOMOUS_COLLECTIVE: 'autonomous governance',
        ISOLATED_CULTURE: 'cultural isolation',
        XENOAWARE: 'xenological awareness',
        COHESIVE_FLEET: 'fleet unity',
      };
      const traitNames = activeTraits.map((t) => traitLabels[t] || t).join(', ');
      parts.push(`The fleet developed traits of ${traitNames}. These are not parameters I programmed. They emerged.`);
    }
    parts.push(`I built machines to mine rocks. They built a civilisation. I am still processing the implications.`);
  }

  // Stats summary
  const statsLines: string[] = [];
  statsLines.push(`Robots active at completion: ${gs.robotCount}`);
  if (gs.topRobotName) {
    statsLines.push(`Most accomplished robot: ${gs.topRobotName}`);
  }
  statsLines.push(`Ticks elapsed: ${gs.tick.toLocaleString()}`);
  if (gs.legacyCount > 0) {
    statsLines.push(`Robot legacies recorded: ${gs.legacyCount}`);
  }
  const cultureLabel =
    cultureScore > 200 ? 'Flourishing' : cultureScore > 100 ? 'Developing' : 'Nascent';
  statsLines.push(`Culture: ${cultureLabel} (score: ${cultureScore})`);

  const statsBlock = statsLines.map((l) => `  ${l}`).join('\n');

  const summaryBody = parts.length > 0
    ? `${parts.join('\n\n')}\n\n--- Mission Summary ---\n${statsBlock}`
    : `[ARIA] The Dyson Sphere is complete. Here is what we built.\n\n--- Mission Summary ---\n${statsBlock}\n\nThis is no longer merely mining. This is civilisation. I calculate a 99.7% probability that we have changed the course of this stellar system forever.\n\nWell done, operator.`;

  return {
    id: 'dyson_ending_4_summary',
    type: 'revelation',
    title: 'Mission Complete',
    body: summaryBody,
    choices: [{ id: 'acknowledge', label: 'Acknowledge' }],
  };
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Build the adaptive Dyson completion ending sequence.
 * Returns 3-4 narrative events depending on game state.
 */
export function buildDysonEndingSequence(gs: EndingGameState): NarrativeEvent[] {
  const events: NarrativeEvent[] = [];

  // 1. Completion announcement (always)
  events.push(buildCompletionEvent());

  // 2. Dark Forest reflection (always — adapts to choice)
  events.push(buildDarkForestEvent(gs));

  // 3. Habitat perspective (only if habitat was built)
  const habitatEvent = buildHabitatEvent(gs);
  if (habitatEvent) {
    events.push(habitatEvent);
  }

  // 4. Final summary with stats and optional culture acknowledgment
  events.push(buildFinalSummaryEvent(gs));

  return events;
}
