/**
 * Resource Refining System
 *
 * Converts raw ores (from asteroid mining) into refined materials.
 * Phase 3 unlocks: ore_refining tech → basic refinery, advanced_refining → alloy recipes.
 *
 * Refining happens at base stations that have a refinery module.
 * The refinery system runs each tick and advances active jobs.
 */

// ── Recipe definitions ────────────────────────────────────────────────────────

export interface RefiningRecipe {
  id: string;
  name: string;
  /** Raw inputs from Storage (field names) */
  inputs: Partial<Record<string, number>>;
  /** Refined outputs (field names in RefinedStorage) */
  outputs: Partial<Record<string, number>>;
  /** Seconds to complete one batch */
  duration: number;
  /** 'basic' = requires ore_refining, 'advanced' = requires advanced_refining */
  tier: 'basic' | 'advanced';
}

