import {
  Position,
  Velocity,
  Energy,
  Fuel,
  RobotState,
  PathTarget,
  Storage,
} from '../components';
import { ROBOT_STATES } from '../robotCreation';
import { transferInventoryToStorage } from '../robotInventory';
import { distanceTo, BASE_PROXIMITY, ICE_PER_FUEL_UNIT } from './types';

export function handleReturningRobot(eid: number, baseEid: number): void {
  if (baseEid < 0) {
    RobotState.state[eid] = ROBOT_STATES.IDLE;
    return;
  }
  const dist = distanceTo(eid, PathTarget.x[eid], PathTarget.y[eid], PathTarget.z[eid]);
  const speed = Math.sqrt(
    Velocity.x[eid] * Velocity.x[eid] +
      Velocity.y[eid] * Velocity.y[eid] +
      Velocity.z[eid] * Velocity.z[eid],
  );
  if (dist < BASE_PROXIMITY && speed < 5) {
    Velocity.x[eid] = 0;
    Velocity.y[eid] = 0;
    Velocity.z[eid] = 0;

    transferInventoryToStorage(eid, baseEid);

    // Refuel from base ice supply (propellant = electrolyzed ice)
    const fuelNeeded = Fuel.max[eid] - Fuel.current[eid];
    const iceNeeded = fuelNeeded * ICE_PER_FUEL_UNIT;
    const iceAvailable = Storage.ice[baseEid];
    if (iceAvailable >= iceNeeded) {
      Storage.ice[baseEid] -= iceNeeded;
      Fuel.current[eid] = Fuel.max[eid];
    } else {
      // Partial refuel with whatever ice is available
      const fuelFromIce = iceAvailable / ICE_PER_FUEL_UNIT;
      Fuel.current[eid] += fuelFromIce;
      Storage.ice[baseEid] = 0;
    }

    if (Energy.current[eid] / Energy.max[eid] < 0.5) {
      RobotState.state[eid] = ROBOT_STATES.CHARGING;
    } else {
      RobotState.state[eid] = ROBOT_STATES.IDLE;
    }
  }
}
