/**
 * Threat tick phase: generates and resolves kinetic threat events.
 *
 * Runs alongside the old combat phase during transition. Once the threat
 * renderer replaces FactionShipRenderer, the old combat phase will be removed.
 *
 * Phase 2: Claim jump + signal jam arrival effects.
 * Phase 3: Mass driver impact — building damage, defenseScore mitigation, storage loss.
 */
import { query } from 'bitecs';
import { BaseStationTag, Position, Storage } from '../../components';
import { workerState, runSystem, sendMessage } from '../state';
import {
  tickThreatGeneration,
  tickThreatResolution,
  claimJumpArrivalEffect,
  massDriverImpact,
} from '../../threatSystem';
import type { ThreatEvent, ThreatResponseType } from '../../threatSystem';
import { FACTION_DEFS } from '../../factions/factionSystem';
import { addMessage, getInboxSnapshot } from '../../inbox/inboxStore';
import type { InboxMessage } from '../../inbox/inboxTypes';
import { formatTickDuration } from '../state';
import { computeBuildingEffects, applyDamageToBuildings, serializeBuildingState } from '../../buildings';

let nextInboxId = 91000; // high range to avoid collision with combat phase IDs

const THREAT_TYPE_LABELS: Record<string, string> = {
  trajectory_interjection: 'Trajectory Interjection',
  claim_jump: 'Claim Jumping',
  mass_driver_threat: 'Mass Driver Threat',
  signal_jam: 'Signal Jamming',
};

const STORAGE_KEYS = ['iron', 'nickel', 'cobalt', 'platinum', 'ice', 'carbon', 'silicate'] as const;

/** Available player responses per threat type */
const THREAT_RESPONSES: Record<string, ThreatResponseType[]> = {
  trajectory_interjection: ['reroute', 'evacuate', 'ignore'],
  claim_jump: ['negotiate', 'contest', 'ignore'],
  mass_driver_threat: ['deflect', 'evacuate', 'ignore'],
  signal_jam: ['negotiate', 'ignore'],
};

export function tickThreatPhase(): void {
  const s = workerState;
  if (!s.world || !s.factionSystemState || !s.threatState) return;

  // Find primary base for threat targeting
  const bases = query(s.world, [BaseStationTag, Position]);
  let baseX = 0;
  let baseY = 0;
  let baseZ = 0;
  if (bases.length > 0) {
    baseX = Position.x[bases[0]];
    baseY = Position.y[bases[0]];
    baseZ = Position.z[bases[0]];
  }

  // Generate new threats
  runSystem('threatGen', () => {
    tickThreatGeneration(
      s.tick,
      s.factionSystemState!,
      s.threatState!,
      baseX,
      baseY,
      baseZ,
      s.eventRng,
      onThreatGenerated,
    );
  });

  // Resolve arriving threats
  runSystem('threatResolve', () => {
    tickThreatResolution(s.tick, s.threatState!, onThreatArrived);
  });
}

function onThreatGenerated(threat: ThreatEvent): void {
  const s = workerState;
  const factionName = FACTION_DEFS[threat.factionId].name;
  const typeLabel = THREAT_TYPE_LABELS[threat.type] ?? threat.type;
  const eta = formatTickDuration(threat.arrivalTick - threat.detectedTick);

  let body: string;
  switch (threat.type) {
    case 'claim_jump':
      body = `${factionName} is deploying a claim beacon near your mining operations. ` +
        `ETA: ${eta}. Respond with negotiate or contest before arrival, or lose the claim.`;
      break;
    case 'signal_jam':
      body = `${factionName} is jamming communications with Earth. ` +
        `Market orders and Aria updates are blocked for ${eta}. ` +
        `Negotiate a ceasefire or wait it out.`;
      break;
    case 'mass_driver_threat':
      body = `ALERT: ${factionName} has launched a kinetic projectile toward your base. ` +
        `Impact ETA: ${eta}. Build turrets to reduce damage, or deflect if turrets are available.`;
      break;
    default:
      body = `${factionName} ${typeLabel.toLowerCase()} detected. ` +
        `Estimated arrival in ${eta}.`;
      break;
  }

  const msg: InboxMessage = {
    id: nextInboxId++,
    factionId: threat.factionId,
    senderName: 'ARIA',
    type: 'aria_auto',
    subject: `Threat Detected: ${typeLabel}`,
    body,
    priority: threat.type === 'mass_driver_threat' ? 'urgent' : 'normal',
    tick: s.tick,
    triaged: true,
    triageResult: 'relevant',
    read: false,
    threatData: {
      threatId: threat.id,
      threatType: threat.type,
      responses: THREAT_RESPONSES[threat.type] ?? ['ignore'],
    },
  };
  addMessage(msg);
  sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });
}

function onThreatArrived(threat: ThreatEvent): void {
  const s = workerState;
  const factionName = FACTION_DEFS[threat.factionId].name;
  const typeLabel = THREAT_TYPE_LABELS[threat.type] ?? threat.type;

  let body: string;
  let priority: 'urgent' | 'normal' | 'low' = 'normal';

  switch (threat.type) {
    case 'claim_jump': {
      // Apply disposition penalty — faction successfully seized territory
      if (s.factionSystemState) {
        const effect = claimJumpArrivalEffect(threat);
        const faction = s.factionSystemState.factions[threat.factionId];
        if (faction) {
          faction.disposition = Math.max(-100, faction.disposition + effect.dispositionDelta);
          faction.recentEvents.push({ text: effect.description, tick: s.tick });
        }
      }
      body = `${factionName} has planted a claim beacon on contested asteroid territory. ` +
        `No response was taken — relations damaged. ` +
        `Diplomatic standing with ${factionName} has worsened.`;
      priority = 'urgent';
      break;
    }
    case 'signal_jam':
      body = `${factionName} signal jamming has ended. ` +
        `Earth communications restored — market orders and Aria updates are back online.`;
      break;
    case 'mass_driver_threat': {
      // Apply mass driver impact — building damage + storage loss
      const impactBody = applyMassDriverImpact(threat);
      body = impactBody;
      priority = 'urgent';
      break;
    }
    case 'trajectory_interjection': {
      // Trajectory interjection disrupts robot mining — scatter robots near impact zone
      // Disposition penalty for ignored interjection
      if (s.factionSystemState) {
        const faction = s.factionSystemState.factions[threat.factionId];
        if (faction) {
          faction.disposition = Math.max(-100, faction.disposition - 10);
          faction.recentEvents.push({
            text: 'Trajectory interjection disrupted mining operations',
            tick: s.tick,
          });
        }
      }
      body = `${factionName} trajectory interjection reached mining zone. ` +
        `Robot operations disrupted — fleet temporarily scattered. ` +
        `No evasive action was taken.`;
      priority = 'urgent';
      break;
    }
    default:
      body = `${factionName} ${typeLabel.toLowerCase()} has arrived. ` +
        `No response was taken — threat resolved as ignored.`;
      break;
  }

  const msg: InboxMessage = {
    id: nextInboxId++,
    factionId: threat.factionId,
    senderName: 'ARIA',
    type: 'aria_auto',
    subject: threat.type === 'signal_jam'
      ? `Communications Restored`
      : threat.type === 'mass_driver_threat'
        ? `IMPACT: Mass Driver Strike`
        : `Threat Resolved: ${typeLabel}`,
    body,
    priority,
    tick: s.tick,
    triaged: true,
    triageResult: 'relevant',
    read: false,
  };
  addMessage(msg);
  sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });
}

/**
 * Apply mass driver impact to the player's base:
 * 1. Calculate damage (reduced by defenseScore from turrets)
 * 2. Damage buildings closest to impact point
 * 3. Destroy a fraction of stored resources
 * Returns the ARIA notification body text.
 */
function applyMassDriverImpact(threat: ThreatEvent): string {
  const s = workerState;
  const factionName = FACTION_DEFS[threat.factionId].name;
  const parts: string[] = [];

  // Get defenseScore from turrets
  const effects = computeBuildingEffects(s.buildingState);
  const impact = massDriverImpact(effects.defenseScore, threat.responseType);

  parts.push(`${factionName} kinetic projectile struck near base.`);
  parts.push(impact.description);

  // Apply building damage
  const dmgResult = applyDamageToBuildings(
    s.buildingState,
    threat.targetX,
    threat.targetZ,
    impact.damage,
  );

  if (dmgResult.destroyed.length > 0) {
    parts.push(`${dmgResult.destroyed.length} building(s) destroyed.`);
  }
  if (dmgResult.damaged.length > 0) {
    parts.push(`${dmgResult.damaged.length} building(s) damaged.`);
  }
  if (dmgResult.destroyed.length === 0 && dmgResult.damaged.length === 0) {
    parts.push('No buildings in impact zone.');
  }

  // Apply storage loss
  if (impact.storageLossFraction > 0 && s.baseEidGlobal >= 0) {
    const losses: string[] = [];
    for (const key of STORAGE_KEYS) {
      const field = Storage[key as keyof typeof Storage] as Float32Array;
      const current = field[s.baseEidGlobal];
      if (current > 0) {
        const lost = Math.floor(current * impact.storageLossFraction);
        if (lost > 0) {
          field[s.baseEidGlobal] -= lost;
          losses.push(`${lost} ${key}`);
        }
      }
    }
    if (losses.length > 0) {
      parts.push(`Resources lost: ${losses.join(', ')}.`);
    }
  }

  // Broadcast updated building state
  sendMessage({
    type: 'sim:build_state',
    payload: {
      buildings: serializeBuildingState(s.buildingState).buildings,
      tick: s.tick,
    },
  });

  return parts.join(' ');
}
