/**
 * Megastructure message handlers.
 */
import { query } from 'bitecs';
import { RobotTag, RobotType } from '../../components';
import { workerState, sendMessage } from '../state';
import { ROBOT_TYPES } from '../../robotProfiles';
import {
  startMegastructureStage,
  resolveCrisis,
  skipCrisis,
  snapshotProject,
} from '../../megastructures';
import type { SimStartMegastructureStageMessage, SimResolveMegastructureCrisisMessage, SimSkipMegastructureCrisisMessage } from '../../messages';

function countEngineers(world: (typeof workerState)['world']): number {
  if (!world) return 0;
  const robots = query(world, [RobotTag, RobotType]);
  let count = 0;
  for (let i = 0; i < robots.length; i++) {
    if (RobotType.type[robots[i]] === ROBOT_TYPES.ENGINEER) count++;
  }
  return count;
}

function broadcastMegaState(engCount: number): void {
  const s = workerState;
  sendMessage({
    type: 'sim:megastructure_state',
    payload: {
      projects: Array.from(s.megastructureState.projects.values()).map((p) =>
        snapshotProject(p, engCount),
      ),
      tick: s.tick,
    },
  });
}

export function handleStartMegastructureStage(payload: SimStartMegastructureStageMessage['payload']): void {
  const s = workerState;
  const { id, stageIndex } = payload;
  const result = startMegastructureStage(
    s.megastructureState,
    id,
    stageIndex,
    s.refineryState.refined,
    s._unlockedTechIds,
  );
  if (!result.ok) {
    console.warn('[worker] Megastructure stage failed:', result.error);
  }
  broadcastMegaState(countEngineers(s.world));
}

export function handleResolveMegastructureCrisis(payload: SimResolveMegastructureCrisisMessage['payload']): void {
  const s = workerState;
  const result = resolveCrisis(s.megastructureState, payload.id, s.refineryState.refined);
  if (!result.ok) {
    console.warn('[worker] Crisis resolution failed:', result.error);
  }
  broadcastMegaState(countEngineers(s.world));
}

export function handleSkipMegastructureCrisis(payload: SimSkipMegastructureCrisisMessage['payload']): void {
  const s = workerState;
  skipCrisis(s.megastructureState, payload.id);
  broadcastMegaState(countEngineers(s.world));
}
