import { Energy, RobotState } from '../components';
import { ROBOT_STATES } from '../robotCreation';

export function handleChargingRobot(eid: number, dt: number, chargeRateBonus: number): void {
  const chargeRate = 20 + chargeRateBonus;
  Energy.current[eid] = Math.min(Energy.max[eid], Energy.current[eid] + chargeRate * dt);
  if (Energy.current[eid] >= Energy.max[eid]) {
    RobotState.state[eid] = ROBOT_STATES.IDLE;
  }
}
