/**
 * Shared unlock-effect logic applied whenever a tech node is unlocked —
 * both during live simulation ticks and during save/load restore.
 */
import { workerState } from './state';
import { TECH_NODE_BY_ID } from '../techTree';

export function applyUnlockEffects(nodeId: string): void {
  const s = workerState;
  if (nodeId === 'ore_refining') s.refineryState.built = true;
  if (nodeId === 'advanced_refining') s.refineryState.advancedBuilt = true;
  if (nodeId === 'thermal_radiators') s.refineryState.hasRadiator = true;
  if (nodeId === 'concentrated_solar') s.refineryState.hasSolarFurnace = true;
  // robot_factory tech grants +2 robot cap bonus (factory already starts built)
  if (nodeId === 'robot_factory') s.megaRobotCapBonus += 2;

  // Process narrative_trigger effects from the tech node's unlockEffects
  const node = TECH_NODE_BY_ID.get(nodeId);
  if (node) {
    for (const effect of node.unlockEffects) {
      if (effect.kind === 'narrative_trigger') {
        s.eventEngine.setFlag(effect.eventId, true);
      }
    }
  }
}
