/**
 * Resource Market system.
 *
 * Players list resources for sale. Factions buy based on their shortage.
 * Completing a sale requires a hauler robot to transport goods from
 * the player's base to the faction base.
 */

import type { FactionId } from './factions/factionSystem';
import type { FactionTradeWindow } from './factions/factionDefs';
import type { TaskQueue } from './taskQueue';
import { TASK_TYPES, TASK_STATUS } from './taskQueue';
import { Position, Storage } from './components';
import { RESOURCE_VALUE } from './resourceValues';

export { RESOURCE_VALUE };

/**
 * Map UI resource names (CORE_RESOURCES) to ECS Storage field names.
 * water→ice, silicon→silicate, others are identity.
 */
function toStorageKey(resource: string): string {
  if (resource === 'water') return 'ice';
  if (resource === 'silicon') return 'silicate';
  return resource;
}

/**
 * Map UI resource names to faction resource keys.
 * Factions track: iron, carbon, silicon.
 */
function toFactionKey(resource: string): string {
  if (resource === 'water') return 'iron'; // factions don't track water, pay in iron
  return resource;
}

export type MarketListingStatus = 'pending' | 'hauling' | 'completed' | 'cancelled';

export interface MarketListing {
  id: string;
  resource: string;
  quantity: number;
  pricePerUnit: number;
  buyerFactionId: FactionId;
  status: MarketListingStatus;
  /** Task ID in the TaskQueue for the hauler delivery (-1 if not yet created). */
  haulTaskId: number;
  /** Tick when the listing was created. */
  createdTick: number;
}

export interface MarketState {
  listings: Map<string, MarketListing>;
  nextListingIndex: number;
  lastTickProcessed: number;
}

export interface MarketSnapshot {
  listings: MarketListing[];
}

export interface SerializedMarketState {
  listings: MarketListing[];
  nextListingIndex: number;
}

const MARKET_TICK_INTERVAL = 120; // every 2 seconds at 60 ticks/s

export function createMarketState(): MarketState {
  return {
    listings: new Map(),
    nextListingIndex: 1,
    lastTickProcessed: 0,
  };
}

/**
 * Create a new market listing. Deducts resources from the player's base
 * immediately (they are "reserved" for the sale).
 *
 * Returns the listing if successful, or null if the player lacks resources.
 */
export function createListing(
  state: MarketState,
  resource: string,
  quantity: number,
  buyerFactionId: FactionId,
  baseEid: number,
  tick: number,
  buyerTradeWindow?: FactionTradeWindow | null,
): MarketListing | null {
  // Check player has enough of the resource
  const storageKey = toStorageKey(resource);
  const storageField = Storage[storageKey as keyof typeof Storage] as Float32Array | undefined;
  if (!storageField) return null;
  const available = storageField[baseEid];
  if (available < quantity) return null;

  // Deduct resources from base storage (reserve for sale)
  storageField[baseEid] -= quantity;

  const basePrice = RESOURCE_VALUE[resource] ?? 1.0;
  // Apply trade window bonus if the buyer faction has an active window for this resource
  const multiplier =
    buyerTradeWindow && buyerTradeWindow.resource === resource
      ? buyerTradeWindow.rateMultiplier
      : 1.0;
  const pricePerUnit = basePrice * multiplier;
  const id = `market_${state.nextListingIndex++}`;
  const listing: MarketListing = {
    id,
    resource,
    quantity,
    pricePerUnit,
    buyerFactionId,
    status: 'pending',
    haulTaskId: -1,
    createdTick: tick,
  };
  state.listings.set(id, listing);
  return listing;
}

/**
 * Cancel a pending listing. Returns resources to the player's base.
 * Can only cancel listings that haven't started hauling yet.
 */
export function cancelListing(
  state: MarketState,
  listingId: string,
  baseEid: number,
): boolean {
  const listing = state.listings.get(listingId);
  if (!listing || listing.status !== 'pending') return false;

  // Return resources to base
  const storageKey = toStorageKey(listing.resource);
  const storageField = Storage[storageKey as keyof typeof Storage] as Float32Array | undefined;
  if (storageField) {
    storageField[baseEid] += listing.quantity;
  }

  listing.status = 'cancelled';
  return true;
}

/**
 * Tick the market: generate TRADE_DELIVERY tasks for pending listings,
 * check if hauling tasks completed, and finalize transfers.
 */
export function tickMarket(
  state: MarketState,
  tick: number,
  taskQueue: TaskQueue,
  baseEid: number,
  factionBases: Array<{ id: FactionId; x: number; y: number; z: number }>,
  factionResources: Array<{ id: FactionId; resources: Record<string, number> }>,
): { completedListings: MarketListing[] } {
  if (tick - state.lastTickProcessed < MARKET_TICK_INTERVAL) {
    return { completedListings: [] };
  }
  state.lastTickProcessed = tick;

  const completedListings: MarketListing[] = [];

  for (const listing of state.listings.values()) {
    if (listing.status === 'pending' && listing.haulTaskId === -1) {
      // Create a TRADE_DELIVERY task for this listing
      const factionBase = factionBases.find((f) => f.id === listing.buyerFactionId);
      if (!factionBase) continue;

      const taskId = taskQueue.addTask(
        TASK_TYPES.TRADE_DELIVERY,
        baseEid,
        Position.x[baseEid],
        Position.y[baseEid],
        Position.z[baseEid],
        factionBase.x,
        factionBase.y,
        factionBase.z,
        3, // medium priority
        'auto',
      );
      listing.haulTaskId = taskId;
      listing.status = 'hauling';
    } else if (listing.status === 'hauling' && listing.haulTaskId >= 0) {
      // Check if the haul task is completed
      const task = taskQueue.getTask(listing.haulTaskId);
      if (task && task.status === TASK_STATUS.COMPLETED) {
        // Transfer complete: credit payment to player, add resources to faction
        const payment = listing.quantity * listing.pricePerUnit;
        // Payment in iron (universal currency)
        Storage.iron[baseEid] += payment;

        // Credit the sold resource to the faction
        const faction = factionResources.find((f) => f.id === listing.buyerFactionId);
        if (faction) {
          const fKey = toFactionKey(listing.resource);
          if (fKey in faction.resources) {
            (faction.resources as Record<string, number>)[fKey] += listing.quantity;
          }
        }

        listing.status = 'completed';
        completedListings.push(listing);
      }
    }
  }

  // Cleanup old completed/cancelled listings (keep last 20)
  const allListings = Array.from(state.listings.values());
  const done = allListings.filter((l) => l.status === 'completed' || l.status === 'cancelled');
  if (done.length > 20) {
    const toRemove = done.slice(0, done.length - 20);
    for (const l of toRemove) {
      state.listings.delete(l.id);
    }
  }

  return { completedListings };
}

export function snapshotMarket(state: MarketState): MarketSnapshot {
  return {
    listings: Array.from(state.listings.values()),
  };
}

export function serializeMarketState(state: MarketState): SerializedMarketState {
  return {
    listings: Array.from(state.listings.values()),
    nextListingIndex: state.nextListingIndex,
  };
}

export function deserializeMarketState(data: SerializedMarketState): MarketState {
  const state = createMarketState();
  state.nextListingIndex = data.nextListingIndex;
  for (const l of data.listings) {
    state.listings.set(l.id, l);
  }
  return state;
}

/**
 * Compute which faction has the most demand for a given resource.
 * Returns factions sorted by demand (lowest stock first).
 */
export function getFactionDemand(
  factionResources: Array<{ id: FactionId; resources: Record<string, number> }>,
  resource: string,
): Array<{ factionId: FactionId; stock: number }> {
  const mapped = resource === 'water' ? 'ice' : resource === 'silicon' ? 'silicate' : resource;
  // Map CORE_RESOURCE names to faction resource keys
  const factionKey = mapped === 'ice' || mapped === 'silicate' ? mapped : resource;

  return factionResources
    .map((f) => ({
      factionId: f.id,
      stock: (f.resources as Record<string, number>)[factionKey] ?? 0,
    }))
    .sort((a, b) => a.stock - b.stock);
}
