/**
 * Core simulation message handlers: init, start, stop, pause, resume, save, load, robot orders.
 */
import {
  RobotType,
  RobotState,
  Energy,
  Inventory,
  TaskRef,
  PathTarget,
  Position,
  AsteroidType,
  AsteroidSizeTier,
  AsteroidHealth,
  AsteroidRichness,
  MineralComposition,
  AnomalyFlag,
  Orbit,
} from '../../components';
import { ROBOT_STATES } from '../../robotSystems';
import { MINERAL_FIELDS } from '../../minerals';
import { TASK_TYPES, TASK_STATUS } from '../../taskQueue';
import { workerState, sendMessage, buildCultureStatePayload } from '../state';
import { simulationTick } from '../tick';
import { serializeWorld, restoreWorld } from '../serialize';
import { handleSimInit } from '../init';
import { serializeTechState } from '../../techTree';
import { computeRobotCap, serializeBuildingState } from '../../buildings';
import { serializeAutomationState } from '../../automation';
import { getBaseInfos } from '../../logistics';
import { createLogisticsState } from '../../logistics';
import { createTransitState } from '../../transit';
import { createMegastructureState, snapshotProject } from '../../megastructures';
import { resetInbox, getInboxSnapshot } from '../../inbox/inboxStore';
import { resetCommsState } from '../../commsGenerator';
import { snapshotMarket } from '../../market';
import { snapshotTransit } from '../../transit';
import type { SimSaveRequestMessage, SimLoadMessage } from '../../messages';

export function handleInit(payload: Parameters<typeof handleSimInit>[0]): void {
  handleSimInit(payload);
}

export function handleStart(): void {
  const s = workerState;
  if (s.running) return;
  s.running = true;
  s.paused = false;
  s.lastStatsTime = performance.now();
  s.intervalId = setInterval(simulationTick, 1000 / 60);
}

export function handleStop(): void {
  const s = workerState;
  s.running = false;
  s.paused = false;
  s.speedMultiplier = 1;
  if (s.intervalId) { clearInterval(s.intervalId); s.intervalId = null; }
  s.world = null;
  s.grid = null;
  s.taskQueue = null;
  s.asteroidEntities = [];
  s.tick = 0;
  s.respawnTimer = 0;
  s.fieldConfig = null;
  s.discoveredAnomalies.clear();
  s.studySystem.clear();
  s.eventEngine.reset();
  s.entitySystem.reset();
  s.factionSystemState = null;
  s.megastructureState = createMegastructureState();
  s.megaRobotCapBonus = 0;
  s.megaSensorRangeMultiplier = 1;
  s.megaEnergyUnlimited = false;
  s.baseEidGlobal = -1;
  s.logisticsState = createLogisticsState(-1);
  s.transitState = createTransitState();
  resetInbox();
}

export function handlePause(): void {
  workerState.paused = true;
}

export function handleResume(): void {
  workerState.paused = false;
}

export function handleSetSpeed(payload: { multiplier: number }): void {
  const m = Math.max(1, Math.min(4, payload.multiplier));
  workerState.speedMultiplier = m;
}

export function handleSetMaterialWeights(payload: { weights: import('../../materialPriorities').MaterialWeights }): void {
  workerState.materialWeights = payload.weights;
}

export function handleSaveRequest(payload: SimSaveRequestMessage['payload']): void {
  const s = workerState;
  if (!s.world) return;
  try {
    const data = serializeWorld(payload.seed);
    sendMessage({ type: 'sim:save_data', payload: { slot: payload.slot, data } });
  } catch (err) {
    console.error('[worker] Save failed:', err);
    sendMessage({
      type: 'sim:save_failed',
      payload: { slot: payload.slot, error: String(err) },
    });
  }
}

export function handleLoad(payload: SimLoadMessage['payload']): void {
  const s = workerState;
  const wasRunning = s.running;
  if (s.running && s.intervalId) {
    clearInterval(s.intervalId);
    s.intervalId = null;
    s.running = false;
  }
  try {
    restoreWorld(payload.data);
    resetCommsState();
    sendMessage({
      type: 'sim:loaded',
      payload: {
        tick: s.tick,
        commanderState: payload.data.commanderState,
        anomalyAnnotations: payload.data.anomalyAnnotations,
        materialWeights: { ...s.materialWeights },
        commandersLog: payload.data.commandersLog,
        gameEventLog: payload.data.gameEventLog,
        beltEchoesState: payload.data.beltEchoesState,
        speedMultiplier: s.speedMultiplier,
      },
    });
    sendMessage({
      type: 'sim:tech_state',
      payload: {
        techState: serializeTechState(s.techState),
        refined: { ...s.refineryState.refined },
        justUnlocked: null,
        factoryQueueLength: s.factoryState.queue.length,
        factoryProgress: null,
        factoryRemainingSeconds: null,
        robotCap: computeRobotCap(s.buildingState),
        buildings: serializeBuildingState(s.buildingState),
        tick: s.tick,
      },
    });
    sendMessage({
      type: 'sim:automation_state',
      payload: {
        ...serializeAutomationState(s.autoQueueState, s.supplyChainState, s.sectorState),
        tick: s.tick,
      },
    });
    sendMessage({
      type: 'sim:logistics_state',
      payload: {
        bases: getBaseInfos(s.logisticsState),
        routes: Array.from(s.logisticsState.routes.values()),
        tick: s.tick,
      },
    });
    sendMessage({
      type: 'sim:megastructure_state',
      payload: {
        projects: Array.from(s.megastructureState.projects.values()).map((p) =>
          snapshotProject(p, 0),
        ),
        tick: s.tick,
      },
    });
    sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });
    sendMessage({
      type: 'sim:market_state',
      payload: { listings: snapshotMarket(s.marketState).listings, tick: s.tick },
    });
    sendMessage({ type: 'sim:culture_state', payload: buildCultureStatePayload() });
    if (s.transitState.shipments.size > 0) {
      const playerAngle = s.baseEidGlobal >= 0 ? (Orbit.angle[s.baseEidGlobal] || 0) : 0;
      sendMessage({
        type: 'sim:transit_state',
        payload: { ...snapshotTransit(s.transitState, playerAngle), tick: s.tick },
      });
    }
    if (s.habitatState) {
      const h = s.habitatState;
      sendMessage({
        type: 'sim:habitat_state',
        payload: {
          population: h.population,
          morale: h.morale,
          politicalCapital: h.politicalCapital,
          demands: h.demands,
          arrivalTick: h.arrivalTick,
          growthPaused: h.growthPaused,
          dormant: h.dormant,
          tick: s.tick,
        },
      });
    }
    if (wasRunning) {
      s.running = true;
      s.paused = false;
      s.lastStatsTime = performance.now();
      s.intervalId = setInterval(simulationTick, 1000 / 60);
    }
  } catch (err) {
    console.error('[worker] Load failed:', err);
    if (wasRunning) {
      s.running = true;
      s.paused = false;
      s.lastStatsTime = performance.now();
      s.intervalId = setInterval(simulationTick, 1000 / 60);
    }
    sendMessage({ type: 'sim:load_failed', payload: { error: String(err) } });
  }
}

export function handleRobotOrder(payload: { robotEid: number; order: string }): void {
  const s = workerState;
  if (!s.world) return;
  const { robotEid, order } = payload;
  const baseEid = s.baseEidGlobal;
  if (order === 'return_to_base' && baseEid >= 0) {
    if (TaskRef.taskId[robotEid] >= 0 && s.taskQueue) {
      s.taskQueue.releaseTask(TaskRef.taskId[robotEid]);
      TaskRef.taskId[robotEid] = -1;
    }
    RobotState.state[robotEid] = ROBOT_STATES.RETURNING;
    PathTarget.x[robotEid] = Position.x[baseEid];
    PathTarget.y[robotEid] = Position.y[baseEid];
    PathTarget.z[robotEid] = Position.z[baseEid];
  } else if (order === 'idle') {
    if (TaskRef.taskId[robotEid] >= 0 && s.taskQueue) {
      s.taskQueue.releaseTask(TaskRef.taskId[robotEid]);
      TaskRef.taskId[robotEid] = -1;
    }
    RobotState.state[robotEid] = ROBOT_STATES.IDLE;
  }
}

export function handleAddTask(payload: {
  taskType: number;
  targetEid: number;
  targetX: number;
  targetY: number;
  targetZ: number;
  priority?: number;
  robotEid?: number;
}): void {
  const s = workerState;
  if (!s.taskQueue || !s.world) return;
  const baseEid = s.baseEidGlobal;
  const destX = baseEid >= 0 ? Position.x[baseEid] : 0;
  const destY = baseEid >= 0 ? Position.y[baseEid] : 0;
  const destZ = baseEid >= 0 ? Position.z[baseEid] : 0;
  const preferredRobotEid = payload.robotEid ?? -1;
  const taskId = s.taskQueue.addTask(
    payload.taskType,
    payload.targetEid,
    payload.targetX,
    payload.targetY,
    payload.targetZ,
    destX,
    destY,
    destZ,
    payload.priority ?? 10,
    'manual',
    preferredRobotEid,
  );

  // Direct-claim: if a specific robot was targeted and it's currently idle,
  // immediately assign the task to it instead of waiting for the AI scoring loop.
  if (preferredRobotEid >= 0) {
    const currentState = RobotState.state[preferredRobotEid];
    if (currentState === ROBOT_STATES.IDLE) {
      if (s.taskQueue.claimTask(taskId, preferredRobotEid)) {
        TaskRef.taskId[preferredRobotEid] = taskId;
        RobotState.state[preferredRobotEid] = ROBOT_STATES.MOVING_TO;
        PathTarget.x[preferredRobotEid] = payload.targetX;
        PathTarget.y[preferredRobotEid] = payload.targetY;
        PathTarget.z[preferredRobotEid] = payload.targetZ;
      }
    }
  }
}

export function handleRobotDetailRequest(payload: { robotEid: number }): void {
  const s = workerState;
  if (!s.world) return;
  const { robotEid } = payload;
  const inventory: Record<string, number> = {};
  for (const field of MINERAL_FIELDS) {
    inventory[field] = Inventory[field][robotEid];
  }

  // Biography data from culture state
  const stats = s.cultureState.robotStats.get(robotEid);
  const name = s.cultureState.robotNames.get(robotEid) ?? null;
  let distanceFromBase = 0;
  if (s.baseEidGlobal >= 0) {
    const dx = Position.x[robotEid] - Position.x[s.baseEidGlobal];
    const dy = Position.y[robotEid] - Position.y[s.baseEidGlobal];
    const dz = Position.z[robotEid] - Position.z[s.baseEidGlobal];
    distanceFromBase = Math.sqrt(dx * dx + dy * dy + dz * dz);
  }

  sendMessage({
    type: 'sim:robot_detail',
    payload: {
      robotEid,
      robotType: RobotType.type[robotEid],
      state: RobotState.state[robotEid],
      energyPct: Energy.max[robotEid] > 0 ? Energy.current[robotEid] / Energy.max[robotEid] : 0,
      inventory,
      inventoryUsed: Inventory.used[robotEid],
      inventoryCapacity: Inventory.capacity[robotEid],
      taskId: TaskRef.taskId[robotEid],
      name,
      spawnTick: stats?.spawnTick ?? 0,
      currentTick: s.tick,
      tasksCompleted: stats?.tasksCompleted ?? 0,
      asteroidsNamed: stats?.asteroidsNamed ?? 0,
      anomaliesStudied: stats?.anomaliesStudied ?? 0,
      distanceFromBase,
    },
  });
}

const ASTEROID_TYPE_NAMES: Record<number, string> = {
  0: 'Carbonaceous',
  1: 'Silicate',
  2: 'Metallic',
  3: 'Exotic',
};

const ANOMALY_NAMES: Record<number, string> = {
  1: 'Strange Mineral',
  2: 'Structured Signal',
  3: 'Spatial Distortion',
};

export function handleQueryAsteroid(payload: { eid: number }): void {
  const s = workerState;
  if (!s.world) return;
  const { eid } = payload;

  const typeEnum = AsteroidType.type[eid];
  const typeName = ASTEROID_TYPE_NAMES[typeEnum] ?? `Unknown (${typeEnum})`;
  const sizeTier = AsteroidSizeTier.tier[eid];

  const composition: Record<string, number> = {};
  for (const field of MINERAL_FIELDS) {
    composition[field] = MineralComposition[field][eid];
  }

  const current = AsteroidHealth.current[eid];
  const max = AsteroidHealth.max[eid];
  const healthPct = max > 0 ? current / max : 0;
  const richness = AsteroidRichness.multiplier[eid];
  const anomalyType = AnomalyFlag.type[eid];

  // Estimate depletion: count active miners targeting this asteroid
  let estimatedDepletionTicks: number | null = null;
  if (s.taskQueue) {
    const mineTasks = s.taskQueue.getTasksByType(TASK_TYPES.MINE);
    let minerCount = 0;
    for (const task of mineTasks) {
      if (task.targetEid === eid && task.claimedBy >= 0 &&
          (task.status === TASK_STATUS.CLAIMED || task.status === TASK_STATUS.IN_PROGRESS)) {
        minerCount++;
      }
    }
    if (minerCount > 0) {
      // Each miner extracts ~1 health/tick (baseline); richness doesn't affect health drain
      const drainPerTick = minerCount;
      estimatedDepletionTicks = Math.ceil(current / drainPerTick);
    }
  }

  sendMessage({
    type: 'sim:asteroid_detail',
    payload: {
      eid,
      typeName,
      sizeTier,
      composition,
      healthPct,
      richness,
      anomalyType,
      estimatedDepletionTicks,
    },
  });
}
