/**
 * Inbox message generation tick phase + inbox broadcast.
 */
import { workerState, runSystem, sendMessage, INBOX_BROADCAST_INTERVAL } from '../state';
import { tickInbox, getInboxSnapshot } from '../../inbox/inboxStore';
import type { FactionId } from '../../factions/factionSystem';
import { getRawStorage } from './helpers';

export function tickInboxPhase(allRobotsWithPos: ArrayLike<number>): void {
  const s = workerState;
  if (!s.factionSystemState) return;

  runSystem('inbox', () => {
    const raw = getRawStorage();
    const factionDispositions = {} as Record<FactionId, number>;
    const factionResources = {} as Record<FactionId, { iron: number; carbon: number; silicon: number }>;
    for (const f of s.factionSystemState!.factions) {
      factionDispositions[f.id] = f.disposition;
      factionResources[f.id] = { ...f.resources };
    }
    tickInbox(
      s.tick,
      { iron: raw.iron ?? 0, carbon: raw.carbon ?? 0, silicon: raw.silicon ?? 0, water: raw.ice ?? 0 },
      allRobotsWithPos.length,
      factionDispositions,
      factionResources,
    );
  });

  if (s.tick % INBOX_BROADCAST_INTERVAL === 0) {
    sendMessage({
      type: 'sim:inbox_snapshot',
      payload: getInboxSnapshot(s.tick),
    });
  }
}
