/**
 * Narrative Event Engine
 *
 * Tick-based scheduler that checks event trigger conditions,
 * fires events, and tracks consequence flags across the playthrough.
 *
 * Runs entirely in the sim worker thread. Fires events by returning
 * them from tick(); the worker forwards them to the main thread.
 */

import { EVENT_CATALOG } from './catalog';
import type { NarrativeEvent, EventChoice } from './catalog';

export type { NarrativeEvent, EventChoice };

export interface FiredEvent {
  event: NarrativeEvent;
  tick: number;
}

export interface SerializedEventState {
  firedEventIds: string[];
  flags: Record<string, boolean | number>;
  pendingDilemmaId: string | null;
}

export class EventEngine {
  /** Flags set by event consequences or external sim state */
  private flags: Map<string, boolean | number> = new Map();
  /** IDs of events that have already fired (prevent duplicates) */
  private firedIds: Set<string> = new Set();
  /** If a dilemma is waiting for a player choice, store its event ID */
  private pendingDilemmaId: string | null = null;

  // ── External flag setters (called by worker to inform event conditions) ────

  setFlag(key: string, value: boolean | number): void {
    this.flags.set(key, value);
  }

  getFlag(key: string): boolean | number | undefined {
    return this.flags.get(key);
  }

  /** Returns true if flag is set and truthy */
  isFlagSet(key: string): boolean {
    const v = this.flags.get(key);
    return v !== undefined && v !== false && v !== 0;
  }

  hasPendingDilemma(): boolean {
    return this.pendingDilemmaId !== null;
  }

  /**
   * Called when the player makes a choice on a dilemma event.
   * Applies the choice's consequences and clears the pending dilemma.
   * Returns the choice's setFlags (so caller can pass them back).
   */
  resolveChoice(eventId: string, choiceId: string): Record<string, boolean | number> {
    if (this.pendingDilemmaId !== eventId) return {};

    this.pendingDilemmaId = null;

    const event = EVENT_CATALOG.find((e) => e.id === eventId);
    if (!event?.choices) return {};

    const choice = event.choices.find((c) => c.id === choiceId);
    if (!choice) return {};

    const applied: Record<string, boolean | number> = {};
    for (const [k, v] of Object.entries(choice.setFlags ?? {})) {
      this.flags.set(k, v);
      applied[k] = v;
    }
    return applied;
  }

  // ── Tick ──────────────────────────────────────────────────────────────────

  /**
   * Check all events, return any that should fire this tick.
   * The worker is responsible for sending these to the main thread.
   */
  tick(currentTick: number, rng: () => number): FiredEvent[] {
    // Don't fire new events while a dilemma is unresolved
    if (this.pendingDilemmaId !== null) return [];

    const fired: FiredEvent[] = [];

    for (const event of EVENT_CATALOG) {
      if (this.firedIds.has(event.id)) continue;
      if (!this.conditionsMet(event, currentTick)) continue;

      const shouldFire = event.triggerOnce ? true : rng() < (event.chancePerTick ?? 0);

      if (!shouldFire) continue;

      // Apply auto-setFlags (for non-dilemma events or the "fired" flag)
      for (const [k, v] of Object.entries(event.setFlags ?? {})) {
        this.flags.set(k, v);
      }

      this.firedIds.add(event.id);

      if (event.type === 'dilemma' && event.choices) {
        this.pendingDilemmaId = event.id;
      }

      fired.push({ event, tick: currentTick });

      // Only fire one event per tick to avoid information overload
      break;
    }

    return fired;
  }

  private conditionsMet(event: NarrativeEvent, currentTick: number): boolean {
    if (event.minTick !== undefined && currentTick < event.minTick) return false;

    for (const flag of event.requiredFlags ?? []) {
      if (!this.isFlagSet(flag)) return false;
    }

    for (const flag of event.forbiddenFlags ?? []) {
      if (this.isFlagSet(flag)) return false;
    }

    return true;
  }

  // ── Serialization ─────────────────────────────────────────────────────────

  serialize(): SerializedEventState {
    const flags: Record<string, boolean | number> = {};
    for (const [k, v] of this.flags) {
      flags[k] = v;
    }
    return {
      firedEventIds: [...this.firedIds],
      flags,
      pendingDilemmaId: this.pendingDilemmaId,
    };
  }

  deserialize(state: SerializedEventState): void {
    this.firedIds = new Set(state.firedEventIds);
    this.flags = new Map(Object.entries(state.flags));
    this.pendingDilemmaId = state.pendingDilemmaId;
  }

  reset(): void {
    this.flags.clear();
    this.firedIds.clear();
    this.pendingDilemmaId = null;
  }
}
