/**
 * Spatial hash grid for O(1) average-case spatial queries.
 * Lives in the simulation worker.
 */

const SHIFT_Y = 20n;
const SHIFT_X = 40n;

function packKey(cx: number, cy: number, cz: number): bigint {
  return (
    (BigInt(cx & 0xfffff) << SHIFT_X) | (BigInt(cy & 0xfffff) << SHIFT_Y) | BigInt(cz & 0xfffff)
  );
}

export class SpatialGrid {
  private cellSize: number;
  private invCellSize: number;
  private cells: Map<bigint, Set<number>> = new Map();
  private entityCells: Map<number, bigint> = new Map();

  constructor(cellSize: number = 500) {
    this.cellSize = cellSize;
    this.invCellSize = 1 / cellSize;
  }

  private toCell(v: number): number {
    return Math.floor(v * this.invCellSize);
  }

  insert(eid: number, x: number, y: number, z: number): void {
    const key = packKey(this.toCell(x), this.toCell(y), this.toCell(z));
    let cell = this.cells.get(key);
    if (!cell) {
      cell = new Set();
      this.cells.set(key, cell);
    }
    cell.add(eid);
    this.entityCells.set(eid, key);
  }

  remove(eid: number): void {
    const key = this.entityCells.get(eid);
    if (key === undefined) return;
    const cell = this.cells.get(key);
    if (cell) {
      cell.delete(eid);
      if (cell.size === 0) this.cells.delete(key);
    }
    this.entityCells.delete(eid);
  }

  update(eid: number, x: number, y: number, z: number): void {
    const newKey = packKey(this.toCell(x), this.toCell(y), this.toCell(z));
    const oldKey = this.entityCells.get(eid);
    if (oldKey === newKey) return;
    if (oldKey !== undefined) {
      const oldCell = this.cells.get(oldKey);
      if (oldCell) {
        oldCell.delete(eid);
        if (oldCell.size === 0) this.cells.delete(oldKey);
      }
    }
    let cell = this.cells.get(newKey);
    if (!cell) {
      cell = new Set();
      this.cells.set(newKey, cell);
    }
    cell.add(eid);
    this.entityCells.set(eid, newKey);
  }

  /**
   * Query all entities within an axis-aligned bounding box.
   */
  queryAABB(
    minX: number,
    minY: number,
    minZ: number,
    maxX: number,
    maxY: number,
    maxZ: number,
  ): number[] {
    const results: number[] = [];
    const cMinX = this.toCell(minX);
    const cMinY = this.toCell(minY);
    const cMinZ = this.toCell(minZ);
    const cMaxX = this.toCell(maxX);
    const cMaxY = this.toCell(maxY);
    const cMaxZ = this.toCell(maxZ);

    for (let cx = cMinX; cx <= cMaxX; cx++) {
      for (let cy = cMinY; cy <= cMaxY; cy++) {
        for (let cz = cMinZ; cz <= cMaxZ; cz++) {
          const cell = this.cells.get(packKey(cx, cy, cz));
          if (cell) {
            for (const eid of cell) {
              results.push(eid);
            }
          }
        }
      }
    }
    return results;
  }

  /**
   * Query all entities within a radius of a point.
   */
  queryRadius(x: number, y: number, z: number, radius: number): number[] {
    return this.queryAABB(x - radius, y - radius, z - radius, x + radius, y + radius, z + radius);
  }

  clear(): void {
    this.cells.clear();
    this.entityCells.clear();
  }

  get entityCount(): number {
    return this.entityCells.size;
  }
}
