/**
 * Inbox Store — manages the inbox message queue on the sim worker thread.
 *
 * Messages are generated on tick intervals and broadcast to the main thread.
 * The main thread handles LLM processing (Commander triage) and UI display.
 */

import type { FactionId } from '../factions/factionSystem';
import type { InboxMessage, InboxSnapshot } from './inboxTypes';
import type { SerializedInboxState } from '../saveLoad';
import { generateMessages, resetMessageGenerator } from './messageGenerator';

// ── State ────────────────────────────────────────────────────────────────────

const messages: InboxMessage[] = [];
const MAX_MESSAGES = 200;
let totalGenerated = 0;
let lastGenerationTick = 0;

/** Ticks between message generation batches */
const GENERATION_INTERVAL = 600; // ~10 seconds at 60 Hz

// ── Public API ───────────────────────────────────────────────────────────────

export function getInboxSnapshot(tick: number): InboxSnapshot {
  return {
    messages: [...messages],
    tick,
    totalGenerated,
  };
}

/**
 * Add a single message to the inbox (used for system-generated messages
 * like robot replacement choices).
 */
export function addMessage(msg: InboxMessage): void {
  messages.push(msg);
  totalGenerated++;
  while (messages.length > MAX_MESSAGES) {
    messages.shift();
  }
}

export function getUntriagedCount(): number {
  return messages.filter((m) => !m.triaged).length;
}

/**
 * Called each sim tick. Generates messages at intervals.
 */
export function tickInbox(
  tick: number,
  playerResources: { iron: number; carbon: number; silicon: number; water: number },
  playerRobotCount: number,
  factionDispositions: Record<FactionId, number>,
  factionResources: Record<FactionId, { iron: number; carbon: number; silicon: number }>,
): InboxMessage[] | null {
  if (tick - lastGenerationTick < GENERATION_INTERVAL) return null;
  lastGenerationTick = tick;

  const newMessages = generateMessages({
    tick,
    playerResources,
    playerRobotCount,
    factionDispositions,
    factionResources,
  });

  for (const msg of newMessages) {
    messages.push(msg);
    totalGenerated++;
  }

  // Cap stored messages
  while (messages.length > MAX_MESSAGES) {
    messages.shift();
  }

  return newMessages;
}

/**
 * Mark messages as triaged with Commander results.
 */
export function updateTriageResults(
  results: Array<{
    messageId: number;
    triageResult: 'relevant' | 'spam' | 'urgent';
    summary?: string;
    recommendedAction?: string;
  }>,
): void {
  for (const result of results) {
    const msg = messages.find((m) => m.id === result.messageId);
    if (msg) {
      msg.triaged = true;
      msg.triageResult = result.triageResult;
      if (result.summary) msg.summary = result.summary;
      if (result.recommendedAction) msg.recommendedAction = result.recommendedAction;
    }
  }
}

/**
 * Mark a message as read by the player.
 */
export function markRead(messageId: number): void {
  const msg = messages.find((m) => m.id === messageId);
  if (msg) msg.read = true;
}

/**
 * Delete a message from the inbox.
 */
export function deleteMessage(messageId: number): void {
  const idx = messages.findIndex((m) => m.id === messageId);
  if (idx !== -1) messages.splice(idx, 1);
}

export function resetInbox(): void {
  messages.length = 0;
  totalGenerated = 0;
  lastGenerationTick = 0;
  resetMessageGenerator();
}

export function serializeInboxState(): SerializedInboxState {
  return {
    messages: [...messages],
    totalGenerated,
    lastGenerationTick,
  };
}

export function restoreInboxState(state: SerializedInboxState): void {
  messages.length = 0;
  for (const msg of state.messages) {
    messages.push(msg);
  }
  totalGenerated = state.totalGenerated;
  lastGenerationTick = state.lastGenerationTick;
}
