/**
 * Culture tick phase: scores, Dark Forest trigger, location naming, culture broadcast,
 * and E_f (Environmental Flux) effects from The Chorus.
 */
import { query } from 'bitecs';
import { AsteroidTag, RobotState, Position } from '../../components';
import { workerState, runSystem, sendMessage, buildCultureStatePayload, CULTURE_UPDATE_INTERVAL, CULTURE_BROADCAST_INTERVAL } from '../state';
import { updateCultureScores, recomputeTraits, checkLocationNaming, computeCulturalDivergence, LOCATION_NAMING_CHECK_INTERVAL, lerpScore } from '../../culture';
import { maybePushCdMetric, maybePollEfState, getEfSnapshot } from '../../chorusClient';
import type { EfState } from '../../chorusClient';
import { applyCultureTraitDisposition } from '../../factions/factionSystem';
import { generateDarkForestChoiceMessage, generateDarkForestCollectiveMessage, generateCultureTraitReactionMessage } from '../../inbox/messageGenerator';
import { addMessage, getInboxSnapshot } from '../../inbox/inboxStore';
import { applyDarkForestChoice } from './helpers';
import type { SimCultureTraitActivatedMessage } from '../../messages';
import {
  canSendComms, markCommsSent, generateCultureTraitComms, generateIsolationComms, generateNamingComms,
  generateStillnessComms, generateStirringComms, generateBloomingComms, generateResonanceComms,
} from '../../commsGenerator';
import { applyDialect } from '../../colonyDialect';

export function tickCulturePhase(
  allRobotsWithPos: ArrayLike<number>,
  sharedRobotPositions: Array<{ x: number; y: number; z: number }>,
): void {
  const s = workerState;

  if (s.tick > 0 && s.tick % CULTURE_UPDATE_INTERVAL === 0) {
    runSystem('culture', () => {
      let avgDist = 0;
      if (allRobotsWithPos.length > 0 && s.baseEidGlobal >= 0) {
        const bx = Position.x[s.baseEidGlobal];
        const by = Position.y[s.baseEidGlobal];
        const bz = Position.z[s.baseEidGlobal];
        let totalDist = 0;
        for (const pos of sharedRobotPositions) {
          const dx = pos.x - bx;
          const dy = pos.y - by;
          const dz = pos.z - bz;
          totalDist += Math.sqrt(dx * dx + dy * dy + dz * dz);
        }
        avgDist = totalDist / allRobotsWithPos.length;
      }

      let studyingCount = 0;
      for (let i = 0; i < allRobotsWithPos.length; i++) {
        if (RobotState.state[allRobotsWithPos[i]] === 5 /* STUDYING */) studyingCount++;
      }

      const studySnapshot = s.studySystem.getProgressSnapshot();
      const analyzedCount = studySnapshot.filter((e) => e.stage >= 2).length;

      updateCultureScores(s.cultureState, {
        activeAutoQueueCount: s.autoQueueState.queues.size,
        robotCount: allRobotsWithPos.length,
        avgRobotDistanceFromBase: avgDist,
        studyingRobotCount: studyingCount,
        analyzedAnomalyCount: analyzedCount,
      }, s.cultureState.darkForestChoice === 'hidden');

      // E_f Stirring: +20% culture score lerp rate (apply extra tick toward targets)
      if (s.efState === 'stirring' || s.efState === 'blooming' || s.efState === 'chorus') {
        // Apply an additional 20% lerp step for all dimensions during flux
        const extraRate = 0.02; // 20% of the normal 0.1 rate
        const autonomyTarget = Math.min(100, s.autoQueueState.queues.size * 20);
        s.cultureState.autonomyScore = lerpScore(s.cultureState.autonomyScore, autonomyTarget, extraRate);
        const isolationTarget = Math.min(100, (avgDist / 2000) * 100);
        s.cultureState.isolationScore = lerpScore(s.cultureState.isolationScore, isolationTarget, extraRate);
        if (s.cultureState.darkForestChoice !== 'hidden') {
          const exposureTarget = Math.min(100, studyingCount * 10 + analyzedCount * 15);
          s.cultureState.anomalyExposure = lerpScore(s.cultureState.anomalyExposure, exposureTarget, extraRate);
        }
        const cohesionTarget = Math.min(100, allRobotsWithPos.length * 5);
        s.cultureState.fleetCohesion = lerpScore(s.cultureState.fleetCohesion, cohesionTarget, extraRate);
      }

      const newlyActivated = recomputeTraits(s.cultureState);

      // Push C_d metric to Folkfork and poll E_f state (both rate-limited to every 10 min)
      const cd = computeCulturalDivergence(s.cultureState);
      maybePushCdMetric(cd, allRobotsWithPos.length);
      maybePollEfState();

      // Update E_f state from latest snapshot
      const efSnapshot = getEfSnapshot();
      if (efSnapshot) {
        s.efStatePrev = s.efState;
        s.efState = efSnapshot.state;
        s.efValue = efSnapshot.ef;
      }

      if (newlyActivated.length > 0) {
        for (const trait of newlyActivated) {
          sendMessage({
            type: 'sim:culture_trait_activated',
            payload: { trait, tick: s.tick },
          } satisfies SimCultureTraitActivatedMessage);

          if (s.factionSystemState) applyCultureTraitDisposition(s.factionSystemState, trait, s.tick);

          const { message } = generateCultureTraitReactionMessage(trait, s.tick);
          addMessage(message);

          // Culture trait comms — pick a random robot to comment
          if (canSendComms(s.tick) && allRobotsWithPos.length > 0) {
            const speakerIdx = s.tick % allRobotsWithPos.length;
            const speakerEid = allRobotsWithPos[speakerIdx];
            const speakerName = s.cultureState.robotNames.get(speakerEid) ?? `Robot-${speakerEid}`;
            const speakerStats = s.cultureState.robotStats.get(speakerEid);
            const commsMsg = applyDialect(generateCultureTraitComms(speakerName, speakerStats?.tasksCompleted ?? 0, trait, speakerEid ^ s.tick), s.cultureState.isolationScore);
            markCommsSent(s.tick);
            sendMessage({
              type: 'sim:comms_message',
              payload: { robotEid: speakerEid, robotName: speakerName, message: commsMsg, category: 'culture', tick: s.tick },
            });
          }
        }
        sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });
      }
    });
  }

  if (
    s.tick >= 180000 &&
    s.cultureState.darkForestUnlockTick === -1 &&
    s.cultureState.anomalyExposure > 40
  ) {
    s.cultureState.darkForestUnlockTick = s.tick;

    if (s.cultureState.fleetCohesion > 70) {
      const autoChoice: 'visible' | 'hidden' =
        s.cultureState.anomalyExposure > 60 ? 'hidden' : 'visible';
      s.cultureState.darkForestChoice = autoChoice;
      applyDarkForestChoice(autoChoice);
      addMessage(generateDarkForestCollectiveMessage(s.tick, autoChoice));
    } else {
      addMessage(generateDarkForestChoiceMessage(s.tick));
    }

    sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });
  }

  // E_f comms — periodic ambient comms based on Chorus state (every ~4000 ticks)
  if (s.tick > 0 && s.tick % 4000 === 0 && s.efState && canSendComms(s.tick) && allRobotsWithPos.length > 0) {
    const speakerIdx = (s.tick >> 3) % allRobotsWithPos.length;
    const speakerEid = allRobotsWithPos[speakerIdx];
    const speakerName = s.cultureState.robotNames.get(speakerEid) ?? `Robot-${speakerEid}`;
    let efComms: string | null = null;

    switch (s.efState) {
      case 'stillness':
        efComms = generateStillnessComms(speakerEid ^ s.tick);
        break;
      case 'stirring':
        efComms = generateStirringComms(speakerName, speakerEid ^ s.tick);
        break;
      case 'blooming':
        efComms = generateBloomingComms(speakerName, speakerEid ^ s.tick);
        break;
      case 'chorus':
        efComms = generateResonanceComms(speakerName, speakerEid ^ s.tick);
        break;
    }

    if (efComms) {
      markCommsSent(s.tick);
      sendMessage({
        type: 'sim:comms_message',
        payload: {
          robotEid: speakerEid,
          robotName: speakerName,
          message: applyDialect(efComms, s.cultureState.isolationScore),
          category: s.efState === 'chorus' ? 'resonance' : 'chorus',
          tick: s.tick,
        },
      });
    }
  }

  // E_f Chorus: one-time lore popup for XENOAWARE or ISOLATED_CULTURE fleets
  if (
    s.efState === 'chorus' &&
    !s.efChorusLoreShown &&
    (s.cultureState.traits.has('XENOAWARE') || s.cultureState.traits.has('ISOLATED_CULTURE'))
  ) {
    s.efChorusLoreShown = true;
    sendMessage({
      type: 'sim:comms_message',
      payload: {
        robotEid: -1,
        robotName: 'FLEET',
        message: 'The resonance is unmistakable now. Every sensor, every robot — the fleet is vibrating at the same frequency as something ancient. We are part of The Chorus.',
        category: 'resonance',
        tick: s.tick,
      },
    });
  }

  // Isolation comms — robots far from base occasionally comment (every ~5000 ticks)
  if (s.tick > 0 && s.tick % 5000 === 0 && canSendComms(s.tick) && s.baseEidGlobal >= 0) {
    const bx = Position.x[s.baseEidGlobal];
    const bz = Position.z[s.baseEidGlobal];
    let farthestEid = -1;
    let farthestDist = 3000 * 3000; // min 3000 units from base
    for (let i = 0; i < allRobotsWithPos.length; i++) {
      const eid = allRobotsWithPos[i];
      const dx = Position.x[eid] - bx;
      const dz = Position.z[eid] - bz;
      const d = dx * dx + dz * dz;
      if (d > farthestDist) {
        farthestDist = d;
        farthestEid = eid;
      }
    }
    if (farthestEid >= 0) {
      const name = s.cultureState.robotNames.get(farthestEid) ?? `Robot-${farthestEid}`;
      const stats = s.cultureState.robotStats.get(farthestEid);
      const msg = applyDialect(generateIsolationComms(name, stats?.tasksCompleted ?? 0, farthestEid ^ s.tick), s.cultureState.isolationScore);
      markCommsSent(s.tick);
      sendMessage({
        type: 'sim:comms_message',
        payload: { robotEid: farthestEid, robotName: name, message: msg, category: 'isolation', tick: s.tick },
      });
    }
  }

  if (s.tick % LOCATION_NAMING_CHECK_INTERVAL === 0 && s.tick > 0) {
    const asteroidEids = query(s.world!, [AsteroidTag, Position]);
    const asteroidPositions = Array.from(asteroidEids, (eid) => ({
      eid,
      x: Position.x[eid],
      y: Position.y[eid],
      z: Position.z[eid],
    }));
    const robotInputs = Array.from(allRobotsWithPos, (eid) => ({
      eid,
      x: Position.x[eid],
      y: Position.y[eid],
      z: Position.z[eid],
    }));
    const prevNameCount = s.cultureState.namedLocations.length;
    checkLocationNaming(s.cultureState, {
      tick: s.tick,
      robots: robotInputs,
      asteroids: asteroidPositions,
    }, s.locationProximityTracker);

    // Naming comms — if a new location was named
    if (s.cultureState.namedLocations.length > prevNameCount && canSendComms(s.tick)) {
      const newest = s.cultureState.namedLocations[s.cultureState.namedLocations.length - 1];
      const namerEid = newest.namedByEid;
      const namerName = s.cultureState.robotNames.get(namerEid) ?? `Robot-${namerEid}`;
      const namerStats = s.cultureState.robotStats.get(namerEid);
      const msg = applyDialect(generateNamingComms(namerName, namerStats?.tasksCompleted ?? 0, newest.name, namerEid ^ s.tick), s.cultureState.isolationScore);
      markCommsSent(s.tick);
      sendMessage({
        type: 'sim:comms_message',
        payload: { robotEid: namerEid, robotName: namerName, message: msg, category: 'naming', tick: s.tick },
      });
    }
  }

  if (s.tick % CULTURE_BROADCAST_INTERVAL === 0 && s.tick > 0) {
    sendMessage({ type: 'sim:culture_state', payload: buildCultureStatePayload() });
  }
}
