/**
 * Culture-related message handlers: replacement choice, dark forest choice,
 * fleet color/manifesto, colony naming, asteroid naming, colony epithet.
 */
import { query } from 'bitecs';
import { BaseStationTag, Position, RobotTag } from '../../components';
import { workerState, sendMessage, buildCultureStatePayload } from '../state';
import { computeRobotCap } from '../../buildings';
import { applyDarkForestChoice } from '../phases/helpers';
import { applyReplacementChoice, configureReplacementRobot, generateRobotName } from '../../culture';
import { createRobot } from '../../robotCreation';
import { snapshotFactions } from '../../factions/factionSystem';
import type {
  SimReplacementChoiceMessage,
  SimDarkForestChoiceMessage,
  SimSetFleetColorMessage,
  SimSetFleetManifestoMessage,
  SimSetColonyNameMessage,
  SimNameAsteroidMessage,
  SimSetColonyEpithetMessage,
} from '../../messages';
import {
  getFleetColorPalette,
  getManifestoPreset,
  MANIFESTO_MAX_LENGTH,
  COLONY_NAME_MAX_LENGTH,
  ASTEROID_NAME_MAX_LENGTH,
  COLONY_EPITHET_MAX_LENGTH,
} from '../../culture';

/** Send a culture state broadcast using the shared builder. */
function broadcastCultureState(): void {
  sendMessage({ type: 'sim:culture_state', payload: buildCultureStatePayload() });
}

export function handleReplacementChoice(payload: SimReplacementChoiceMessage['payload']): void {
  const s = workerState;
  if (!s.world || !s.grid) return;
  const { legacyEid, choice } = payload;
  applyReplacementChoice(s.cultureState, legacyEid, choice);

  const bases = query(s.world, [BaseStationTag, Position]);
  const beid = bases.length > 0 ? bases[0] : -1;
  const robotCap = computeRobotCap(s.buildingState) + s.megaRobotCapBonus;
  const currentRobotCount = query(s.world, [RobotTag]).length;

  if (beid >= 0 && currentRobotCount < robotCap) {
    let legacy: (typeof s.cultureState.robotLegacies)[number] | undefined;
    for (let i = s.cultureState.robotLegacies.length - 1; i >= 0; i--) {
      if (s.cultureState.robotLegacies[i].eid === legacyEid) {
        legacy = s.cultureState.robotLegacies[i];
        break;
      }
    }
    const spawnX = Position.x[beid] + (Math.random() - 0.5) * 100;
    const spawnY = Position.y[beid] + (Math.random() - 0.5) * 20;
    const spawnZ = Position.z[beid] + (Math.random() - 0.5) * 100;
    const robotType = legacy?.robotType ?? 0;
    const newEid = createRobot(s.world, robotType, spawnX, spawnY, spawnZ, s.grid);
    if (newEid >= 0) {
      configureReplacementRobot(s.cultureState, newEid, choice);
      if (s.cultureState.autonomyScore > 40) {
        s.cultureState.robotNames.set(newEid, generateRobotName(newEid));
      }
      s.cultureState.robotStats.set(newEid, {
        tasksCompleted: 0,
        asteroidsNamed: 0,
        anomaliesStudied: 0,
        spawnTick: s.tick,
        taskHint: -1,
        knowledgeBoostUntil: 0,
        mourningUntil: 0,
        lastTaskTypes: [],
      });
    }
    void legacy;
  }

  broadcastCultureState();
}

export function handleDarkForestChoice(payload: SimDarkForestChoiceMessage['payload']): void {
  const s = workerState;
  const { choice } = payload;

  const resolvedChoice: 'visible' | 'hidden' =
    choice === 'robots_decide'
      ? (s.cultureState.anomalyExposure > 60 ? 'hidden' : 'visible')
      : choice;

  s.cultureState.darkForestChoice = resolvedChoice;
  applyDarkForestChoice(resolvedChoice);

  broadcastCultureState();
  if (s.factionSystemState) {
    sendMessage({
      type: 'sim:faction_state',
      payload: { factions: snapshotFactions(s.factionSystemState), tick: s.tick },
    });
  }
}

export function handleSetFleetColor(payload: SimSetFleetColorMessage['payload']): void {
  const s = workerState;
  const palette = getFleetColorPalette(payload.paletteId);
  if (!palette) throw new Error(`Unknown fleet color palette: ${payload.paletteId}`);

  s.cultureState.fleetColorPaletteId = payload.paletteId;
  broadcastCultureState();
}

export function handleSetFleetManifesto(payload: SimSetFleetManifestoMessage['payload']): void {
  const s = workerState;
  const text = payload.text.slice(0, MANIFESTO_MAX_LENGTH);
  const isChange = s.cultureState.fleetManifesto !== null && s.cultureState.fleetManifesto !== text;

  s.cultureState.fleetManifesto = text;
  s.cultureState.fleetManifestoPresetId = payload.presetId;

  // Apply cultural seed bonus from preset (only on first manifesto, not on revisions)
  if (!isChange && payload.presetId) {
    const preset = getManifestoPreset(payload.presetId);
    if (preset) {
      s.cultureState[preset.seedDimension] = Math.min(100, s.cultureState[preset.seedDimension] + 10);
    }
  }

  broadcastCultureState();
}

export function handleSetColonyName(payload: SimSetColonyNameMessage['payload']): void {
  const s = workerState;
  s.cultureState.colonyName = payload.name.slice(0, COLONY_NAME_MAX_LENGTH) || null;
  broadcastCultureState();
}

export function handleNameAsteroid(payload: SimNameAsteroidMessage['payload']): void {
  const s = workerState;
  const name = payload.name.trim().slice(0, ASTEROID_NAME_MAX_LENGTH);
  if (!name) {
    // Remove name if empty
    s.cultureState.playerNamedAsteroids.delete(payload.asteroidEid);
  } else {
    s.cultureState.playerNamedAsteroids.set(payload.asteroidEid, name);
  }
  broadcastCultureState();
}

export function handleSetColonyEpithet(payload: SimSetColonyEpithetMessage['payload']): void {
  const s = workerState;
  s.cultureState.colonyEpithet = payload.epithet.slice(0, COLONY_EPITHET_MAX_LENGTH) || null;
  broadcastCultureState();
}
