/**
 * Threat response message handlers.
 *
 * When the player responds to a threat (negotiate, contest, etc.),
 * this applies the gameplay effects and updates faction state.
 */
import { workerState, sendMessage } from '../state';
import { respondToThreat, threatResponseEffect } from '../../threatSystem';
import { snapshotFactions } from '../../factions/factionSystem';
import { addMessage, getInboxSnapshot } from '../../inbox/inboxStore';
import { FACTION_DEFS } from '../../factions/factionSystem';
import type { SimThreatResponseMessage } from '../../messages';
import type { InboxMessage } from '../../inbox/inboxTypes';

let nextInboxId = 92000; // high range to avoid collision with other phase IDs

export function handleThreatResponse(payload: SimThreatResponseMessage['payload']): void {
  const s = workerState;
  if (!s.threatState) return;

  // Find the threat before resolving (for effect calculation)
  const threat = s.threatState.threats.find((t) => t.id === payload.threatId);
  if (!threat || threat.resolved) return;

  // Resolve the threat
  const resolved = respondToThreat(s.threatState, payload.threatId, payload.response);
  if (!resolved) return;

  // Apply gameplay effects (disposition changes, etc.)
  if (s.factionSystemState) {
    const effect = threatResponseEffect(threat, payload.response);
    if (effect) {
      const faction = s.factionSystemState.factions[effect.factionId];
      if (faction) {
        faction.disposition = Math.max(-100, Math.min(100, faction.disposition + effect.dispositionDelta));
        faction.recentEvents.push({ text: effect.description, tick: s.tick });
      }
    }

    // Broadcast updated faction state
    sendMessage({
      type: 'sim:faction_state',
      payload: { factions: snapshotFactions(s.factionSystemState), tick: s.tick },
    });
  }

  // Send ARIA notification about the response
  const factionName = FACTION_DEFS[threat.factionId].name;
  const responseLabels: Record<string, string> = {
    negotiate: 'Negotiated resolution',
    contest: 'Contested claim',
    deflect: 'Deflected threat',
    reroute: 'Rerouted cargo',
    evacuate: 'Evacuated area',
    ignore: 'No action taken',
  };
  const responseLabel = responseLabels[payload.response] ?? payload.response;

  const msg: InboxMessage = {
    id: nextInboxId++,
    factionId: threat.factionId,
    senderName: 'ARIA',
    type: 'aria_auto',
    subject: `Threat Response: ${responseLabel}`,
    body: `${responseLabel} against ${factionName} ${threat.type.replace(/_/g, ' ')}. ` +
      `Threat neutralized.`,
    priority: 'normal',
    tick: s.tick,
    triaged: true,
    triageResult: 'relevant',
    read: false,
  };
  addMessage(msg);
  sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });
}
