/**
 * Blueprint message handlers: save, delete, rename, load (restore) blueprints.
 */
import { workerState, sendMessage } from '../state';
import {
  saveBlueprint,
  deleteBlueprint,
  renameBlueprint,
  computeEfficiency,
  serializeBlueprintState,
} from '../../blueprints';
import { serializeAutomationState } from '../../automation';
import { Storage } from '../../components';
import { query } from 'bitecs';
import { RobotTag, RobotState, Energy } from '../../components';
import type { AutoQueue, SupplyRule, Sector } from '../../automation';

function getCurrentEfficiency() {
  const s = workerState;
  if (!s.world) return computeEfficiency(0, 0, 0, 0);

  const robotEids = query(s.world, [RobotTag]);
  let idle = 0;
  let lowEnergy = 0;
  for (const eid of robotEids) {
    if (RobotState.state[eid] === 0) idle++;
    if (Energy.current[eid] / (Energy.max[eid] || 1) < 0.25) lowEnergy++;
  }

  // Resource delta per tick: use accumulated delta / sample interval
  const resourceDelta = s._resourceDeltaAccum / 60; // normalized per tick
  return computeEfficiency(resourceDelta, robotEids.length, idle, lowEnergy);
}

export function handleSaveBlueprint(payload: { name: string }): void {
  const s = workerState;
  const automationSnapshot = serializeAutomationState(
    s.autoQueueState,
    s.supplyChainState,
    s.sectorState,
  );
  const efficiency = getCurrentEfficiency();
  saveBlueprint(s.blueprintState, payload.name, automationSnapshot, efficiency, s.tick);

  // Broadcast updated blueprint state
  sendMessage({
    type: 'sim:blueprint_state',
    payload: serializeBlueprintState(s.blueprintState),
  });
}

export function handleDeleteBlueprint(payload: { id: string }): void {
  deleteBlueprint(workerState.blueprintState, payload.id);
  sendMessage({
    type: 'sim:blueprint_state',
    payload: serializeBlueprintState(workerState.blueprintState),
  });
}

export function handleRenameBlueprint(payload: { id: string; name: string }): void {
  renameBlueprint(workerState.blueprintState, payload.id, payload.name);
  sendMessage({
    type: 'sim:blueprint_state',
    payload: serializeBlueprintState(workerState.blueprintState),
  });
}

export function handleLoadBlueprint(payload: { id: string }): void {
  const s = workerState;
  const bp = s.blueprintState.blueprints.get(payload.id);
  if (!bp) return;

  // Mark all blueprints inactive, then mark this one active
  for (const b of s.blueprintState.blueprints.values()) b.active = false;
  bp.active = true;

  // Restore automation state from blueprint
  s.autoQueueState.queues.clear();
  for (const q of bp.automation.queues) {
    s.autoQueueState.queues.set(q.id, q as AutoQueue);
  }
  s.supplyChainState.rules.clear();
  for (const r of bp.automation.supplyRules) {
    s.supplyChainState.rules.set(r.resource, r as SupplyRule);
  }
  s.sectorState.sectors.clear();
  for (const sec of bp.automation.sectors) {
    s.sectorState.sectors.set(sec.id, sec as Sector);
  }

  // Broadcast updated automation + blueprint state
  sendMessage({
    type: 'sim:automation_state',
    payload: {
      ...serializeAutomationState(s.autoQueueState, s.supplyChainState, s.sectorState),
      tick: s.tick,
    },
  });
  sendMessage({
    type: 'sim:blueprint_state',
    payload: serializeBlueprintState(s.blueprintState),
  });
}
