/**
 * Outpost tick phase: auto-mine + mass driver.
 */
import { workerState } from '../state';
import { tickOutpostAutoMine, tickMassDriver } from '../../outpost';

export function tickOutpostPhase(): void {
  const s = workerState;
  if (!s.world) return;

  tickOutpostAutoMine(s.world);
  tickMassDriver(s.world, s.tick, s.outpostState, s.logisticsState);
}
