/**
 * World maintenance tick phase: asteroid respawn, dust decay, spatial grid update.
 */
import { query, hasComponent } from 'bitecs';
import { RobotTag, Position, AsteroidHusk, AsteroidHealth } from '../../components';
import { workerState, runSystem, FIXED_DT, RESPAWN_INTERVAL_TICKS } from '../state';
import { spawnAsteroid } from '../../asteroidGen';

export function tickWorldMaintenancePhase(): ArrayLike<number> {
  const s = workerState;

  runSystem('dustDecay', () => {
    s.dustGrid.decay(FIXED_DT);
  });

  if (s.fieldConfig && s.grid) {
    s.respawnTimer++;
    if (s.respawnTimer >= RESPAWN_INTERVAL_TICKS) {
      s.respawnTimer = 0;
      for (let i = s.asteroidEntities.length - 1; i >= 0; i--) {
        const eid = s.asteroidEntities[i];
        if (hasComponent(s.world!, eid, AsteroidHusk) && AsteroidHealth.current[eid] <= 0) {
          s.asteroidEntities[i] = s.asteroidEntities[s.asteroidEntities.length - 1];
          s.asteroidEntities.pop();
        }
      }
      const newEid = spawnAsteroid(s.world!, s.fieldConfig, s.grid);
      if (newEid >= 0) {
        s.asteroidEntities.push(newEid);
      }
    }
  }

  const robots = query(s.world!, [RobotTag, Position]);
  for (let i = 0; i < robots.length; i++) {
    const eid = robots[i];
    s.grid!.update(eid, Position.x[eid], Position.y[eid], Position.z[eid]);
  }

  return robots;
}
