import {
  Position,
  Energy,
  RobotState,
  TaskRef,
  PathTarget,
} from '../components';
import type { RobotProfile } from '../robotProfiles';
import type { TaskQueue } from '../taskQueue';
import { TASK_TYPES } from '../taskQueue';
import { ROBOT_STATES } from '../robotCreation';
import { advanceConstruction, CONSTRUCTION_DURATION_TICKS, CONSTRUCTION_STATE } from '../buildings';
import type { BaseBuildingState } from '../buildings';

export function handleConstructingRobot(
  eid: number,
  dt: number,
  taskQueue: TaskQueue,
  profile: RobotProfile,
  baseEid: number,
  buildingState: BaseBuildingState | null,
): void {
  const taskId = TaskRef.taskId[eid];
  const task = taskId >= 0 ? taskQueue.getTask(taskId) : undefined;
  if (!task || !buildingState) {
    RobotState.state[eid] = ROBOT_STATES.IDLE;
    return;
  }

  // Find the building being constructed (targetEid stores building id)
  const building = buildingState.buildings.find((b) => b.id === task.targetEid);
  if (!building || building.constructionState === CONSTRUCTION_STATE.COMPLETE) {
    taskQueue.completeTask(taskId);
    TaskRef.taskId[eid] = -1;
    RobotState.state[eid] = ROBOT_STATES.IDLE;
    return;
  }

  RobotState.stateTimer[eid] += dt;
  Energy.current[eid] -= profile.energyConsumptionRate * profile.maxThrust * 0.4 * dt;

  // Advance construction: engineer contributes progress per tick
  const progressPerTick = dt / (CONSTRUCTION_DURATION_TICKS / 60); // normalize to seconds
  const done = advanceConstruction(building, progressPerTick);

  if (done || Energy.current[eid] / Energy.max[eid] < 0.2) {
    taskQueue.completeTask(taskId);
    TaskRef.taskId[eid] = -1;
    RobotState.stateTimer[eid] = 0;

    if (baseEid >= 0) {
      RobotState.state[eid] = ROBOT_STATES.RETURNING;
      PathTarget.x[eid] = Position.x[baseEid];
      PathTarget.y[eid] = Position.y[baseEid];
      PathTarget.z[eid] = Position.z[baseEid];
    } else {
      RobotState.state[eid] = ROBOT_STATES.IDLE;
    }
  }
}

/**
 * Generate CONSTRUCT tasks for buildings in PLANNED or UNDER_CONSTRUCTION state
 * that don't already have an active task.
 */
export function constructionTaskGenerationSystem(
  taskQueue: TaskQueue,
  buildingState: BaseBuildingState,
): void {
  for (const building of buildingState.buildings) {
    if (building.constructionState === CONSTRUCTION_STATE.COMPLETE) continue;
    // Check if there's already an active CONSTRUCT task for this building
    const existingTasks = taskQueue.getTasksByType(TASK_TYPES.CONSTRUCT);
    const hasTask = existingTasks.some((t) => t.targetEid === building.id);
    if (hasTask) continue;

    taskQueue.addTask(
      TASK_TYPES.CONSTRUCT,
      building.id, // targetEid = building instance ID
      building.worldX,
      building.worldY,
      building.worldZ,
      0, 0, 0,
      5, // high priority
      'auto',
    );
  }
}
