import type { CultureTrait, IntelligenceTier } from '../culture';

/** Lightweight culture effects passed into robot AI systems. */
export interface CultureEffects {
  /** Active culture traits. */
  activeTraits: Set<CultureTrait>;
  /** Current autonomy score (0–100) for tiered AUTONOMOUS_COLLECTIVE effects. */
  autonomyScore: number;
  /** Current fleet cohesion score (0–100). */
  fleetCohesion: number;
  /** Current isolation score (0–100). */
  isolationScore: number;
  /** Per-robot efficiency multiplier from replacement inheritance. */
  efficiencyMultipliers: Map<number, number>;
  /** Robots with full-transfer memory glitch flag. */
  glitchFlags: Set<number>;
  /** RNG function for glitch rolls. */
  glitchRng: () => number;
  /** Per-robot stats for task hints, knowledge boost, mourning, and task history. */
  robotStats: Map<number, { taskHint: number; knowledgeBoostUntil: number; mourningUntil: number; lastTaskTypes: number[] }>;
  /** Output: robot EIDs that experienced directive drift this tick (for comms). */
  directiveDriftEids: number[];
  /** Output: robot EIDs that glitched this tick (for groupthink cascade). */
  glitchedEids: number[];
  /** Current simulation tick. */
  currentTick: number;
  /** Per-robot intelligence tier (from getIntelligenceTier). */
  intelligenceTiers?: Map<number, IntelligenceTier>;
  /** Chorus E_f efficiency boost (1.0 = no boost, 1.05 = Chorus active). */
  efEfficiencyMult: number;
  /** Active isolation sub-trait IDs (from getActiveIsolationTraits). */
  activeIsolationTraitIds?: Set<string>;
}

export type AnomalyDiscoveredCallback = (
  robotEid: number,
  asteroidEid: number,
  anomalyType: number,
  x: number,
  y: number,
  z: number,
) => void;

// Proximity threshold for base approach
export const BASE_PROXIMITY = 30;

// COHESIVE_FLEET: swarm mining proximity radius (800 units)
export const SWARM_RADIUS_SQ = 800 * 800;
// COHESIVE_FLEET: groupthink cascade radius (1000 units)
export const GROUPTHINK_RADIUS_SQ = 1000 * 1000;

// Tool tier mining multipliers (index = tier)
export const TIER_MULTIPLIERS = [1.0, 1.0, 1.8, 3.0] as const;

/** Ice consumed per unit of fuel refilled. */
export const ICE_PER_FUEL_UNIT = 0.05;

import { Position } from '../components';

export function distanceTo(eid: number, tx: number, ty: number, tz: number): number {
  const dx = Position.x[eid] - tx;
  const dy = Position.y[eid] - ty;
  const dz = Position.z[eid] - tz;
  return Math.sqrt(dx * dx + dy * dy + dz * dz);
}
