/**
 * Periodic state broadcasts: study, tech, automation, logistics, dust, stats.
 */
import { query } from 'bitecs';
import { AsteroidTag, RobotTag, RobotState, Energy, Storage, Orbit } from '../../components';
import {
  workerState,
  sendMessage,
  STUDY_BROADCAST_INTERVAL,
  TECH_STATE_INTERVAL,
  AUTOMATION_BROADCAST_INTERVAL,
  LOGISTICS_BROADCAST_INTERVAL,
  MARKET_BROADCAST_INTERVAL,
  DUST_BROADCAST_INTERVAL,
  STATS_INTERVAL,
  TRANSIT_BROADCAST_INTERVAL,
} from '../state';
import { serializeTechState } from '../../techTree';
import { computeRobotCap, serializeBuildingState } from '../../buildings';
import { serializeAutomationState } from '../../automation';
import { getBaseInfos } from '../../logistics';
import { getOutpostInfos } from '../../outpost';
import { snapshotMarket } from '../../market';
import { snapshotTransit } from '../../transit';
import { recordEfficiencySample, computeEfficiency, EFFICIENCY_SAMPLE_INTERVAL } from '../../blueprints';
import type { SimStudyUpdateMessage } from '../../messages';

export function broadcastPeriodicState(
  justUnlocked: string | null,
  robots: ArrayLike<number>,
  startTime: number,
): void {
  const s = workerState;

  if (s.tick % STUDY_BROADCAST_INTERVAL === 0 && s.studySystem.size > 0) {
    const studyMsg: SimStudyUpdateMessage = {
      type: 'sim:study_update',
      payload: {
        entries: s.studySystem.getProgressSnapshot(),
        tick: s.tick,
      },
    };
    sendMessage(studyMsg);
  }

  if (s.tick % TECH_STATE_INTERVAL === 0) {
    sendMessage({
      type: 'sim:tech_state',
      payload: {
        techState: serializeTechState(s.techState),
        refined: { ...s.refineryState.refined },
        justUnlocked,
        factoryQueueLength: s.factoryState.queue.length,
        factoryProgress: s.factoryState.activeBuild
          ? s.factoryState.activeBuild.progress / s.factoryState.activeBuild.duration
          : null,
        factoryRemainingSeconds: s.factoryState.activeBuild
          ? s.factoryState.activeBuild.duration - s.factoryState.activeBuild.progress
          : null,
        robotCap: computeRobotCap(s.buildingState),
        buildings: serializeBuildingState(s.buildingState),
        tick: s.tick,
      },
    });
  }

  if (s.tick % AUTOMATION_BROADCAST_INTERVAL === 0) {
    sendMessage({
      type: 'sim:automation_state',
      payload: {
        ...serializeAutomationState(s.autoQueueState, s.supplyChainState, s.sectorState),
        tick: s.tick,
      },
    });
  }

  // Efficiency sampling for blueprint trend tracking
  // Guard: world must be fully initialized (has entity storage for queries)
  if (s.tick % EFFICIENCY_SAMPLE_INTERVAL === 0 && s.world && (s.world as Record<string, unknown>).dirtyQueries) {
    const robotEids = query(s.world, [RobotTag]);
    let idle = 0;
    for (const eid of robotEids) {
      if (RobotState.state[eid] === 0) idle++;
    }
    // Compute current total resources at base
    const baseEid = s.baseEidGlobal;
    const totalNow = baseEid >= 0
      ? Storage.iron[baseEid] + Storage.nickel[baseEid] + Storage.cobalt[baseEid] +
        Storage.platinum[baseEid] + Storage.ice[baseEid] + Storage.carbon[baseEid] +
        Storage.silicate[baseEid]
      : 0;
    const delta = s._lastResourceTotal > 0 ? totalNow - s._lastResourceTotal : 0;
    s._lastResourceTotal = totalNow;
    s._resourceDeltaAccum = delta > 0 ? delta : 0;

    const eff = computeEfficiency(
      s._resourceDeltaAccum / EFFICIENCY_SAMPLE_INTERVAL,
      robotEids.length,
      idle,
      0,
    );
    recordEfficiencySample(
      s.blueprintState,
      s.tick,
      eff.resourcesPerMinute,
      eff.idleRobotPct,
    );
  }

  if (s.tick % LOGISTICS_BROADCAST_INTERVAL === 0) {
    sendMessage({
      type: 'sim:logistics_state',
      payload: {
        bases: getBaseInfos(s.logisticsState),
        routes: Array.from(s.logisticsState.routes.values()),
        tick: s.tick,
      },
    });

    // Broadcast outpost state alongside logistics
    if (s.world) {
      const outposts = getOutpostInfos(s.world);
      if (outposts.length > 0) {
        sendMessage({
          type: 'sim:outpost_state',
          payload: { outposts, tick: s.tick },
        });
      }
    }
  }

  if (s.tick % MARKET_BROADCAST_INTERVAL === 0) {
    const snapshot = snapshotMarket(s.marketState);
    sendMessage({
      type: 'sim:market_state',
      payload: {
        listings: snapshot.listings,
        tick: s.tick,
      },
    });
  }

  if (s.tick % TRANSIT_BROADCAST_INTERVAL === 0 && s.transitState.shipments.size > 0) {
    const playerAngle = s.baseEidGlobal >= 0 ? (Orbit.angle[s.baseEidGlobal] || 0) : 0;
    sendMessage({
      type: 'sim:transit_state',
      payload: { ...snapshotTransit(s.transitState, playerAngle), tick: s.tick },
    });
  }

  if (s.tick % DUST_BROADCAST_INTERVAL === 0 && s.dustGrid.size > 0) {
    sendMessage({
      type: 'sim:dust_state',
      payload: { cells: s.dustGrid.serialize(), tick: s.tick },
    });
  }

  const now = performance.now();
  if (now - s.lastStatsTime > STATS_INTERVAL) {
    const asteroids = query(s.world!, [AsteroidTag]);
    sendMessage({
      type: 'sim:stats',
      payload: {
        tickDurationMs: now - startTime,
        entityCount: asteroids.length + robots.length,
        asteroidCount: asteroids.length,
        robotCount: robots.length,
      },
    });
    s.lastStatsTime = now;
  }
}
