/**
 * Chorus Client — pushes the C_d (Cultural Divergence) metric to the
 * Folkfork Metrics Ingestion API and polls the E_f (Environmental Flux)
 * state every 10 minutes of real time.
 *
 * Designed to run inside the sim worker. C_d pushes require both
 * FOLKFORK_API_URL and FOLKFORK_API_KEY; E_f polling only needs the URL
 * (the /api/chorus/state endpoint is public).
 */

// ── E_f State Types ──────────────────────────────────────────────────────────

export type EfState = 'stillness' | 'stirring' | 'blooming' | 'chorus';

export interface EfSnapshot {
  ef: number;
  state: EfState;
}

/** Classify an E_f value into its named state. */
export function classifyEf(ef: number): EfState {
  if (ef >= 0.8) return 'chorus';
  if (ef >= 0.6) return 'blooming';
  if (ef >= 0.3) return 'stirring';
  return 'stillness';
}

// ── Timing ───────────────────────────────────────────────────────────────────

const PUSH_INTERVAL_MS = 10 * 60 * 1000; // 10 minutes

let lastPushTime = 0;
let lastPollTime = 0;

/** Last known E_f snapshot. Null until first successful poll. */
let _lastEfSnapshot: EfSnapshot | null = null;

/**
 * Attempt to push the C_d metric if enough real time has elapsed.
 * Call this every tick; it will only fire the HTTP request once per interval.
 *
 * @returns true if a push was attempted this call, false otherwise.
 */
export function maybePushCdMetric(cd: number, robotCount: number): boolean {
  const apiUrl = import.meta.env.VITE_FOLKFORK_API_URL;
  const apiKey = import.meta.env.VITE_FOLKFORK_API_KEY;

  if (!apiUrl || !apiKey) return false;

  const now = Date.now();
  if (now - lastPushTime < PUSH_INTERVAL_MS) return false;

  lastPushTime = now;

  const payload = {
    gameId: 'cotb',
    metric: 'c_d',
    value: cd,
    robotCount: robotCount,
    timestamp: new Date(now).toISOString(),
  };

  fetch(`${apiUrl}/api/chorus/metrics`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify(payload),
  }).catch(() => {
    // Retry once on failure
    fetch(`${apiUrl}/api/chorus/metrics`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${apiKey}`,
      },
      body: JSON.stringify(payload),
    }).catch(() => {
      // Silent fail — no crash when API is unreachable
    });
  });

  return true;
}

// ── E_f Polling ──────────────────────────────────────────────────────────────

/**
 * Poll the Folkfork /api/chorus/state endpoint for the current E_f value.
 * Rate-limited to the same 10-minute interval as C_d pushes.
 * Returns the latest snapshot (may be cached from last poll) or null if unavailable.
 */
export function maybePollEfState(): EfSnapshot | null {
  const apiUrl = import.meta.env.VITE_FOLKFORK_API_URL;

  if (!apiUrl) return _lastEfSnapshot;

  const now = Date.now();
  if (now - lastPollTime < PUSH_INTERVAL_MS) return _lastEfSnapshot;

  lastPollTime = now;

  fetch(`${apiUrl}/api/chorus/state`)
    .then((res) => {
      if (!res.ok) return;
      return res.json();
    })
    .then((data: unknown) => {
      if (data && typeof data === 'object' && 'ef' in data && typeof (data as { ef: number }).ef === 'number') {
        const ef = (data as { ef: number }).ef;
        _lastEfSnapshot = { ef, state: classifyEf(ef) };
      }
    })
    .catch(() => {
      // Graceful fallback — keep last known state
    });

  return _lastEfSnapshot;
}

/** Get the current E_f snapshot without triggering a poll. */
export function getEfSnapshot(): EfSnapshot | null {
  return _lastEfSnapshot;
}

/** Set the E_f snapshot directly (for tests or forced updates). */
export function setEfSnapshot(snapshot: EfSnapshot | null): void {
  _lastEfSnapshot = snapshot;
}

/** Reset internal timers (useful for tests). */
export function resetChorusTimer(): void {
  lastPushTime = 0;
  lastPollTime = 0;
  _lastEfSnapshot = null;
}
