/**
 * Human Habitat System
 *
 * Manages the human colonist population, morale, political capital, and demands.
 * Activated when the human_habitat megastructure completes Stage 2 (Life Support).
 *
 * Morale is a constraint system that creates resource allocation tension with Dyson Swarm.
 * Demands arrive periodically and must be addressed to maintain morale/political capital.
 */

// ── Interfaces ───────────────────────────────────────────────────────────────

// HumanDemand canonical definition lives in shared/habitatTypes — re-export for sim-internal use
export type { HumanDemand } from '../shared/habitatTypes';
import type { HumanDemand } from '../shared/habitatTypes';

export interface HabitatState {
  /** Current colonist count (starts at 50, max 500) */
  population: number;
  /** Morale 0–100 */
  morale: number;
  /** Accumulated political capital */
  politicalCapital: number;
  /** Active demands with deadlines */
  demands: HumanDemand[];
  /** Tick when humans first arrived */
  arrivalTick: number;
  /** True when population growth is paused (morale < 30) */
  growthPaused: boolean;
  /** True when humans have evacuated (morale hit 0) — habitat dormant */
  dormant: boolean;
  /** Ticks since last population growth */
  growthAccumulator: number;
  /** Ticks since last demand generation */
  demandAccumulator: number;
  /** Ticks since last political capital / morale interval */
  intervalAccumulator: number;
  /** Next demand ID counter */
  nextDemandId: number;
}

export interface HabitatTickContext {
  /** Current simulation tick */
  currentTick: number;
  /** Whether life support drain was fully met this interval */
  lifeSupportMet: boolean;
  /** Whether there is surplus beyond life support needs */
  lifeSupportSurplus: boolean;
}

export interface HabitatTickResult {
  /** Research points per second modifier from morale */
  rpModifier: number;
  /** True if humans evacuated this tick */
  evacuated: boolean;
  /** Demands that expired this tick (unresolved, past deadline) */
  expiredDemands: HumanDemand[];
  /** New demand generated this tick, if any */
  newDemand: HumanDemand | null;
  /** Population drain scaling: { water, oxygen, electronics } per drain interval */
  populationDrain: { water: number; oxygen: number; electronics: number };
}

// ── Constants ────────────────────────────────────────────────────────────────

export const HABITAT_CONSTANTS = {
  INITIAL_POPULATION: 50,
  MAX_POPULATION: 500,
  INITIAL_MORALE: 60,

  /** Ticks between population growth checks */
  GROWTH_INTERVAL: 3600,
  /** Minimum morale for population growth */
  GROWTH_MORALE_THRESHOLD: 50,

  /** Ticks between demand generation */
  DEMAND_INTERVAL: 18000,
  /** How many ticks a demand lasts before deadline */
  DEMAND_DEADLINE_WINDOW: 36000,

  /** Ticks between morale/political capital updates */
  UPDATE_INTERVAL: 3600,

  /** Morale change per interval when life support is stalling */
  MORALE_DRAIN_RATE: -5,
  /** Morale change per interval when life support met with surplus */
  MORALE_SURPLUS_RATE: 3,
  /** Morale change per interval when life support met without surplus */
  MORALE_MET_RATE: 1,

  /** Morale threshold for crisis mode */
  MORALE_CRISIS_THRESHOLD: 30,
  /** Morale threshold for bonus mode */
  MORALE_BONUS_THRESHOLD: 70,

  /** RP modifier when morale < 30 */
  RP_PENALTY: -0.5,
  /** RP modifier when morale > 70 */
  RP_BONUS: 1.0,

  /** Political capital earned per interval when morale > 70 */
  POLITICAL_CAPITAL_RATE: 1,
  /** Political capital decay per interval when morale < 40 */
  POLITICAL_CAPITAL_DECAY: 0.5,
  POLITICAL_CAPITAL_DECAY_THRESHOLD: 40,

  /** Population per drain unit scaling */
  DRAIN_POP_DIVISOR: 50,
} as const;

// ── State creation ───────────────────────────────────────────────────────────

export function createHabitatState(arrivalTick: number): HabitatState {
  return {
    population: HABITAT_CONSTANTS.INITIAL_POPULATION,
    morale: HABITAT_CONSTANTS.INITIAL_MORALE,
    politicalCapital: 0,
    demands: [],
    arrivalTick,
    growthPaused: false,
    dormant: false,
    growthAccumulator: 0,
    demandAccumulator: 0,
    intervalAccumulator: 0,
    nextDemandId: 1,
  };
}

// ── Population drain calculation ─────────────────────────────────────────────

/**
 * Calculate extra drain from population.
 * Each 50 colonists: +1 water, +0.5 oxygen, +0.5 electronics per drain interval.
 */
export function getPopulationDrain(population: number): {
  water: number;
  oxygen: number;
  electronics: number;
} {
  const units = Math.floor(population / HABITAT_CONSTANTS.DRAIN_POP_DIVISOR);
  return {
    water: units,
    oxygen: units * 0.5,
    electronics: units * 0.5,
  };
}

// ── Demand generation ────────────────────────────────────────────────────────

const DEMAND_TEMPLATES: Array<{
  type: HumanDemand['type'];
  description: string;
  moralePenalty: number;
  politicalReward: number;
}> = [
  {
    type: 'resource_allocation',
    description: 'Colonists demand increased water production to meet growing needs.',
    moralePenalty: 8,
    politicalReward: 3,
  },
  {
    type: 'resource_allocation',
    description: 'Electronics shortages are affecting daily life. Colonists want more production.',
    moralePenalty: 6,
    politicalReward: 2,
  },
  {
    type: 'priority_shift',
    description: 'Colonists are asking you to pause megastructure construction and focus on habitat improvements.',
    moralePenalty: 10,
    politicalReward: 5,
  },
  {
    type: 'safety_concern',
    description: 'Reports of structural stress near the spin ring. Colonists demand an inspection.',
    moralePenalty: 12,
    politicalReward: 4,
  },
  {
    type: 'safety_concern',
    description: 'Air recycler efficiency dropping. Colonists want redundant systems installed.',
    moralePenalty: 10,
    politicalReward: 3,
  },
  {
    type: 'expansion_request',
    description: 'Population is growing — colonists want expanded living quarters.',
    moralePenalty: 5,
    politicalReward: 4,
  },
];

function generateDemand(
  state: HabitatState,
  currentTick: number,
  rng: () => number,
): HumanDemand {
  const templateIndex = Math.floor(rng() * DEMAND_TEMPLATES.length);
  const template = DEMAND_TEMPLATES[templateIndex];
  const demand: HumanDemand = {
    id: state.nextDemandId++,
    type: template.type,
    description: template.description,
    deadlineTick: currentTick + HABITAT_CONSTANTS.DEMAND_DEADLINE_WINDOW,
    moralePenalty: template.moralePenalty,
    politicalReward: template.politicalReward,
    resolved: false,
  };
  return demand;
}

// ── Resolve demand ───────────────────────────────────────────────────────────

export function resolveDemand(state: HabitatState, demandId: number): boolean {
  const demand = state.demands.find((d) => d.id === demandId && !d.resolved);
  if (!demand) return false;

  demand.resolved = true;
  state.politicalCapital += demand.politicalReward;
  state.morale = Math.min(100, state.morale + 2);
  return true;
}

// ── Tick ──────────────────────────────────────────────────────────────────────

export function tickHabitat(
  state: HabitatState,
  ctx: HabitatTickContext,
  rng: () => number = Math.random,
): HabitatTickResult {
  const result: HabitatTickResult = {
    rpModifier: 0,
    evacuated: false,
    expiredDemands: [],
    newDemand: null,
    populationDrain: getPopulationDrain(state.population),
  };

  if (state.dormant) return result;

  // ── Interval-based updates (morale, political capital) ───────────────────
  state.intervalAccumulator++;
  if (state.intervalAccumulator >= HABITAT_CONSTANTS.UPDATE_INTERVAL) {
    state.intervalAccumulator = 0;

    // Morale update
    if (!ctx.lifeSupportMet) {
      state.morale = Math.max(0, state.morale + HABITAT_CONSTANTS.MORALE_DRAIN_RATE);
    } else if (ctx.lifeSupportSurplus) {
      state.morale = Math.min(100, state.morale + HABITAT_CONSTANTS.MORALE_SURPLUS_RATE);
    } else {
      state.morale = Math.min(100, state.morale + HABITAT_CONSTANTS.MORALE_MET_RATE);
    }

    // Political capital
    if (state.morale > HABITAT_CONSTANTS.MORALE_BONUS_THRESHOLD) {
      state.politicalCapital += HABITAT_CONSTANTS.POLITICAL_CAPITAL_RATE;
    } else if (state.morale < HABITAT_CONSTANTS.POLITICAL_CAPITAL_DECAY_THRESHOLD) {
      state.politicalCapital = Math.max(
        0,
        state.politicalCapital - HABITAT_CONSTANTS.POLITICAL_CAPITAL_DECAY,
      );
    }
  }

  // ── Check evacuation ─────────────────────────────────────────────────────
  if (state.morale <= 0) {
    state.dormant = true;
    result.evacuated = true;
    return result;
  }

  // ── Growth pause ─────────────────────────────────────────────────────────
  state.growthPaused = state.morale < HABITAT_CONSTANTS.MORALE_CRISIS_THRESHOLD;

  // ── Population growth ────────────────────────────────────────────────────
  if (!state.growthPaused && state.morale > HABITAT_CONSTANTS.GROWTH_MORALE_THRESHOLD) {
    state.growthAccumulator++;
    if (state.growthAccumulator >= HABITAT_CONSTANTS.GROWTH_INTERVAL) {
      state.growthAccumulator = 0;
      if (state.population < HABITAT_CONSTANTS.MAX_POPULATION) {
        state.population++;
        result.populationDrain = getPopulationDrain(state.population);
      }
    }
  }

  // ── RP modifier ──────────────────────────────────────────────────────────
  if (state.morale < HABITAT_CONSTANTS.MORALE_CRISIS_THRESHOLD) {
    result.rpModifier = HABITAT_CONSTANTS.RP_PENALTY;
  } else if (state.morale > HABITAT_CONSTANTS.MORALE_BONUS_THRESHOLD) {
    result.rpModifier = HABITAT_CONSTANTS.RP_BONUS;
  }

  // ── Demand expiry ────────────────────────────────────────────────────────
  for (const demand of state.demands) {
    if (!demand.resolved && ctx.currentTick >= demand.deadlineTick) {
      demand.resolved = true; // mark as expired/resolved
      state.morale = Math.max(0, state.morale - demand.moralePenalty);
      result.expiredDemands.push(demand);
    }
  }

  // Clean up resolved demands immediately (don't wait for deadline)
  state.demands = state.demands.filter((d) => !d.resolved);

  // ── Demand generation ────────────────────────────────────────────────────
  state.demandAccumulator++;
  if (state.demandAccumulator >= HABITAT_CONSTANTS.DEMAND_INTERVAL) {
    state.demandAccumulator = 0;
    const demand = generateDemand(state, ctx.currentTick, rng);
    state.demands.push(demand);
    result.newDemand = demand;
  }

  return result;
}

// ── Serialization ────────────────────────────────────────────────────────────

export interface SerializedHabitatState {
  population: number;
  morale: number;
  politicalCapital: number;
  demands: HumanDemand[];
  arrivalTick: number;
  growthPaused: boolean;
  dormant: boolean;
  growthAccumulator: number;
  demandAccumulator: number;
  intervalAccumulator: number;
  nextDemandId: number;
}

export function serializeHabitatState(state: HabitatState): SerializedHabitatState {
  return { ...state };
}

export function deserializeHabitatState(data: SerializedHabitatState): HabitatState {
  return {
    population: data.population ?? HABITAT_CONSTANTS.INITIAL_POPULATION,
    morale: data.morale ?? HABITAT_CONSTANTS.INITIAL_MORALE,
    politicalCapital: data.politicalCapital ?? 0,
    demands: data.demands ?? [],
    arrivalTick: data.arrivalTick ?? 0,
    growthPaused: data.growthPaused ?? false,
    dormant: data.dormant ?? false,
    growthAccumulator: data.growthAccumulator ?? 0,
    demandAccumulator: data.demandAccumulator ?? 0,
    intervalAccumulator: data.intervalAccumulator ?? 0,
    nextDemandId: data.nextDemandId ?? 1,
  };
}
