/**
 * Transit Queue system — interplanetary cargo delivery.
 *
 * Players dispatch cargo shipments from base storage to planetary destinations.
 * Resources are deducted on dispatch, payment credited on arrival.
 * Transit time depends on destination distance and orbital alignment.
 * Demand curves modulate pricing per destination/resource over time.
 *
 * 1 game-day = 60 real-seconds (3600 ticks at 60 Hz).
 */

import type { MineralField } from './minerals';
import { MINERAL_FIELDS } from './minerals';
import { Storage } from './components';

// ── Constants ────────────────────────────────────────────────────────────────

/** Ticks per game-day (60 ticks/s × 60 seconds). */
export const TICKS_PER_GAME_DAY = 3600;

/** How often (in ticks) to check for arrived shipments. */
export const TRANSIT_CHECK_INTERVAL = 60; // every second

/** Iron mined threshold to unlock Luna (Phase 1→2 transition). */
export const LUNA_UNLOCK_IRON_THRESHOLD = 10_000;

/** How often (in ticks) to update demand curves. Once per game-day. */
export const DEMAND_UPDATE_INTERVAL = TICKS_PER_GAME_DAY;

// ── Planetary Destinations ───────────────────────────────────────────────────

export interface PlanetaryDestination {
  id: string;
  name: string;
  /** Base transit time in game-days (at opposition / closest approach). */
  baseTransitDays: number;
  /** Orbital angle in radians (simplified, drifts slowly). */
  orbitalAngle: number;
  /** Orbital period in game-days (for angle drift). */
  orbitalPeriodDays: number;
  /** Base price multiplier per mineral type (relative to base iron=1.0). */
  pricing: Record<MineralField, number>;
  /** Whether this destination requires an unlock condition. */
  locked?: boolean;
  /** Flavor description for ARIA dispatch messages. */
  dispatchFlavor?: string;
}

/** Tier 1 destinations — Sprint 1 only includes Earth and Luna. */
export const DESTINATIONS: PlanetaryDestination[] = [
  {
    id: 'earth',
    name: 'Earth',
    baseTransitDays: 180,
    orbitalAngle: 0,
    orbitalPeriodDays: 365,
    pricing: {
      iron: 1.0,
      nickel: 1.2,
      cobalt: 2.0,
      platinum: 4.0,
      ice: 0.8,
      carbon: 1.5,
      silicate: 0.6,
    },
    dispatchFlavor: 'Cargo routed through L1 orbital station — the space elevator will handle descent to surface.',
  },
  {
    id: 'luna',
    name: 'Luna',
    baseTransitDays: 180,
    orbitalAngle: 0, // co-orbital with Earth
    orbitalPeriodDays: 365,
    pricing: {
      iron: 0.8,
      nickel: 0.9,
      cobalt: 1.5,
      platinum: 3.0,
      ice: 1.5, // Luna premium for ice
      carbon: 1.0,
      silicate: 1.2, // Luna premium for silicates
    },
    locked: true,
    dispatchFlavor: 'Shipment bound for Shackleton Base — south pole receiving dock.',
  },
];

export function getDestination(id: string): PlanetaryDestination | undefined {
  return DESTINATIONS.find((d) => d.id === id);
}

// ── Demand Curves ────────────────────────────────────────────────────────────

/**
 * Per-destination demand multipliers that modulate base pricing.
 * Earth demand is stable (drifts ±5%). Luna fluctuates more (±20%).
 */
export interface DemandLevel {
  /** Current demand multiplier per resource (centered around 1.0). */
  multipliers: Record<MineralField, number>;
}

/** Create default demand at 1.0 for all resources. */
export function createDemandLevel(): DemandLevel {
  const multipliers = {} as Record<MineralField, number>;
  for (const f of MINERAL_FIELDS) multipliers[f] = 1.0;
  return { multipliers };
}

/**
 * Drift demand multipliers with bounded random walk.
 * @param demand Current demand level (mutated in place).
 * @param volatility Max change per update (e.g. 0.05 for Earth, 0.20 for Luna).
 * @param rng Random number generator returning [0,1).
 */
export function tickDemand(demand: DemandLevel, volatility: number, rng: () => number): void {
  for (const f of MINERAL_FIELDS) {
    const drift = (rng() - 0.5) * 2 * volatility;
    demand.multipliers[f] = Math.max(0.5, Math.min(2.0, demand.multipliers[f] + drift));
  }
}

/** Earth demand volatility per game-day. Stable market. */
export const EARTH_DEMAND_VOLATILITY = 0.02;
/** Luna demand volatility per game-day. Expansion-driven fluctuations. */
export const LUNA_DEMAND_VOLATILITY = 0.08;

/** Get the effective price for a resource at a destination, including demand. */
export function getEffectivePrice(
  dest: PlanetaryDestination,
  resource: MineralField,
  demand: DemandLevel,
): number {
  return dest.pricing[resource] * demand.multipliers[resource];
}

// ── Progression State ────────────────────────────────────────────────────────

export interface ProgressionState {
  /** Whether the player has completed at least one Earth delivery. */
  firstEarthDelivery: boolean;
  /** Lifetime iron mined (tracked externally, fed in via updateIronMined). */
  totalIronMined: number;
  /** Whether Luna has been unlocked. */
  lunaUnlocked: boolean;
  /** Current game phase (1 = Sole Proprietor, 2 = Lunar Rush). */
  phase: number;
}

export function createProgressionState(): ProgressionState {
  return {
    firstEarthDelivery: false,
    totalIronMined: 0,
    lunaUnlocked: false,
    phase: 1,
  };
}

/**
 * Check if Luna unlock conditions are met and transition to Phase 2.
 * Returns true if Luna was just unlocked this call.
 */
export function checkPhaseTransition(progression: ProgressionState): boolean {
  if (progression.lunaUnlocked) return false;
  if (
    progression.firstEarthDelivery &&
    progression.totalIronMined >= LUNA_UNLOCK_IRON_THRESHOLD
  ) {
    progression.lunaUnlocked = true;
    progression.phase = 2;
    return true;
  }
  return false;
}

/** Check whether a destination is available given current progression. */
export function isDestinationAvailable(
  dest: PlanetaryDestination,
  progression: ProgressionState,
): boolean {
  if (dest.id === 'luna') return progression.lunaUnlocked;
  return !dest.locked;
}

// ── Orbital Alignment ────────────────────────────────────────────────────────

/**
 * Compute alignment factor between player's belt position and a destination.
 * Returns 1.0 (opposition, closest) to 2.5 (conjunction, far side of sun).
 *
 * From spec: alignmentFactor = 1.0 + 1.5 * (1 - cos(playerAngle - destAngle)) / 2
 */
export function computeAlignmentFactor(playerAngle: number, destAngle: number): number {
  return 1.0 + 1.5 * (1 - Math.cos(playerAngle - destAngle)) / 2;
}

/**
 * Compute transit time in ticks for a destination given current orbital state.
 */
export function computeTransitTicks(
  dest: PlanetaryDestination,
  playerAngle: number,
): number {
  const alignment = computeAlignmentFactor(playerAngle, dest.orbitalAngle);
  const transitDays = dest.baseTransitDays * alignment;
  return Math.round(transitDays * TICKS_PER_GAME_DAY);
}

// ── Cargo Manifest ───────────────────────────────────────────────────────────

export type CargoManifest = Record<MineralField, number>;

export function emptyManifest(): CargoManifest {
  return {
    iron: 0,
    nickel: 0,
    cobalt: 0,
    platinum: 0,
    ice: 0,
    carbon: 0,
    silicate: 0,
  };
}

export function manifestTotal(manifest: CargoManifest): number {
  let total = 0;
  for (const f of MINERAL_FIELDS) total += manifest[f];
  return total;
}

// ── Transit Shipment ─────────────────────────────────────────────────────────

export type ShipmentStatus = 'in_transit' | 'arrived';

export interface TransitShipment {
  id: number;
  destinationId: string;
  cargo: CargoManifest;
  departureTick: number;
  arrivalTick: number;
  status: ShipmentStatus;
  /** Credits earned on arrival. */
  payment: number;
}

// ── Transit State ────────────────────────────────────────────────────────────

export interface TransitState {
  shipments: Map<number, TransitShipment>;
  nextShipmentId: number;
  /** Player's credits balance (new currency). */
  credits: number;
  /** Total credits ever earned (for stats). */
  totalCreditsEarned: number;
  lastTickProcessed: number;
  /** Per-destination demand curves. */
  demand: Map<string, DemandLevel>;
  /** Last tick demand was updated. */
  lastDemandTick: number;
  /** Phase progression tracking. */
  progression: ProgressionState;
}

export function createTransitState(): TransitState {
  const demand = new Map<string, DemandLevel>();
  for (const d of DESTINATIONS) demand.set(d.id, createDemandLevel());
  return {
    shipments: new Map(),
    nextShipmentId: 1,
    credits: 0,
    totalCreditsEarned: 0,
    lastTickProcessed: 0,
    demand,
    lastDemandTick: 0,
    progression: createProgressionState(),
  };
}

// ── Serialization ────────────────────────────────────────────────────────────

export interface SerializedDemandLevel {
  multipliers: Record<MineralField, number>;
}

export interface SerializedTransitState {
  shipments: TransitShipment[];
  nextShipmentId: number;
  credits: number;
  totalCreditsEarned: number;
  demand?: Record<string, SerializedDemandLevel>;
  progression?: ProgressionState;
}

export function serializeTransitState(state: TransitState): SerializedTransitState {
  const demand: Record<string, SerializedDemandLevel> = {};
  for (const [id, dl] of state.demand) {
    demand[id] = { multipliers: { ...dl.multipliers } };
  }
  return {
    shipments: Array.from(state.shipments.values()),
    nextShipmentId: state.nextShipmentId,
    credits: state.credits,
    totalCreditsEarned: state.totalCreditsEarned,
    demand,
    progression: { ...state.progression },
  };
}

export function deserializeTransitState(data: SerializedTransitState): TransitState {
  const state = createTransitState();
  state.nextShipmentId = data.nextShipmentId;
  state.credits = data.credits;
  state.totalCreditsEarned = data.totalCreditsEarned;
  for (const s of data.shipments) {
    state.shipments.set(s.id, s);
  }
  if (data.demand) {
    for (const [id, dl] of Object.entries(data.demand)) {
      state.demand.set(id, { multipliers: { ...dl.multipliers } });
    }
  }
  if (data.progression) {
    state.progression = { ...data.progression };
  }
  return state;
}

// ── Core Logic ───────────────────────────────────────────────────────────────

/**
 * Compute the payment for a cargo manifest at a given destination.
 * If demand is provided, prices are modulated by demand multipliers.
 */
export function computePayment(
  dest: PlanetaryDestination,
  cargo: CargoManifest,
  demand?: DemandLevel,
): number {
  let total = 0;
  for (const f of MINERAL_FIELDS) {
    const price = demand ? getEffectivePrice(dest, f, demand) : dest.pricing[f];
    total += cargo[f] * price;
  }
  return Math.round(total * 100) / 100;
}

export interface DispatchResult {
  ok: boolean;
  error?: string;
  shipment?: TransitShipment;
}

/**
 * Dispatch a cargo shipment: deduct resources from base storage,
 * create a TransitShipment with computed arrival time.
 * Respects destination lock state (e.g. Luna requires unlock).
 */
export function dispatchCargo(
  state: TransitState,
  destinationId: string,
  cargo: CargoManifest,
  baseEid: number,
  playerAngle: number,
  currentTick: number,
): DispatchResult {
  const dest = getDestination(destinationId);
  if (!dest) return { ok: false, error: `Unknown destination: ${destinationId}` };

  // Check destination availability
  if (!isDestinationAvailable(dest, state.progression)) {
    return { ok: false, error: `${dest.name} is not yet available for trade` };
  }

  // Validate cargo is non-empty
  const total = manifestTotal(cargo);
  if (total <= 0) return { ok: false, error: 'Cargo manifest is empty' };

  // Validate sufficient base storage
  for (const f of MINERAL_FIELDS) {
    if (cargo[f] > 0 && Storage[f][baseEid] < cargo[f]) {
      return { ok: false, error: `Insufficient ${f}: need ${cargo[f]}, have ${Storage[f][baseEid]}` };
    }
  }

  // Deduct resources from base
  for (const f of MINERAL_FIELDS) {
    if (cargo[f] > 0) {
      Storage[f][baseEid] -= cargo[f];
    }
  }

  const transitTicks = computeTransitTicks(dest, playerAngle);
  const demand = state.demand.get(destinationId);
  const payment = computePayment(dest, cargo, demand);

  const shipment: TransitShipment = {
    id: state.nextShipmentId++,
    destinationId,
    cargo: { ...cargo },
    departureTick: currentTick,
    arrivalTick: currentTick + transitTicks,
    status: 'in_transit',
    payment,
  };

  state.shipments.set(shipment.id, shipment);
  return { ok: true, shipment };
}

export interface TransitTickResult {
  arrived: TransitShipment[];
  /** True if Luna was just unlocked this tick. */
  lunaJustUnlocked: boolean;
}

/**
 * Tick the transit system: check for arrived shipments, credit payments,
 * update demand curves, check phase transitions.
 */
export function tickTransit(
  state: TransitState,
  currentTick: number,
  rng?: () => number,
): TransitTickResult {
  const result: TransitTickResult = { arrived: [], lunaJustUnlocked: false };

  if (currentTick - state.lastTickProcessed < TRANSIT_CHECK_INTERVAL) return result;
  state.lastTickProcessed = currentTick;

  // Update demand curves periodically
  if (rng && currentTick - state.lastDemandTick >= DEMAND_UPDATE_INTERVAL) {
    state.lastDemandTick = currentTick;
    const earthDemand = state.demand.get('earth');
    if (earthDemand) tickDemand(earthDemand, EARTH_DEMAND_VOLATILITY, rng);
    const lunaDemand = state.demand.get('luna');
    if (lunaDemand) tickDemand(lunaDemand, LUNA_DEMAND_VOLATILITY, rng);
  }

  for (const shipment of state.shipments.values()) {
    if (shipment.status === 'in_transit' && currentTick >= shipment.arrivalTick) {
      shipment.status = 'arrived';
      state.credits += shipment.payment;
      state.totalCreditsEarned += shipment.payment;
      result.arrived.push(shipment);

      // Track Earth delivery for progression
      if (shipment.destinationId === 'earth' && !state.progression.firstEarthDelivery) {
        state.progression.firstEarthDelivery = true;
      }
    }
  }

  // Check phase transition after processing arrivals
  if (checkPhaseTransition(state.progression)) {
    result.lunaJustUnlocked = true;
  }

  // Clean up arrived shipments (keep for one check cycle, then remove)
  for (const shipment of state.shipments.values()) {
    if (shipment.status === 'arrived' && currentTick > shipment.arrivalTick + TRANSIT_CHECK_INTERVAL) {
      state.shipments.delete(shipment.id);
    }
  }

  return result;
}

/**
 * Get current orbital angle for a destination at a given tick.
 * Planets slowly orbit: angle advances based on orbital period.
 */
export function getDestinationAngle(dest: PlanetaryDestination, tick: number): number {
  const periodTicks = dest.orbitalPeriodDays * TICKS_PER_GAME_DAY;
  return dest.orbitalAngle + (2 * Math.PI * tick) / periodTicks;
}

/**
 * Snapshot for UI broadcast.
 */
export interface TransitSnapshot {
  shipments: TransitShipment[];
  credits: number;
  totalCreditsEarned: number;
  destinations: Array<{
    id: string;
    name: string;
    currentTransitDays: number;
    /** Effective pricing including demand modifiers. */
    pricing: Record<MineralField, number>;
  }>;
  progression: {
    phase: number;
    lunaUnlocked: boolean;
    firstEarthDelivery: boolean;
    totalIronMined: number;
  };
}

export function snapshotTransit(
  state: TransitState,
  playerAngle: number,
): TransitSnapshot {
  // Only show available destinations
  const available = DESTINATIONS.filter((d) => isDestinationAvailable(d, state.progression));
  return {
    shipments: Array.from(state.shipments.values()),
    credits: state.credits,
    totalCreditsEarned: state.totalCreditsEarned,
    destinations: available.map((d) => {
      const alignment = computeAlignmentFactor(playerAngle, d.orbitalAngle);
      const demand = state.demand.get(d.id);
      const pricing = {} as Record<MineralField, number>;
      for (const f of MINERAL_FIELDS) {
        pricing[f] = Math.round(getEffectivePrice(d, f, demand ?? createDemandLevel()) * 100) / 100;
      }
      return {
        id: d.id,
        name: d.name,
        currentTransitDays: Math.round(d.baseTransitDays * alignment),
        pricing,
      };
    }),
    progression: {
      phase: state.progression.phase,
      lunaUnlocked: state.progression.lunaUnlocked,
      firstEarthDelivery: state.progression.firstEarthDelivery,
      totalIronMined: state.progression.totalIronMined,
    },
  };
}
