/**
 * Anomaly study tick phase: lore fragments, event flags, and XENOAWARE dark forest mechanics.
 *
 * XENOAWARE trade-off system (anomalyExposure thresholds):
 *   >=40: +20% study speed (existing), anomaly prediction (culture broadcast)
 *   >=60: Xenotech research bonus (20% chance on study completion)
 *   >=70: Study backlash (5% per study tick, damages studying robot 10%)
 *   >=80: Dark forest echo (10% on study completion, hostile secondary anomaly)
 *   >=90: Backlash intensifies (12% chance, 20% damage)
 */
import { hasComponent } from 'bitecs';
import { RobotTag, RobotType, Position, ToolTier, Energy } from '../../components';
import { workerState, runSystem, FIXED_DT, sendMessage } from '../state';
import { getEfficiencyMultiplier } from '../../techTree';
import { canSendComms, markCommsSent, generateBacklashComms, generateDarkForestEchoComms } from '../../commsGenerator';
import { applyDialect } from '../../colonyDialect';
import type { SimLoreFragmentMessage, SimResearchBonusMessage } from '../../messages';

// ── Constants ────────────────────────────────────────────────────────────────

const STUDY_RANGE = 300;
/** Radius within which dark forest echoes damage robots. */
const ECHO_DAMAGE_RADIUS = 400;
/** Damage per tick from a dark forest echo (fraction of max energy). */
const ECHO_DAMAGE_PER_TICK = 0.001;
/** Study time (seconds) to resolve a dark forest echo with 1 scout tier 1. */
const ECHO_STUDY_DURATION = 90;

// ── Backlash configuration ───────────────────────────────────────────────────

interface BacklashTier {
  minExposure: number;
  chance: number;
  damageFraction: number;
}

const BACKLASH_TIERS: BacklashTier[] = [
  { minExposure: 90, chance: 0.12, damageFraction: 0.20 },
  { minExposure: 70, chance: 0.05, damageFraction: 0.10 },
];

function getBacklashTier(anomalyExposure: number): BacklashTier | null {
  for (const tier of BACKLASH_TIERS) {
    if (anomalyExposure >= tier.minExposure) return tier;
  }
  return null;
}

// ── Main phase ───────────────────────────────────────────────────────────────

export function tickAnomalyStudyPhase(): void {
  const s = workerState;
  const hasStudy = s.studySystem.size > 0;
  const hasEchoes = s.darkForestEchoes.length > 0;
  if (!hasStudy && !hasEchoes) return;

  const scanMult = getEfficiencyMultiplier(s.techState, 'scanning');
  const xenoMult = s.cultureState.traits.has('XENOAWARE') ? 1.2 : 1;
  const exposure = s.cultureState.anomalyExposure;
  const backlashTier = s.cultureState.traits.has('XENOAWARE') ? getBacklashTier(exposure) : null;

  runSystem('anomalyStudy', () => {
    // ── Tick active anomaly studies ────────────────────────────────────────
    if (hasStudy) {
      tickStudyEntries(s, scanMult, xenoMult, backlashTier);
    }

    // ── Tick dark forest echoes ────────────────────────────────────────────
    if (hasEchoes) {
      tickDarkForestEchoes(s, scanMult, xenoMult);
    }
  });
}

// ── Study entries ────────────────────────────────────────────────────────────

function tickStudyEntries(
  s: typeof workerState,
  scanMult: number,
  xenoMult: number,
  backlashTier: BacklashTier | null,
): void {
  const exposure = s.cultureState.anomalyExposure;

  const studyUpdates = s.studySystem.tick(FIXED_DT, (ax, ay, az) => {
    const nearby = s.grid!.queryRadius(ax, ay, az, STUDY_RANGE);
    let count = 0;
    let tierSum = 0;
    for (const eid of nearby) {
      if (!hasComponent(s.world!, eid, RobotTag)) continue;
      if (RobotType.type[eid] !== 0 /* SCOUT */) continue;
      count++;
      tierSum += Math.max(1, ToolTier.tier[eid]);

      // ── Study backlash: damage studying robots ─────────────────────
      if (backlashTier && count > 0) {
        applyBacklash(s, eid, backlashTier);
      }
    }
    const avgTier = count > 0 ? tierSum / count : 0;
    return { count, avgTier: avgTier * scanMult * xenoMult };
  });

  for (const update of studyUpdates) {
    if (update.newFragments.length > 0 || update.revelation !== null) {
      const loreMsg: SimLoreFragmentMessage = {
        type: 'sim:lore_fragment',
        payload: {
          asteroidEid: update.asteroidEid,
          anomalyType: update.anomalyType,
          stage: update.stage,
          newFragmentIndices: update.newFragments,
          chainNextType: update.chainNextType,
          revelation: update.revelation,
          civilizationAttribution: update.civilizationAttribution,
          tick: s.tick,
        },
      };
      sendMessage(loreMsg);
    }
    if (update.stage >= 2) s.eventEngine.setFlag('anomaly_scanning', true);
    if (update.stage >= 3) {
      s.eventEngine.setFlag('anomaly_analyzed', true);
      if (hasComponent(s.world!, update.asteroidEid, Position)) {
        const ax = Position.x[update.asteroidEid];
        const ay = Position.y[update.asteroidEid];
        const az = Position.z[update.asteroidEid];
        const nearbyEids = s.grid!.queryRadius(ax, ay, az, 300);
        for (const eid of nearbyEids) {
          if (!hasComponent(s.world!, eid, RobotTag)) continue;
          const stats = s.cultureState.robotStats.get(eid);
          if (stats) stats.anomaliesStudied++;
        }
      }
    }
    if (update.stage >= 4) {
      s.eventEngine.setFlag('anomaly_understood', true);

      // ── Xenotech research bonus (exposure >= 60, 20% chance) ─────
      if (exposure >= 60 && s.eventRng() < 0.2) {
        const bonusMsg: SimResearchBonusMessage = {
          type: 'sim:research_bonus',
          payload: {
            asteroidEid: update.asteroidEid,
            anomalyType: update.anomalyType,
            tick: s.tick,
          },
        };
        sendMessage(bonusMsg);
        // Grant bonus research points to active research (if any)
        if (s.techState.activeResearch) {
          s.techState.activeResearch.pointsAccumulated += 50;
        }
      }

      // ── Dark forest echo (exposure >= 80, 10% chance) ────────────
      if (exposure >= 80 && s.eventRng() < 0.1) {
        spawnDarkForestEcho(s, update.asteroidEid);
      }
    }
  }
}

// ── Backlash ─────────────────────────────────────────────────────────────────

function applyBacklash(
  s: typeof workerState,
  robotEid: number,
  tier: BacklashTier,
): void {
  if (s.eventRng() >= tier.chance) return;

  const maxE = Energy.max[robotEid];
  if (maxE <= 0) return;
  const damage = maxE * tier.damageFraction;
  Energy.current[robotEid] = Math.max(0, Energy.current[robotEid] - damage);

  if (canSendComms(s.tick)) {
    const name = s.cultureState.robotNames.get(robotEid) ?? `Robot-${robotEid}`;
    const stats = s.cultureState.robotStats.get(robotEid);
    const msg = generateBacklashComms(name, stats?.tasksCompleted ?? 0, robotEid ^ s.tick);
    markCommsSent(s.tick);
    sendMessage({
      type: 'sim:comms_message',
      payload: { robotEid, robotName: name, message: applyDialect(msg, s.cultureState.isolationScore), category: 'backlash', tick: s.tick },
    });
  }
}

// ── Dark forest echo spawn ───────────────────────────────────────────────────

function spawnDarkForestEcho(s: typeof workerState, asteroidEid: number): void {
  const x = Position.x[asteroidEid];
  const y = Position.y[asteroidEid];
  const z = Position.z[asteroidEid];

  s.darkForestEchoes.push({
    x, y, z,
    progress: 0,
    spawnTick: s.tick,
  });

  // Fire dramatic comms
  if (canSendComms(s.tick)) {
    const nearbyEids = s.grid!.queryRadius(x, y, z, ECHO_DAMAGE_RADIUS);
    let reporterEid = -1;
    for (const eid of nearbyEids) {
      if (hasComponent(s.world!, eid, RobotTag)) {
        reporterEid = eid;
        break;
      }
    }
    if (reporterEid >= 0) {
      const name = s.cultureState.robotNames.get(reporterEid) ?? `Robot-${reporterEid}`;
      const stats = s.cultureState.robotStats.get(reporterEid);
      const msg = generateDarkForestEchoComms(name, stats?.tasksCompleted ?? 0, reporterEid ^ s.tick);
      markCommsSent(s.tick);
      sendMessage({
        type: 'sim:comms_message',
        payload: { robotEid: reporterEid, robotName: name, message: applyDialect(msg, s.cultureState.isolationScore), category: 'dark_forest_echo', tick: s.tick },
      });
    }
  }
}

// ── Dark forest echo tick ────────────────────────────────────────────────────

function tickDarkForestEchoes(
  s: typeof workerState,
  scanMult: number,
  xenoMult: number,
): void {
  const resolved: number[] = [];

  for (let i = 0; i < s.darkForestEchoes.length; i++) {
    const echo = s.darkForestEchoes[i];

    // Damage nearby robots
    const nearbyEids = s.grid!.queryRadius(echo.x, echo.y, echo.z, ECHO_DAMAGE_RADIUS);
    let scoutCount = 0;
    let tierSum = 0;

    for (const eid of nearbyEids) {
      if (!hasComponent(s.world!, eid, RobotTag)) continue;

      // Damage all robots in range
      const maxE = Energy.max[eid];
      if (maxE > 0) {
        Energy.current[eid] = Math.max(0, Energy.current[eid] - maxE * ECHO_DAMAGE_PER_TICK);
      }

      // Count scouts for study resolution
      if (RobotType.type[eid] === 0 /* SCOUT */) {
        scoutCount++;
        tierSum += Math.max(1, ToolTier.tier[eid]);
      }
    }

    // Scouts studying the echo can resolve it
    if (scoutCount > 0) {
      const avgTier = (tierSum / scoutCount) * scanMult * xenoMult;
      const rate = scoutCount * Math.max(1, avgTier);
      echo.progress += (FIXED_DT * rate) / ECHO_STUDY_DURATION;
    }

    if (echo.progress >= 1) {
      resolved.push(i);
    }
  }

  // Remove resolved echoes (iterate backwards to maintain indices)
  for (let i = resolved.length - 1; i >= 0; i--) {
    s.darkForestEchoes.splice(resolved[i], 1);
  }
}
