/**
 * Ancient entity system tick phase + entity broadcast.
 */
import { hasComponent } from 'bitecs';
import { RobotTag, RobotType, Position } from '../../components';
import { workerState, runSystem, sendMessage, ENTITY_BROADCAST_INTERVAL, FIXED_DT } from '../state';
import { ENTITY_TYPES } from '../../entities/entitySystem';

export function tickEntityPhase(
  allRobotsWithPos: ArrayLike<number>,
  sharedRobotPositions: Array<{ x: number; y: number; z: number }>,
): void {
  const s = workerState;

  let drifterProximity = false;
  let resonantInterference = false;
  let alienFleetProximity = false;
  runSystem('entitySystem', () => {
    const studySnapshot = s.studySystem.getProgressSnapshot();
    let analyzedAnomalyCount = 0;
    const anomalyPositions: Array<{ x: number; y: number; z: number }> = [];
    for (const e of studySnapshot) {
      if (e.stage >= 3) {
        analyzedAnomalyCount++;
        anomalyPositions.push({
          x: Position.x[e.asteroidEid] ?? 0,
          y: Position.y[e.asteroidEid] ?? 0,
          z: Position.z[e.asteroidEid] ?? 0,
        });
      }
    }

    let xenoawareRobotPositions: Array<{ x: number; y: number; z: number }> | undefined;
    if (s.cultureState.traits.has('XENOAWARE')) {
      xenoawareRobotPositions = [];
      for (let i = 0; i < allRobotsWithPos.length; i++) {
        const eid = allRobotsWithPos[i];
        if (RobotType.type[eid] === 0 /* SCOUT */) {
          xenoawareRobotPositions.push({ x: Position.x[eid], y: Position.y[eid], z: Position.z[eid] });
        }
      }
    }

    const effects = s.entitySystem.tick(FIXED_DT, {
      robotCount: allRobotsWithPos.length,
      analyzedAnomalyCount,
      robotPositions: sharedRobotPositions,
      anomalyPositions,
      beltOuterRadius: s.fieldConfig?.beltOuterRadius ?? 6000,
      tick: s.tick,
      alienArrived: s.eventEngine.isFlagSet('alien_arrived'),
      resonantSpawnMultiplier: s.cultureState.darkForestChoice === 'hidden' ? (1 / 0.7) : 1,
      xenoawareRobotPositions,
    });

    for (const fx of effects) {
      if (fx.entityType === ENTITY_TYPES.DRIFTER) {
        drifterProximity = true;
        s.eventEngine.setFlag('drifter_present', true);
      }
      if (fx.entityType === ENTITY_TYPES.RESONANT) {
        resonantInterference = true;
        s.eventEngine.setFlag('entities_confirmed', true);
        s.eventEngine.setFlag('entities_suspected', true);
      }
      if (fx.entityType === ENTITY_TYPES.ALIEN_FLEET) {
        alienFleetProximity = true;
        s.eventEngine.setFlag('alien_fleet_proximity', true);
      }
    }
  });

  if (s.tick % ENTITY_BROADCAST_INTERVAL === 0) {
    sendMessage({
      type: 'sim:entity_frame',
      payload: {
        entities: s.entitySystem.getAll(),
        tick: s.tick,
        drifterProximity,
        resonantInterference,
        alienFleetProximity,
      },
    });
  }
}
