/**
 * Market tick phase: processes pending listings, generates haul tasks,
 * and completes sales when deliveries finish.
 *
 * Signal jam blocking: when an active signal_jam threat exists, market
 * processing is skipped (Earth communication cut off).
 */
import { workerState, sendMessage } from '../state';
import { tickMarket, snapshotMarket } from '../../market';
import { isSignalJamActive } from '../../threatSystem';

export function tickMarketPhase(): void {
  const s = workerState;
  if (!s.taskQueue || !s.factionSystemState || s.baseEidGlobal < 0) return;

  // Signal jamming blocks all market processing (Earth comms cut)
  if (s.threatState && isSignalJamActive(s.threatState)) return;

  const factionBases = s.factionSystemState.factions.map((f) => ({
    id: f.id,
    x: f.base.x,
    y: f.base.y,
    z: f.base.z,
  }));

  const factionResources = s.factionSystemState.factions.map((f) => ({
    id: f.id,
    resources: f.resources,
  }));

  const { completedListings } = tickMarket(
    s.marketState,
    s.tick,
    s.taskQueue,
    s.baseEidGlobal,
    factionBases,
    factionResources,
  );

  // Improve disposition for completed trades
  for (const listing of completedListings) {
    const faction = s.factionSystemState.factions[listing.buyerFactionId];
    if (faction) {
      faction.disposition = Math.min(100, faction.disposition + 5);
      faction.recentEvents.push({
        text: `Market sale completed — received ${listing.resource}`,
        tick: s.tick,
      });
    }
  }
}
