/**
 * Automation Blueprints — named snapshots of automation configurations with
 * efficiency metrics. Players can save, compare, and restore their automation
 * setups (task queues, supply rules, sectors).
 */

import type { AutoQueue, SupplyRule, Sector, SerializedAutomationState } from './automation';

// ── Data model ──────────────────────────────────────────────────────────────

export interface EfficiencyMetrics {
  /** Total raw resources mined per 60 ticks (1 second of game time). */
  resourcesPerMinute: number;
  /** Fraction of robots in idle state (0-1). */
  idleRobotPct: number;
  /** Fraction of fleet energy wasted (robots below 25% energy). */
  energyWastePct: number;
}

export interface Blueprint {
  id: string;
  name: string;
  savedAt: number; // game tick when saved
  /** Snapshot of automation state at save time. */
  automation: SerializedAutomationState;
  /** Efficiency metrics sampled at save time. */
  efficiency: EfficiencyMetrics;
  /** Whether this blueprint is currently the active configuration. */
  active: boolean;
}

export interface BlueprintState {
  blueprints: Map<string, Blueprint>;
  /** Ring buffer of recent efficiency samples for trend tracking. */
  efficiencyHistory: EfficiencySample[];
  /** Index for next write in the ring buffer. */
  _historyIndex: number;
  /** Tick counter for throttled sampling. */
  _sampleTimer: number;
}

export interface EfficiencySample {
  tick: number;
  resourcesPerMinute: number;
  idleRobotPct: number;
}

/** Max samples kept for efficiency trend (about 8 minutes at 1 sample/tick-second). */
export const MAX_EFFICIENCY_SAMPLES = 500;
/** Sample efficiency every N ticks (1 game-second). */
export const EFFICIENCY_SAMPLE_INTERVAL = 60;

// ── State management ────────────────────────────────────────────────────────

export function createBlueprintState(): BlueprintState {
  return {
    blueprints: new Map(),
    efficiencyHistory: [],
    _historyIndex: 0,
    _sampleTimer: 0,
  };
}

export function saveBlueprint(
  state: BlueprintState,
  name: string,
  automationSnapshot: SerializedAutomationState,
  efficiency: EfficiencyMetrics,
  tick: number,
): Blueprint {
  const id = `bp_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`;
  const bp: Blueprint = {
    id,
    name,
    savedAt: tick,
    automation: {
      queues: automationSnapshot.queues.map((q) => ({ ...q })),
      supplyRules: automationSnapshot.supplyRules.map((r) => ({ ...r })),
      sectors: automationSnapshot.sectors.map((s) => ({ ...s })),
    },
    efficiency: { ...efficiency },
    active: false,
  };
  state.blueprints.set(id, bp);
  return bp;
}

export function deleteBlueprint(state: BlueprintState, id: string): boolean {
  return state.blueprints.delete(id);
}

export function renameBlueprint(state: BlueprintState, id: string, name: string): boolean {
  const bp = state.blueprints.get(id);
  if (!bp) return false;
  bp.name = name;
  return true;
}

/**
 * Compute the difference between two blueprints' efficiency metrics.
 * Positive values mean `a` is better than `b`.
 */
export function compareBlueprints(
  a: Blueprint,
  b: Blueprint,
): {
  resourcesDelta: number;
  resourcesDeltaPct: number;
  idleDelta: number;
  energyWasteDelta: number;
} {
  const rDelta = a.efficiency.resourcesPerMinute - b.efficiency.resourcesPerMinute;
  const base = b.efficiency.resourcesPerMinute || 1;
  return {
    resourcesDelta: rDelta,
    resourcesDeltaPct: (rDelta / base) * 100,
    idleDelta: a.efficiency.idleRobotPct - b.efficiency.idleRobotPct,
    energyWasteDelta: a.efficiency.energyWastePct - b.efficiency.energyWastePct,
  };
}

// ── Efficiency calculation ──────────────────────────────────────────────────

/**
 * Compute current efficiency metrics from live sim state.
 */
export function computeEfficiency(
  resourceDeltaPerTick: number,
  totalRobots: number,
  idleRobots: number,
  lowEnergyRobots: number,
): EfficiencyMetrics {
  return {
    resourcesPerMinute: resourceDeltaPerTick * 60, // per 60 ticks = 1 game second
    idleRobotPct: totalRobots > 0 ? idleRobots / totalRobots : 0,
    energyWastePct: totalRobots > 0 ? lowEnergyRobots / totalRobots : 0,
  };
}

/**
 * Record an efficiency sample into the ring buffer.
 */
export function recordEfficiencySample(
  state: BlueprintState,
  tick: number,
  resourcesPerMinute: number,
  idleRobotPct: number,
): void {
  state._sampleTimer++;
  if (state._sampleTimer < EFFICIENCY_SAMPLE_INTERVAL) return;
  state._sampleTimer = 0;

  const sample: EfficiencySample = { tick, resourcesPerMinute, idleRobotPct };

  if (state.efficiencyHistory.length < MAX_EFFICIENCY_SAMPLES) {
    state.efficiencyHistory.push(sample);
  } else {
    state.efficiencyHistory[state._historyIndex] = sample;
  }
  state._historyIndex = (state._historyIndex + 1) % MAX_EFFICIENCY_SAMPLES;
}

/**
 * Get the efficiency trend as ordered samples (oldest first).
 */
export function getEfficiencyTrend(state: BlueprintState): EfficiencySample[] {
  const len = state.efficiencyHistory.length;
  if (len < MAX_EFFICIENCY_SAMPLES) return [...state.efficiencyHistory];
  // Ring buffer: reorder from oldest to newest
  const idx = state._historyIndex;
  return [...state.efficiencyHistory.slice(idx), ...state.efficiencyHistory.slice(0, idx)];
}

// ── Serialization ───────────────────────────────────────────────────────────

export interface SerializedBlueprint {
  id: string;
  name: string;
  savedAt: number;
  automation: SerializedAutomationState;
  efficiency: EfficiencyMetrics;
  active: boolean;
}

export interface SerializedBlueprintState {
  blueprints: SerializedBlueprint[];
  efficiencyHistory: EfficiencySample[];
}

export function serializeBlueprintState(state: BlueprintState): SerializedBlueprintState {
  return {
    blueprints: Array.from(state.blueprints.values()).map((bp) => ({
      id: bp.id,
      name: bp.name,
      savedAt: bp.savedAt,
      automation: bp.automation,
      efficiency: bp.efficiency,
      active: bp.active,
    })),
    efficiencyHistory: getEfficiencyTrend(state),
  };
}

export function deserializeBlueprintState(data: SerializedBlueprintState): BlueprintState {
  const state = createBlueprintState();
  for (const bp of data.blueprints) {
    state.blueprints.set(bp.id, {
      id: bp.id,
      name: bp.name,
      savedAt: bp.savedAt,
      automation: bp.automation,
      efficiency: bp.efficiency,
      active: bp.active,
    });
  }
  state.efficiencyHistory = data.efficiencyHistory ?? [];
  state._historyIndex = state.efficiencyHistory.length % MAX_EFFICIENCY_SAMPLES;
  return state;
}
