/**
 * Shared entity type constants and state types.
 *
 * Imported by both sim and render layers — keeps the worker/main thread boundary clean.
 */

export const ENTITY_TYPES = {
  DRIFTER: 1,
  RESONANT: 2,
  ALIEN_FLEET: 3,
} as const;

export type EntityType = 1 | 2 | 3;

export interface EntityState {
  id: number;
  type: EntityType;
  x: number;
  y: number;
  z: number;
  vx: number;
  vy: number;
  vz: number;
  radius: number;
  /** Resonant group ID (0 for drifters) */
  groupId: number;
  /** 0–1 pulse phase for visual effects */
  phase: number;
  /** How long until this entity despawns (ticks, -1 = permanent) */
  lifetime: number;
}
