/**
 * ECS Components for bitECS v0.4
 *
 * Components are plain objects:
 * - Tag components: empty objects {}
 * - Store components: objects with typed array properties
 *
 * Max entity count set to 10000 for initial implementation.
 */

import { MINERAL_FIELDS, type MineralField } from './minerals';

const MAX_ENTITIES = 10000;

/** Build a Float32Array store for every mineral field. */
type MineralArrays = Record<MineralField, Float32Array>;
function makeMineralArrays(): MineralArrays {
  return Object.fromEntries(
    MINERAL_FIELDS.map((f) => [f, new Float32Array(MAX_ENTITIES)]),
  ) as MineralArrays;
}

// === Shared Components ===

export const Position = {
  x: new Float64Array(MAX_ENTITIES),
  y: new Float64Array(MAX_ENTITIES),
  z: new Float64Array(MAX_ENTITIES),
};

export const Velocity = {
  x: new Float32Array(MAX_ENTITIES),
  y: new Float32Array(MAX_ENTITIES),
  z: new Float32Array(MAX_ENTITIES),
};

export const Rotation = {
  angle: new Float32Array(MAX_ENTITIES),
};

// === Asteroid Components ===

export const AsteroidTag = {};

/** Tag marking a fully-depleted asteroid husk. Only Deep Core drills can mine husks. */
export const AsteroidHusk = {};

export const AsteroidType = {
  type: new Uint8Array(MAX_ENTITIES), // 0=Carbonaceous, 1=Silicate, 2=Metallic, 3=Exotic
};

export const AsteroidSize = {
  radius: new Float32Array(MAX_ENTITIES),
};

/** Tiered size category: 0=small, 1=medium, 2=large, 3=mega */
export const AsteroidSizeTier = {
  tier: new Uint8Array(MAX_ENTITIES),
};

export const MineralComposition = makeMineralArrays();

export const AsteroidHealth = {
  current: new Float32Array(MAX_ENTITIES),
  max: new Float32Array(MAX_ENTITIES),
};

export const AnomalyFlag = {
  type: new Uint8Array(MAX_ENTITIES), // 0=none, 1=Strange Mineral, 2=Structured Signal, 3=Spatial Distortion, 4=Geometric Void, 5=Biological Trace, 6=Gravitational Anomaly
};

export const ChunkRef = {
  cx: new Int16Array(MAX_ENTITIES),
  cy: new Int16Array(MAX_ENTITIES),
  cz: new Int16Array(MAX_ENTITIES),
};

/**
 * Resource richness multiplier for an asteroid.
 * Values > 1 yield more minerals per unit of health mined.
 * Set at generation time; stays constant.
 */
export const AsteroidRichness = {
  multiplier: new Float32Array(MAX_ENTITIES),
};

// === Orbital Components ===

/**
 * Simple circular orbit around the origin (xz plane).
 * Asteroids with this component have their Position derived from orbital state.
 * Period uses compressed Kepler's law for visible gameplay drift.
 */
export const Orbit = {
  /** Orbital radius in game units (distance from origin in xz plane) */
  radius: new Float32Array(MAX_ENTITIES),
  /** Current angular position in radians */
  angle: new Float32Array(MAX_ENTITIES),
  /** Orbital period in game-seconds */
  period: new Float32Array(MAX_ENTITIES),
  /** Fixed Y offset (belt thickness position) */
  baseY: new Float32Array(MAX_ENTITIES),
};

// === Transient Cluster Components ===

/** Tag marking an asteroid as part of a transient rich cluster. */
export const TransientClusterTag = {};

/**
 * Links an asteroid to its transient cluster.
 * clusterId: unique ID for the cluster this asteroid belongs to.
 */
export const ClusterMembership = {
  clusterId: new Uint16Array(MAX_ENTITIES),
};

// === Robot Components ===

export const RobotTag = {};

