// === Spatial ===

export const SpatialCell = {
  keyHigh: new Uint32Array(MAX_ENTITIES),
  keyLow: new Uint32Array(MAX_ENTITIES),
};

// === Base Station ===

export const BaseStationTag = {};

/**
 * Tag marking a base station as a remote mining outpost (not the primary base).
 * Outposts auto-mine nearby asteroids and mass-drive ore to the primary base.
 */
export const OutpostTag = {};

/**
 * Links an outpost to the asteroid it was claimed on.
 * asteroidEid: the entity ID of the asteroid this outpost occupies.
 */
export const OutpostAsteroidRef = {
  asteroidEid: new Int32Array(MAX_ENTITIES),
};

export const Storage = {
  ...makeMineralArrays(),
  capacity: new Float32Array(MAX_ENTITIES), // 0 = unlimited
};

/**
 * Upgrade slots for robots. Each robot has 2 upgrade slots.
 * Values are UPGRADE_TYPES constants (0 = empty).
 */
export const UpgradeSlots = {
  slotA: new Uint8Array(MAX_ENTITIES),
  slotB: new Uint8Array(MAX_ENTITIES),
};

/**
 * Fuel (delta-v budget) for robots.
 * Consumed proportional to distance traveled. Replenished at base stations.
 * Task scoring penalizes distant targets when fuel is insufficient for round trip.
 */
export const Fuel = {
  current: new Float32Array(MAX_ENTITIES),
  max: new Float32Array(MAX_ENTITIES),
};

// === Faction Ship Components ===

/** Tag marking an entity as a faction ship. */
export const FactionShipTag = {};

/**
 * Faction ship data: health, faction ownership, and attack cooldown.
 * factionId: matches FACTION_IDS (0=Helix, 1=Astral, 2=Vanguard, 3=Ceres, 4=Titan, 5=Kuiper)
 */
export const FactionShipData = {
  health: new Float32Array(MAX_ENTITIES),
  maxHealth: new Float32Array(MAX_ENTITIES),
  factionId: new Uint8Array(MAX_ENTITIES),
  /** Ticks remaining before this ship can be attacked again (prevents instant kills) */
  damageCooldown: new Float32Array(MAX_ENTITIES),
};
