/**
 * Simulation tick orchestration.
 * Imports phase functions and coordinates the tick loop.
 */
import { query } from 'bitecs';
import { Position, RobotTag, ToolTier } from '../components';
import { ROBOT_TYPE_NAMES } from '../robotProfiles';
import { workerState, sendMessage, PERF_BROADCAST_INTERVAL, PHASE_WARN_THRESHOLD_MS } from './state';
import { computeBuildingEffects } from '../buildings';
import {
  getRawStorage,
  writeRawStorage,
  buildFrameData,
  applyDarkForestChoice,
  tickEconomyPhase,
  tickAutomationPhase,
  tickOrbitalPhase,
  tickRobotPhase,
  tickAnomalyStudyPhase,
  tickNarrativePhase,
  tickEntityPhase,
  tickFactionPhase,
  tickCombatPhase,
  tickThreatPhase,
  tickInboxPhase,
  tickCulturePhase,
  tickMegastructurePhase,
  tickHabitatPhase,
  tickMarketPhase,
  tickTransientClusterPhase,
  tickMeridianPhase,
  tickOutpostPhase,
  tickTransitPhase,
  tickWorldMaintenancePhase,
  broadcastPeriodicState,
} from './phases';

// Re-export helpers consumed by messageHandler and tests
export { getRawStorage, writeRawStorage, buildFrameData, applyDarkForestChoice };

// ── Reusable robot-position buffer ────────────────────────────────────────────

const _robotPosBuf: Array<{ x: number; y: number; z: number }> = [];

function fillRobotPositionBuffer(
  eids: ArrayLike<number>,
): Array<{ x: number; y: number; z: number }> {
  const len = eids.length;
  while (_robotPosBuf.length < len) {
    _robotPosBuf.push({ x: 0, y: 0, z: 0 });
  }
  _robotPosBuf.length = len;
  for (let i = 0; i < len; i++) {
    const eid = eids[i];
    _robotPosBuf[i].x = Position.x[eid];
    _robotPosBuf[i].y = Position.y[eid];
    _robotPosBuf[i].z = Position.z[eid];
  }
  return _robotPosBuf;
}

// ── Phase timing helpers ──────────────────────────────────────────────────────

/**
 * Time a named tick phase using performance.mark/measure.
 * Updates per-phase max tracking on workerState.
 */
function timePhase<T>(name: string, fn: () => T): T {
  const markStart = `tick:${name}:start`;
  const markEnd = `tick:${name}:end`;
  performance.mark(markStart);
  const result = fn();
  performance.mark(markEnd);
  const measure = performance.measure(`tick:${name}`, markStart, markEnd);
  const duration = measure.duration;

  const s = workerState;
  if (!(name in s._perfPhaseMax) || duration > s._perfPhaseMax[name]) {
    s._perfPhaseMax[name] = duration;
  }

  performance.clearMarks(markStart);
  performance.clearMarks(markEnd);
  performance.clearMeasures(`tick:${name}`);

  return result;
}

// ── Main simulation tick (coordinator) ────────────────────────────────────────

/**
 * Run a single simulation step (one tick of game time).
 * Called internally by simulationStep(); do not call directly.
 */
function singleTick(): void {
  const s = workerState;

  const startTime = performance.now();

  const bldgEffects = computeBuildingEffects(s.buildingState);
  const economyResult = timePhase('economy', () => tickEconomyPhase(bldgEffects));
  const justUnlocked = economyResult.justUnlocked;

  for (const robotType of economyResult.spawnedRobotTypes) {
    sendMessage({
      type: 'sim:robot_produced',
      payload: {
        robotType,
        robotTypeName: ROBOT_TYPE_NAMES[robotType] ?? 'Robot',
      },
    });
  }

  if (economyResult.researchDeadEnd) {
    const nodeId = s.techState.activeResearch?.nodeId;
    sendMessage({
      type: 'sim:research_dead_end',
      payload: { nodeId: nodeId ?? 'unknown' },
    });
  }

  const allRobots = query(s.world!, [RobotTag]);
  let deepCoreCount = 0;
  for (let i = 0; i < allRobots.length; i++) {
    if (ToolTier.tier[allRobots[i]] >= 3) deepCoreCount++;
  }

  timePhase('automation', () => tickAutomationPhase());
  timePhase('orbital', () => tickOrbitalPhase());
  timePhase('robot', () => tickRobotPhase(deepCoreCount, allRobots));
  timePhase('anomalyStudy', () => tickAnomalyStudyPhase());
  timePhase('narrative', () => tickNarrativePhase());

  const allRobotsWithPos = query(s.world!, [RobotTag, Position]);
  const sharedRobotPositions = fillRobotPositionBuffer(allRobotsWithPos);

  timePhase('entity', () => tickEntityPhase(allRobotsWithPos, sharedRobotPositions));
  timePhase('faction', () => tickFactionPhase(sharedRobotPositions));
  timePhase('combat', () => tickCombatPhase());
  timePhase('threat', () => tickThreatPhase());
  timePhase('inbox', () => tickInboxPhase(allRobotsWithPos));
  timePhase('culture', () => tickCulturePhase(allRobotsWithPos, sharedRobotPositions));
  timePhase('megastructure', () => tickMegastructurePhase());
  timePhase('habitat', () => tickHabitatPhase());
  timePhase('market', () => tickMarketPhase());
  timePhase('transientClusters', () => tickTransientClusterPhase());
  timePhase('meridian', () => tickMeridianPhase());
  timePhase('outpost', () => tickOutpostPhase());
  timePhase('transit', () => tickTransitPhase());

  const robots = timePhase('worldMaintenance', () => tickWorldMaintenancePhase());

  s.tick++;
  buildFrameData();
  broadcastPeriodicState(justUnlocked, robots, startTime);

  const tickDuration = performance.now() - startTime;
  s._perfTickCount++;
  s._perfTickSum += tickDuration;
  if (tickDuration > s._perfTickMax) s._perfTickMax = tickDuration;

  if (s.tick % PERF_BROADCAST_INTERVAL === 0 && s._perfTickCount > 0) {
    const asteroidCount = s.asteroidEntities.length;
    const phaseMaxMs = { ...s._perfPhaseMax };
    const thresholdExceeded = Object.values(phaseMaxMs).some(
      (v) => v > PHASE_WARN_THRESHOLD_MS,
    );
    sendMessage({
      type: 'sim:worker_perf',
      payload: {
        tick: s.tick,
        avgTickMs: s._perfTickSum / s._perfTickCount,
        maxTickMs: s._perfTickMax,
        entityCount: asteroidCount + robots.length,
        robotCount: robots.length,
        asteroidCount,
        phaseMaxMs,
        thresholdExceeded,
      },
    });
    s._perfTickCount = 0;
    s._perfTickSum = 0;
    s._perfTickMax = 0;
    s._perfPhaseMax = {};
  }
}

/**
 * Simulation step called once per interval (~60 Hz).
 * Runs singleTick() N times based on speedMultiplier,
 * so speed is achieved by advancing more game ticks per
 * wall-clock interval rather than increasing interval frequency.
 */
export function simulationTick(): void {
  const s = workerState;
  if (!s.world || !s.grid || !s.taskQueue || s.paused) return;

  const steps = s.speedMultiplier;
  for (let i = 0; i < steps; i++) {
    try {
      singleTick();
    } catch (err) {
      const errMessage = err instanceof Error ? err.message : String(err);
      const stack = err instanceof Error ? err.stack : undefined;
      console.error('[worker] simulationTick error (tick', s.tick, '):', stack ?? errMessage);
      sendMessage({
        type: 'sim:worker_error',
        payload: {
          message: errMessage,
          tick: s.tick,
          system: 'simulationTick',
          stack,
        },
      });
      sendMessage({
        type: 'sim:error',
        payload: {
          message: `Sim error at tick ${s.tick}: ${errMessage}`,
          tick: s.tick,
        },
      });
      break;
    }
  }
}
