/**
 * Build and send frame data to the main thread.
 */
import { query, hasComponent } from 'bitecs';
import {
  Position,
  AsteroidTag,
  AsteroidType,
  AsteroidSize,
  AsteroidSizeTier,
  AnomalyFlag,
  AsteroidHusk,
  TransientClusterTag,
  RobotTag,
  RobotType,
  RobotState,
  Rotation,
  Energy,
  BaseStationTag,
  Storage,
} from '../../components';
import { workerState, sendMessage } from '../state';
import { transitWindowFactor } from '../../orbitalSystem';
import { getActiveThreats } from '../../threatSystem';
import {
  ROBOT_STRIDE,
  ROBOT_OFF_EID,
  ROBOT_OFF_X,
  ROBOT_OFF_Y,
  ROBOT_OFF_Z,
  ROBOT_OFF_ROTATION,
  ROBOT_OFF_TYPE,
  ROBOT_OFF_STATE,
  ROBOT_OFF_ENERGY_PCT,
  ASTEROID_STRIDE,
  ASTEROID_OFF_EID,
  ASTEROID_OFF_X,
  ASTEROID_OFF_Y,
  ASTEROID_OFF_Z,
  ASTEROID_OFF_RADIUS,
  ASTEROID_OFF_TYPE,
  ASTEROID_OFF_ANOMALY_FLAG,
  ASTEROID_OFF_HUSK_FLAG,
  ASTEROID_OFF_TIER,
  ASTEROID_OFF_CLUSTER_FLAG,
  ASTEROID_OFF_TRANSIT_FACTOR,
  THREAT_STRIDE,
  THREAT_OFF_ID,
  THREAT_OFF_TYPE,
  THREAT_OFF_FACTION_ID,
  THREAT_OFF_ORIGIN_X,
  THREAT_OFF_ORIGIN_Y,
  THREAT_OFF_ORIGIN_Z,
  THREAT_OFF_TARGET_X,
  THREAT_OFF_TARGET_Y,
  THREAT_OFF_TARGET_Z,
  THREAT_OFF_PROGRESS,
  THREAT_TYPE_ENUM,
} from '../../bufferLayout';

export function buildFrameData(): void {
  const { world, tick } = workerState;
  if (!world) return;

  const asteroids = query(world, [AsteroidTag, Position, AsteroidType, AsteroidSize]);
  const robots = query(world, [RobotTag, Position, RobotType, RobotState]);

  // Find primary base station position for transit window calculation
  const bases = query(world, [BaseStationTag]);
  let baseX = 0;
  let baseZ = 0;
  if (bases.length > 0) {
    baseX = Position.x[bases[0]];
    baseZ = Position.z[bases[0]];
  }

  const asteroidBuffer = new Float64Array(asteroids.length * ASTEROID_STRIDE);
  for (let i = 0; i < asteroids.length; i++) {
    const eid = asteroids[i];
    const offset = i * ASTEROID_STRIDE;
    asteroidBuffer[offset + ASTEROID_OFF_EID] = eid;
    asteroidBuffer[offset + ASTEROID_OFF_X] = Position.x[eid];
    asteroidBuffer[offset + ASTEROID_OFF_Y] = Position.y[eid];
    asteroidBuffer[offset + ASTEROID_OFF_Z] = Position.z[eid];
    asteroidBuffer[offset + ASTEROID_OFF_RADIUS] = AsteroidSize.radius[eid];
    asteroidBuffer[offset + ASTEROID_OFF_TYPE] = AsteroidType.type[eid];
    asteroidBuffer[offset + ASTEROID_OFF_ANOMALY_FLAG] = AnomalyFlag.type[eid];
    asteroidBuffer[offset + ASTEROID_OFF_HUSK_FLAG] = hasComponent(world, eid, AsteroidHusk) ? 1 : 0;
    asteroidBuffer[offset + ASTEROID_OFF_TIER] = AsteroidSizeTier.tier[eid];
    asteroidBuffer[offset + ASTEROID_OFF_CLUSTER_FLAG] = hasComponent(world, eid, TransientClusterTag) ? 1 : 0;
    asteroidBuffer[offset + ASTEROID_OFF_TRANSIT_FACTOR] = transitWindowFactor(eid, baseX, baseZ);
  }

  const robotBuffer = new Float32Array(robots.length * ROBOT_STRIDE);
  for (let i = 0; i < robots.length; i++) {
    const eid = robots[i];
    const offset = i * ROBOT_STRIDE;
    robotBuffer[offset + ROBOT_OFF_EID] = eid;
    robotBuffer[offset + ROBOT_OFF_X] = Position.x[eid];
    robotBuffer[offset + ROBOT_OFF_Y] = Position.y[eid];
    robotBuffer[offset + ROBOT_OFF_Z] = Position.z[eid];
    robotBuffer[offset + ROBOT_OFF_ROTATION] = Rotation.angle[eid];
    robotBuffer[offset + ROBOT_OFF_TYPE] = RobotType.type[eid];
    robotBuffer[offset + ROBOT_OFF_STATE] = RobotState.state[eid];
    robotBuffer[offset + ROBOT_OFF_ENERGY_PCT] = Energy.max[eid] > 0 ? Energy.current[eid] / Energy.max[eid] : 0;
  }

  // Build threat buffer from active (unresolved) threats
  const activeThreats = workerState.threatState ? getActiveThreats(workerState.threatState) : [];
  const threatBuffer = new Float32Array(activeThreats.length * THREAT_STRIDE);
  for (let i = 0; i < activeThreats.length; i++) {
    const t = activeThreats[i];
    const offset = i * THREAT_STRIDE;
    const totalDuration = t.arrivalTick - t.detectedTick;
    const elapsed = tick - t.detectedTick;
    threatBuffer[offset + THREAT_OFF_ID] = t.id;
    threatBuffer[offset + THREAT_OFF_TYPE] = THREAT_TYPE_ENUM[t.type] ?? 0;
    threatBuffer[offset + THREAT_OFF_FACTION_ID] = t.factionId;
    threatBuffer[offset + THREAT_OFF_ORIGIN_X] = t.originX;
    threatBuffer[offset + THREAT_OFF_ORIGIN_Y] = t.originY;
    threatBuffer[offset + THREAT_OFF_ORIGIN_Z] = t.originZ;
    threatBuffer[offset + THREAT_OFF_TARGET_X] = t.targetX;
    threatBuffer[offset + THREAT_OFF_TARGET_Y] = t.targetY;
    threatBuffer[offset + THREAT_OFF_TARGET_Z] = t.targetZ;
    threatBuffer[offset + THREAT_OFF_PROGRESS] = totalDuration > 0
      ? Math.min(1, elapsed / totalDuration)
      : 1;
  }

  const storageBuffer = new Float32Array(7);
  for (let i = 0; i < bases.length; i++) {
    const beid = bases[i];
    storageBuffer[0] += Storage.iron[beid];
    storageBuffer[1] += Storage.nickel[beid];
    storageBuffer[2] += Storage.cobalt[beid];
    storageBuffer[3] += Storage.platinum[beid];
    storageBuffer[4] += Storage.ice[beid];
    storageBuffer[5] += Storage.carbon[beid];
    storageBuffer[6] += Storage.silicate[beid];
  }

  sendMessage({
    type: 'sim:frame',
    payload: {
      tick,
      asteroidBuffer: asteroidBuffer.buffer,
      asteroidCount: asteroids.length,
      robotBuffer: robotBuffer.buffer,
      robotCount: robots.length,
      storageBuffer: storageBuffer.buffer,
      threatBuffer: threatBuffer.buffer,
      threatCount: activeThreats.length,
    },
  }, [asteroidBuffer.buffer, robotBuffer.buffer, storageBuffer.buffer, threatBuffer.buffer]);
}
