import {
  Position,
  Energy,
  RobotState,
  PathTarget,
} from '../components';
import { ROBOT_STATES } from '../robotCreation';
import { distanceTo } from './types';

export function handleBrokenRobot(eid: number, dt: number, baseEid: number): void {
  // Self-repair: recover energy when near-ish to base.
  // Robots that ran out of energy on return trips may be hundreds of units away,
  // so use a generous recovery radius.
  if (baseEid < 0) return;
  const distToBase = distanceTo(
    eid,
    Position.x[baseEid],
    Position.y[baseEid],
    Position.z[baseEid],
  );
  const recoveryRadius = 500;
  if (distToBase < recoveryRadius) {
    // Faster recovery when closer to base
    const proximityFactor = 1 - distToBase / recoveryRadius;
    const repairRate = 2 + proximityFactor * 8; // 2–10 energy/sec
    Energy.current[eid] = Math.min(Energy.max[eid], Energy.current[eid] + repairRate * dt);
    if (Energy.current[eid] >= Energy.max[eid] * 0.3) {
      // Enough energy to limp home — switch to RETURNING
      RobotState.state[eid] = ROBOT_STATES.RETURNING;
      PathTarget.x[eid] = Position.x[baseEid];
      PathTarget.y[eid] = Position.y[baseEid];
      PathTarget.z[eid] = Position.z[baseEid];
    }
  }
}
