/**
 * Economy tick phase: research, refinery, factory, and robot spawning.
 */
import { query } from 'bitecs';
import { Position, BaseStationTag, RobotTag } from '../../components';
import { workerState, runSystem, refreshUnlockedIds, FIXED_DT } from '../state';
import { applyUnlockEffects } from '../unlocks';
import { tickResearch, isRobotTypeUnlocked, getEfficiencyMultiplier } from '../../techTree';
import { tickRefinery } from '../../refining';
import { tickFactory } from '../../robotFactory';
import { computeRobotCap, type computeBuildingEffects } from '../../buildings';
import { computeResearchRate, createRobot } from '../../robotSystems';
import { generateRobotName } from '../../culture';
import { getRawStorage, writeRawStorage } from './helpers';

export interface EconomyPhaseResult {
  justUnlocked: string | null;
  spawnedRobotTypes: number[];
  /** True if research hit a dead end this tick. */
  researchDeadEnd: boolean;
}

export function tickEconomyPhase(bldgEffects: ReturnType<typeof computeBuildingEffects>): EconomyPhaseResult {
  const s = workerState;

  s.techState.researchRate = computeResearchRate(s.world!, s.techState, bldgEffects.researchRateBonus);

  if (s.habitatRpModifier !== 0) {
    s.techState.researchRate = Math.max(0, s.techState.researchRate * (1 + s.habitatRpModifier));
  }

  let justUnlocked: string | null = null;
  let researchDeadEnd = false;
  runSystem('research', () => {
    const result = tickResearch(s.techState, FIXED_DT, s.eventRng);
    if (result.completed) {
      justUnlocked = result.completed;
      refreshUnlockedIds();
      applyUnlockEffects(result.completed);
    }
    if (result.deadEnd) {
      researchDeadEnd = true;
    }
  });

  const raw = getRawStorage();
  runSystem('refinery', () => {
    const refiningMult = getEfficiencyMultiplier(s.techState, 'refining');
    tickRefinery(s.refineryState, raw, FIXED_DT, bldgEffects.refiningSpeedMultiplier * refiningMult);
    writeRawStorage(raw);
  });

  let factoryResult: { completedTypes: number[] } = { completedTypes: [] };
  runSystem('factory', () => {
    const buildTimeMult = getEfficiencyMultiplier(s.techState, 'build_time');
    const result = tickFactory(
      s.factoryState,
      s.refineryState.refined,
      raw,
      FIXED_DT,
      s._unlockedTechIds,
      buildTimeMult,
    );
    writeRawStorage(raw);
    factoryResult = result;
  });

  const spawnedRobotTypes: number[] = [];

  if (factoryResult.completedTypes.length > 0 && s.world && s.grid) {
    const bases = query(s.world, [BaseStationTag, Position]);
    const beid = bases.length > 0 ? bases[0] : -1;
    const robotCap = computeRobotCap(s.buildingState) + s.megaRobotCapBonus;
    const currentRobotCount = query(s.world, [RobotTag]).length;
    let activeCount = currentRobotCount;
    for (const robotType of factoryResult.completedTypes) {
      if (!isRobotTypeUnlocked(s.techState, robotType)) continue;
      if (activeCount >= robotCap) break;
      const spawnX = beid >= 0 ? Position.x[beid] + (s.eventRng() - 0.5) * 100 : 0;
      const spawnY = beid >= 0 ? Position.y[beid] + (s.eventRng() - 0.5) * 20 : 0;
      const spawnZ = beid >= 0 ? Position.z[beid] + (s.eventRng() - 0.5) * 100 : 0;
      const newEid = createRobot(s.world, robotType, spawnX, spawnY, spawnZ, s.grid);
      if (newEid >= 0 && s.cultureState.autonomyScore > 40) {
        s.cultureState.robotNames.set(newEid, generateRobotName(newEid));
      }
      if (newEid >= 0) {
        s.cultureState.robotStats.set(newEid, { tasksCompleted: 0, asteroidsNamed: 0, anomaliesStudied: 0, spawnTick: s.tick, taskHint: -1, knowledgeBoostUntil: 0, mourningUntil: 0, lastTaskTypes: [] });
        spawnedRobotTypes.push(robotType);
      }
      activeCount++;
    }
  }

  return { justUnlocked, spawnedRobotTypes, researchDeadEnd };
}
