/**
 * Automation tiers 1-3: Named task queues, supply chains, autonomous sectors.
 *
 * Tier 1 (always available): Player-defined named task queues with priority,
 *   type filter, and repeat mode. Injects tasks into the global TaskQueue.
 *
 * Tier 2 (requires automated_logistics tech): Supply chain rules that detect
 *   resource deficits and automatically queue mining tasks.
 *
 * Tier 3 (requires sector_mapping tech): Named sectors with bounds; robots
 *   assigned to sectors pick tasks only within those bounds.
 */

import { TASK_TYPES } from './taskQueue';
import type { TaskQueue } from './taskQueue';

// ── Tier 1: Named Task Queues ─────────────────────────────────────────────────

export interface AutoQueue {
  id: string;
  name: string;
  /** TASK_TYPES constant: MINE=0, HAUL=1, EXPLORE=2 */
  taskType: number;
  /** Priority injected into generated tasks (1-10) */
  priority: number;
  /** When true, immediately re-queues after all tasks of this type complete */
  repeat: boolean;
  enabled: boolean;
  /** Optional: only target asteroids with >0 of this mineral */
  preferMineral?: string;
}

export interface AutoQueueState {
  queues: Map<string, AutoQueue>;
}

export function createAutoQueueState(): AutoQueueState {
  return { queues: new Map() };
}

export function upsertAutoQueue(state: AutoQueueState, queue: AutoQueue): void {
  state.queues.set(queue.id, queue);
}

export function deleteAutoQueue(state: AutoQueueState, id: string): void {
  state.queues.delete(id);
}

/**
 * Tick auto-queues: inject tasks into the task queue based on enabled queues.
 * Called each simulation tick. Respects an overall cap to avoid flooding.
 */
export function tickAutoQueues(
  state: AutoQueueState,
  asteroidEntities: number[],
  getAsteroidPos: (eid: number) => { x: number; y: number; z: number },
  getAsteroidHealth: (eid: number) => number,
  getAsteroidMinerals: (eid: number) => Record<string, number>,
  getAnomalyFlag: (eid: number) => number,
  taskQueue: TaskQueue,
  rng: () => number,
  maxInject: number = 3,
): void {
  for (const q of state.queues.values()) {
    if (!q.enabled) continue;

    const pending = taskQueue.getUnclaimedTasks().filter((t) => t.taskType === q.taskType);
    if (pending.length >= maxInject) continue;

    const needed = maxInject - pending.length;
    let injected = 0;

    // Shuffle asteroid list for variety
    const candidates = [...asteroidEntities];
    shuffleArray(candidates, rng);

    for (const eid of candidates) {
      if (injected >= needed) break;
      const health = getAsteroidHealth(eid);
      if (health <= 0) continue;

      // Mineral filter
      if (q.preferMineral) {
        const minerals = getAsteroidMinerals(eid);
        if ((minerals[q.preferMineral] ?? 0) <= 0) continue;
      }

      // For EXPLORE, prefer anomalies
      if (q.taskType === TASK_TYPES.EXPLORE && getAnomalyFlag(eid) === 0) continue;

      const pos = getAsteroidPos(eid);
      taskQueue.addTask(q.taskType, eid, pos.x, pos.y, pos.z, 0, 0, 0, q.priority, 'auto');
      injected++;
    }
  }
}

// ── Tier 2: Supply Chain Automation ──────────────────────────────────────────

export interface SupplyRule {
  resource: string; // raw resource: 'iron', 'nickel', 'cobalt', etc.
  targetLevel: number; // auto-mine until storage >= targetLevel
  priority: number; // task priority when deficit detected
  enabled: boolean;
}

export interface SupplyChainState {
  rules: Map<string, SupplyRule>;
  /** Ticks since last deficit check (throttle to avoid over-injection) */
  _checkTimer: number;
}

export function createSupplyChainState(): SupplyChainState {
  return { rules: new Map(), _checkTimer: 0 };
}

export function upsertSupplyRule(state: SupplyChainState, rule: SupplyRule): void {
  state.rules.set(rule.resource, rule);
}

export function deleteSupplyRule(state: SupplyChainState, resource: string): void {
  state.rules.delete(resource);
}

/**
 * Check supply deficits and inject mining tasks as needed.
 * Throttled: only runs every `checkEveryTicks` ticks.
 */
export function tickSupplyChain(
  state: SupplyChainState,
  storage: Record<string, number>,
  asteroidEntities: number[],
  getAsteroidPos: (eid: number) => { x: number; y: number; z: number },
  getAsteroidHealth: (eid: number) => number,
  getAsteroidMinerals: (eid: number) => Record<string, number>,
  taskQueue: TaskQueue,
  checkEveryTicks: number = 60,
): void {
  state._checkTimer++;
  if (state._checkTimer < checkEveryTicks) return;
  state._checkTimer = 0;

  for (const rule of state.rules.values()) {
    if (!rule.enabled) continue;

    const current = storage[rule.resource] ?? 0;
    if (current >= rule.targetLevel) continue;

    // Deficit: ensure at least one mining task is queued for this resource
    const existingMine = taskQueue
      .getUnclaimedTasks()
      .filter((t) => t.taskType === TASK_TYPES.MINE);
    if (existingMine.length >= 5) continue; // don't flood queue

    // Find asteroid richest in the needed resource
    let bestEid = -1;
    let bestScore = 0;
    for (const eid of asteroidEntities) {
      const health = getAsteroidHealth(eid);
      if (health <= 0) continue;
      const minerals = getAsteroidMinerals(eid);
      const score = (minerals[rule.resource] ?? 0) * health;
      if (score > bestScore) {
        bestScore = score;
        bestEid = eid;
      }
    }

    if (bestEid < 0) continue;
    const pos = getAsteroidPos(bestEid);
    taskQueue.addTask(TASK_TYPES.MINE, bestEid, pos.x, pos.y, pos.z, 0, 0, 0, rule.priority, 'auto');
  }
}

// ── Tier 3: Autonomous Sectors ────────────────────────────────────────────────

export type SectorGoal = 'maximize_mining' | 'explore_anomalies' | 'balanced';

export interface Sector {
  id: string;
  name: string;
  minX: number;
  maxX: number;
  minZ: number;
  maxZ: number;
  goal: SectorGoal;
  enabled: boolean;
  /** Robot entity ids assigned to this sector */
  assignedRobotEids: number[];
  /** Cumulative tasks generated (stat) */
  tasksGenerated: number;
}

export interface SectorState {
  sectors: Map<string, Sector>;
  _tickTimer: number;
}

export function createSectorState(): SectorState {
  return { sectors: new Map(), _tickTimer: 0 };
}

export function upsertSector(state: SectorState, sector: Sector): void {
  state.sectors.set(sector.id, sector);
}

export function deleteSector(state: SectorState, id: string): void {
  state.sectors.delete(id);
}

export function isPositionInSector(sector: Sector, x: number, z: number): boolean {
  return x >= sector.minX && x <= sector.maxX && z >= sector.minZ && z <= sector.maxZ;
}

/**
 * Sector AI tick: generate tasks within each sector's bounds.
 * Throttled to avoid injecting too many tasks.
 */
export function tickSectors(
  state: SectorState,
  asteroidEntities: number[],
  getAsteroidPos: (eid: number) => { x: number; y: number; z: number },
  getAsteroidHealth: (eid: number) => number,
  getAnomalyFlag: (eid: number) => number,
  taskQueue: TaskQueue,
  rng: () => number,
  checkEveryTicks: number = 90,
): void {
  state._tickTimer++;
  if (state._tickTimer < checkEveryTicks) return;
  state._tickTimer = 0;

  for (const sector of state.sectors.values()) {
    if (!sector.enabled) continue;

    // Find asteroids within sector bounds with health remaining
    const inSector: number[] = [];
    for (const eid of asteroidEntities) {
      const pos = getAsteroidPos(eid);
      const health = getAsteroidHealth(eid);
      if (health > 0 && isPositionInSector(sector, pos.x, pos.z)) {
        inSector.push(eid);
      }
    }
    if (inSector.length === 0) continue;

    // Don't add more than 2 tasks per sector per check
    const existingPending = taskQueue.pendingCount;
    if (existingPending >= 10) continue;

    const toAdd = Math.min(2, 10 - existingPending);
    shuffleArray(inSector, rng);

    for (let i = 0; i < Math.min(toAdd, inSector.length); i++) {
      const eid = inSector[i];
      const pos = getAsteroidPos(eid);
      const health = getAsteroidHealth(eid);
      const anomaly = getAnomalyFlag(eid);

      let taskType: number;
      if (sector.goal === 'explore_anomalies' && anomaly > 0) {
        taskType = TASK_TYPES.EXPLORE;
      } else if (sector.goal === 'balanced' && anomaly > 0 && rng() < 0.3) {
        taskType = TASK_TYPES.EXPLORE;
      } else {
        taskType = TASK_TYPES.MINE;
      }

      const priority = Math.min(10, Math.max(1, health / 1000));
      taskQueue.addTask(taskType, eid, pos.x, pos.y, pos.z, 0, 0, 0, priority, 'auto');
      sector.tasksGenerated++;
    }
  }
}

// ── Serialization ─────────────────────────────────────────────────────────────

export type SerializedAutoQueue = AutoQueue;

export type SerializedSupplyRule = SupplyRule;

export interface SerializedSector extends Omit<Sector, 'assignedRobotEids'> {
  assignedRobotEids: number[];
}

export interface SerializedAutomationState {
  queues: SerializedAutoQueue[];
  supplyRules: SerializedSupplyRule[];
  sectors: SerializedSector[];
}

export function serializeAutomationState(
  autoQueueState: AutoQueueState,
  supplyChainState: SupplyChainState,
  sectorState: SectorState,
): SerializedAutomationState {
  return {
    queues: Array.from(autoQueueState.queues.values()),
    supplyRules: Array.from(supplyChainState.rules.values()),
    sectors: Array.from(sectorState.sectors.values()).map((s) => ({ ...s })),
  };
}

// ── Utility ───────────────────────────────────────────────────────────────────

function shuffleArray<T>(arr: T[], rng: () => number): void {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
}
