/**
 * Combat tick phase: faction ship spawning and Defender combat.
 */
import { query } from 'bitecs';
import { BaseStationTag, Position, Storage } from '../../components';
import { workerState, runSystem, FIXED_DT, sendMessage } from '../state';
import { tickShipSpawning, tickCombat } from '../../combatSystem';
import type { FactionId } from '../../factions/factionSystem';
import { FACTION_DEFS } from '../../factions/factionSystem';
import { addMessage, getInboxSnapshot } from '../../inbox/inboxStore';
import type { InboxMessage } from '../../inbox/inboxTypes';

let nextInboxId = 90000; // high range to avoid collision with other inbox generators

export function tickCombatPhase(): void {
  const s = workerState;
  if (!s.world || !s.grid || !s.factionSystemState || !s.combatState) return;

  // Spawn ships for hostile factions
  runSystem('combatSpawn', () => {
    tickShipSpawning(
      s.world!,
      s.grid!,
      s.factionSystemState!,
      s.combatState!,
      s.eventRng,
    );
  });

  // Run combat
  runSystem('combat', () => {
    tickCombat(
      s.world!,
      FIXED_DT,
      s.grid!,
      s.factionSystemState!,
      s.combatState!,
      s.eventRng,
      (defenderEid, _shipEid, factionId, x, y, z, lootMineral, lootAmount) => {
        onFactionShipKill(factionId, x, y, z, lootMineral, lootAmount);
      },
    );
  });
}

function onFactionShipKill(
  factionId: FactionId,
  x: number,
  y: number,
  z: number,
  lootMineral: string,
  lootAmount: number,
): void {
  const s = workerState;
  const factionName = FACTION_DEFS[factionId].name;

  // Deposit loot at nearest base
  const allBases = query(s.world!, [BaseStationTag, Position]);
  if (allBases.length > 0) {
    let nearestBase = allBases[0];
    let nearestDist2 = Infinity;
    for (let i = 0; i < allBases.length; i++) {
      const beid = allBases[i];
      const dx = Position.x[beid] - x;
      const dy = Position.y[beid] - y;
      const dz = Position.z[beid] - z;
      const d2 = dx * dx + dy * dy + dz * dz;
      if (d2 < nearestDist2) {
        nearestDist2 = d2;
        nearestBase = beid;
      }
    }
    // Add loot to base storage
    const store = Storage as Record<string, Float32Array>;
    if (store[lootMineral]) {
      store[lootMineral][nearestBase] += lootAmount;
    }
  }

  // Send ARIA broadcast via inbox
  const msg: InboxMessage = {
    id: nextInboxId++,
    factionId: null,
    senderName: 'ARIA',
    type: 'aria_auto',
    subject: 'Defender Kill Report',
    body:
      `Defender unit neutralized a ${factionName} raider. ` +
      `Salvaged ${lootAmount} units of ${lootMineral} deposited at nearest base.`,
    priority: 'normal',
    tick: s.tick,
    triaged: true,
    triageResult: 'relevant',
    read: false,
  };
  addMessage(msg);
  sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });
}
