/**
 * Mulberry32 PRNG - fast, seedable, deterministic.
 * Used for all procedural generation to ensure reproducibility.
 */
export function mulberry32(seed: number): () => number {
  let s = seed | 0;
  return (): number => {
    s = (s + 0x6d2b79f5) | 0;
    let t = Math.imul(s ^ (s >>> 15), 1 | s);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/**
 * Mix a world seed with chunk coordinates to get a per-chunk seed.
 */
export function chunkSeed(worldSeed: number, cx: number, cy: number, cz: number): number {
  let h = worldSeed | 0;
  h = Math.imul(h ^ cx, 0x85ebca6b);
  h = Math.imul(h ^ cy, 0xc2b2ae35);
  h = Math.imul(h ^ cz, 0x27d4eb2f);
  h ^= h >>> 16;
  return h >>> 0;
}

/**
 * Generate a gaussian-distributed random number using Box-Muller transform.
 */
export function gaussian(rng: () => number, mean: number = 0, stddev: number = 1): number {
  const u1 = rng();
  const u2 = rng();
  const z = Math.sqrt(-2 * Math.log(u1 || 1e-10)) * Math.cos(2 * Math.PI * u2);
  return mean + z * stddev;
}

/**
 * Generate a log-normal distributed value.
 */
export function logNormal(rng: () => number, mu: number, sigma: number): number {
  return Math.exp(gaussian(rng, mu, sigma));
}
