/**
 * Narrative event engine tick phase.
 */
import { workerState, runSystem, sendMessage } from '../state';

export function tickNarrativePhase(): void {
  const s = workerState;
  runSystem('eventEngine', () => {
    const firedEvents = s.eventEngine.tick(s.tick, s.eventRng);
    for (const { event } of firedEvents) {
      sendMessage({
        type: 'sim:narrative_event',
        payload: { event, tick: s.tick },
      });
    }
  });
}
