import {
  Position,
  Velocity,
  RobotType,
  RobotState,
  Energy,
  ToolType,
  ResearchOutput,
  TaskRef,
  PathTarget,
  Thrust,
} from '../components';
import type { RobotProfile } from '../robotProfiles';
import { ROBOT_TYPES, TOOL_TYPES } from '../robotProfiles';
import type { TaskQueue } from '../taskQueue';
import { TASK_TYPES } from '../taskQueue';
import { ROBOT_STATES, ARRIVAL_RADIUS } from '../robotCreation';
import { distanceTo } from './types';

export function handleMovingToRobot(
  eid: number,
  taskQueue: TaskQueue,
  profile: RobotProfile,
  baseEid: number,
): void {
  // Energy-aware abort: estimate energy needed to return to base.
  // If remaining energy can't cover the return trip with a safety margin, abort.
  if (baseEid >= 0) {
    const distToBase = distanceTo(
      eid,
      Position.x[baseEid],
      Position.y[baseEid],
      Position.z[baseEid],
    );
    const maxSpeed = Thrust.maxSpeed[eid] || 40;
    const maxThrustForCalc = Thrust.maxThrust[eid] || 30;
    const massForCalc = Thrust.mass[eid] || 15;
    const returnTime = distToBase / maxSpeed;
    const energyPerSec = profile.energyConsumptionRate * maxThrustForCalc;
    const returnEnergy = returnTime * energyPerSec;
    // Account for speed reversal cost: robot may be traveling at maxSpeed toward
    // the asteroid and must decelerate + re-accelerate toward base (2× braking distance).
    const brakingDist = (maxSpeed * maxSpeed * massForCalc) / (2 * maxThrustForCalc);
    const reversalEnergy = 2 * (brakingDist / maxSpeed) * energyPerSec;
    // Abort if we can't afford the return trip including reversal, with a 1.5× safety margin
    if (Energy.current[eid] < (returnEnergy + reversalEnergy) * 1.5) {
      const taskId = TaskRef.taskId[eid];
      if (taskId >= 0) {
        taskQueue.releaseTask(taskId);
        TaskRef.taskId[eid] = -1;
      }
      RobotState.state[eid] = ROBOT_STATES.RETURNING;
      PathTarget.x[eid] = Position.x[baseEid];
      PathTarget.y[eid] = Position.y[baseEid];
      PathTarget.z[eid] = Position.z[baseEid];
      return;
    }
  }

  const dist = distanceTo(eid, PathTarget.x[eid], PathTarget.y[eid], PathTarget.z[eid]);
  const speed = Math.sqrt(
    Velocity.x[eid] * Velocity.x[eid] +
      Velocity.y[eid] * Velocity.y[eid] +
      Velocity.z[eid] * Velocity.z[eid],
  );

  if (dist < ARRIVAL_RADIUS && speed < 5) {
    Velocity.x[eid] = 0;
    Velocity.y[eid] = 0;
    Velocity.z[eid] = 0;

    const taskId = TaskRef.taskId[eid];
    if (taskId >= 0) {
      const task = taskQueue.getTask(taskId);
      if (task) {
        taskQueue.startTask(taskId);
        if (
          task.taskType === TASK_TYPES.MINE &&
          (ToolType.type[eid] === TOOL_TYPES.DRILL ||
            RobotType.type[eid] === ROBOT_TYPES.MINER)
        ) {
          RobotState.state[eid] = ROBOT_STATES.MINING;
        } else if (task.taskType === TASK_TYPES.HAUL || task.taskType === TASK_TYPES.TRADE_DELIVERY) {
          RobotState.state[eid] = ROBOT_STATES.HAULING;
        } else if (task.taskType === TASK_TYPES.TRANSFER) {
          // subState preserved: 0=at source (load), 1=at dest (unload)
          RobotState.state[eid] = ROBOT_STATES.TRANSFERRING;
        } else if (
          task.taskType === TASK_TYPES.EXPLORE &&
          RobotType.type[eid] === ROBOT_TYPES.RESEARCHER
        ) {
          // Researcher arrives at study target
          RobotState.state[eid] = ROBOT_STATES.STUDYING;
          RobotState.stateTimer[eid] = 0;
          ResearchOutput.isStudying[eid] = 1;
        } else if (
          task.taskType === TASK_TYPES.CONSTRUCT &&
          ToolType.type[eid] === TOOL_TYPES.CONSTRUCTOR
        ) {
          // Engineer arrives at construction site
          RobotState.state[eid] = ROBOT_STATES.CONSTRUCTING;
          RobotState.stateTimer[eid] = 0;
        } else {
          taskQueue.completeTask(taskId);
          TaskRef.taskId[eid] = -1;
          RobotState.state[eid] = ROBOT_STATES.IDLE;
        }
      }
    } else {
      RobotState.state[eid] = ROBOT_STATES.CHARGING;
    }
  }
}
