/**
 * Logistics message handlers: build base, routes.
 */
import { workerState, sendMessage } from '../state';
import { Storage } from '../../components';
import { getRawStorage, writeRawStorage } from '../phases/helpers';
import { createBaseStation } from '../../robotSystems';
import {
  upsertRoute,
  deleteRoute,
  getBaseInfos,
  BASE_BUILD_COSTS,
  DEFAULT_BASE_CAPACITY,
} from '../../logistics';

export function handleBuildBase(payload: { x: number; y: number; z: number }): void {
  const s = workerState;
  if (!s.world || !s.grid) return;
  const { x, y, z } = payload;
  const rawStorage = getRawStorage();

  if (rawStorage.iron < BASE_BUILD_COSTS.iron || rawStorage.carbon < BASE_BUILD_COSTS.carbon) {
    sendMessage({
      type: 'sim:base_built',
      payload: {
        ok: false,
        error: `Need ${BASE_BUILD_COSTS.iron} iron and ${BASE_BUILD_COSTS.carbon} carbon`,
        bases: getBaseInfos(s.logisticsState),
      },
    });
    return;
  }

  rawStorage.iron -= BASE_BUILD_COSTS.iron;
  rawStorage.carbon -= BASE_BUILD_COSTS.carbon;
  writeRawStorage(rawStorage);

  const newBaseEid = createBaseStation(s.world, x, y, z, s.grid);
  Storage.capacity[newBaseEid] = DEFAULT_BASE_CAPACITY;
  s.logisticsState.baseEids.push(newBaseEid);

  sendMessage({
    type: 'sim:base_built',
    payload: { ok: true, bases: getBaseInfos(s.logisticsState) },
  });
}

export function handleUpsertRoute(payload: Parameters<typeof upsertRoute>[1]): void {
  upsertRoute(workerState.logisticsState, payload);
}

export function handleDeleteRoute(payload: { id: string }): void {
  deleteRoute(workerState.logisticsState, payload.id);
}
