import {
  Position,
  Energy,
  Fuel,
  ToolType,
  RobotType,
} from '../components';
import type { RobotProfile } from '../robotProfiles';
import { ROBOT_TYPES, TOOL_TYPES } from '../robotProfiles';
import { TASK_TYPES } from '../taskQueue';
import { transitCostMultiplier } from '../orbitalSystem';
import { distanceTo } from './types';

/** Compute the AUTONOMOUS_COLLECTIVE culture factor for auto-queue task scoring.
 *  Tiered: 60+ → 1.1x, 80+ → 1.25x (priority inversion). */
export function getAutonomyCultureFactor(autonomyScore: number, isAutoTask: boolean): number {
  if (!isAutoTask || autonomyScore < 60) return 1.0;
  if (autonomyScore >= 80) return 1.25; // priority inversion
  return 1.1;
}

export function scoreTask(
  eid: number,
  task: { taskType: number; targetEid: number; targetX: number; targetY: number; targetZ: number; priority: number; source: 'manual' | 'auto'; preferredRobotEid: number },
  profile: RobotProfile,
  autonomyScore: number,
  taskHintType: number,
  isolationSignalDelay = false,
  baseX = 0, baseY = 0, baseZ = 0,
): number {
  // If this task has a preferred robot and we're not it, score -Infinity so it's reserved.
  if (task.preferredRobotEid >= 0 && task.preferredRobotEid !== eid) return -Infinity;

  const dist = distanceTo(eid, task.targetX, task.targetY, task.targetZ);
  // CONSTRUCT tasks can only be taken by engineers
  if (task.taskType === TASK_TYPES.CONSTRUCT && ToolType.type[eid] !== TOOL_TYPES.CONSTRUCTOR) return -Infinity;

  const toolMatch =
    (task.taskType === TASK_TYPES.MINE && ToolType.type[eid] === TOOL_TYPES.DRILL) ||
    ((task.taskType === TASK_TYPES.HAUL || task.taskType === TASK_TYPES.TRADE_DELIVERY) && ToolType.type[eid] === TOOL_TYPES.CARGO) ||
    (task.taskType === TASK_TYPES.EXPLORE && ToolType.type[eid] === TOOL_TYPES.SCANNER) ||
    (task.taskType === TASK_TYPES.CONSTRUCT && ToolType.type[eid] === TOOL_TYPES.CONSTRUCTOR)
      ? 10
      : 1;
  const energyFactor = Energy.current[eid] / Energy.max[eid];

  // Transit window multiplier: asteroids outside the window cost more fuel
  const transitMult = task.targetEid >= 0 ? transitCostMultiplier(task.targetEid, baseX, baseZ) : 1.0;

  // Fuel cost factor: penalize distant tasks when robot lacks fuel for the round trip.
  // Transit window multiplier increases effective fuel cost for out-of-window asteroids.
  const fuelForRoundTrip = 2 * dist * profile.fuelPerUnit * transitMult;
  const fuelAvailable = Fuel.current[eid];
  const fuelFactor =
    fuelAvailable >= fuelForRoundTrip ? 1.0 : fuelAvailable / (fuelForRoundTrip + 1e-6);

  // AUTONOMOUS_COLLECTIVE: tiered auto-queue bonus (60→1.1x, 80→1.25x)
  const cultureFactor = getAutonomyCultureFactor(autonomyScore, task.source === 'auto');

  // Auto-redistribution: 1.15x boost for task types matching the taskHint from a nearby completing robot
  const hintFactor = (taskHintType >= 0 && task.taskType === taskHintType) ? 1.15 : 1.0;

  // If this robot is the preferred one, give a massive priority boost
  const preferredFactor = (task.preferredRobotEid >= 0 && task.preferredRobotEid === eid) ? 100.0 : 1.0;

  // ISOLATED_CULTURE: signal delay — manual tasks penalized when robot is far from base
  let signalDelayFactor = 1.0;
  if (isolationSignalDelay && task.source === 'manual') {
    const dx = Position.x[eid] - baseX;
    const dy = Position.y[eid] - baseY;
    const dz = Position.z[eid] - baseZ;
    const distFromBase = Math.sqrt(dx * dx + dy * dy + dz * dz);
    if (distFromBase > 3000) signalDelayFactor = 0.6;
  }

  // task.priority encodes estimated yield; higher yield favors this task
  return (task.priority * toolMatch * energyFactor * fuelFactor * cultureFactor * hintFactor * preferredFactor * signalDelayFactor) / (1 + dist * 0.001);
}
