/**
 * Inbox message handlers: triage results, mark read, delete, inject.
 */
import { workerState, sendMessage } from '../state';
import {
  updateTriageResults,
  markRead,
  deleteMessage as deleteInboxMessage,
  addMessage as addInboxMessage,
  getInboxSnapshot,
} from '../../inbox/inboxStore';
import type {
  SimInboxTriageResultMessage,
  SimInboxMarkReadMessage,
  SimInboxDeleteMessage,
  SimInboxInjectMessage,
} from '../../messages';

export function handleInboxTriageResult(payload: SimInboxTriageResultMessage['payload']): void {
  updateTriageResults(payload.results);
  sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(workerState.tick) });
}

export function handleInboxMarkRead(payload: SimInboxMarkReadMessage['payload']): void {
  markRead(payload.messageId);
}

export function handleInboxDelete(payload: SimInboxDeleteMessage['payload']): void {
  deleteInboxMessage(payload.messageId);
}

export function handleInboxInject(payload: SimInboxInjectMessage['payload']): void {
  addInboxMessage(payload.message);
  sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(workerState.tick) });
}
