/**
 * onmessage dispatch: routes MainToWorkerMessage types to their handlers.
 */
import { workerState, sendMessage } from './state';
import type { MainToWorkerMessage } from '../messages';
import {
  handleInit, handleStart, handleStop, handlePause, handleResume, handleSetSpeed,
  handleSaveRequest, handleLoad, handleRobotOrder, handleRobotDetailRequest, handleAddTask, handleQueryAsteroid,
  handleStartResearch, handleEnqueueRecipe, handleEnqueueBuild, handleBuildBuilding,
  handleUpsertAutoQueue, handleDeleteAutoQueue, handleUpsertSupplyRule,
  handleDeleteSupplyRule, handleUpsertSector, handleDeleteSector,
  handleBuildBase, handleUpsertRoute, handleDeleteRoute,
  handleEventChoice, handleFactionDiplomacy,
  handleStartMegastructureStage, handleResolveMegastructureCrisis, handleSkipMegastructureCrisis,
  handleReplacementChoice, handleDarkForestChoice, handleSetFleetColor, handleSetFleetManifesto,
  handleSetColonyName, handleNameAsteroid, handleSetColonyEpithet,
  handleSetMaterialWeights,
  handleHabitatDemandResponse,
  handleDispositionEventResponse,
  handleTradeWindowResponse,
  handleMarketCreateListing,
  handleMarketCancelListing,
  handleThreatResponse,
  handleInboxTriageResult, handleInboxMarkRead, handleInboxDelete, handleInboxInject,
  handleSaveBlueprint, handleDeleteBlueprint, handleRenameBlueprint, handleLoadBlueprint,
  handleClaimAsteroid, handleRecallOutpost,
  handleDispatchCargo,
} from './handlers';

export function handleMessage(e: MessageEvent<MainToWorkerMessage>): void {
  try {
    dispatch(e.data);
  } catch (err) {
    const errMessage = err instanceof Error ? err.message : String(err);
    const stack = err instanceof Error ? err.stack : undefined;
    console.error('[worker] handleMessage threw:', stack ?? errMessage);
    sendMessage({
      type: 'sim:worker_error',
      payload: { message: errMessage, tick: workerState.tick, system: `messageHandler:${e.data?.type ?? 'unknown'}`, stack },
    });
    sendMessage({
      type: 'sim:error',
      payload: { message: `Worker message handler error: ${errMessage}`, tick: workerState.tick },
    });
  }
}

function dispatch(msg: MainToWorkerMessage): void {
  switch (msg.type) {
    case 'sim:init': handleInit(msg.payload); break;
    case 'sim:start': handleStart(); break;
    case 'sim:stop': handleStop(); break;
    case 'sim:pause': handlePause(); break;
    case 'sim:resume': handleResume(); break;
    case 'sim:set_speed': handleSetSpeed(msg.payload); break;
    case 'sim:start_research': handleStartResearch(msg.payload); break;
    case 'sim:enqueue_recipe': handleEnqueueRecipe(msg.payload); break;
    case 'sim:enqueue_build': handleEnqueueBuild(msg.payload); break;
    case 'sim:build_building': handleBuildBuilding(msg.payload); break;
    case 'sim:upsert_auto_queue': handleUpsertAutoQueue(msg.payload); break;
    case 'sim:delete_auto_queue': handleDeleteAutoQueue(msg.payload); break;
    case 'sim:upsert_supply_rule': handleUpsertSupplyRule(msg.payload); break;
    case 'sim:delete_supply_rule': handleDeleteSupplyRule(msg.payload); break;
    case 'sim:upsert_sector': handleUpsertSector(msg.payload); break;
    case 'sim:delete_sector': handleDeleteSector(msg.payload); break;
    case 'sim:build_base': handleBuildBase(msg.payload); break;
    case 'sim:upsert_route': handleUpsertRoute(msg.payload); break;
    case 'sim:delete_route': handleDeleteRoute(msg.payload); break;
    case 'sim:event_choice': handleEventChoice(msg.payload); break;
    case 'sim:faction_diplomacy': handleFactionDiplomacy(msg.payload); break;
    case 'sim:start_megastructure_stage': handleStartMegastructureStage(msg.payload); break;
    case 'sim:resolve_megastructure_crisis': handleResolveMegastructureCrisis(msg.payload); break;
    case 'sim:skip_megastructure_crisis': handleSkipMegastructureCrisis(msg.payload); break;
    case 'sim:save_request': handleSaveRequest(msg.payload); break;
    case 'sim:load': handleLoad(msg.payload); break;
    case 'sim:robot_order': handleRobotOrder(msg.payload); break;
    case 'sim:robot_detail_request': handleRobotDetailRequest(msg.payload); break;
    case 'sim:add_task': handleAddTask(msg.payload); break;
    case 'sim:query_asteroid': handleQueryAsteroid(msg.payload); break;
    case 'sim:inbox_triage_result': handleInboxTriageResult(msg.payload); break;
    case 'sim:inbox_mark_read': handleInboxMarkRead(msg.payload); break;
    case 'sim:inbox_delete': handleInboxDelete(msg.payload); break;
    case 'sim:inbox_inject': handleInboxInject(msg.payload); break;
    case 'sim:replacement_choice': handleReplacementChoice(msg.payload); break;
    case 'sim:dark_forest_choice': handleDarkForestChoice(msg.payload); break;
    case 'sim:set_fleet_color': handleSetFleetColor(msg.payload); break;
    case 'sim:set_fleet_manifesto': handleSetFleetManifesto(msg.payload); break;
    case 'sim:set_colony_name': handleSetColonyName(msg.payload); break;
    case 'sim:name_asteroid': handleNameAsteroid(msg.payload); break;
    case 'sim:set_colony_epithet': handleSetColonyEpithet(msg.payload); break;
    case 'sim:habitat_demand_response': handleHabitatDemandResponse(msg.payload); break;
    case 'sim:disposition_event_response': handleDispositionEventResponse(msg.payload); break;
    case 'sim:trade_window_response': handleTradeWindowResponse(msg.payload); break;
    case 'sim:market_create_listing': handleMarketCreateListing(msg.payload); break;
    case 'sim:market_cancel_listing': handleMarketCancelListing(msg.payload); break;
    case 'sim:threat_response': handleThreatResponse(msg.payload); break;
    case 'sim:set_material_weights': handleSetMaterialWeights(msg.payload); break;
    case 'sim:save_blueprint': handleSaveBlueprint(msg.payload); break;
    case 'sim:delete_blueprint': handleDeleteBlueprint(msg.payload); break;
    case 'sim:rename_blueprint': handleRenameBlueprint(msg.payload); break;
    case 'sim:load_blueprint': handleLoadBlueprint(msg.payload); break;
    case 'sim:claim_asteroid': handleClaimAsteroid(msg.payload); break;
    case 'sim:recall_outpost': handleRecallOutpost(msg.payload); break;
    case 'sim:dispatch_cargo': handleDispatchCargo(msg.payload); break;
    default: console.warn('[worker] Unhandled message type:', (msg as { type: string }).type); break;
  }
}
