/**
 * Faction diplomacy and event choice message handlers.
 */
import { workerState, sendMessage } from '../state';
import {
  shareAnomalyWithFaction,
  tradeResourcesWithFaction,
  threatenFaction,
  proposeTerritoryAgreement,
  applyDispositionEventResponse,
  respondToTradeWindow,
  snapshotFactions,
} from '../../factions/factionSystem';
import type { FactionId } from '../../factions/factionSystem';
import type { DispositionEventType } from '../../inbox/inboxTypes';
import type { SimFactionDiplomacyMessage, SimTradeWindowResponseMessage } from '../../messages';
import { getInboxSnapshot } from '../../inbox/inboxStore';
import { computeCulturalDistance, getDiplomacyMultiplier } from '../../colonyDialect';

export function handleFactionDiplomacy(payload: SimFactionDiplomacyMessage['payload']): void {
  const s = workerState;
  if (!s.factionSystemState) return;
  const { factionId, action } = payload;
  const culturalDist = computeCulturalDistance(s.cultureState, factionId);
  const dipMult = getDiplomacyMultiplier(culturalDist);
  switch (action) {
    case 'share_anomaly':
      shareAnomalyWithFaction(s.factionSystemState, factionId, s.tick, dipMult);
      break;
    case 'trade_resources':
      tradeResourcesWithFaction(s.factionSystemState, factionId, s.tick, dipMult);
      break;
    case 'threaten':
      threatenFaction(s.factionSystemState, factionId, s.tick);
      break;
    case 'territory_agreement':
      proposeTerritoryAgreement(s.factionSystemState, factionId, s.tick);
      break;
  }
  sendMessage({
    type: 'sim:faction_state',
    payload: { factions: snapshotFactions(s.factionSystemState), tick: s.tick },
  });
}

export function handleEventChoice(payload: { eventId: string; choiceId: string }): void {
  workerState.eventEngine.resolveChoice(payload.eventId, payload.choiceId);
}

export function handleDispositionEventResponse(payload: {
  factionId: FactionId;
  eventType: DispositionEventType;
  response: 'accept' | 'reject' | 'ignore';
}): void {
  const s = workerState;
  if (!s.factionSystemState) return;
  applyDispositionEventResponse(
    s.factionSystemState,
    payload.factionId,
    payload.eventType,
    payload.response,
    s.tick,
  );
  sendMessage({
    type: 'sim:faction_state',
    payload: { factions: snapshotFactions(s.factionSystemState), tick: s.tick },
  });
  sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });
}

export function handleTradeWindowResponse(payload: SimTradeWindowResponseMessage['payload']): void {
  const s = workerState;
  if (!s.factionSystemState) return;
  const culturalDist = computeCulturalDistance(s.cultureState, payload.factionId);
  const dipMult = getDiplomacyMultiplier(culturalDist);
  respondToTradeWindow(s.factionSystemState, payload.factionId, payload.response, s.tick, dipMult);
  sendMessage({
    type: 'sim:faction_state',
    payload: { factions: snapshotFactions(s.factionSystemState), tick: s.tick },
  });
}
