/**
 * Narrative Event Catalog
 *
 * ~20 events across 5 types: Discovery, Dilemma, Revelation, Threat, Opportunity.
 * Events are pure data — trigger logic lives in the EventEngine.
 */

export type EventType = 'discovery' | 'dilemma' | 'revelation' | 'threat' | 'opportunity';

export interface EventChoice {
  id: string;
  label: string;
  /** Flags to set when this choice is made */
  setFlags?: Record<string, boolean | number>;
}

export interface NarrativeEvent {
  id: string;
  type: EventType;
  title: string;
  body: string;

  // ── Trigger conditions (all must be true) ──────────────────────────────────
  /** Minimum game tick before this can fire */
  minTick?: number;
  /** Flags that must be set (truthy) for this to trigger */
  requiredFlags?: string[];
  /** Flags that must NOT be set for this to trigger */
  forbiddenFlags?: string[];
  /** Fire exactly once when conditions are first met (no random chance) */
  triggerOnce?: boolean;
  /** Probability per tick when conditions met (e.g. 0.0008 = ~once per 20 sim-seconds at 60fps) */
  chancePerTick?: number;

  // ── Consequences ────────────────────────────────────────────────────────────
  /** For dilemma events: player choices (each sets flags) */
  choices?: EventChoice[];
  /** Auto-applied flags on dismissal (non-dilemma events) */
  setFlags?: Record<string, boolean | number>;
}

