/**
 * Trade Windows
 *
 * Lifecycle management for time-limited faction trade windows.
 */

import {
  FACTION_DEFS,
  TRADE_WINDOW_WARNING_TICKS,
  TRADE_WINDOW_DISPOSITION_THRESHOLD,
  TRADE_WINDOW_COOLDOWN,
  TRADE_WINDOW_PROBABILITY,
  TRADE_WINDOW_OFFERS,
  TRADE_WINDOW_DURATION,
} from './factionDefs.js';
import type { FactionSystemState, FactionId } from './factionDefs.js';

export interface TradeWindowEvent {
  factionId: FactionId;
  factionName: string;
  type: 'opened' | 'warning' | 'expired';
  resource?: string;
  resourceLabel?: string;
  rateMultiplier?: number;
  ticksRemaining?: number;
}

/**
 * Tick all faction trade windows: open new ones probabilistically,
 * count down active ones, and expire them.
 */
export function tickTradeWindows(
  state: FactionSystemState,
  tick: number,
  rng: () => number,
): TradeWindowEvent[] {
  const events: TradeWindowEvent[] = [];

  for (const faction of state.factions) {
    const def = FACTION_DEFS[faction.id];

    if (faction.tradeWindow) {
      // Count down active window
      faction.tradeWindow.ticksRemaining--;

      // Warning when about to close
      if (faction.tradeWindow.ticksRemaining === TRADE_WINDOW_WARNING_TICKS) {
        events.push({
          factionId: faction.id,
          factionName: def.name,
          type: 'warning',
          resource: faction.tradeWindow.resource,
          ticksRemaining: TRADE_WINDOW_WARNING_TICKS,
        });
      }

      // Expired
      if (faction.tradeWindow.ticksRemaining <= 0) {
        events.push({
          factionId: faction.id,
          factionName: def.name,
          type: 'expired',
          resource: faction.tradeWindow.resource,
        });
        faction.tradeWindow = null;
        faction.lastTradeWindowTick = tick;
      }
    } else {
      // Try to open a new window if eligible
      if (
        faction.disposition >= TRADE_WINDOW_DISPOSITION_THRESHOLD &&
        tick - faction.lastTradeWindowTick >= TRADE_WINDOW_COOLDOWN &&
        rng() < TRADE_WINDOW_PROBABILITY
      ) {
        const offer = TRADE_WINDOW_OFFERS[Math.floor(rng() * TRADE_WINDOW_OFFERS.length)];
        faction.tradeWindow = {
          resource: offer.resource,
          rateMultiplier: offer.multiplier,
          ticksRemaining: TRADE_WINDOW_DURATION,
        };
        faction.recentEvents.push({
          text: `${def.name} opened a ${offer.label} trade window`,
          tick,
        });
        events.push({
          factionId: faction.id,
          factionName: def.name,
          type: 'opened',
          resource: offer.resource,
          resourceLabel: offer.label,
          rateMultiplier: offer.multiplier,
          ticksRemaining: TRADE_WINDOW_DURATION,
        });
      }
    }
  }

  return events;
}
