import { query } from 'bitecs';
import type { World } from '../../core/ecs';
import {
  Position,
  Velocity,
  RobotTag,
  RobotType,
  RobotState,
  Energy,
  TaskRef,
  BaseStationTag,
} from '../components';
import { ROBOT_PROFILES, ROBOT_TYPES } from '../robotProfiles';
import type { TaskQueue } from '../taskQueue';
import { ROBOT_STATES } from '../robotCreation';
import { TechState, getEfficiencyMultiplier, isTechUnlocked } from '../techTree';
import type { IntelligenceTier } from '../culture';
import { INTELLIGENCE_TIER_EFFICIENCY, EMERGENT_LEADERSHIP_BONUS, INTELLIGENCE_TIERS, CULTURE_TRAIT_MIN_TIER, getDriftSpecialization } from '../culture';
import type { DustGrid } from '../dustGrid';
import type { BaseBuildingState } from '../buildings';
import type { CultureEffects, AnomalyDiscoveredCallback } from './types';
import { SWARM_RADIUS_SQ, distanceTo } from './types';
import { handleIdleRobot } from './idleHandler';
import { handleMovingToRobot } from './movingToHandler';
import { handleMiningRobot } from './miningHandler';
import { handleHaulingRobot } from './haulingHandler';
import { handleTransferringRobot } from './transferHandler';
import { handleReturningRobot } from './returningHandler';
import { handleChargingRobot } from './chargingHandler';
import { handleBrokenRobot } from './brokenHandler';
import { handleStudyingRobot } from './studyingHandler';
import { handleConstructingRobot } from './constructionHandler';

export function robotAISystem(
  world: World,
  dt: number,
  taskQueue: TaskQueue,
  discoveredAnomalies?: Set<number>,
  onAnomalyDiscovered?: AnomalyDiscoveredCallback,
  techState?: TechState,
  cultureEffects?: CultureEffects,
  dustGrid?: DustGrid,
  energyUnlimited?: boolean,
  sensorRangeMultiplier?: number,
  chargeRateBonus?: number,
  buildingState?: BaseBuildingState,
): void {
  const robots = query(world, [RobotTag, Position, Velocity, RobotState, Energy]);
  // Cache base query for the whole system tick (shared, not per-robot)
  const allBases = query(world, [BaseStationTag, Position]);

  // Pre-compute tech multipliers once per tick
  const miningMult = techState ? getEfficiencyMultiplier(techState, 'mining') : 1;
  const miningBurstMult = techState ? getEfficiencyMultiplier(techState, 'mining_burst') : 1;
  const iceMiningMult = techState ? getEfficiencyMultiplier(techState, 'ice_mining') : 1;
  const haulerCapMult = techState ? getEfficiencyMultiplier(techState, 'hauler_capacity') : 1;
  const dustClearingMult = techState ? getEfficiencyMultiplier(techState, 'dust_clearing') : 1;
  const dustSweepersUnlocked = techState ? isTechUnlocked(techState, 'dust_sweepers') : false;

  // Pre-compute culture trait flags once per tick
  const autonomyActive = cultureEffects?.activeTraits.has('AUTONOMOUS_COLLECTIVE') ?? false;
  const autonomyScore = autonomyActive ? (cultureEffects?.autonomyScore ?? 0) : 0;
  const cohesiveActive = cultureEffects?.activeTraits.has('COHESIVE_FLEET') ?? false;
  const isolationActive = cultureEffects?.activeTraits.has('ISOLATED_CULTURE') ?? false;

  for (let i = 0; i < robots.length; i++) {
    const eid = robots[i];
    const state = RobotState.state[eid];
    const profile = ROBOT_PROFILES[RobotType.type[eid]];
    if (!profile) continue;

    // Find nearest base to this robot's current position
    let baseEid = -1;
    if (allBases.length === 1) {
      baseEid = allBases[0];
    } else if (allBases.length > 1) {
      let minD2 = Infinity;
      for (let b = 0; b < allBases.length; b++) {
        const beid = allBases[b];
        const d2 =
          (Position.x[beid] - Position.x[eid]) ** 2 +
          (Position.y[beid] - Position.y[eid]) ** 2 +
          (Position.z[beid] - Position.z[eid]) ** 2;
        if (d2 < minD2) {
          minD2 = d2;
          baseEid = beid;
        }
      }
    }

    // Energy depletion check (skipped when megastructure grants unlimited energy)
    if (energyUnlimited) {
      Energy.current[eid] = Energy.max[eid];
    } else if (
      Energy.current[eid] <= 0 &&
      state !== ROBOT_STATES.BROKEN &&
      state !== ROBOT_STATES.CHARGING
    ) {
      RobotState.state[eid] = ROBOT_STATES.BROKEN;
      Velocity.x[eid] = 0;
      Velocity.y[eid] = 0;
      Velocity.z[eid] = 0;
      if (TaskRef.taskId[eid] >= 0) {
        taskQueue.releaseTask(TaskRef.taskId[eid]);
        TaskRef.taskId[eid] = -1;
      }
      continue;
    }

    switch (state) {
      case ROBOT_STATES.IDLE: {
        const taskHintType = cultureEffects?.robotStats?.get(eid)?.taskHint ?? -1;
        // Culture trait effects (directive drift) only apply to tier 3+ robots
        const robotTierIdle = cultureEffects?.intelligenceTiers?.get(eid) ?? 0;
        const effectiveAutonomy = robotTierIdle >= CULTURE_TRAIT_MIN_TIER ? autonomyScore : 0;
        handleIdleRobot(eid, taskQueue, baseEid, profile, effectiveAutonomy, sensorRangeMultiplier ?? 1, cultureEffects?.glitchRng, taskHintType, cultureEffects?.directiveDriftEids, isolationActive);
        break;
      }
      case ROBOT_STATES.MOVING_TO:
        handleMovingToRobot(eid, taskQueue, profile, baseEid);
        break;
      case ROBOT_STATES.MINING: {
        // Intelligence tier efficiency multiplier
        const robotTier = cultureEffects?.intelligenceTiers?.get(eid) ?? 0;
        const tierEfficiency = INTELLIGENCE_TIER_EFFICIENCY[robotTier as IntelligenceTier];
        // COHESIVE_FLEET: apply per-robot efficiency multiplier from replacement inheritance
        const robotCultureMult = cultureEffects?.efficiencyMultipliers.get(eid) ?? 1;
        // COHESIVE_FLEET: swarm mining bonus — nearby robots boost efficiency
        let swarmMult = 1.0;
        if (cohesiveActive && cultureEffects) {
          let nearbyCount = 0;
          for (let j = 0; j < robots.length; j++) {
            const other = robots[j];
            if (other === eid) continue;
            const dx = Position.x[other] - Position.x[eid];
            const dy = Position.y[other] - Position.y[eid];
            const dz = Position.z[other] - Position.z[eid];
            if (dx * dx + dy * dy + dz * dz < SWARM_RADIUS_SQ) nearbyCount++;
          }
          if (nearbyCount >= 2) swarmMult = Math.min(1.2, 1 + nearbyCount * 0.05);
        }
        // Emergent leadership aura: nearby tier-4 robots boost lower-tier robots
        let leadershipMult = 1.0;
        if (cultureEffects?.intelligenceTiers && robotTier < INTELLIGENCE_TIERS.EMERGENT) {
          for (let j = 0; j < robots.length; j++) {
            const other = robots[j];
            if (other === eid) continue;
            const otherTier = cultureEffects.intelligenceTiers.get(other) ?? 0;
            if (otherTier === INTELLIGENCE_TIERS.EMERGENT) {
              const dx = Position.x[other] - Position.x[eid];
              const dy = Position.y[other] - Position.y[eid];
              const dz = Position.z[other] - Position.z[eid];
              if (dx * dx + dy * dy + dz * dz < SWARM_RADIUS_SQ) {
                leadershipMult = 1 + EMERGENT_LEADERSHIP_BONUS;
                break; // only one leader bonus stacks
              }
            }
          }
        }
        // Knowledge boost and mourning multipliers
        let knowledgeMult = 1.0;
        let mourningMult = 1.0;
        if (cohesiveActive && cultureEffects) {
          const stats = cultureEffects.robotStats.get(eid);
          if (stats) {
            if (stats.knowledgeBoostUntil > cultureEffects.currentTick) knowledgeMult = 1.1;
            if (stats.mourningUntil > cultureEffects.currentTick) mourningMult = 0.85;
          }
        }
        // ISOLATED_CULTURE: frontier discovery bonus — 1.15x yield when far from base
        let frontierMult = 1.0;
        if (isolationActive && baseEid >= 0) {
          const distFromBase = distanceTo(eid, Position.x[baseEid], Position.y[baseEid], Position.z[baseEid]);
          if (distFromBase > 2000) frontierMult = 1.15;
        }
        // DEEP_FIELD_INSTINCT: +5% mining efficiency beyond 2000u from base
        let deepFieldMult = 1.0;
        if (cultureEffects?.activeIsolationTraitIds?.has('deep_field_instinct') && baseEid >= 0) {
          const distFromBaseDF = distanceTo(eid, Position.x[baseEid], Position.y[baseEid], Position.z[baseEid]);
          if (distFromBaseDF > 2000) deepFieldMult = 1.05;
        }
        // Drift specialization: 1.1x efficiency when robot repeats same task type 20+ times
        let driftMult = 1.0;
        if (isolationActive && cultureEffects) {
          const lastTypes = cultureEffects.robotStats.get(eid)?.lastTaskTypes;
          if (lastTypes) driftMult = getDriftSpecialization(lastTypes).mult;
        }
        const efMult = cultureEffects?.efEfficiencyMult ?? 1;
        handleMiningRobot(world, eid, dt, taskQueue, profile, baseEid, discoveredAnomalies, onAnomalyDiscovered, miningMult * miningBurstMult * tierEfficiency * robotCultureMult * swarmMult * leadershipMult * knowledgeMult * mourningMult * frontierMult * deepFieldMult * driftMult * efMult, dustGrid, iceMiningMult);
        break;
      }
      case ROBOT_STATES.HAULING:
        handleHaulingRobot(eid, taskQueue, allBases, haulerCapMult);
        break;
      case ROBOT_STATES.TRANSFERRING:
        handleTransferringRobot(eid, taskQueue, allBases, haulerCapMult);
        break;
      case ROBOT_STATES.RETURNING:
        handleReturningRobot(eid, baseEid);
        break;
      case ROBOT_STATES.CHARGING:
        handleChargingRobot(eid, dt, chargeRateBonus ?? 0);
        break;
      case ROBOT_STATES.BROKEN:
        handleBrokenRobot(eid, dt, baseEid);
        break;
      case ROBOT_STATES.STUDYING:
        handleStudyingRobot(eid, dt, taskQueue, profile, baseEid);
        break;
      case ROBOT_STATES.CONSTRUCTING:
        handleConstructingRobot(eid, dt, taskQueue, profile, baseEid, buildingState ?? null);
        break;
    }

    // Memory glitch: full-transfer replacement robots have a 1% chance per 100 ticks
    // to fail their current task and go idle.
    if (
      cultureEffects &&
      cultureEffects.glitchFlags.has(eid) &&
      RobotState.state[eid] !== ROBOT_STATES.IDLE &&
      RobotState.state[eid] !== ROBOT_STATES.BROKEN &&
      RobotState.state[eid] !== ROBOT_STATES.CHARGING &&
      RobotState.state[eid] !== ROBOT_STATES.RETURNING
    ) {
      // Check every 100 ticks (stateTimer is in seconds, dt ≈ 1/60 → ~100 ticks = ~1.67s)
      const ticksInState = Math.round(RobotState.stateTimer[eid] / dt);
      if (ticksInState > 0 && ticksInState % 100 === 0 && cultureEffects.glitchRng() < 0.01) {
        // Glitch: fail the task and go idle
        if (TaskRef.taskId[eid] >= 0) {
          taskQueue.failTask(TaskRef.taskId[eid]);
          TaskRef.taskId[eid] = -1;
        }
        RobotState.state[eid] = ROBOT_STATES.IDLE;
        RobotState.stateTimer[eid] = 0;
        Velocity.x[eid] = 0;
        Velocity.y[eid] = 0;
        Velocity.z[eid] = 0;
        // Track for groupthink cascade
        cultureEffects.glitchedEids.push(eid);
      }
    }

    // Dust hazard effects
    if (dustGrid) {
      const rx = Position.x[eid];
      const rz = Position.z[eid];

      // Maintenance drag: extra energy drain when in dusty cells
      const dustMult = dustGrid.getMaintenanceMultiplier(rx, rz);
      if (dustMult > 1.0) {
        // Apply extra energy drain proportional to the dust penalty
        const extraDrain = (dustMult - 1.0) * profile.energyConsumptionRate * profile.maxThrust * dt;
        Energy.current[eid] -= extraDrain;
      }

      // Scout dust clearing: scouts on EXPLORE tasks passively clear dust
      if (
        dustSweepersUnlocked &&
        RobotType.type[eid] === ROBOT_TYPES.SCOUT &&
        (RobotState.state[eid] === ROBOT_STATES.MOVING_TO ||
         RobotState.state[eid] === ROBOT_STATES.STUDYING)
      ) {
        dustGrid.clearAt(rx, rz, 0.01 * dustClearingMult * dt);
      }
    }
  }
}
