export interface RobotProfile {
  type: number;
  name: string;
  maxSpeed: number;
  maxThrust: number;
  mass: number;
  energyCapacity: number;
  energyConsumptionRate: number; // per unit thrust per second
  miningRate: number; // resource units per second
  inventoryCapacity: number;
  toolType: number; // 0=None, 1=Scanner, 2=Drill, 3=Cargo, 4=ResearchKit
  sensorRange: number;
  /** Fuel tank capacity (delta-v budget) */
  fuelCapacity: number;
  /** Fuel consumed per unit of distance traveled */
  fuelPerUnit: number;
  /** Research points generated per second (researcher robots only) */
  researchRate?: number;
  /** Tech node ID required to unlock this robot type */
  unlockTechId?: string;
}

