/** Upgrade type IDs */
export const UPGRADE_TYPES = {
  NONE: 0,
  SPEED_PLUS: 1,
  CAPACITY_PLUS: 2,
  EFFICIENCY_PLUS: 3,
  RANGE_PLUS: 4,
  ARMOR_PLUS: 5,
} as const;

export type UpgradeType = (typeof UPGRADE_TYPES)[keyof typeof UPGRADE_TYPES];

export interface UpgradeDef {
  id: UpgradeType;
  name: string;
  /** Refined material costs */
  cost: Partial<Record<string, number>>;
  /** Multiplier applied to the relevant stat */
  statMultiplier: number;
  /** Which stat this upgrades */
  stat: 'maxSpeed' | 'inventoryCapacity' | 'miningRate' | 'sensorRange' | 'armor';
}

