/**
 * Outpost System — remote mining outposts on claimed asteroids.
 *
 * Once the Asteroid Claim Beacon tech is unlocked, players can claim
 * unclaimed asteroids to establish outposts. Outposts auto-mine the
 * host asteroid and periodically mass-drive ore to the primary base.
 *
 * Outposts have limited building slots (MAX_OUTPOST_BUILDING_SLOTS).
 */

import { query } from 'bitecs';
import type { World } from '../core/ecs';
import {
  Position,
  Storage,
  BaseStationTag,
  OutpostTag,
  OutpostAsteroidRef,
  AsteroidTag,
  AsteroidHealth,
  MineralComposition,
  AsteroidRichness,
  AsteroidHusk,
} from './components';
import { MINERAL_FIELDS, type MineralField } from './minerals';
import type { LogisticsState } from './logistics';

// ── Constants ──────────────────────────────────────────────────────────────────

/** Resource cost to deploy a claim beacon on an asteroid. */
export const CLAIM_BEACON_COST: Partial<Record<string, number>> = {
  refined_iron: 500,
};

/** Maximum building slots for an outpost (vs unlimited for primary base). */
export const MAX_OUTPOST_BUILDING_SLOTS = 5;

/** Auto-mine rate: units of asteroid health consumed per tick. */
export const OUTPOST_MINE_RATE = 0.02;

/** Mass driver interval: how often (in ticks) ore is sent to primary base. */
export const MASS_DRIVER_INTERVAL = 300; // every 5 seconds at 60 tps

/** Fraction of each mineral extracted per unit of health mined. */
const MINERAL_EXTRACT_FRACTION = 0.01;

// ── Outpost State ──────────────────────────────────────────────────────────────

export interface OutpostInfo {
  eid: number;
  asteroidEid: number;
  x: number;
  y: number;
  z: number;
  iron: number;
  nickel: number;
  cobalt: number;
  platinum: number;
  ice: number;
  carbon: number;
  silicate: number;
  capacity: number;
  buildingSlots: number;
  miningActive: boolean;
}

export interface OutpostState {
  /** Tick of last mass driver send. */
  lastMassDriverTick: number;
}

export function createOutpostState(): OutpostState {
  return {
    lastMassDriverTick: 0,
  };
}

// ── Outpost Queries ────────────────────────────────────────────────────────────

/**
 * Get info for all outposts for broadcasting to the main thread.
 */
export function getOutpostInfos(world: World): OutpostInfo[] {
  const outposts = Array.from(query(world, [BaseStationTag, OutpostTag, Position, Storage]));
  return outposts.map((eid) => {
    const asteroidEid = OutpostAsteroidRef.asteroidEid[eid];
    const hasHealth =
      asteroidEid >= 0 && AsteroidHealth.current[asteroidEid] > 0;
    return {
      eid,
      asteroidEid,
      x: Position.x[eid],
      y: Position.y[eid],
      z: Position.z[eid],
      iron: Storage.iron[eid],
      nickel: Storage.nickel[eid],
      cobalt: Storage.cobalt[eid],
      platinum: Storage.platinum[eid],
      ice: Storage.ice[eid],
      carbon: Storage.carbon[eid],
      silicate: Storage.silicate[eid],
      capacity: Storage.capacity[eid],
      buildingSlots: MAX_OUTPOST_BUILDING_SLOTS,
      miningActive: hasHealth,
    };
  });
}

/**
 * Check if a base entity is an outpost (has OutpostTag).
 */
export function isOutpost(world: World, eid: number): boolean {
  const outposts = query(world, [BaseStationTag, OutpostTag]);
  return outposts.includes(eid);
}

// ── Outpost Auto-Mine ──────────────────────────────────────────────────────────

/**
 * Auto-mine: each outpost extracts minerals from its host asteroid
 * and stores them locally. Runs every tick.
 */
export function tickOutpostAutoMine(world: World): void {
  const outposts = query(world, [BaseStationTag, OutpostTag, Storage]);
  for (const eid of outposts) {
    const astEid = OutpostAsteroidRef.asteroidEid[eid];
    if (astEid < 0) continue;

    // Skip depleted asteroids (husks)
    const health = AsteroidHealth.current[astEid];
    if (health <= 0) continue;

    // Mine
    const mineAmount = Math.min(OUTPOST_MINE_RATE, health);
    AsteroidHealth.current[astEid] -= mineAmount;

    const richness = AsteroidRichness.multiplier[astEid] || 1;
    const extractRate = mineAmount * MINERAL_EXTRACT_FRACTION * richness;

    for (const field of MINERAL_FIELDS) {
      const mineralAmount =
        (MineralComposition as Record<MineralField, Float32Array>)[field][astEid] * extractRate;
      if (mineralAmount > 0) {
        (Storage as Record<string, Float32Array>)[field][eid] += mineralAmount;
      }
    }
  }
}

// ── Mass Driver ────────────────────────────────────────────────────────────────

/**
 * Mass driver: periodically transfer all outpost storage to the primary base.
 */
export function tickMassDriver(
  world: World,
  tick: number,
  outpostState: OutpostState,
  logisticsState: LogisticsState,
): void {
  if (tick - outpostState.lastMassDriverTick < MASS_DRIVER_INTERVAL) return;
  outpostState.lastMassDriverTick = tick;

  const primaryBaseEid = logisticsState.baseEids[0];
  if (primaryBaseEid == null || primaryBaseEid < 0) return;

  const outposts = query(world, [BaseStationTag, OutpostTag, Storage]);
  for (const eid of outposts) {
    for (const field of MINERAL_FIELDS) {
      const storageArr = (Storage as Record<string, Float32Array>)[field];
      const amount = storageArr[eid];
      if (amount > 0) {
        storageArr[primaryBaseEid] += amount;
        storageArr[eid] = 0;
      }
    }
  }
}

// ── Building Slot Limits ────────────────────────────────────────────────────────

/**
 * Returns the max building slots for a given base.
 * Outposts have MAX_OUTPOST_BUILDING_SLOTS; primary base has no limit.
 */
export function getMaxBuildingSlots(world: World, baseEid: number): number | undefined {
  if (isOutpost(world, baseEid)) {
    return MAX_OUTPOST_BUILDING_SLOTS;
  }
  return undefined; // no limit for primary base
}

// ── Serialization ──────────────────────────────────────────────────────────────

export interface SerializedOutpostState {
  lastMassDriverTick: number;
}

export function serializeOutpostState(state: OutpostState): SerializedOutpostState {
  return { lastMassDriverTick: state.lastMassDriverTick };
}

export function deserializeOutpostState(data: SerializedOutpostState): OutpostState {
  return { lastMassDriverTick: data.lastMassDriverTick };
}
