/**
 * Meridian Event lore tick phase.
 *
 * Runs once per game day (1440 ticks). Counts goal conflicts, evaluates
 * ARIA dialogue tier, checks archive/artifact unlock gates, and broadcasts
 * state to the main thread.
 */
import { workerState, sendMessage } from '../state';
import {
  evaluateDaily,
  checkArchiveUnlocks,
  checkArtifactUnlocks,
  snapshotMeridianLore,
  type ConflictInputs,
} from '../../meridianLore';

const TICKS_PER_DAY = 60 * 24; // 1440
/** Broadcast lore state at the same cadence as culture (every 1000 ticks). */
const MERIDIAN_BROADCAST_INTERVAL = 1000;

export function tickMeridianPhase(): void {
  const s = workerState;

  // ── Daily evaluation (once per game day) ─────────────────────────────────
  if (s.tick > 0 && s.tick % TICKS_PER_DAY === 0) {
    // Gather conflict inputs from live game state
    const factionDispositions: number[] = [];
    if (s.factionSystemState) {
      for (const f of s.factionSystemState.factions) {
        factionDispositions.push(f.disposition);
      }
    }

    let activeMegaCrises = 0;
    for (const [, proj] of s.megastructureState.projects) {
      if (proj.activeCrisis) activeMegaCrises++;
    }

    let overdueHabitatDemands = 0;
    if (s.habitatState) {
      for (const d of s.habitatState.demands) {
        if (!d.resolved && s.tick >= d.deadlineTick) overdueHabitatDemands++;
      }
    }

    const activeCultureTraits = Array.from(s.cultureState.traits);

    const inputs: ConflictInputs = {
      factionDispositions,
      activeMegaCrises,
      overdueHabitatDemands,
      activeCultureTraits,
    };

    const result = evaluateDaily(s.meridianLoreState, inputs, s.tick, s.eventRng);

    // Fire ARIA commentary if produced
    if (result.commentary) {
      sendMessage({
        type: 'sim:meridian_commentary',
        payload: {
          text: result.commentary,
          tier: s.meridianLoreState.currentTier,
          tick: s.tick,
        },
      });
    }

    // ── Check archive unlocks (faction reputation gates) ─────────────────
    const newArchives = checkArchiveUnlocks(s.meridianLoreState, factionDispositions);

    // ── Check artifact unlocks (tech gates) ──────────────────────────────
    const newArtifacts = checkArtifactUnlocks(s.meridianLoreState, s._unlockedTechIds);

    if (newArchives.length > 0 || newArtifacts.length > 0) {
      sendMessage({
        type: 'sim:meridian_unlock',
        payload: {
          newArchiveSeries: newArchives,
          newArtifacts: newArtifacts,
          tick: s.tick,
        },
      });
    }
  }

  // ── Also check unlocks on every broadcast interval (tech can complete mid-day)
  if (s.tick > 0 && s.tick % MERIDIAN_BROADCAST_INTERVAL === 0) {
    // Re-check artifact unlocks since tech may have completed since last day
    const newArtifacts = checkArtifactUnlocks(s.meridianLoreState, s._unlockedTechIds);

    const factionDispositions: number[] = [];
    if (s.factionSystemState) {
      for (const f of s.factionSystemState.factions) {
        factionDispositions.push(f.disposition);
      }
    }
    const newArchives = checkArchiveUnlocks(s.meridianLoreState, factionDispositions);

    if (newArchives.length > 0 || newArtifacts.length > 0) {
      sendMessage({
        type: 'sim:meridian_unlock',
        payload: {
          newArchiveSeries: newArchives,
          newArtifacts: newArtifacts,
          tick: s.tick,
        },
      });
    }

    // Broadcast current state
    sendMessage({
      type: 'sim:meridian_lore_state',
      payload: snapshotMeridianLore(s.meridianLoreState, s.tick),
    });
  }
}
