/**
 * Transit tick phase: checks for arrived shipments and credits payments.
 * Fires ARIA inbox notifications on arrival and phase transitions.
 * Updates demand curves and progression state.
 */
import { workerState, sendMessage } from '../state';
import { tickTransit, getDestination, TICKS_PER_GAME_DAY } from '../../transit';
import { addMessage, getInboxSnapshot } from '../../inbox/inboxStore';
import { Storage } from '../../components';

let nextInboxId = 93000; // high range to avoid collision with other phase IDs

export function tickTransitPhase(): void {
  const s = workerState;
  if (s.baseEidGlobal < 0) return;

  // Update lifetime iron mined tracking for progression.
  // We approximate by tracking base iron: iron only increases from mining,
  // so total iron in base + credits spent is a proxy. We use base storage
  // as a running tally — a proper totalIronMined counter would require
  // hooking into the mining phase. For now, use a simple accumulator:
  // the base storage iron + all iron ever dispatched + credits proxy.
  // Simpler: just track the high-water mark of base iron.
  const baseIron = Storage.iron[s.baseEidGlobal] ?? 0;
  if (baseIron > s.transitState.progression.totalIronMined) {
    s.transitState.progression.totalIronMined = baseIron;
  }

  const result = tickTransit(s.transitState, s.tick, s.eventRng);

  for (const shipment of result.arrived) {
    const dest = getDestination(shipment.destinationId);
    const destName = dest?.name ?? shipment.destinationId;
    const transitDays = Math.round(
      (shipment.arrivalTick - shipment.departureTick) / TICKS_PER_GAME_DAY,
    );

    // Build cargo summary
    const cargoLines: string[] = [];
    for (const [resource, amount] of Object.entries(shipment.cargo)) {
      if (amount > 0) cargoLines.push(`${amount} ${resource}`);
    }
    const cargoSummary = cargoLines.join(', ');

    // Space elevator flavor for Earth arrivals
    const flavorSuffix = dest?.id === 'earth'
      ? ' The L1 orbital station confirms receipt — cargo descending via space elevator.'
      : '';

    // ARIA notification for arrival
    addMessage({
      id: nextInboxId++,
      factionId: null,
      senderName: 'ARIA',
      type: 'aria_auto',
      subject: `Shipment arrived at ${destName}`,
      body: `The ${destName} shipment has arrived after ${transitDays} days in transit. Cargo delivered: ${cargoSummary}. Payment received: ${shipment.payment.toFixed(1)} credits. Current balance: ${s.transitState.credits.toFixed(1)} credits.${flavorSuffix}`,
      priority: 'normal',
      tick: s.tick,
      triaged: true,
      triageResult: 'relevant',
      read: false,
    });
    sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });
  }

  // Luna unlock notification (Phase 1→2 transition)
  if (result.lunaJustUnlocked) {
    addMessage({
      id: nextInboxId++,
      factionId: null,
      senderName: 'ARIA',
      type: 'aria_auto',
      subject: 'Shackleton Base announces Phase II expansion',
      body: 'ARIA: Incoming transmission from Luna — Shackleton Base has announced Phase II of their south pole expansion. They are requesting bulk ice and silicate deliveries for habitat construction. Luna is now available as a trade destination. Ice commands a 1.5× premium at Shackleton; they cannot extract it cheaply from the permanently shadowed craters at the volumes they need.',
      priority: 'urgent',
      tick: s.tick,
      triaged: true,
      triageResult: 'relevant',
      read: false,
    });
    sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });

    // Set event flag so narrative engine knows about the phase transition
    s.eventEngine.setFlag('luna_unlocked', true);
    s.eventEngine.setFlag('phase_2', true);
  }
}
