/**
 * Market message handlers: create and cancel listings.
 */
import { workerState, sendMessage } from '../state';
import { createListing, cancelListing, snapshotMarket } from '../../market';
import { isSignalJamActive } from '../../threatSystem';
import type { SimMarketCreateListingMessage, SimMarketCancelListingMessage } from '../../messages';

function broadcastMarketState(): void {
  const s = workerState;
  sendMessage({
    type: 'sim:market_state',
    payload: {
      listings: snapshotMarket(s.marketState).listings,
      tick: s.tick,
    },
  });
}

export function handleMarketCreateListing(
  payload: SimMarketCreateListingMessage['payload'],
): void {
  const s = workerState;
  if (s.baseEidGlobal < 0) return;

  // Signal jamming blocks market listing creation (Earth comms cut)
  if (s.threatState && isSignalJamActive(s.threatState)) {
    sendMessage({
      type: 'sim:market_error',
      payload: { error: 'Communications jammed — cannot create market orders while signal jamming is active.' },
    });
    return;
  }

  // Look up buyer faction's active trade window for rate multiplier
  const buyerFaction = s.factionSystemState?.factions[payload.buyerFactionId];
  const tradeWindow = buyerFaction?.tradeWindow ?? null;

  const listing = createListing(
    s.marketState,
    payload.resource,
    payload.quantity,
    payload.buyerFactionId,
    s.baseEidGlobal,
    s.tick,
    tradeWindow,
  );

  if (listing) {
    broadcastMarketState();
  }
}

export function handleMarketCancelListing(
  payload: SimMarketCancelListingMessage['payload'],
): void {
  const s = workerState;
  if (s.baseEidGlobal < 0) return;

  const cancelled = cancelListing(s.marketState, payload.listingId, s.baseEidGlobal);
  if (cancelled) {
    broadcastMarketState();
  }
}
