/**
 * Robot Factory System
 *
 * Manufacture new robots at a base station using refined materials.
 * Unlocked by the 'robot_factory' tech node.
 *
 * Build orders consume refined materials and produce a robot entity
 * after the production time elapses.
 */

import { ROBOT_TYPES, UPGRADE_TYPES, UPGRADE_DEFS, type UpgradeType } from './robotProfiles';

// ── Build recipes ─────────────────────────────────────────────────────────────

export interface RobotRecipe {
  robotType: number;
  name: string;
  /** Refined material costs */
  refinedCost: Partial<Record<string, number>>;
  /** Raw material costs (fallback if refinery not built) */
  rawCost: Partial<Record<string, number>>;
  /** Production time in seconds */
  duration: number;
  /** Tech node required to build this robot type */
  unlockTechId?: string;
}

