/**
 * Faction system tick phase + faction broadcast.
 */
import { Position, AsteroidHealth } from '../../components';
import { workerState, runSystem, sendMessage, FACTION_BROADCAST_INTERVAL } from '../state';
import { tickFactions, snapshotFactions, checkDispositionThresholds, tickTradeWindows } from '../../factions/factionSystem';
import { getActiveIsolationTraits } from '../../colonyDialect';
import type { BorderDispute, TradeWindowEvent } from '../../factions/factionSystem';
import { addMessage } from '../../inbox/inboxStore';
import { generateBorderDisputeMessage, generateDispositionEventMessage } from '../../inbox/messageGenerator';

export function tickFactionPhase(
  sharedRobotPositions: Array<{ x: number; y: number; z: number }>,
): void {
  const s = workerState;
  if (!s.factionSystemState || !s.world) return;

  const playerBasePos =
    s.baseEidGlobal >= 0
      ? {
          x: Position.x[s.baseEidGlobal],
          y: Position.y[s.baseEidGlobal],
          z: Position.z[s.baseEidGlobal],
        }
      : { x: 0, y: 0, z: 0 };

  let disputes: BorderDispute[] = [];

  runSystem('factions', () => {
    disputes = tickFactions(s.factionSystemState!, {
      tick: s.tick,
      asteroidEntities: s.asteroidEntities,
      getAsteroidPos: (eid) => ({ x: Position.x[eid], y: Position.y[eid], z: Position.z[eid] }),
      getAsteroidHealth: (eid) => AsteroidHealth.current[eid] ?? 0,
      damageAsteroid: (eid, amount) => {
        if (AsteroidHealth.current[eid] !== undefined) {
          AsteroidHealth.current[eid] = Math.max(0, AsteroidHealth.current[eid] - amount);
        }
      },
      playerBasePos,
      playerRobotPositions: sharedRobotPositions,
      rng: s.eventRng,
      aggressionMultiplier: s.factionAggressionMultiplier,
      silenceProtocolActive: getActiveIsolationTraits(s.cultureState.isolationScore).some(
        (t) => t.id === 'silence_protocol',
      ),
    });
  });

  // Inject border dispute messages into the inbox
  for (const dispute of disputes) {
    addMessage(generateBorderDisputeMessage(
      dispute.factionA,
      dispute.factionB,
      dispute.atWar,
      s.tick,
    ));
  }

  // Tick trade windows (open, countdown, expire)
  const tradeWindowEvents = tickTradeWindows(s.factionSystemState!, s.tick, s.eventRng);
  for (const twEvent of tradeWindowEvents) {
    sendMessage({
      type: 'sim:trade_window_event',
      payload: { ...twEvent, tick: s.tick },
    });
  }

  // Check for disposition threshold events
  const dispEvents = checkDispositionThresholds(s.factionSystemState!, s.tick);
  for (const ev of dispEvents) {
    addMessage(generateDispositionEventMessage(ev.factionId, ev.eventType, ev.disposition, s.tick));
  }

  if (s.tick % FACTION_BROADCAST_INTERVAL === 0) {
    sendMessage({
      type: 'sim:faction_state',
      payload: {
        factions: snapshotFactions(s.factionSystemState),
        tick: s.tick,
      },
    });
  }
}
