/**
 * Orbital motion tick phase — advances asteroid orbits.
 * Runs before robot AI so that asteroid positions are current
 * when robots compute paths and score tasks.
 */
import { workerState, FIXED_DT } from '../state';
import { orbitalSystem } from '../../orbitalSystem';

export function tickOrbitalPhase(): void {
  const s = workerState;
  if (!s.world || !s.grid) return;
  orbitalSystem(s.world, FIXED_DT, s.grid);
}
