/**
 * Automation message handlers: auto-queues, supply rules, sectors.
 */
import { workerState } from '../state';
import {
  upsertAutoQueue,
  deleteAutoQueue,
  upsertSupplyRule,
  deleteSupplyRule,
  upsertSector,
  deleteSector,
} from '../../automation';

export function handleUpsertAutoQueue(payload: Parameters<typeof upsertAutoQueue>[1]): void {
  upsertAutoQueue(workerState.autoQueueState, payload);
}

export function handleDeleteAutoQueue(payload: { id: string }): void {
  deleteAutoQueue(workerState.autoQueueState, payload.id);
}

export function handleUpsertSupplyRule(payload: Parameters<typeof upsertSupplyRule>[1]): void {
  upsertSupplyRule(workerState.supplyChainState, payload);
}

export function handleDeleteSupplyRule(payload: { resource: string }): void {
  deleteSupplyRule(workerState.supplyChainState, payload.resource);
}

export function handleUpsertSector(payload: Parameters<typeof upsertSector>[1]): void {
  upsertSector(workerState.sectorState, payload);
}

export function handleDeleteSector(payload: { id: string }): void {
  deleteSector(workerState.sectorState, payload.id);
}
