/**
 * Save/load serialization: serializeWorld() and restoreWorld().
 */
import { addComponent, addEntity, createWorld, hasComponent, query } from 'bitecs';
import {
  Position,
  Velocity,
  AsteroidTag,
  AsteroidType,
  AsteroidSize,
  AnomalyFlag,
  AsteroidHusk,
  AsteroidRichness,
  AsteroidHealth,
  MineralComposition,
  ChunkRef,
  RobotTag,
  RobotType,
  RobotState,
  Rotation,
  Energy,
  Fuel,
  Inventory,
  ToolType,
  ToolTier,
  ResearchOutput,
  TaskRef,
  PathTarget,
  Thrust,
  UpgradeSlots,
  BaseStationTag,
  Storage,
  Orbit,
  OutpostTag,
  OutpostAsteroidRef,
} from '../components';
import { SpatialGrid } from '../spatialGrid';
import { TaskQueue } from '../taskQueue';
import { DEFAULT_FIELD_CONFIG } from '../asteroidGen';
import type { SaveData } from '../saveLoad';
import { SAVE_VERSION } from '../saveLoad';
import { deserializeTechState, serializeTechState } from '../techTree';
import { createRefineryState } from '../refining';
import { createFactoryState } from '../robotFactory';
import { createBaseBuildingState, CONSTRUCTION_STATE } from '../buildings';
import type { BuildingType, ConstructionState } from '../buildings';
import {
  createAutoQueueState,
  createSupplyChainState,
  createSectorState,
  serializeAutomationState,
} from '../automation';
import type { AutoQueue, SupplyRule, Sector } from '../automation';
import { serializeBlueprintState, deserializeBlueprintState, createBlueprintState } from '../blueprints';
import { deserializeLogisticsState } from '../logistics';
import {
  createMegastructureState,
  deserializeMegastructureState,
  serializeMegastructureState,
} from '../megastructures';
import type { StudyStage } from '../anomalyStudy';
import { workerState, refreshUnlockedIds } from './state';
import { serializeInboxState, restoreInboxState } from '../inbox/inboxStore';
import { serializeCultureState, deserializeCultureState, initCultureState } from '../culture';
import { serializeMeridianLore, deserializeMeridianLore, initMeridianLoreState } from '../meridianLore';
import { resetChorusTimer } from '../chorusClient';
import { serializeHabitatState, deserializeHabitatState } from '../habitat';
import {
  createFactionSystem,
  serializeFactionSystem,
  deserializeFactionSystem,
} from '../factions/factionSystem';
import { createCombatState, serializeCombatState, deserializeCombatState } from '../combatSystem';
import { createThreatState, serializeThreatState, deserializeThreatState } from '../threatSystem';
import { getDifficultySettings } from '../difficulty';
import { createMarketState, serializeMarketState, deserializeMarketState } from '../market';
import { resetTransientClusterSpawnState } from './phases/tickTransientClusterPhase';
import { serializeOutpostState, deserializeOutpostState, createOutpostState } from '../outpost';
import { serializeTransitState, deserializeTransitState, createTransitState } from '../transit';

// ── serializeWorld ────────────────────────────────────────────────────────────

export function serializeWorld(seed: number): SaveData {
  const s = workerState;
  const now = Date.now();
  if (!s.world) throw new Error('No world to serialize');

  const asteroidEids = query(s.world, [AsteroidTag, Position]);
  const asteroids = Array.from(asteroidEids).map((eid) => ({
    x: Position.x[eid],
    y: Position.y[eid],
    z: Position.z[eid],
    type: AsteroidType.type[eid],
    radius: AsteroidSize.radius[eid],
    iron: MineralComposition.iron[eid],
    nickel: MineralComposition.nickel[eid],
    cobalt: MineralComposition.cobalt[eid],
    platinum: MineralComposition.platinum[eid],
    ice: MineralComposition.ice[eid],
    carbon: MineralComposition.carbon[eid],
    silicate: MineralComposition.silicate[eid],
    health: AsteroidHealth.current[eid],
    healthMax: AsteroidHealth.max[eid],
    anomalyType: AnomalyFlag.type[eid],
    cx: ChunkRef.cx[eid],
    cy: ChunkRef.cy[eid],
    cz: ChunkRef.cz[eid],
    richness: AsteroidRichness.multiplier[eid],
    isHusk: hasComponent(s.world!, eid, AsteroidHusk),
    orbitRadius: Orbit.radius[eid] || undefined,
    orbitAngle: Orbit.angle[eid] || undefined,
    orbitPeriod: Orbit.period[eid] || undefined,
  }));

  const eidToAsteroidIndex = new Map<number, number>();
  Array.from(asteroidEids).forEach((eid, i) => eidToAsteroidIndex.set(eid, i));

  const robotEids = query(s.world, [RobotTag, Position]);
  const robots = Array.from(robotEids).map((eid) => ({
    x: Position.x[eid],
    y: Position.y[eid],
    z: Position.z[eid],
    rotation: Rotation.angle[eid],
    robotType: RobotType.type[eid],
    energy: Energy.current[eid],
    energyMax: Energy.max[eid],
    fuel: Fuel.current[eid],
    fuelMax: Fuel.max[eid],
    invIron: Inventory.iron[eid],
    invNickel: Inventory.nickel[eid],
    invCobalt: Inventory.cobalt[eid],
    invPlatinum: Inventory.platinum[eid],
    invIce: Inventory.ice[eid],
    invCarbon: Inventory.carbon[eid],
    invSilicate: Inventory.silicate[eid],
    invCapacity: Inventory.capacity[eid],
    invUsed: Inventory.used[eid],
    toolType: ToolType.type[eid],
    toolTier: ToolTier.tier[eid],
    researchRate: ResearchOutput.pointsPerSecond[eid],
    thrustMax: Thrust.maxThrust[eid],
    speedMax: Thrust.maxSpeed[eid],
    mass: Thrust.mass[eid],
    upgradeA: UpgradeSlots.slotA[eid],
    upgradeB: UpgradeSlots.slotB[eid],
  }));

  const baseEid = s.baseEidGlobal;
  const base = {
    x: baseEid >= 0 ? Position.x[baseEid] : 0,
    y: baseEid >= 0 ? Position.y[baseEid] : 0,
    z: baseEid >= 0 ? Position.z[baseEid] : 0,
    iron: baseEid >= 0 ? Storage.iron[baseEid] : 0,
    nickel: baseEid >= 0 ? Storage.nickel[baseEid] : 0,
    cobalt: baseEid >= 0 ? Storage.cobalt[baseEid] : 0,
    platinum: baseEid >= 0 ? Storage.platinum[baseEid] : 0,
    ice: baseEid >= 0 ? Storage.ice[baseEid] : 0,
    carbon: baseEid >= 0 ? Storage.carbon[baseEid] : 0,
    silicate: baseEid >= 0 ? Storage.silicate[baseEid] : 0,
  };

  const discoveredAnomalyIndices = Array.from(s.discoveredAnomalies)
    .map((eid) => eidToAsteroidIndex.get(eid))
    .filter((idx): idx is number => idx !== undefined);

  const studySnapshot = s.studySystem.getProgressSnapshot();
  const studyEntries = studySnapshot.map((e) => {
    const astIdx = eidToAsteroidIndex.get(e.asteroidEid) ?? -1;
    return {
      asteroidIndex: astIdx,
      anomalyType: e.anomalyType,
      stage: e.stage,
      progress: e.progress,
      x: asteroids[astIdx]?.x ?? 0,
      y: asteroids[astIdx]?.y ?? 0,
      z: asteroids[astIdx]?.z ?? 0,
      revealedFragments: e.revealedFragments,
      chainRevealed: e.stage === 4,
      civilizationAttributed: e.stage === 4,
    };
  });

  const extraBases = s.logisticsState.baseEids.slice(1).map((beid) => {
    const isOutpostBase = hasComponent(s.world!, beid, OutpostTag);
    const asteroidEid = isOutpostBase ? OutpostAsteroidRef.asteroidEid[beid] : -1;
    return {
      x: Position.x[beid],
      y: Position.y[beid],
      z: Position.z[beid],
      iron: Storage.iron[beid],
      nickel: Storage.nickel[beid],
      cobalt: Storage.cobalt[beid],
      platinum: Storage.platinum[beid],
      ice: Storage.ice[beid],
      carbon: Storage.carbon[beid],
      silicate: Storage.silicate[beid],
      capacity: Storage.capacity[beid],
      isOutpost: isOutpostBase || undefined,
      asteroidIndex: isOutpostBase ? (eidToAsteroidIndex.get(asteroidEid) ?? -1) : undefined,
    };
  });

  return {
    version: SAVE_VERSION,
    tick: s.tick,
    seed,
    timestamp: now,
    asteroids,
    robots,
    base,
    techState: serializeTechState(s.techState),
    refineryBuilt: s.refineryState.built,
    refineryAdvancedBuilt: s.refineryState.advancedBuilt,
    refineryHasRadiator: s.refineryState.hasRadiator,
    refineryHasSolarFurnace: s.refineryState.hasSolarFurnace,
    refineryHeatBatches: s.refineryState.heatBatches,
    refineryOverheatCooldown: s.refineryState.overheatCooldown,
    refineryQueue: [...s.refineryState.queue],
    refinedMaterials: { ...s.refineryState.refined },
    factoryBuilt: s.factoryState.built,
    factoryQueue: [...s.factoryState.queue],
    buildings: s.buildingState.buildings.map((b) => ({
      id: b.id,
      type: b.type,
      health: b.health,
      active: b.active,
      worldX: b.worldX,
      worldY: b.worldY,
      worldZ: b.worldZ,
      constructionState: b.constructionState,
      constructionProgress: b.constructionProgress,
    })),
    buildingsNextId: s.buildingState.nextId,
    automationState: serializeAutomationState(s.autoQueueState, s.supplyChainState, s.sectorState),
    extraBases,
    logisticsRoutes: Array.from(s.logisticsState.routes.values()),
    discoveredAnomalyIndices,
    studyEntries,
    eventState: s.eventEngine.serialize(),
    entityState: s.entitySystem.serialize(),
    respawnTimer: s.respawnTimer,
    megastructures: serializeMegastructureState(s.megastructureState),
    megaRobotCapBonus: s.megaRobotCapBonus,
    megaSensorRangeMultiplier: s.megaSensorRangeMultiplier,
    megaEnergyUnlimited: s.megaEnergyUnlimited,
    inboxState: serializeInboxState(),
    cultureState: serializeCultureState(s.cultureState),
    habitatState: s.habitatState ? serializeHabitatState(s.habitatState) : undefined,
    factionState: s.factionSystemState ? serializeFactionSystem(s.factionSystemState) : undefined,
    combatState: serializeCombatState(s.combatState),
    threatState: serializeThreatState(s.threatState),
    difficultyMode: s.difficultyMode,
    materialWeights: s.materialWeights,
    marketState: serializeMarketState(s.marketState),
    meridianLoreState: serializeMeridianLore(s.meridianLoreState),
    efState: s.efState,
    efValue: s.efValue,
    blueprintState: serializeBlueprintState(s.blueprintState),
    outpostState: serializeOutpostState(s.outpostState),
    transitState: serializeTransitState(s.transitState),
    speedMultiplier: s.speedMultiplier,
  };
}

// ── restoreWorld ──────────────────────────────────────────────────────────────

export function restoreWorld(data: SaveData): void {
  const s = workerState;

  s.world = createWorld();
  s.grid = new SpatialGrid(500);
  s.taskQueue = new TaskQueue();
  s.tick = data.tick;
  s.respawnTimer = data.respawnTimer;
  s.speedMultiplier = data.speedMultiplier ?? 1;
  s.discoveredAnomalies.clear();
  s.studySystem.clear();
  s.eventEngine.reset();
  s.transientClusters.clear();
  s.nextClusterId = 1;
  resetTransientClusterSpawnState();
  // Restore inbox state if present (otherwise inbox starts fresh)
  if (data.inboxState) {
    restoreInboxState(data.inboxState);
  }
  if (data.eventState) {
    s.eventEngine.deserialize(data.eventState);
  }
  s.entitySystem.reset();
  if (data.entityState) {
    s.entitySystem.deserialize(data.entityState);
  }
  // Restore culture state if present (otherwise starts fresh)
  s.cultureState = data.cultureState
    ? deserializeCultureState(data.cultureState)
    : initCultureState();

  // Restore difficulty settings
  const diff = getDifficultySettings(data.difficultyMode ?? 'normal');
  s.difficultyMode = diff.mode;
  s.factionAggressionMultiplier = diff.factionAggression;

  // Restore field config from seed with difficulty multipliers
  s.fieldConfig = {
    ...DEFAULT_FIELD_CONFIG,
    worldSeed: data.seed,
    baseAsteroidDensity: DEFAULT_FIELD_CONFIG.baseAsteroidDensity * diff.mineralDensity,
    anomalyChance: diff.anomalyChance,
  };

  // Restore non-ECS state
  s.techState = deserializeTechState(data.techState);
  refreshUnlockedIds();

  s.refineryState = createRefineryState();
  s.refineryState.built = data.refineryBuilt;
  s.refineryState.advancedBuilt = data.refineryAdvancedBuilt;
  s.refineryState.hasRadiator = data.refineryHasRadiator ?? false;
  s.refineryState.hasSolarFurnace = data.refineryHasSolarFurnace ?? false;
  s.refineryState.heatBatches = data.refineryHeatBatches ?? 0;
  s.refineryState.overheatCooldown = data.refineryOverheatCooldown ?? 0;
  s.refineryState.queue = [...data.refineryQueue];
  s.refineryState.refined = { ...data.refinedMaterials };

  s.factoryState = createFactoryState();
  s.factoryState.built = data.factoryBuilt;
  s.factoryState.queue = [...data.factoryQueue];

  s.buildingState = createBaseBuildingState();
  s.buildingState.nextId = data.buildingsNextId;
  const savedBuildings = data.buildings;

  // Restore automation
  s.autoQueueState = createAutoQueueState();
  s.supplyChainState = createSupplyChainState();
  s.sectorState = createSectorState();
  for (const q of data.automationState.queues) {
    s.autoQueueState.queues.set(q.id, q as AutoQueue);
  }
  for (const r of data.automationState.supplyRules) {
    s.supplyChainState.rules.set(r.resource, r as SupplyRule);
  }
  for (const sector of data.automationState.sectors) {
    s.sectorState.sectors.set(sector.id, sector as Sector);
  }

  // Recreate ECS entities — asteroids
  s.asteroidEntities = [];
  const newAsteroidEids: number[] = [];

  for (const a of data.asteroids) {
    const eid = addEntity(s.world);
    addComponent(s.world, eid, Position);
    addComponent(s.world, eid, AsteroidTag);
    addComponent(s.world, eid, AsteroidType);
    addComponent(s.world, eid, AsteroidSize);
    addComponent(s.world, eid, MineralComposition);
    addComponent(s.world, eid, AsteroidHealth);
    addComponent(s.world, eid, AnomalyFlag);
    addComponent(s.world, eid, ChunkRef);
    addComponent(s.world, eid, AsteroidRichness);
    addComponent(s.world, eid, Orbit);
    if (a.isHusk) addComponent(s.world, eid, AsteroidHusk);

    Position.x[eid] = a.x;
    Position.y[eid] = a.y;
    Position.z[eid] = a.z;
    AsteroidType.type[eid] = a.type;
    AsteroidSize.radius[eid] = a.radius;
    MineralComposition.iron[eid] = a.iron;
    MineralComposition.nickel[eid] = a.nickel;
    MineralComposition.cobalt[eid] = a.cobalt;
    MineralComposition.platinum[eid] = a.platinum;
    MineralComposition.ice[eid] = a.ice;
    MineralComposition.carbon[eid] = a.carbon;
    MineralComposition.silicate[eid] = a.silicate;
    AsteroidHealth.current[eid] = a.health;
    AsteroidHealth.max[eid] = a.healthMax;
    AnomalyFlag.type[eid] = a.anomalyType;
    ChunkRef.cx[eid] = a.cx;
    ChunkRef.cy[eid] = a.cy;
    ChunkRef.cz[eid] = a.cz;
    AsteroidRichness.multiplier[eid] = a.richness;
    Orbit.radius[eid] = a.orbitRadius ?? 0;
    Orbit.angle[eid] = a.orbitAngle ?? 0;
    Orbit.period[eid] = a.orbitPeriod ?? 0;

    s.grid.insert(eid, a.x, a.y, a.z);
    s.asteroidEntities.push(eid);
    newAsteroidEids.push(eid);
  }

  // Restore discovered anomalies
  for (const idx of data.discoveredAnomalyIndices) {
    if (idx >= 0 && idx < newAsteroidEids.length) {
      s.discoveredAnomalies.add(newAsteroidEids[idx]);
    }
  }

  // Restore study entries
  for (const se of data.studyEntries) {
    if (se.asteroidIndex < 0 || se.asteroidIndex >= newAsteroidEids.length) continue;
    const eid = newAsteroidEids[se.asteroidIndex];
    s.studySystem.restoreEntry(eid, {
      asteroidEid: eid,
      anomalyType: se.anomalyType,
      stage: se.stage as StudyStage,
      progress: se.progress,
      x: se.x,
      y: se.y,
      z: se.z,
      revealedFragments: [...se.revealedFragments],
      chainRevealed: se.chainRevealed,
      civilizationAttributed: se.civilizationAttributed ?? false,
    });
  }

  // Restore robots
  for (const r of data.robots) {
    const eid = addEntity(s.world);
    addComponent(s.world, eid, RobotTag);
    addComponent(s.world, eid, Position);
    addComponent(s.world, eid, Velocity);
    addComponent(s.world, eid, Rotation);
    addComponent(s.world, eid, RobotType);
    addComponent(s.world, eid, RobotState);
    addComponent(s.world, eid, Energy);
    addComponent(s.world, eid, Fuel);
    addComponent(s.world, eid, Inventory);
    addComponent(s.world, eid, ToolType);
    addComponent(s.world, eid, ToolTier);
    addComponent(s.world, eid, ResearchOutput);
    addComponent(s.world, eid, TaskRef);
    addComponent(s.world, eid, PathTarget);
    addComponent(s.world, eid, Thrust);
    addComponent(s.world, eid, UpgradeSlots);

    Position.x[eid] = r.x;
    Position.y[eid] = r.y;
    Position.z[eid] = r.z;
    Velocity.x[eid] = 0;
    Velocity.y[eid] = 0;
    Velocity.z[eid] = 0;
    Rotation.angle[eid] = r.rotation;
    RobotType.type[eid] = r.robotType;
    RobotState.state[eid] = 0;
    Energy.current[eid] = r.energy;
    Energy.max[eid] = r.energyMax;
    // Fuel: fall back to energyMax for saves from before fuel was added
    Fuel.current[eid] = r.fuel ?? r.energyMax;
    Fuel.max[eid] = r.fuelMax ?? r.energyMax;
    Inventory.iron[eid] = r.invIron;
    Inventory.nickel[eid] = r.invNickel;
    Inventory.cobalt[eid] = r.invCobalt;
    Inventory.platinum[eid] = r.invPlatinum;
    Inventory.ice[eid] = r.invIce;
    Inventory.carbon[eid] = r.invCarbon;
    Inventory.silicate[eid] = r.invSilicate;
    Inventory.capacity[eid] = r.invCapacity;
    Inventory.used[eid] = r.invUsed;
    ToolType.type[eid] = r.toolType;
    ToolTier.tier[eid] = r.toolTier;
    ResearchOutput.pointsPerSecond[eid] = r.researchRate;
    ResearchOutput.isStudying[eid] = 0;
    TaskRef.taskId[eid] = -1;
    PathTarget.x[eid] = 0;
    PathTarget.y[eid] = 0;
    PathTarget.z[eid] = 0;
    PathTarget.arrivalRadius[eid] = 20;
    Thrust.maxThrust[eid] = r.thrustMax;
    Thrust.maxSpeed[eid] = r.speedMax;
    Thrust.mass[eid] = r.mass;
    UpgradeSlots.slotA[eid] = r.upgradeA;
    UpgradeSlots.slotB[eid] = r.upgradeB;

    s.grid.insert(eid, r.x, r.y, r.z);
  }

  // Restore base station
  const beid = addEntity(s.world);
  addComponent(s.world, beid, BaseStationTag);
  addComponent(s.world, beid, Position);
  addComponent(s.world, beid, Storage);

  Position.x[beid] = data.base.x;
  Position.y[beid] = data.base.y;
  Position.z[beid] = data.base.z;
  Storage.iron[beid] = data.base.iron;
  Storage.nickel[beid] = data.base.nickel;
  Storage.cobalt[beid] = data.base.cobalt;
  Storage.platinum[beid] = data.base.platinum;
  Storage.ice[beid] = data.base.ice;
  Storage.carbon[beid] = data.base.carbon;
  Storage.silicate[beid] = data.base.silicate;

  s.grid.insert(beid, data.base.x, data.base.y, data.base.z);
  s.baseEidGlobal = beid;

  // Restore extra bases
  const allBaseEids: number[] = [beid];
  for (const eb of data.extraBases ?? []) {
    const ebeid = addEntity(s.world);
    addComponent(s.world, ebeid, BaseStationTag);
    addComponent(s.world, ebeid, Position);
    addComponent(s.world, ebeid, Storage);
    Position.x[ebeid] = eb.x;
    Position.y[ebeid] = eb.y;
    Position.z[ebeid] = eb.z;
    Storage.iron[ebeid] = eb.iron;
    Storage.nickel[ebeid] = eb.nickel;
    Storage.cobalt[ebeid] = eb.cobalt;
    Storage.platinum[ebeid] = eb.platinum;
    Storage.ice[ebeid] = eb.ice;
    Storage.carbon[ebeid] = eb.carbon;
    Storage.silicate[ebeid] = eb.silicate;
    Storage.capacity[ebeid] = eb.capacity;
    s.grid.insert(ebeid, eb.x, eb.y, eb.z);
    allBaseEids.push(ebeid);

    // Restore outpost tag and asteroid reference
    if (eb.isOutpost) {
      addComponent(s.world, ebeid, OutpostTag);
      addComponent(s.world, ebeid, OutpostAsteroidRef);
      const astIdx = eb.asteroidIndex ?? -1;
      OutpostAsteroidRef.asteroidEid[ebeid] =
        astIdx >= 0 && astIdx < newAsteroidEids.length ? newAsteroidEids[astIdx] : -1;
    }
  }

  // Restore logistics state
  const savedRoutes = data.logisticsRoutes ?? [];
  s.logisticsState = deserializeLogisticsState(
    { routes: savedRoutes, nextBaseIndex: allBaseEids.length },
    allBaseEids,
  );

  // Restore outpost state
  s.outpostState = data.outpostState
    ? deserializeOutpostState(data.outpostState)
    : createOutpostState();

  // Restore megastructures
  s.megastructureState = data.megastructures
    ? deserializeMegastructureState(data.megastructures)
    : createMegastructureState();
  s.megaRobotCapBonus = data.megaRobotCapBonus ?? 0;
  s.megaSensorRangeMultiplier = data.megaSensorRangeMultiplier ?? 1;
  s.megaEnergyUnlimited = data.megaEnergyUnlimited ?? false;

  // Restore habitat state
  s.habitatState = data.habitatState
    ? deserializeHabitatState(data.habitatState)
    : null;

  // Restore faction system (dispositions, resources, goal) — falls back to fresh state
  s.factionSystemState = data.factionState
    ? deserializeFactionSystem(
        data.factionState,
        s.fieldConfig.beltInnerRadius,
        s.fieldConfig.beltOuterRadius,
      )
    : createFactionSystem(s.fieldConfig.beltInnerRadius, s.fieldConfig.beltOuterRadius);

  // Restore combat spawn timers (attack cooldowns are ephemeral, reset harmlessly)
  s.combatState = data.combatState
    ? deserializeCombatState(data.combatState)
    : createCombatState();

  // Restore threat state (kinetic threat model)
  s.threatState = data.threatState
    ? deserializeThreatState(data.threatState)
    : createThreatState();

  // Restore material priority weights
  if (data.materialWeights) {
    s.materialWeights = data.materialWeights;
  }

  // Restore market state (pending/hauling listings survive save/load)
  s.marketState = data.marketState
    ? deserializeMarketState(data.marketState)
    : createMarketState();

  // Restore Meridian lore state (ARIA tier, archive unlocks, conflict count)
  s.meridianLoreState = data.meridianLoreState
    ? deserializeMeridianLore(data.meridianLoreState)
    : initMeridianLoreState();

  // Restore automation blueprints
  s.blueprintState = data.blueprintState
    ? deserializeBlueprintState(data.blueprintState)
    : createBlueprintState();

  // Restore planetary transit queue
  s.transitState = data.transitState
    ? deserializeTransitState(data.transitState)
    : createTransitState();

  // Restore E_f (Environmental Flux) chorus state
  s.efState = data.efState ?? null;
  s.efStatePrev = null;
  s.efValue = data.efValue ?? 0;
  s.efChorusLoreShown = false;
  resetChorusTimer();

  // Restore buildings with correct baseEntityId
  s.buildingState.buildings = savedBuildings.map((b) => ({
    id: b.id,
    type: b.type as BuildingType,
    baseEntityId: beid,
    health: b.health,
    active: b.active,
    worldX: b.worldX ?? Position.x[beid],
    worldY: b.worldY ?? Position.y[beid],
    worldZ: b.worldZ ?? Position.z[beid],
    constructionState: (b.constructionState ?? (b.active ? CONSTRUCTION_STATE.COMPLETE : CONSTRUCTION_STATE.PLANNED)) as ConstructionState,
    constructionProgress: b.constructionProgress ?? (b.active ? 1 : 0),
  }));
}

export { applyUnlockEffects } from './unlocks';
