/**
 * Outpost message handlers: claim asteroid, recall outpost.
 */
import { addComponent, query } from 'bitecs';
import { workerState, sendMessage } from '../state';
import {
  Position,
  Storage,
  AsteroidTag,
  AsteroidHealth,
  OutpostTag,
  OutpostAsteroidRef,
  BaseStationTag,
} from '../../components';
import { createBaseStation } from '../../robotSystems';
import { CLAIM_BEACON_COST, getOutpostInfos } from '../../outpost';
import { DEFAULT_BASE_CAPACITY } from '../../logistics';

export function handleClaimAsteroid(payload: { asteroidEid: number }): void {
  const s = workerState;
  if (!s.world || !s.grid) return;

  const { asteroidEid } = payload;

  // Validate multi_base tech is unlocked
  if (!s._unlockedTechIds.has('multi_base')) {
    sendMessage({
      type: 'sim:outpost_claimed',
      payload: { ok: false, error: 'Asteroid Claim Beacon tech not yet researched' },
    });
    return;
  }

  // Validate asteroid exists and has health
  const asteroids = query(s.world, [AsteroidTag]);
  if (!asteroids.includes(asteroidEid)) {
    sendMessage({
      type: 'sim:outpost_claimed',
      payload: { ok: false, error: 'Invalid asteroid' },
    });
    return;
  }

  if (AsteroidHealth.current[asteroidEid] <= 0) {
    sendMessage({
      type: 'sim:outpost_claimed',
      payload: { ok: false, error: 'Asteroid is depleted' },
    });
    return;
  }

  // Check not already claimed
  const existingOutposts = query(s.world, [BaseStationTag, OutpostTag]);
  for (const eid of existingOutposts) {
    if (OutpostAsteroidRef.asteroidEid[eid] === asteroidEid) {
      sendMessage({
        type: 'sim:outpost_claimed',
        payload: { ok: false, error: 'Asteroid already has an outpost' },
      });
      return;
    }
  }

  // Check refined material cost
  for (const [resource, amount] of Object.entries(CLAIM_BEACON_COST)) {
    const available = s.refineryState.refined[resource] ?? 0;
    if (available < (amount ?? 0)) {
      sendMessage({
        type: 'sim:outpost_claimed',
        payload: {
          ok: false,
          error: `Need ${amount} ${resource} (have ${Math.floor(available)})`,
        },
      });
      return;
    }
  }

  // Deduct costs
  for (const [resource, amount] of Object.entries(CLAIM_BEACON_COST)) {
    s.refineryState.refined[resource] = (s.refineryState.refined[resource] ?? 0) - (amount ?? 0);
  }

  // Create outpost base station at asteroid position
  const x = Position.x[asteroidEid];
  const y = Position.y[asteroidEid];
  const z = Position.z[asteroidEid];

  const outpostEid = createBaseStation(s.world, x, y, z, s.grid);
  Storage.capacity[outpostEid] = DEFAULT_BASE_CAPACITY;

  // Tag as outpost and link to asteroid
  addComponent(s.world, outpostEid, OutpostTag);
  addComponent(s.world, outpostEid, OutpostAsteroidRef);
  OutpostAsteroidRef.asteroidEid[outpostEid] = asteroidEid;

  // Add to logistics base list
  s.logisticsState.baseEids.push(outpostEid);

  const outposts = getOutpostInfos(s.world);
  const newOutpost = outposts.find((o) => o.eid === outpostEid);

  sendMessage({
    type: 'sim:outpost_claimed',
    payload: { ok: true, outpost: newOutpost },
  });
}

export function handleRecallOutpost(payload: { outpostEid: number }): void {
  const s = workerState;
  if (!s.world) return;

  const { outpostEid } = payload;

  // Validate it's an outpost
  const outposts = query(s.world, [BaseStationTag, OutpostTag]);
  if (!outposts.includes(outpostEid)) {
    sendMessage({
      type: 'sim:outpost_recalled',
      payload: { ok: false, error: 'Not a valid outpost', outpostEid },
    });
    return;
  }

  // Transfer remaining resources to primary base before removing
  const primaryBaseEid = s.logisticsState.baseEids[0];
  if (primaryBaseEid != null && primaryBaseEid >= 0) {
    const fields = ['iron', 'nickel', 'cobalt', 'platinum', 'ice', 'carbon', 'silicate'] as const;
    for (const field of fields) {
      const amount = (Storage as Record<string, Float32Array>)[field][outpostEid];
      if (amount > 0) {
        (Storage as Record<string, Float32Array>)[field][primaryBaseEid] += amount;
        (Storage as Record<string, Float32Array>)[field][outpostEid] = 0;
      }
    }
  }

  // Remove from logistics base list
  const idx = s.logisticsState.baseEids.indexOf(outpostEid);
  if (idx > 0) {
    s.logisticsState.baseEids.splice(idx, 1);
  }

  // Remove haul routes referencing this outpost
  for (const [id, route] of s.logisticsState.routes) {
    if (route.fromBaseEid === outpostEid || route.toBaseEid === outpostEid) {
      s.logisticsState.routes.delete(id);
    }
  }

  // Note: we don't removeEntity because bitECS doesn't support entity removal cleanly.
  // The outpost entity remains but without being in the base list, it's inert.
  // Clear the outpost tag data so queries won't pick it up.
  OutpostAsteroidRef.asteroidEid[outpostEid] = -1;

  sendMessage({
    type: 'sim:outpost_recalled',
    payload: { ok: true, outpostEid },
  });
}
