/**
 * DustGrid: coarse spatial grid tracking dust density across the asteroid belt.
 *
 * Mining asteroids deposits dust into nearby cells. Dust causes maintenance
 * drag on robots passing through. Scouts with DUST_SWEEPERS tech clear dust
 * passively, creating visible "lanes" of clean space.
 *
 * Cell size is 4000 units — coarse enough to keep the map sparse while giving
 * meaningful regional density.
 */

export const DUST_CELL_SIZE = 4000;

/** Minimum density to include in serialised broadcasts. */
export const DUST_BROADCAST_THRESHOLD = 0.05;

/** Density below which maintenance drag is zero (cell considered "cleared"). */
export const DUST_CLEARED_THRESHOLD = 0.1;

/** Density above which maintenance multiplier starts applying. */
export const DUST_HAZARD_THRESHOLD = 0.3;

/** Very slow natural decay rate per second (density units / s). */
const NATURAL_DECAY_RATE = 0.001;

export interface DustCell {
  gx: number;
  gz: number;
  density: number;
}

function cellKey(gx: number, gz: number): string {
  return `${gx},${gz}`;
}

function worldToGrid(v: number): number {
  return Math.floor(v / DUST_CELL_SIZE);
}

export class DustGrid {
  private cells: Map<string, number> = new Map(); // key → density 0.0–1.0

  /** Deposit dust at a world position, spreading to the target cell. */
  deposit(x: number, z: number, amount: number): void {
    const gx = worldToGrid(x);
    const gz = worldToGrid(z);
    const key = cellKey(gx, gz);
    const current = this.cells.get(key) ?? 0;
    this.cells.set(key, Math.min(1.0, current + amount));
  }

  /** Natural decay: very slow settling over time. */
  decay(dt: number): void {
    const decayAmount = NATURAL_DECAY_RATE * dt;
    for (const [key, density] of this.cells) {
      const newDensity = density - decayAmount;
      if (newDensity <= 0) {
        this.cells.delete(key);
      } else {
        this.cells.set(key, newDensity);
      }
    }
  }

  /** Get dust density at a world position. */
  getDensityAt(x: number, z: number): number {
    const key = cellKey(worldToGrid(x), worldToGrid(z));
    return this.cells.get(key) ?? 0;
  }

  /** Clear dust at a world position (e.g. by scout sweepers). */
  clearAt(x: number, z: number, amount: number): void {
    const gx = worldToGrid(x);
    const gz = worldToGrid(z);
    const key = cellKey(gx, gz);
    const current = this.cells.get(key);
    if (current === undefined) return;
    const newDensity = current - amount;
    if (newDensity <= 0) {
      this.cells.delete(key);
    } else {
      this.cells.set(key, newDensity);
    }
  }

  /**
   * Returns the maintenance multiplier for a robot at (x, z).
   * 1.0 = no drag. Up to 1.2 at full density. 0 drag below cleared threshold.
   */
  getMaintenanceMultiplier(x: number, z: number): number {
    const density = this.getDensityAt(x, z);
    if (density < DUST_HAZARD_THRESHOLD) return 1.0;
    // Linear ramp from 1.0 at threshold to 1.2 at density=1.0
    const t = (density - DUST_HAZARD_THRESHOLD) / (1.0 - DUST_HAZARD_THRESHOLD);
    return 1.0 + t * 0.2;
  }

  /** Number of active cells (for stats). */
  get size(): number {
    return this.cells.size;
  }

  /** Serialize to sparse array of cells above broadcast threshold. */
  serialize(): DustCell[] {
    const result: DustCell[] = [];
    for (const [key, density] of this.cells) {
      if (density < DUST_BROADCAST_THRESHOLD) continue;
      const [gxStr, gzStr] = key.split(',');
      result.push({ gx: Number(gxStr), gz: Number(gzStr), density });
    }
    return result;
  }

  /** Reset all dust. */
  clear(): void {
    this.cells.clear();
  }
}
