/**
 * Shared helpers used by tick phases and the message handler.
 */
import { Position, AsteroidHealth, AnomalyFlag, MineralComposition, Storage } from '../../components';
import { workerState, sendMessage } from '../state';
import type { SimEventMessage, SimLoreFragmentMessage } from '../../messages';
import { canSendComms, markCommsSent, generateAnomalyComms } from '../../commsGenerator';

// ── Raw storage read/write ────────────────────────────────────────────────────

export function getRawStorage(): Record<string, number> {
  const { world, baseEidGlobal } = workerState;
  if (!world || baseEidGlobal < 0) return {};
  return {
    iron: Storage.iron[baseEidGlobal],
    nickel: Storage.nickel[baseEidGlobal],
    cobalt: Storage.cobalt[baseEidGlobal],
    platinum: Storage.platinum[baseEidGlobal],
    ice: Storage.ice[baseEidGlobal],
    carbon: Storage.carbon[baseEidGlobal],
    silicate: Storage.silicate[baseEidGlobal],
  };
}

export function writeRawStorage(raw: Record<string, number>): void {
  const { baseEidGlobal } = workerState;
  if (baseEidGlobal < 0) return;
  Storage.iron[baseEidGlobal] = raw.iron ?? 0;
  Storage.nickel[baseEidGlobal] = raw.nickel ?? 0;
  Storage.cobalt[baseEidGlobal] = raw.cobalt ?? 0;
  Storage.platinum[baseEidGlobal] = raw.platinum ?? 0;
  Storage.ice[baseEidGlobal] = raw.ice ?? 0;
  Storage.carbon[baseEidGlobal] = raw.carbon ?? 0;
  Storage.silicate[baseEidGlobal] = raw.silicate ?? 0;
}

// ── Asteroid query helpers ────────────────────────────────────────────────────

export function getAsteroidPos(eid: number): { x: number; y: number; z: number } {
  return { x: Position.x[eid], y: Position.y[eid], z: Position.z[eid] };
}

export function getAsteroidHealth(eid: number): number {
  return AsteroidHealth.current[eid] ?? 0;
}

export function getAnomalyFlag(eid: number): number {
  return AnomalyFlag.type[eid] ?? 0;
}

export function getAsteroidMinerals(eid: number): Record<string, number> {
  return {
    iron: MineralComposition.iron[eid] ?? 0,
    nickel: MineralComposition.nickel[eid] ?? 0,
    cobalt: MineralComposition.cobalt[eid] ?? 0,
    platinum: MineralComposition.platinum[eid] ?? 0,
    ice: MineralComposition.ice[eid] ?? 0,
    carbon: MineralComposition.carbon[eid] ?? 0,
    silicate: MineralComposition.silicate[eid] ?? 0,
  };
}

// ── Anomaly discovery callback ────────────────────────────────────────────────

export function onAnomalyDiscovered(
  robotEid: number,
  asteroidEid: number,
  anomalyType: number,
  x: number,
  y: number,
  z: number,
): void {
  const { eventEngine, studySystem, tick } = workerState;

  const event: SimEventMessage = {
    type: 'sim:event',
    payload: {
      kind: 'anomaly_discovered',
      robotEid,
      asteroidEid,
      anomalyType,
      x,
      y,
      z,
      tick,
    },
  };
  sendMessage(event);

  // Anomaly discovery comms
  if (canSendComms(tick)) {
    const name = workerState.cultureState.robotNames.get(robotEid) ?? `Robot-${robotEid}`;
    const stats = workerState.cultureState.robotStats.get(robotEid);
    const msg = generateAnomalyComms(name, stats?.tasksCompleted ?? 0, robotEid ^ tick);
    markCommsSent(tick);
    sendMessage({
      type: 'sim:comms_message',
      payload: { robotEid, robotName: name, message: msg, category: 'anomaly', tick },
    });
  }

  eventEngine.setFlag('anomaly_found', true);

  const initial = studySystem.discover(asteroidEid, anomalyType, x, y, z);
  if (initial && initial.newFragments.length > 0) {
    const loreMsg: SimLoreFragmentMessage = {
      type: 'sim:lore_fragment',
      payload: {
        asteroidEid,
        anomalyType,
        stage: initial.stage,
        newFragmentIndices: initial.newFragments,
        chainNextType: 0,
        revelation: null,
        civilizationAttribution: null,
        tick,
      },
    };
    sendMessage(loreMsg);
  }
}

// ── Dark Forest consequence application ───────────────────────────────────────

export function applyDarkForestChoice(choice: 'visible' | 'hidden'): void {
  const s = workerState;

  if (choice === 'visible') {
    if (s.factionSystemState) {
      // Original 3 factions react strongly; new factions react moderately
      const darkForestDeltas = [-15, 20, -10, -5, -8, 12];
      for (let i = 0; i < s.factionSystemState.factions.length; i++) {
        const delta = darkForestDeltas[i] ?? 0;
        const f = s.factionSystemState.factions[i];
        f.disposition = Math.max(-100, Math.min(100, f.disposition + delta));
      }
    }
    s.eventEngine.setFlag('CULTURE_VISIBLE', true);
  } else {
    s.eventEngine.setFlag('QUIET_ASCENSION', true);
  }
}
