/**
 * Combat System
 *
 * Handles Defender robot attacks on hostile faction ships and faction ship lifecycle.
 * Faction ships are spawned as ECS entities near faction bases when disposition is hostile.
 * Defender robots engage hostile ships within sensor range.
 */

import { addComponent, addEntity, query, removeEntity } from 'bitecs';
import type { World } from '../core/ecs';
import {
  Position,
  Velocity,
  RobotTag,
  RobotType,
  RobotState,
  FactionShipTag,
  FactionShipData,
} from './components';
import { ROBOT_TYPES, ROBOT_PROFILES } from './robotProfiles';
import { ROBOT_STATES } from './robotCreation';
import type { FactionSystemState, FactionId } from './factions/factionSystem';
import { FACTION_DEFS } from './factions/factionSystem';
import type { SpatialGrid } from './spatialGrid';
import { MINERAL_FIELDS } from './minerals';

// ── Constants ──────────────────────────────────────────────────────────────────

/** Minimum disposition to be considered hostile (below this → ships may spawn) */
const HOSTILE_DISPOSITION_THRESHOLD = -40;

/** Base HP for faction ships */
const FACTION_SHIP_BASE_HP = 100;

/** Defender attack interval in seconds */
const ATTACK_INTERVAL_SEC = 3;

/** Damage multiplier applied to defender's base armor value */
const DAMAGE_MULTIPLIER = 0.3;

/** Base "armor" value for defenders (used in damage calc) */
const DEFENDER_BASE_ARMOR = 30;

/** Minimum loot dropped on kill */
const MIN_LOOT = 5;

/** Maximum loot dropped on kill */
const MAX_LOOT = 15;

/** Max faction ships per faction at any time */
const MAX_SHIPS_PER_FACTION = 3;

/** Ticks between ship spawn attempts per faction */
const SPAWN_INTERVAL_TICKS = 60 * 60; // 60 seconds

// ── State ──────────────────────────────────────────────────────────────────────

export interface CombatState {
  /** Per-faction spawn cooldown timers */
  spawnTimers: number[];
  /** Per-defender attack cooldown in seconds (keyed by eid) */
  attackCooldowns: Map<number, number>;
}

export function createCombatState(): CombatState {
  return {
    spawnTimers: FACTION_DEFS.map(() => 0),
    attackCooldowns: new Map(),
  };
}

// ── Kill callback ──────────────────────────────────────────────────────────────

export type FactionShipKillCallback = (
  defenderEid: number,
  shipEid: number,
  factionId: FactionId,
  x: number,
  y: number,
  z: number,
  lootMineral: string,
  lootAmount: number,
) => void;

// ── Ship spawning ──────────────────────────────────────────────────────────────

/**
 * Spawn a faction raider ship as an ECS entity near the faction's base.
 */
export function spawnFactionShip(
  world: World,
  grid: SpatialGrid,
  factionId: FactionId,
  baseX: number,
  baseY: number,
  baseZ: number,
  rng: () => number,
): number {
  const eid = addEntity(world);
  addComponent(world, eid, FactionShipTag);
  addComponent(world, eid, FactionShipData);
  addComponent(world, eid, Position);
  addComponent(world, eid, Velocity);

  // Spawn near faction base with some random offset
  const offsetRange = 2000;
  Position.x[eid] = baseX + (rng() - 0.5) * offsetRange;
  Position.y[eid] = baseY;
  Position.z[eid] = baseZ + (rng() - 0.5) * offsetRange;

  Velocity.x[eid] = 0;
  Velocity.y[eid] = 0;
  Velocity.z[eid] = 0;

  FactionShipData.health[eid] = FACTION_SHIP_BASE_HP;
  FactionShipData.maxHealth[eid] = FACTION_SHIP_BASE_HP;
  FactionShipData.factionId[eid] = factionId;
  FactionShipData.damageCooldown[eid] = 0;

  grid.insert(eid, Position.x[eid], Position.y[eid], Position.z[eid]);
  return eid;
}

// ── Ship spawning logic ────────────────────────────────────────────────────────

export function tickShipSpawning(
  world: World,
  grid: SpatialGrid,
  factionState: FactionSystemState,
  combatState: CombatState,
  rng: () => number,
): void {
  // Count existing ships per faction
  const allShips = query(world, [FactionShipTag, FactionShipData]);
  const shipCounts: number[] = FACTION_DEFS.map(() => 0);
  for (let i = 0; i < allShips.length; i++) {
    const fid = FactionShipData.factionId[allShips[i]];
    if (fid < shipCounts.length) shipCounts[fid]++;
  }

  for (const faction of factionState.factions) {
    // Only spawn ships for hostile factions
    if (faction.disposition >= HOSTILE_DISPOSITION_THRESHOLD) continue;
    if (shipCounts[faction.id] >= MAX_SHIPS_PER_FACTION) continue;

    combatState.spawnTimers[faction.id]++;
    if (combatState.spawnTimers[faction.id] >= SPAWN_INTERVAL_TICKS) {
      combatState.spawnTimers[faction.id] = 0;
      spawnFactionShip(
        world,
        grid,
        faction.id,
        faction.base.x,
        faction.base.y,
        faction.base.z,
        rng,
      );
    }
  }
}

// ── Combat logic ───────────────────────────────────────────────────────────────

/**
 * Calculate damage a Defender deals per attack.
 * Formula: DEFENDER_BASE_ARMOR × DAMAGE_MULTIPLIER = 30 × 0.3 = 9 damage per hit
 */
export function calculateDefenderDamage(): number {
  return DEFENDER_BASE_ARMOR * DAMAGE_MULTIPLIER;
}

/**
 * Run the combat tick: Defenders find and attack nearby hostile faction ships.
 */
export function tickCombat(
  world: World,
  dt: number,
  grid: SpatialGrid,
  factionState: FactionSystemState,
  combatState: CombatState,
  rng: () => number,
  onKill?: FactionShipKillCallback,
): void {
  const allDefenders = query(world, [RobotTag, RobotType, RobotState, Position]);
  const allShips = query(world, [FactionShipTag, FactionShipData, Position]);

  if (allShips.length === 0) return;

  // Tick down ship damage cooldowns
  for (let i = 0; i < allShips.length; i++) {
    const sid = allShips[i];
    if (FactionShipData.damageCooldown[sid] > 0) {
      FactionShipData.damageCooldown[sid] -= dt;
    }
  }

  // Build a set of hostile faction IDs for quick lookup
  const hostileFactions = new Set<number>();
  for (const faction of factionState.factions) {
    if (faction.disposition < HOSTILE_DISPOSITION_THRESHOLD) {
      hostileFactions.add(faction.id);
    }
  }
  if (hostileFactions.size === 0) return;

  const damage = calculateDefenderDamage();
  const defenderProfile = ROBOT_PROFILES[ROBOT_TYPES.DEFENDER];
  const sensorRangeSq = defenderProfile.sensorRange * defenderProfile.sensorRange;

  // Track ships to remove after iteration (avoid modifying during iteration)
  const shipsToRemove: number[] = [];

  for (let di = 0; di < allDefenders.length; di++) {
    const deid = allDefenders[di];
    if (RobotType.type[deid] !== ROBOT_TYPES.DEFENDER) continue;
    // Only attack if not broken/charging
    const state = RobotState.state[deid];
    if (state === ROBOT_STATES.BROKEN || state === ROBOT_STATES.CHARGING) continue;

    // Check attack cooldown
    const cooldown = combatState.attackCooldowns.get(deid) ?? 0;
    if (cooldown > 0) {
      combatState.attackCooldowns.set(deid, cooldown - dt);
      continue;
    }

    // Find nearest hostile ship within sensor range
    let nearestShip = -1;
    let nearestDist2 = sensorRangeSq;

    for (let si = 0; si < allShips.length; si++) {
      const sid = allShips[si];
      const fid = FactionShipData.factionId[sid];
      if (!hostileFactions.has(fid)) continue;
      if (FactionShipData.health[sid] <= 0) continue;

      const dx = Position.x[sid] - Position.x[deid];
      const dy = Position.y[sid] - Position.y[deid];
      const dz = Position.z[sid] - Position.z[deid];
      const dist2 = dx * dx + dy * dy + dz * dz;

      if (dist2 < nearestDist2) {
        nearestDist2 = dist2;
        nearestShip = sid;
      }
    }

    if (nearestShip < 0) continue;

    // Attack!
    FactionShipData.health[nearestShip] -= damage;
    combatState.attackCooldowns.set(deid, ATTACK_INTERVAL_SEC);

    // Check for kill
    if (FactionShipData.health[nearestShip] <= 0) {
      const fid = FactionShipData.factionId[nearestShip] as FactionId;
      const shipX = Position.x[nearestShip];
      const shipY = Position.y[nearestShip];
      const shipZ = Position.z[nearestShip];

      // Drop loot: random mineral, random amount 5-15
      const lootAmount = MIN_LOOT + Math.floor(rng() * (MAX_LOOT - MIN_LOOT + 1));
      const lootMineral = MINERAL_FIELDS[Math.floor(rng() * MINERAL_FIELDS.length)];

      onKill?.(deid, nearestShip, fid, shipX, shipY, shipZ, lootMineral, lootAmount);

      shipsToRemove.push(nearestShip);
    }
  }

  // Remove destroyed ships
  for (const sid of shipsToRemove) {
    grid.remove(sid);
    removeEntity(world, sid);
  }
}

// ── Serialization ─────────────────────────────────────────────────────────────

export interface SerializedCombatState {
  spawnTimers: number[];
}

export function serializeCombatState(state: CombatState): SerializedCombatState {
  return {
    spawnTimers: [...state.spawnTimers],
    // attackCooldowns are keyed by defender eid; since robot eids are restored
    // deterministically, we omit them — they reset to 0 harmlessly on load.
  };
}

export function deserializeCombatState(data: SerializedCombatState): CombatState {
  // Pad with zeros for new factions added after save was created
  const timers = [...data.spawnTimers];
  while (timers.length < FACTION_DEFS.length) timers.push(0);
  return {
    spawnTimers: timers,
    attackCooldowns: new Map(),
  };
}
