/**
 * Habitat demand response message handler.
 */
import { workerState } from '../state';
import { resolveDemand } from '../../habitat';
import type { SimHabitatDemandResponseMessage } from '../../messages';

export function handleHabitatDemandResponse(payload: SimHabitatDemandResponseMessage['payload']): void {
  const s = workerState;
  if (!s.habitatState) return;
  const { demandId, action } = payload;
  if (action === 'accept') {
    resolveDemand(s.habitatState, demandId);
  }
  if (action === 'reject' || action === 'negotiate') {
    const demand = s.habitatState.demands.find((d) => d.id === demandId && !d.resolved);
    if (demand) {
      demand.resolved = true;
      if (action === 'reject') {
        s.habitatState.morale = Math.max(0, s.habitatState.morale - Math.floor(demand.moralePenalty / 2));
      }
    }
  }
}
