/**
 * Transient Rich Asteroid Cluster tick phase.
 *
 * Handles spawning, countdown, and faction capture of time-limited
 * high-yield asteroid clusters.
 */
import { removeEntity, hasComponent } from 'bitecs';
import { workerState, runSystem, sendMessage, TRANSIENT_CLUSTER_LIFETIME, TICKS_PER_SECOND } from '../state';
import { spawnTransientCluster } from '../../asteroidGen';
import { TransientClusterTag } from '../../components';
import { FACTION_DEFS } from '../../factions/factionSystem';
import type { FactionState } from '../../factions/factionSystem';

/** Probability per tick of spawning a cluster (~1 every 5 minutes at 60 fps). */
const SPAWN_CHANCE_PER_TICK = 1 / (5 * 60 * TICKS_PER_SECOND); // ≈0.000056

/** Maximum concurrent clusters. */
const MAX_ACTIVE_CLUSTERS = 2;

/** Minimum ticks between spawns (30 seconds real-time). */
const MIN_SPAWN_INTERVAL_TICKS = 30 * TICKS_PER_SECOND; // 1800 ticks

/** Warning fires at 30% lifetime remaining (~3 minutes). */
const EXPIRY_WARNING_TICKS = Math.round(TRANSIENT_CLUSTER_LIFETIME * 0.3);

/** Iron bonus credited to the capturing faction. */
const FACTION_CAPTURE_IRON_BONUS = 500;

/** Broadcast cluster updates once per second, not every 3 ticks. */
const CLUSTER_BROADCAST_INTERVAL = TICKS_PER_SECOND;

/** Track the last tick a cluster was spawned to enforce throttling. */
let lastSpawnTick = 0;

/** Real-time timestamp of the last tick, used to detect catch-up bursts. */
let lastTickRealTime = 0;

/** When true, skip the real-time catch-up burst check (for tests). */
let catchUpCheckDisabled = false;

/** Reset spawn throttle state (for tests and save/load). */
export function resetTransientClusterSpawnState(opts?: { disableCatchUpCheck?: boolean }): void {
  lastSpawnTick = 0;
  lastTickRealTime = 0;
  catchUpCheckDisabled = opts?.disableCatchUpCheck ?? false;
}

export function tickTransientClusterPhase(): void {
  const s = workerState;
  if (!s.world || !s.grid || !s.fieldConfig) return;

  runSystem('transientClusters', () => {
    // ── Catch-up burst detection ────────────────────────────────────────────
    // If multiple ticks run within the same millisecond, we're in a catch-up
    // burst (e.g. after tab-away). Suppress spawning to avoid floods.
    const now = performance.now();
    const isCatchUpBurst = !catchUpCheckDisabled && lastTickRealTime > 0 && (now - lastTickRealTime) < 2;
    lastTickRealTime = now;

    // ── Spawn check ──────────────────────────────────────────────────────────
    const ticksSinceLastSpawn = s.tick - lastSpawnTick;
    // Always consume RNG to keep sequence deterministic regardless of throttle
    const spawnRoll = s.eventRng();
    if (
      !isCatchUpBurst &&
      s.transientClusters.size < MAX_ACTIVE_CLUSTERS &&
      s.tick > 30 &&
      ticksSinceLastSpawn >= MIN_SPAWN_INTERVAL_TICKS
    ) {
      if (spawnRoll < SPAWN_CHANCE_PER_TICK) {
        const clusterId = s.nextClusterId++;
        const { eids, centroidX, centroidZ } = spawnTransientCluster(
          s.world!,
          s.fieldConfig!,
          s.grid!,
          clusterId,
          s.eventRng,
        );

        // Track the cluster asteroids in the global asteroid list
        for (const eid of eids) {
          s.asteroidEntities.push(eid);
        }

        lastSpawnTick = s.tick;

        s.transientClusters.set(clusterId, {
          spawnTick: s.tick,
          ticksRemaining: TRANSIENT_CLUSTER_LIFETIME,
          asteroidEids: eids,
          centroidX,
          centroidZ,
          captured: false,
        });

        sendMessage({
          type: 'sim:transient_cluster_spawned',
          payload: {
            clusterId,
            centroidX,
            centroidZ,
            ticksRemaining: TRANSIENT_CLUSTER_LIFETIME,
            asteroidCount: eids.length,
            tick: s.tick,
          },
        });
      }
    }

    // ── Countdown + expiry ───────────────────────────────────────────────────
    const expiredIds: number[] = [];

    for (const [clusterId, cluster] of s.transientClusters) {
      if (cluster.captured) continue;

      cluster.ticksRemaining--;

      // Send warning when close to expiry
      if (cluster.ticksRemaining === EXPIRY_WARNING_TICKS) {
        sendMessage({
          type: 'sim:transient_cluster_update',
          payload: {
            clusters: [{ clusterId, centroidX: cluster.centroidX, centroidZ: cluster.centroidZ, ticksRemaining: cluster.ticksRemaining }],
            tick: s.tick,
          },
        });
      }

      if (cluster.ticksRemaining <= 0) {
        // Faction captures the cluster — find nearest faction
        const capturingFaction = findNearestFaction(cluster.centroidX, cluster.centroidZ);

        if (capturingFaction) {
          capturingFaction.recentEvents.push({
            text: `${FACTION_DEFS[capturingFaction.id].name} captured a transient asteroid cluster`,
            tick: s.tick,
          });
          capturingFaction.resources.iron += FACTION_CAPTURE_IRON_BONUS;
        }

        sendMessage({
          type: 'sim:transient_cluster_expired',
          payload: {
            clusterId,
            capturingFactionName: capturingFaction ? FACTION_DEFS[capturingFaction.id].name : null,
            capturingFactionId: capturingFaction ? capturingFaction.id : null,
            tick: s.tick,
          },
        });

        // Remove cluster asteroids from the world
        for (const eid of cluster.asteroidEids) {
          if (hasComponent(s.world!, eid, TransientClusterTag)) {
            s.grid!.remove(eid);
            removeEntity(s.world!, eid);
            const idx = s.asteroidEntities.indexOf(eid);
            if (idx >= 0) {
              s.asteroidEntities[idx] = s.asteroidEntities[s.asteroidEntities.length - 1];
              s.asteroidEntities.pop();
            }
          }
        }

        cluster.captured = true;
        expiredIds.push(clusterId);
      }
    }

    // Clean up expired clusters
    for (const id of expiredIds) {
      s.transientClusters.delete(id);
    }

    // After expiry, send an immediate update so the main thread knows current state
    if (expiredIds.length > 0) {
      const remaining: Array<{
        clusterId: number;
        centroidX: number;
        centroidZ: number;
        ticksRemaining: number;
      }> = [];

      for (const [cid, c] of s.transientClusters) {
        if (!c.captured) {
          remaining.push({
            clusterId: cid,
            centroidX: c.centroidX,
            centroidZ: c.centroidZ,
            ticksRemaining: c.ticksRemaining,
          });
        }
      }

      sendMessage({
        type: 'sim:transient_cluster_update',
        payload: { clusters: remaining, tick: s.tick },
      });
    }

    // ── Periodic countdown broadcast ─────────────────────────────────────────
    if (s.transientClusters.size > 0 && s.tick % CLUSTER_BROADCAST_INTERVAL === 0) {
      const clusterUpdates: Array<{
        clusterId: number;
        centroidX: number;
        centroidZ: number;
        ticksRemaining: number;
      }> = [];

      for (const [clusterId, cluster] of s.transientClusters) {
        if (!cluster.captured) {
          clusterUpdates.push({
            clusterId,
            centroidX: cluster.centroidX,
            centroidZ: cluster.centroidZ,
            ticksRemaining: cluster.ticksRemaining,
          });
        }
      }

      if (clusterUpdates.length > 0) {
        sendMessage({
          type: 'sim:transient_cluster_update',
          payload: { clusters: clusterUpdates, tick: s.tick },
        });
      }
    }
  });
}

/** Find the faction whose base is closest to the given position. */
function findNearestFaction(x: number, z: number): FactionState | null {
  const s = workerState;
  if (!s.factionSystemState) return null;

  let best: FactionState | null = null;
  let bestDistSq = Infinity;

  for (const faction of s.factionSystemState.factions) {
    const dx = x - faction.base.x;
    const dz = z - faction.base.z;
    const distSq = dx * dx + dz * dz;
    if (distSq < bestDistSq) {
      bestDistSq = distSq;
      best = faction;
    }
  }

  return best;
}
