import { query } from 'bitecs';
import type { World } from '../core/ecs';
import {
  Position,
  Velocity,
  Rotation,
  RobotTag,
  RobotType,
  RobotState,
  Energy,
  Fuel,
  PathTarget,
  Thrust,
} from './components';
import { ROBOT_PROFILES, ROBOT_TYPES } from './robotProfiles';
import { ROBOT_STATES } from './robotCreation';
import { TechState, getEfficiencyMultiplier } from './techTree';
import { transitCostMultiplierFromPosition } from './orbitalSystem';

export function movementSystem(world: World, dt: number, techState?: TechState, baseX = 0, baseZ = 0): void {
  // Pre-compute propulsion tech multipliers once per tick
  const haulerSpeedMult = techState ? getEfficiencyMultiplier(techState, 'hauler_speed') : 1;
  const haulerRangeMult = techState ? getEfficiencyMultiplier(techState, 'hauler_range') : 1;
  const fuelEffMult = techState ? getEfficiencyMultiplier(techState, 'fuel_efficiency') : 1;
  const transitFuelMult = techState ? getEfficiencyMultiplier(techState, 'transit_fuel_cost') : 1;
  const robots = query(world, [RobotTag, Position, Velocity, RobotState]);

  for (let i = 0; i < robots.length; i++) {
    const eid = robots[i];
    const state = RobotState.state[eid];

    if (state === ROBOT_STATES.MOVING_TO || state === ROBOT_STATES.RETURNING) {
      const tx = PathTarget.x[eid] - Position.x[eid];
      const ty = PathTarget.y[eid] - Position.y[eid];
      const tz = PathTarget.z[eid] - Position.z[eid];
      const dist = Math.sqrt(tx * tx + ty * ty + tz * tz);

      if (dist > 1) {
        const nx = tx / dist;
        const ny = ty / dist;
        const nz = tz / dist;

        const maxThrustVal = Thrust.maxThrust[eid];
        const mass = Thrust.mass[eid];
        const isHauler = RobotType.type[eid] === ROBOT_TYPES.HAULER;
        const maxSpeed = Thrust.maxSpeed[eid] * (isHauler ? haulerSpeedMult : 1);

        const speed = Math.sqrt(
          Velocity.x[eid] * Velocity.x[eid] +
            Velocity.y[eid] * Velocity.y[eid] +
            Velocity.z[eid] * Velocity.z[eid],
        );
        const brakingDist = (speed * speed * mass) / (2 * maxThrustVal);

        let thrustMag: number;
        if (dist < brakingDist + 10) {
          thrustMag = -maxThrustVal;
          if (speed > 0.1) {
            const vx = Velocity.x[eid];
            const vy = Velocity.y[eid];
            const vz = Velocity.z[eid];
            Velocity.x[eid] += (((-vx / speed) * maxThrustVal) / mass) * dt;
            Velocity.y[eid] += (((-vy / speed) * maxThrustVal) / mass) * dt;
            Velocity.z[eid] += (((-vz / speed) * maxThrustVal) / mass) * dt;
          }
        } else {
          thrustMag = maxThrustVal;
          Velocity.x[eid] += ((nx * maxThrustVal) / mass) * dt;
          Velocity.y[eid] += ((ny * maxThrustVal) / mass) * dt;
          Velocity.z[eid] += ((nz * maxThrustVal) / mass) * dt;
        }

        const newSpeed = Math.sqrt(
          Velocity.x[eid] * Velocity.x[eid] +
            Velocity.y[eid] * Velocity.y[eid] +
            Velocity.z[eid] * Velocity.z[eid],
        );
        if (newSpeed > maxSpeed) {
          const scale = maxSpeed / newSpeed;
          Velocity.x[eid] *= scale;
          Velocity.y[eid] *= scale;
          Velocity.z[eid] *= scale;
        }

        const profile = ROBOT_PROFILES[RobotType.type[eid]];
        if (profile) {
          Energy.current[eid] -= Math.abs(thrustMag) * profile.energyConsumptionRate * dt;
          Energy.current[eid] = Math.max(0, Energy.current[eid]);
        }
      }
    }

    // Fuel consumption: proportional to distance traveled this tick
    if (state === ROBOT_STATES.MOVING_TO || state === ROBOT_STATES.RETURNING) {
      const fvx = Velocity.x[eid];
      const fvy = Velocity.y[eid];
      const fvz = Velocity.z[eid];
      const fuelSpeed = Math.sqrt(fvx * fvx + fvy * fvy + fvz * fvz);
      if (fuelSpeed > 0) {
        const movProfile = ROBOT_PROFILES[RobotType.type[eid]];
        if (movProfile && movProfile.fuelPerUnit > 0) {
          const isHaulerBot = RobotType.type[eid] === ROBOT_TYPES.HAULER;
          // Orbital transit window: out-of-window destinations cost more fuel.
          const ptx = PathTarget.x[eid];
          const ptz = PathTarget.z[eid];
          const orbitalMult = transitCostMultiplierFromPosition(ptx, ptz, baseX, baseZ);
          // hauler_range increases range (reduces fuel burn), fuel_efficiency further reduces it,
          // transit_fuel_cost can zero it out entirely (gravity_assist)
          const fuelMult = (isHaulerBot
            ? (1 / (haulerRangeMult * fuelEffMult)) * transitFuelMult
            : 1) * orbitalMult;
          Fuel.current[eid] = Math.max(
            0,
            Fuel.current[eid] - fuelSpeed * dt * movProfile.fuelPerUnit * fuelMult,
          );
        }
      }
    }

    Position.x[eid] += Velocity.x[eid] * dt;
    Position.y[eid] += Velocity.y[eid] * dt;
    Position.z[eid] += Velocity.z[eid] * dt;

    const speed = Math.sqrt(Velocity.x[eid] * Velocity.x[eid] + Velocity.z[eid] * Velocity.z[eid]);
    if (speed > 0.1) {
      Rotation.angle[eid] = Math.atan2(Velocity.x[eid], Velocity.z[eid]);
    }
  }
}
