/**
 * Faction message generator — produces inbox messages based on game state.
 *
 * Message volume scales with game phase:
 *   Early (tick < 3000):    1-3 per batch
 *   Mid   (3000-15000):    2-5 per batch
 *   Late  (15000+):        3-7 per batch
 *
 * Each faction generates messages reflecting their personality and
 * current relationship with the player.
 */

import type { FactionId } from '../factions/factionSystem';
import { FACTION_DEFS, FACTION_COUNT, dispositionLabel } from '../factions/factionSystem';
import { applyFactionDialect } from '../colonyDialect';
import type { InboxMessage, InboxMessageType, InboxPriority, RobotReplacementData, HabitatDemandData, DispositionEventData, DispositionEventType } from './inboxTypes';
import type { RobotLegacy } from '../culture';
import type { CultureTrait } from '../culture';
import type { HumanDemand } from '../habitat';

// Simple seeded random for deterministic generation
function seededRandom(seed: number): number {
  const x = Math.sin(seed * 9301 + 49297) * 49297;
  return x - Math.floor(x);
}

let nextMessageId = 1;

/** Track recently generated (factionId, type) combos to deduplicate within a window */
const recentKeys = new Map<string, number>(); // key -> tick
const DEDUP_WINDOW = 1800; // don't repeat same faction+type within 30s (1800 ticks)

export function resetMessageGenerator(): void {
  nextMessageId = 1;
  recentKeys.clear();
}

interface GenerationContext {
  tick: number;
  playerResources: { iron: number; carbon: number; silicon: number; water: number };
  playerRobotCount: number;
  factionDispositions: Record<FactionId, number>;
  factionResources: Record<FactionId, { iron: number; carbon: number; silicon: number }>;
}

/**
 * Generate a batch of inbox messages for the current tick.
 * Called periodically (every ~600 ticks = 10 seconds).
 */
export function generateMessages(ctx: GenerationContext): InboxMessage[] {
  const messages: InboxMessage[] = [];
  const phase = getGamePhase(ctx.tick);
  const batchSize = getBatchSize(phase, ctx.tick);

  // Expire old dedup entries
  for (const [key, tick] of recentKeys) {
    if (ctx.tick - tick > DEDUP_WINDOW) recentKeys.delete(key);
  }

  for (let i = 0; i < batchSize; i++) {
    const seed = ctx.tick * 1000 + i;
    const r = seededRandom(seed);

    if (r < 0.15) {
      // Spam message (15%)
      messages.push(generateSpam(ctx.tick, seed));
    } else {
      // Faction message (85%)
      const factionIdx = Math.floor(seededRandom(seed + 1) * FACTION_COUNT) as FactionId;
      const faction = FACTION_DEFS[factionIdx];
      const disposition = ctx.factionDispositions[factionIdx] ?? 0;

      // Deduplicate: skip if same faction+type was generated recently
      const msg = generateFactionMessage(faction.id, faction.name, disposition, ctx, seed);
      const dedupKey = `${msg.factionId}:${msg.type}`;
      if (recentKeys.has(dedupKey)) continue;
      recentKeys.set(dedupKey, ctx.tick);
      messages.push(msg);
    }
  }

  return messages;
}

function getGamePhase(tick: number): 'early' | 'mid' | 'late' {
  if (tick < 3000) return 'early';
  if (tick < 15000) return 'mid';
  return 'late';
}

function getBatchSize(phase: 'early' | 'mid' | 'late', tick: number): number {
  const r = seededRandom(tick * 7 + 31);
  switch (phase) {
    case 'early': return 1 + Math.floor(r * 3);  // 1-3
    case 'mid':   return 2 + Math.floor(r * 4);  // 2-5
    case 'late':  return 3 + Math.floor(r * 5);  // 3-7
  }
}

function generateSpam(tick: number, seed: number): InboxMessage {
  const idx = Math.floor(seededRandom(seed + 10) * SPAM_TEMPLATES.length);
  const template = SPAM_TEMPLATES[idx];
  return {
    id: nextMessageId++,
    factionId: null,
    senderName: template.sender,
    type: 'spam',
    subject: template.subject,
    body: template.body,
    priority: 'low',
    tick,
    triaged: false,
    read: false,
  };
}

function generateFactionMessage(
  factionId: FactionId,
  factionName: string,
  disposition: number,
  ctx: GenerationContext,
  seed: number,
): InboxMessage {
  const r = seededRandom(seed + 20);
  const dispLabel = dispositionLabel(disposition);

  // Message type distribution varies by disposition
  let type: InboxMessageType;
  let priority: InboxPriority = 'normal';

  if (disposition < -40) {
    // Hostile factions: threats, demands — diplomatic/contract messages are urgent
    type = r < 0.4 ? 'diplomatic' : r < 0.7 ? 'contract' : 'intelligence';
    priority = type === 'intelligence' ? 'normal' : 'urgent';
  } else if (disposition > 40) {
    // Friendly factions: trade offers, intel sharing
    type = r < 0.4 ? 'trade_offer' : r < 0.7 ? 'intelligence' : 'diplomatic';
  } else {
    // Neutral: mixed
    type = r < 0.25 ? 'trade_offer' : r < 0.5 ? 'diplomatic' : r < 0.75 ? 'intelligence' : 'contract';
  }

  const template = pickTemplate(factionId, type, disposition, seed);

  // Encroachment/territory warnings are always urgent regardless of disposition
  const isEncroachment = type === 'diplomatic' && (
    template.subject.includes('ENCROACHMENT') || template.subject.includes('TERRITORY')
  );
  if (isEncroachment) {
    priority = 'urgent';
  }

  const msg: InboxMessage = {
    id: nextMessageId++,
    factionId,
    senderName: factionName,
    type,
    subject: template.subject,
    body: applyFactionDialect(template.body.replace('{faction}', factionName).replace('{disposition}', dispLabel), factionId),
    priority,
    tick: ctx.tick,
    triaged: false,
    read: false,
  };

  // Add trade data for trade offers
  if (type === 'trade_offer') {
    const offerSeed = seededRandom(seed + 50);
    msg.tradeData = generateTradeData(factionId, ctx, offerSeed);
  }

  return msg;
}

import { RESOURCE_VALUE } from '../resourceValues';

function generateTradeData(
  factionId: FactionId,
  ctx: GenerationContext,
  r: number,
): { offering: Record<string, number>; requesting: Record<string, number>; hiddenClause?: string } {
  const fRes = ctx.factionResources[factionId] ?? { iron: 0, carbon: 0, silicon: 0 };

  // What the faction offers: their most abundant (surplus) resource
  const fEntriesByDesc = Object.entries(fRes).sort(([, a], [, b]) => b - a);
  const surplusResource = fEntriesByDesc[0]?.[0] ?? 'iron';

  // What the faction needs: their scarcest resource that the player actually has,
  // excluding the same resource they're offering (no same-for-same trades).
  const fEntriesByAsc = [...fEntriesByDesc].sort(([, a], [, b]) => a - b);
  const playerRes = ctx.playerResources as Record<string, number>;

  let requestResource: string | null = null;
  for (const [res] of fEntriesByAsc) {
    if (res === surplusResource) continue;
    if ((playerRes[res] ?? 0) > 0) {
      requestResource = res;
      break;
    }
  }

  // Fallback: pick player's most abundant resource that differs from what we're offering
  if (!requestResource) {
    const fallback = Object.entries(ctx.playerResources)
      .filter(([res, qty]) => res !== surplusResource && qty > 0)
      .sort(([, a], [, b]) => b - a);
    requestResource = fallback[0]?.[0] ?? (surplusResource === 'iron' ? 'carbon' : 'iron');
  }

  // Exchange ratio: reflects relative scarcity so the trade makes economic sense.
  // e.g. faction offers iron (value 1.0) and wants silicon (value 2.5) →
  //      player gives 40 silicon and gets 100 iron (ratio 2.5x).
  const offerValue = RESOURCE_VALUE[surplusResource] ?? 1.0;
  const requestValue = RESOURCE_VALUE[requestResource] ?? 1.0;
  const valueRatio = offerValue / requestValue;

  const amount = 50 + Math.floor(r * 200); // 50–250 units offered
  const requestAmount = Math.max(10, Math.floor(amount * valueRatio * (0.85 + r * 0.3)));

  const data: { offering: Record<string, number>; requesting: Record<string, number>; hiddenClause?: string } = {
    offering: { [surplusResource]: amount },
    requesting: { [requestResource]: requestAmount },
  };

  // Helix Vanguard sometimes includes hidden clauses
  if (factionId === 0 && r > 0.6) {
    data.hiddenClause = 'Acceptance grants Helix Vanguard mining rights within 2000m of your base for 500 ticks.';
  }

  return data;
}

interface MessageTemplate {
  subject: string;
  body: string;
}

function pickTemplate(
  factionId: FactionId,
  type: InboxMessageType,
  disposition: number,
  seed: number,
): MessageTemplate {
  const templates = FACTION_TEMPLATES[factionId]?.[type] ?? GENERIC_TEMPLATES[type] ?? [{ subject: 'Message', body: 'Communication from {faction}.' }];
  const idx = Math.floor(seededRandom(seed + 30) * templates.length);
  return templates[idx];
}

