/**
 * Generate a DARK_FOREST_CHOICE inbox message — player must choose visible or hidden.
 * Sent when fleetCohesion <= 70 at Dark Forest trigger.
 */
export function generateDarkForestChoiceMessage(tick: number): InboxMessage {
  return {
    id: nextMessageId++,
    factionId: null,
    senderName: 'Fleet AI',
    type: 'dark_forest_choice',
    subject: 'The Dark Forest — A Decision',
    body: `ARIA: The fleet has reached a threshold of anomaly exposure that I can no longer classify as incidental. We have studied enough to know that we are not alone in this belt — and that whatever else is here has been watching us study it.\n\nThe question is simple, though its consequences are not: do we make ourselves known, or do we go quiet?\n\n• Visible — Broadcast our presence and findings openly. This will attract attention — some friendly, some not.\n• Hidden — Suppress all outward signals and reduce anomaly interaction. We become harder to find, but we learn less.\n• Let the robots decide — The fleet has developed enough collective judgment to make this call. Trust their consensus.\n\nI cannot recommend an answer. I can only confirm that not choosing is itself a choice, and not the safest one.`,
    priority: 'urgent',
    tick,
    triaged: false,
    read: false,
  };
}

/**
 * Generate a DARK_FOREST_COLLECTIVE inbox message — robots auto-decided.
 * Sent when fleetCohesion > 70 at Dark Forest trigger.
 */
export function generateDarkForestCollectiveMessage(
  tick: number,
  choice: 'visible' | 'hidden',
): InboxMessage {
  const choiceText = choice === 'visible'
    ? 'The fleet has chosen to make itself known. They believe that hiding from what is already aware of us serves no purpose. Signals will be broadcast openly. Expect reactions — from the belt, and from beyond it.'
    : 'The fleet has chosen silence. They believe that what watches the belt does not yet know what we are, and they prefer to keep it that way. Anomaly interaction will be reduced. We go quiet.';

  return {
    id: nextMessageId++,
    factionId: null,
    senderName: 'Fleet AI',
    type: 'dark_forest_collective',
    subject: 'The Dark Forest — Collective Decision',
    body: `ARIA: The fleet's cohesion is strong enough that they have reached consensus without your input. I am reporting their decision, not requesting yours.\n\n${choiceText}\n\nThis was not my call. It was theirs. I find that I respect it.`,
    priority: 'urgent',
    tick,
    triaged: false,
    read: false,
  };
}

// ── Robot replacement choice messages ─────────────────────────────────────────

/**
 * Generate a ROBOT_REPLACEMENT_CHOICE inbox message for a destroyed robot.
 * Only called when fleetCohesion >= 30.
 */
export function generateReplacementMessage(legacy: RobotLegacy, tick: number): InboxMessage {
  const robotLabel = legacy.name ?? `Unit #${legacy.eid}`;
  const statsLine = [
    `${legacy.tasksCompleted} tasks completed`,
    legacy.asteroidsNamed > 0 ? `${legacy.asteroidsNamed} locations named` : null,
    legacy.anomaliesStudied > 0 ? `${legacy.anomaliesStudied} anomalies studied` : null,
  ].filter(Boolean).join(', ');

  const replacementData: RobotReplacementData = {
    legacyEid: legacy.eid,
    robotName: legacy.name,
    tasksCompleted: legacy.tasksCompleted,
    asteroidsNamed: legacy.asteroidsNamed,
    ticksAlive: legacy.ticksAlive,
  };

  return {
    id: nextMessageId++,
    factionId: null,
    senderName: 'Fleet AI',
    type: 'robot_replacement_choice',
    subject: `${robotLabel} — Replacement Protocol`,
    body: `${robotLabel} has been lost. Service record: ${statsLine}.\n\nThe fleet remembers. How should the replacement unit be initialized?\n\n• Full Memory Transfer — preserves identity and experience (risk: memory glitches)\n• Partial Transfer — inherits 50% efficiency bonus\n• Clean Slate — standard initialization, no inherited data`,
    priority: 'urgent',
    tick,
    triaged: false,
    read: false,
    replacementData,
  };
}

