/**
 * Generate a one-time inbox message when a culture trait first activates.
 * Returns the message and the factionId that reacts.
 */
export function generateCultureTraitReactionMessage(
  trait: CultureTrait,
  tick: number,
): { message: InboxMessage; factionId: FactionId } {
  const factionId = TRAIT_REACTION_FACTION[trait];
  const faction = FACTION_DEFS[factionId];
  const template = TRAIT_REACTION_TEMPLATES[trait];

  return {
    message: {
      id: nextMessageId++,
      factionId,
      senderName: faction.name,
      type: 'diplomatic',
      subject: template.subject,
      body: applyFactionDialect(template.body, factionId),
      priority: 'normal',
      tick,
      triaged: false,
      read: false,
    },
    factionId,
  };
}

