import { addComponent, hasComponent } from 'bitecs';
import type { World } from '../../core/ecs';
import {
  Position,
  Energy,
  Inventory,
  ToolTier,
  RobotState,
  TaskRef,
  PathTarget,
  AsteroidHealth,
  MineralComposition,
  AsteroidSize,
  AsteroidRichness,
  AsteroidHusk,
  AnomalyFlag,
} from '../components';
import type { RobotProfile } from '../robotProfiles';
import type { TaskQueue } from '../taskQueue';
import { ROBOT_STATES } from '../robotCreation';
import type { AnomalyDiscoveredCallback } from './types';
import { TIER_MULTIPLIERS } from './types';
import type { DustGrid } from '../dustGrid';

export function handleMiningRobot(
  world: World,
  eid: number,
  dt: number,
  taskQueue: TaskQueue,
  profile: RobotProfile,
  baseEid: number,
  discoveredAnomalies: Set<number> | undefined,
  onAnomalyDiscovered: AnomalyDiscoveredCallback | undefined,
  miningMult: number,
  dustGrid?: DustGrid,
  iceMiningMult = 1.0,
): void {
  const taskId = TaskRef.taskId[eid];
  const task = taskId >= 0 ? taskQueue.getTask(taskId) : undefined;
  if (!task) {
    RobotState.state[eid] = ROBOT_STATES.IDLE;
    return;
  }

  const targetEid = task.targetEid;
  const isHusk = hasComponent(world, targetEid, AsteroidHusk);

  // Only Deep Core (tier 3) can mine husks
  const tier = ToolTier.tier[eid] || 1;
  if (isHusk && tier < 3) {
    taskQueue.completeTask(taskId);
    TaskRef.taskId[eid] = -1;
    RobotState.state[eid] = ROBOT_STATES.IDLE;
    return;
  }

  const tierMult = TIER_MULTIPLIERS[Math.min(tier, 3)] ?? 1.0;
  const miningRate = profile.miningRate * tierMult * miningMult * dt;
  const remaining = AsteroidHealth.current[targetEid];

  if (remaining <= 0 || Inventory.used[eid] >= Inventory.capacity[eid]) {
    taskQueue.completeTask(taskId);
    TaskRef.taskId[eid] = -1;
    if (baseEid >= 0) {
      RobotState.state[eid] = ROBOT_STATES.RETURNING;
      PathTarget.x[eid] = Position.x[baseEid];
      PathTarget.y[eid] = Position.y[baseEid];
      PathTarget.z[eid] = Position.z[baseEid];
    } else {
      RobotState.state[eid] = ROBOT_STATES.IDLE;
    }
    return;
  }

  const extracted = Math.min(miningRate, remaining);
  AsteroidHealth.current[targetEid] -= extracted;

  // Anomaly discovery: fires once when health drops below 80% of max
  const anomalyType = AnomalyFlag.type[targetEid];
  if (
    anomalyType > 0 &&
    discoveredAnomalies !== undefined &&
    !discoveredAnomalies.has(targetEid) &&
    AsteroidHealth.current[targetEid] < AsteroidHealth.max[targetEid] * 0.8
  ) {
    discoveredAnomalies.add(targetEid);
    onAnomalyDiscovered?.(
      eid,
      targetEid,
      anomalyType,
      Position.x[targetEid],
      Position.y[targetEid],
      Position.z[targetEid],
    );
  }

  // Apply richness multiplier to mineral yield
  const richness = AsteroidRichness.multiplier[targetEid] || 1.0;
  const yieldAmount = extracted * richness;

  if (isHusk) {
    // Husks yield only exotic/trace minerals
    Inventory.platinum[eid] += MineralComposition.platinum[targetEid] * yieldAmount * 3;
    Inventory.cobalt[eid] += MineralComposition.cobalt[targetEid] * yieldAmount * 2;
    Inventory.used[eid] += extracted * 0.1; // husks give less total mass
  } else {
    Inventory.iron[eid] += MineralComposition.iron[targetEid] * yieldAmount;
    Inventory.nickel[eid] += MineralComposition.nickel[targetEid] * yieldAmount;
    Inventory.cobalt[eid] += MineralComposition.cobalt[targetEid] * yieldAmount;
    Inventory.platinum[eid] += MineralComposition.platinum[targetEid] * yieldAmount;
    Inventory.ice[eid] += MineralComposition.ice[targetEid] * yieldAmount * iceMiningMult;
    Inventory.carbon[eid] += MineralComposition.carbon[targetEid] * yieldAmount;
    Inventory.silicate[eid] += MineralComposition.silicate[targetEid] * yieldAmount;
    Inventory.used[eid] += extracted;
  }

  // Depletion: when health hits 0, convert to husk
  if (AsteroidHealth.current[targetEid] <= 0 && !isHusk) {
    AsteroidHealth.current[targetEid] = 0;
    addComponent(world, targetEid, AsteroidHusk);
    const originalRadius = AsteroidSize.radius[targetEid];
    // Shrink to ~35% radius visually
    AsteroidSize.radius[targetEid] = originalRadius * 0.35;
    // Leave a tiny bit of health for Deep Core mining
    AsteroidHealth.current[targetEid] = AsteroidHealth.max[targetEid] * 0.05;
    // Deposit dust proportional to asteroid size
    if (dustGrid) {
      const dustAmount = Math.min(1.0, originalRadius * 0.005);
      dustGrid.deposit(Position.x[targetEid], Position.z[targetEid], dustAmount);
    }
  }

  Energy.current[eid] -= profile.energyConsumptionRate * profile.maxThrust * 0.5 * dt;
}
