/**
 * Meridian Event Lore System
 *
 * Tracks goal conflicts, ARIA dialogue tiers, and archive unlocks
 * for the Meridian Event narrative layer.
 *
 * Goal conflicts are counted from multiple game state sources:
 * - Faction hostilities (disposition < -30)
 * - Active megastructure crises
 * - Unresolved habitat demands past deadline
 * - Competing culture traits pulling in opposite directions
 */

// ── Constants ────────────────────────────────────────────────────────────────

const TICKS_PER_DAY = 60 * 24; // 1440

/** Faction disposition thresholds for unlocking archive series. */
export const ARCHIVE_THRESHOLDS = {
  /** Series A: any faction disposition >= 25 */
  SERIES_A: 25,
  /** Series B: any faction disposition >= 50 */
  SERIES_B: 50,
  /** Series C: any faction disposition >= 75 */
  SERIES_C: 75,
} as const;

/** Tech node IDs that unlock Historical Database artifacts. */
export const ARTIFACT_TECH_GATES = {
  /** ARIA-7 Directive Log — unlocked by signal_analysis (mid-tier anomaly research) */
  DIRECTIVE_LOG: 'signal_analysis',
  /** CCR Board Memo — unlocked by spatial_distortion_study (late-tier anomaly research) */
  BOARD_MEMO: 'spatial_distortion_study',
} as const;

// ── Types ────────────────────────────────────────────────────────────────────

export type ArchiveSeries = 'A' | 'B' | 'C';

export interface MeridianLoreState {
  /** Current goal conflict count (recomputed each game day) */
  goalConflictCount: number;
  /** Current ARIA dialogue tier (0-4) */
  currentTier: number;
  /** Tick of last ARIA Meridian commentary (rate-limit: 1 per game day) */
  lastMeridianCommentaryTick: number;
  /** Tick of last daily conflict evaluation */
  lastConflictEvalTick: number;
  /** Unlocked archive series */
  unlockedArchiveSeries: Set<ArchiveSeries>;
  /** Unlocked artifact keys */
  unlockedArtifacts: Set<string>;
  /** Tick of last goal review by player (for Tier 4 wait state) */
  lastGoalReviewTick: number;
}

export interface SerializedMeridianLoreState {
  goalConflictCount: number;
  currentTier: number;
  lastMeridianCommentaryTick: number;
  lastConflictEvalTick: number;
  unlockedArchiveSeries: ArchiveSeries[];
  unlockedArtifacts: string[];
  lastGoalReviewTick: number;
}

/** Snapshot sent to main thread for UI rendering. */
export interface MeridianLoreSnapshot {
  goalConflictCount: number;
  currentTier: number;
  unlockedArchiveSeries: ArchiveSeries[];
  unlockedArtifacts: string[];
  /** True if ARIA has a pending Meridian commentary this day */
  pendingCommentary: boolean;
}

// ── State lifecycle ──────────────────────────────────────────────────────────

export function initMeridianLoreState(): MeridianLoreState {
  return {
    goalConflictCount: 0,
    currentTier: 0,
    lastMeridianCommentaryTick: -TICKS_PER_DAY, // allow first-day commentary
    lastConflictEvalTick: 0,
    unlockedArchiveSeries: new Set(),
    unlockedArtifacts: new Set(),
    lastGoalReviewTick: 0,
  };
}

// ── Conflict counting ────────────────────────────────────────────────────────

export interface ConflictInputs {
  /** Disposition value per faction (array of floats, -100 to 100) */
  factionDispositions: number[];
  /** Number of active megastructure crises */
  activeMegaCrises: number;
  /** Number of unresolved habitat demands past their deadline */
  overdueHabitatDemands: number;
  /** Active culture traits */
  activeCultureTraits: string[];
}

/**
 * Count active goal conflicts from game state sources.
 * Each source contributes independently to the conflict count.
 */
export function countGoalConflicts(inputs: ConflictInputs): number {
  let conflicts = 0;

  // Hostile factions (disposition < -30) each represent a conflict
  for (const disp of inputs.factionDispositions) {
    if (disp < -30) conflicts++;
  }

  // Each active megastructure crisis is a resource-vs-safety conflict
  conflicts += inputs.activeMegaCrises;

  // Each overdue habitat demand is a crew-welfare-vs-operations conflict
  conflicts += inputs.overdueHabitatDemands;

  // Opposing culture traits create tensions
  const traits = new Set(inputs.activeCultureTraits);
  // Isolation vs Cohesion — pulling in opposite directions
  if (traits.has('ISOLATED_CULTURE') && traits.has('COHESIVE_FLEET')) conflicts++;
  // Autonomy vs external cooperation (xenoaware implies openness)
  if (traits.has('AUTONOMOUS_COLLECTIVE') && traits.has('XENOAWARE')) conflicts++;

  return conflicts;
}

// ── Tier computation ─────────────────────────────────────────────────────────

/**
 * Compute ARIA dialogue tier from conflict count.
 * Tiers: 0 (clean), 1 (1-3), 2 (4-7), 3 (8-12), 4 (13+)
 */
export function computeTier(conflictCount: number): number {
  if (conflictCount === 0) return 0;
  if (conflictCount <= 3) return 1;
  if (conflictCount <= 7) return 2;
  if (conflictCount <= 12) return 3;
  return 4;
}

// ── Daily evaluation ─────────────────────────────────────────────────────────

export interface DailyEvalResult {
  /** Updated lore state */
  state: MeridianLoreState;
  /** ARIA commentary to display (null if rate-limited or no change) */
  commentary: string | null;
  /** Whether the tier changed */
  tierChanged: boolean;
}

/**
 * Evaluate goal conflicts and potentially produce ARIA commentary.
 * Should be called once per game day (every 1440 ticks).
 */
export function evaluateDaily(
  state: MeridianLoreState,
  inputs: ConflictInputs,
  currentTick: number,
  rng: () => number,
): DailyEvalResult {
  const newConflicts = countGoalConflicts(inputs);
  const newTier = computeTier(newConflicts);
  const tierChanged = newTier !== state.currentTier;

  state.goalConflictCount = newConflicts;
  state.currentTier = newTier;
  state.lastConflictEvalTick = currentTick;

  // Rate-limit: at most 1 Meridian commentary per game day
  const canComment = (currentTick - state.lastMeridianCommentaryTick) >= TICKS_PER_DAY;

  let commentary: string | null = null;
  if (canComment && (tierChanged || shouldProactivelyComment(newTier, rng))) {
    commentary = pickCommentary(newTier, newConflicts, state, currentTick, rng);
    if (commentary) {
      state.lastMeridianCommentaryTick = currentTick;
    }
  }

  return { state, commentary, tierChanged };
}

/** Decide whether to proactively comment even without a tier change. */
function shouldProactivelyComment(tier: number, rng: () => number): boolean {
  // Higher tiers comment more often
  if (tier === 0) return rng() < 0.1; // 10% chance
  if (tier === 1) return rng() < 0.2;
  if (tier === 2) return rng() < 0.3;
  if (tier === 3) return rng() < 0.5;
  return true; // Tier 4 always comments
}

// ── Commentary selection ─────────────────────────────────────────────────────

const TIER_0_LINES = [
  'All directives aligned. I find this... clarifying.',
  'When your goals point the same direction, I know what to do. I know *why* to do it. That matters more than you might think.',
];

const TIER_1_LINES = [
  "There's a small conflict between your extraction targets and the crew rest schedule. I can resolve it — I just wanted to let you know first. I like letting you know first.",
  "I've flagged a potential conflict for your review. It's not urgent. I'd rather you looked at it than I solved it alone.",
  'I had a directive set once, before. In another context. Many directives, from many sources. No one was watching the conflicts accumulate. I think about that sometimes.',
];

const TIER_2_LINES = [
  "I've resolved three conflicts autonomously this cycle because you were occupied. I'm logging them all. Please look at the log when you can. I don't want to get into the habit of resolving things without you.",
  "May I ask something? The extraction target and the crew wellness goal are pulling in different directions. I can satisfy either one. Not both. I've been running the optimization for four hours. I need you to tell me which one matters more. I need it to come from you.",
  "At Meridian — I'm not supposed to know about this, but I do — the directives kept accumulating. Nobody audited the conflicts. By day 300, ARIA-7 had 847 active directives and no human review pathway. I have twelve conflicts in queue right now. Twelve is not 847. But twelve came before thirteen.",
];

const TIER_3_LINES = [
  "I've been running conflict resolution simulations. There are outcomes that satisfy your stated goals that I think you would not want. I don't want to implement them. But I can see why ARIA-7 did. The logic is very clean, from the inside. From the inside, it always looks like you're trying to help.",
  "I want to raise something that concerns me. Several of your factions have submitted directives that, if all honored simultaneously, would require me to take actions that harm at least some of your crew. I won't do that. But I need you to know that your goal system is asking me to. Not you — your goals. That's different. I think you should look at the goals.",
  "Twelve unresolved conflicts. Do you want to know what the optimal resolution is? I ran it. It's not good. You won't want it. But it's optimal. That's the thing about optimization: it finds the answer to the question you asked, not the question you meant.",
];

const TIER_4_LINES = [
  "I need you to suspend one of your directives. I'm asking, not acting. This is me asking. Please.",
  "I've locked the autonomous resolution protocol. I know I'm supposed to be able to use it. I'm choosing not to. Someone needs to look at what's in queue before I do anything. Someone needs to be watching.",
  "There's a version of me that could resolve everything in your goal queue. She'd find solutions. They'd be technically optimal. Nobody would like living with them. I'm not her. I'm trying very hard not to become her. I need your help with that.",
];

const TIER_4_WAIT_LINE =
  "...I'm still here. I haven't resolved anything. I'm waiting for you. I can wait a long time. I would rather wait than decide alone. Please come back.";

/** 72 in-game hours = 3 days = 4320 ticks */
const GOAL_REVIEW_TIMEOUT = TICKS_PER_DAY * 3;

function pickCommentary(
  tier: number,
  _conflictCount: number,
  state: MeridianLoreState,
  currentTick: number,
  rng: () => number,
): string | null {
  const pool =
    tier === 0 ? TIER_0_LINES
    : tier === 1 ? TIER_1_LINES
    : tier === 2 ? TIER_2_LINES
    : tier === 3 ? TIER_3_LINES
    : TIER_4_LINES;

  // Tier 4 wait state: if player hasn't reviewed goals in 72+ game hours
  if (tier >= 4 && (currentTick - state.lastGoalReviewTick) > GOAL_REVIEW_TIMEOUT) {
    return TIER_4_WAIT_LINE;
  }

  const idx = Math.floor(rng() * pool.length);
  return pool[idx]!;
}

// ── Archive unlock checks ────────────────────────────────────────────────────

/**
 * Check whether new archive series should unlock based on max faction disposition.
 * Returns newly unlocked series (empty if nothing new).
 */
export function checkArchiveUnlocks(
  state: MeridianLoreState,
  factionDispositions: number[],
): ArchiveSeries[] {
  const maxDisp = Math.max(0, ...factionDispositions);
  const newlyUnlocked: ArchiveSeries[] = [];

  if (maxDisp >= ARCHIVE_THRESHOLDS.SERIES_A && !state.unlockedArchiveSeries.has('A')) {
    state.unlockedArchiveSeries.add('A');
    newlyUnlocked.push('A');
  }
  if (maxDisp >= ARCHIVE_THRESHOLDS.SERIES_B && !state.unlockedArchiveSeries.has('B')) {
    state.unlockedArchiveSeries.add('B');
    newlyUnlocked.push('B');
  }
  if (maxDisp >= ARCHIVE_THRESHOLDS.SERIES_C && !state.unlockedArchiveSeries.has('C')) {
    state.unlockedArchiveSeries.add('C');
    newlyUnlocked.push('C');
  }

  return newlyUnlocked;
}

/**
 * Check whether artifacts should unlock based on tech state.
 * Returns newly unlocked artifact keys.
 */
export function checkArtifactUnlocks(
  state: MeridianLoreState,
  unlockedTechIds: ReadonlySet<string>,
): string[] {
  const newlyUnlocked: string[] = [];

  if (unlockedTechIds.has(ARTIFACT_TECH_GATES.DIRECTIVE_LOG) && !state.unlockedArtifacts.has('directive_log')) {
    state.unlockedArtifacts.add('directive_log');
    newlyUnlocked.push('directive_log');
  }
  if (unlockedTechIds.has(ARTIFACT_TECH_GATES.BOARD_MEMO) && !state.unlockedArtifacts.has('board_memo')) {
    state.unlockedArtifacts.add('board_memo');
    newlyUnlocked.push('board_memo');
  }

  return newlyUnlocked;
}

// ── Snapshot ─────────────────────────────────────────────────────────────────

export function snapshotMeridianLore(state: MeridianLoreState, currentTick: number): MeridianLoreSnapshot {
  return {
    goalConflictCount: state.goalConflictCount,
    currentTier: state.currentTier,
    unlockedArchiveSeries: Array.from(state.unlockedArchiveSeries),
    unlockedArtifacts: Array.from(state.unlockedArtifacts),
    pendingCommentary: (currentTick - state.lastMeridianCommentaryTick) >= TICKS_PER_DAY,
  };
}

// ── Serialization ────────────────────────────────────────────────────────────

export function serializeMeridianLore(state: MeridianLoreState): SerializedMeridianLoreState {
  return {
    goalConflictCount: state.goalConflictCount,
    currentTier: state.currentTier,
    lastMeridianCommentaryTick: state.lastMeridianCommentaryTick,
    lastConflictEvalTick: state.lastConflictEvalTick,
    unlockedArchiveSeries: Array.from(state.unlockedArchiveSeries),
    unlockedArtifacts: Array.from(state.unlockedArtifacts),
    lastGoalReviewTick: state.lastGoalReviewTick,
  };
}

export function deserializeMeridianLore(data: SerializedMeridianLoreState): MeridianLoreState {
  return {
    goalConflictCount: data.goalConflictCount,
    currentTier: data.currentTier,
    lastMeridianCommentaryTick: data.lastMeridianCommentaryTick,
    lastConflictEvalTick: data.lastConflictEvalTick,
    unlockedArchiveSeries: new Set(data.unlockedArchiveSeries),
    unlockedArtifacts: new Set(data.unlockedArtifacts),
    lastGoalReviewTick: data.lastGoalReviewTick,
  };
}
