/**
 * Habitat tick phase — extracted from tick.ts.
 * Handles morale, population growth, demands, life support checks, and broadcasts.
 */
import { workerState, sendMessage, HABITAT_BROADCAST_INTERVAL } from '../state';
import { tickHabitat, createHabitatState, getPopulationDrain } from '../../habitat';
import type { MegastructureProject } from '../../megastructures';
import { generateHabitatDemandMessage } from '../../inbox/messageGenerator';
import { addMessage, getInboxSnapshot } from '../../inbox/inboxStore';

/** Human habitat: morale, population growth, demands, life support checks. */
export function tickHabitatPhase(): void {
  const s = workerState;

  // Check if human_habitat megastructure Stage 2 (Life Support) is complete
  const habitatProject = s.megastructureState.projects.get('human_habitat') as MegastructureProject | undefined;
  const habitatReady = habitatProject != null && habitatProject.completedStages >= 3;

  // Initialize habitat state when humans first arrive
  // (narrative event is handled by catalog via 'habitat_ready' flag set in tickMegastructurePhase)
  if (habitatReady && !s.habitatState) {
    s.habitatState = createHabitatState(s.tick);
  }

  if (!s.habitatState) return;

  // Determine life support status from megastructure drain
  const drainStalled = habitatProject?.drainStalled ?? false;
  // Check if refined storage has surplus beyond drain requirements
  const refined = s.refineryState.refined;
  const popDrain = getPopulationDrain(s.habitatState.population);
  const lifeSupportSurplus =
    !drainStalled &&
    (refined['water'] ?? 0) > popDrain.water * 2 &&
    (refined['oxygen'] ?? 0) > popDrain.oxygen * 2 &&
    (refined['electronics'] ?? 0) > popDrain.electronics * 2;

  // Deduct population-based drain from refined storage
  if (s.habitatState.intervalAccumulator === 0 && !s.habitatState.dormant) {
    // Deduct population drain at each interval reset
    refined['water'] = Math.max(0, (refined['water'] ?? 0) - popDrain.water);
    refined['oxygen'] = Math.max(0, (refined['oxygen'] ?? 0) - popDrain.oxygen);
    refined['electronics'] = Math.max(0, (refined['electronics'] ?? 0) - popDrain.electronics);
  }

  const habitatResult = tickHabitat(s.habitatState, {
    currentTick: s.tick,
    lifeSupportMet: !drainStalled,
    lifeSupportSurplus,
  }, s.eventRng);

  // Store rpModifier so tickEconomyPhase applies it next tick
  s.habitatRpModifier = habitatResult.rpModifier;

  // Set event flags for habitat narrative events
  if (s.habitatState.morale < 30 && s.eventEngine.getFlag('humans_present')) {
    s.eventEngine.setFlag('habitat_morale_crisis', true);
  }
  if (habitatResult.evacuated) {
    s.eventEngine.setFlag('habitat_evacuated', true);
  }
  if (
    s.eventEngine.getFlag('humans_present') &&
    s.eventEngine.getFlag('dyson_collecting') &&
    s.habitatState.morale < 50
  ) {
    s.eventEngine.setFlag('habitat_dyson_tension', true);
  }

  // Handle evacuation
  if (habitatResult.evacuated) {
    sendMessage({
      type: 'sim:narrative_event',
      payload: {
        event: {
          id: `human_evacuation_${s.tick}`,
          type: 'threat',
          title: 'Colonists Evacuating',
          body: '[ARIA] Morale has collapsed. The last transport is departing. The habitat is now dormant. Perhaps, in time, conditions will improve enough to try again.',
          choices: [{ id: 'acknowledge', label: 'Acknowledged' }],
        },
        tick: s.tick,
      },
    });
  }

  // Create inbox message for new habitat demands
  if (habitatResult.newDemand) {
    const demandMsg = generateHabitatDemandMessage(habitatResult.newDemand, s.tick);
    addMessage(demandMsg);
    sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });
  }

  // Broadcast habitat state periodically
  if (s.tick % HABITAT_BROADCAST_INTERVAL === 0) {
    const h = s.habitatState;
    sendMessage({
      type: 'sim:habitat_state',
      payload: {
        population: h.population,
        morale: h.morale,
        politicalCapital: h.politicalCapital,
        demands: h.demands,
        arrivalTick: h.arrivalTick,
        growthPaused: h.growthPaused,
        dormant: h.dormant,
        tick: s.tick,
      },
    });
  }
}
