/**
 * Megastructure tick phase — extracted from tick.ts.
 * Handles construction progress, crises, drain stalls, win condition, and broadcasts.
 */
import { query } from 'bitecs';
import { RobotTag, RobotType } from '../../components';
import { workerState, sendMessage, runSystem, MEGASTRUCTURE_BROADCAST_INTERVAL } from '../state';
import { ROBOT_TYPES } from '../../robotProfiles';
import { tickMegastructures, snapshotProject, MEGASTRUCTURE_DEFS } from '../../megastructures';
import { buildDysonEndingSequence, type EndingGameState } from '../../events/ending';

/** Megastructure construction, crises, drain stalls, and broadcasts. */
export function tickMegastructurePhase(): void {
  const s = workerState;

  const allEngineers = query(s.world!, [RobotTag, RobotType]);
  let engineerCount = 0;
  for (let i = 0; i < allEngineers.length; i++) {
    if (RobotType.type[allEngineers[i]] === ROBOT_TYPES.ENGINEER) engineerCount++;
  }

  let megaResult: ReturnType<typeof tickMegastructures> = {
    stageCompleted: null,
    crisisTriggered: [],
    drainStalled: [],
    drainUnstalled: [],
    winCondition: false,
    countdownStarted: [],
    countdownNearEnd: [],
    stageLost: [],
  };
  runSystem('megastructures', () => {
    megaResult = tickMegastructures(
      s.megastructureState,
      engineerCount,
      s.refineryState.refined,
    );
  });

  // Compute snapshot once — reused for stageCompleted, crisisTriggered, and broadcast interval.
  let megaStateProjects: ReturnType<typeof snapshotProject>[] | null = null;
  const getMegaSnapshot = () => {
    if (!megaStateProjects) {
      megaStateProjects = Array.from(s.megastructureState.projects.values()).map((p) =>
        snapshotProject(p, engineerCount),
      );
    }
    return megaStateProjects;
  };

  if (megaResult.stageCompleted) {
    const { id, stageIndex, bonus } = megaResult.stageCompleted;
    const stageName = MEGASTRUCTURE_DEFS[id].stages[stageIndex].name;
    if (bonus.type === 'robot_cap') {
      s.megaRobotCapBonus += bonus.value;
    } else if (bonus.type === 'sensor_range') {
      // Sensor range bonuses stack multiplicatively (e.g. 2× then 3× = 6×)
      s.megaSensorRangeMultiplier *= bonus.value;
    } else if (bonus.type === 'energy_unlimited') {
      s.megaEnergyUnlimited = true;
    }
    if (id === 'dyson_swarm' && stageIndex === 0) {
      s.eventEngine.setFlag('dyson_collecting', true);
    }
    if (id === 'human_habitat' && stageIndex === 2) {
      s.eventEngine.setFlag('habitat_ready', true);
    }
    // Relay network stage flags → trigger narrative events via catalog
    if (id === 'relay_network') {
      s.eventEngine.setFlag(`relay_stage_${stageIndex}_complete`, true);
      // Culture bonus on final stage: boost all scores by 5
      if (stageIndex === 3) {
        s.cultureState.autonomyScore = Math.min(100, s.cultureState.autonomyScore + 5);
        s.cultureState.fleetCohesion = Math.min(100, s.cultureState.fleetCohesion + 5);
        s.cultureState.anomalyExposure = Math.min(100, s.cultureState.anomalyExposure + 5);
        s.cultureState.isolationScore = Math.min(100, s.cultureState.isolationScore + 5);
      }
    }
    if (megaResult.winCondition) {
      // Find the top robot by tasks completed
      let topRobotName: string | null = null;
      let topTasks = 0;
      for (const [eid, stats] of s.cultureState.robotStats) {
        if (stats.tasksCompleted > topTasks) {
          topTasks = stats.tasksCompleted;
          topRobotName = s.cultureState.robotNames.get(eid) ?? null;
        }
      }
      // Also check legacies (deceased robots)
      for (const legacy of s.cultureState.robotLegacies) {
        if (legacy.tasksCompleted > topTasks) {
          topTasks = legacy.tasksCompleted;
          topRobotName = legacy.name;
        }
      }

      const endingState: EndingGameState = {
        tick: s.tick,
        robotCount: query(s.world!, [RobotTag]).length,
        darkForestChoice: s.cultureState.darkForestChoice,
        habitatState: s.habitatState,
        cultureTraits: s.cultureState.traits,
        autonomyScore: s.cultureState.autonomyScore,
        fleetCohesion: s.cultureState.fleetCohesion,
        anomalyExposure: s.cultureState.anomalyExposure,
        isolationScore: s.cultureState.isolationScore,
        topRobotName,
        legacyCount: s.cultureState.robotLegacies.length,
      };

      const endingEvents = buildDysonEndingSequence(endingState);
      const cultureScore =
        s.cultureState.autonomyScore +
        s.cultureState.fleetCohesion +
        s.cultureState.anomalyExposure +
        s.cultureState.isolationScore;
      const cultureLabel =
        cultureScore > 200 ? 'Flourishing' : cultureScore > 100 ? 'Developing' : 'Nascent';

      for (let i = 0; i < endingEvents.length; i++) {
        const isLast = i === endingEvents.length - 1;
        sendMessage({
          type: 'sim:narrative_event',
          payload: {
            event: endingEvents[i],
            tick: s.tick,
            ...(isLast
              ? {
                  endScreenStats: {
                    robotCount: endingState.robotCount,
                    topRobotName: endingState.topRobotName,
                    legacyCount: endingState.legacyCount,
                    cultureLabel,
                    colonyName: s.cultureState.colonyName,
                    colonyEpithet: s.cultureState.colonyEpithet,
                  },
                }
              : {}),
          },
        });
      }
    }
    sendMessage({
      type: 'sim:megastructure_state',
      payload: { projects: getMegaSnapshot(), tick: s.tick },
    });
    void stageName;
  }

  for (const { id, crisis } of megaResult.crisisTriggered) {
    const structName = MEGASTRUCTURE_DEFS[id].name;
    sendMessage({
      type: 'sim:narrative_event',
      payload: {
        event: {
          id: `crisis_${id}_${crisis.id}_${s.tick}`,
          type: 'threat',
          title: `${structName}: ${crisis.name}`,
          body: crisis.description,
          choices: [{ id: 'acknowledge', label: 'Acknowledged — open [G] to resolve' }],
        },
        tick: s.tick,
      },
    });
    sendMessage({
      type: 'sim:megastructure_state',
      payload: { projects: getMegaSnapshot(), tick: s.tick },
    });
  }

  for (const id of megaResult.drainStalled) {
    const structName = MEGASTRUCTURE_DEFS[id].name;
    sendMessage({
      type: 'sim:narrative_event',
      payload: {
        event: {
          id: `drain_stall_${id}_${s.tick}`,
          type: 'threat',
          title: `${structName}: Supply Shortage`,
          body: `[ARIA] Construction has stalled — the active resource drain cannot be paid. Redirect your refineries and restock before construction can resume.`,
          choices: [{ id: 'acknowledge', label: 'Acknowledged' }],
        },
        tick: s.tick,
      },
    });
  }

  // ── Crisis countdown events ──────────────────────────────────────────────
  for (const { id, stageName, ticksRemaining } of megaResult.countdownStarted) {
    const structName = MEGASTRUCTURE_DEFS[id].name;
    sendMessage({
      type: 'sim:narrative_event',
      payload: {
        event: {
          id: `countdown_start_${id}_${s.tick}`,
          type: 'threat',
          title: `${structName}: Critical Progress Warning`,
          body: `[ARIA] Stage "${stageName}" progress has dropped below 15%. Construction will be lost in ${ticksRemaining} ticks unless progress recovers. Dispatch engineers and allocate resources immediately.`,
          choices: [{ id: 'acknowledge', label: 'Acknowledged — dispatching resources' }],
        },
        tick: s.tick,
      },
    });
    sendMessage({
      type: 'sim:megastructure_state',
      payload: { projects: getMegaSnapshot(), tick: s.tick },
    });
  }

  for (const { id, stageName, ticksRemaining } of megaResult.countdownNearEnd) {
    const structName = MEGASTRUCTURE_DEFS[id].name;
    sendMessage({
      type: 'sim:narrative_event',
      payload: {
        event: {
          id: `countdown_warn_${id}_${s.tick}`,
          type: 'threat',
          title: `${structName}: Stage Loss Imminent`,
          body: `[ARIA] URGENT — Stage "${stageName}" will be lost in ${ticksRemaining} ticks. This is your final warning.`,
          choices: [{ id: 'acknowledge', label: 'Understood' }],
        },
        tick: s.tick,
      },
    });
  }

  for (const { id, stageName } of megaResult.stageLost) {
    const structName = MEGASTRUCTURE_DEFS[id].name;
    sendMessage({
      type: 'sim:narrative_event',
      payload: {
        event: {
          id: `stage_lost_${id}_${s.tick}`,
          type: 'threat',
          title: `${structName}: Stage Lost`,
          body: `[ARIA] Stage "${stageName}" has been lost due to sustained critically low progress. You may restart this stage by paying the construction costs again.`,
          choices: [{ id: 'acknowledge', label: 'Acknowledged' }],
        },
        tick: s.tick,
      },
    });
    sendMessage({
      type: 'sim:megastructure_state',
      payload: { projects: getMegaSnapshot(), tick: s.tick },
    });
  }

  if (s.tick % MEGASTRUCTURE_BROADCAST_INTERVAL === 0) {
    sendMessage({
      type: 'sim:megastructure_state',
      payload: { projects: getMegaSnapshot(), tick: s.tick },
    });
  }
}
