export const TASK_TYPES = {
  MINE: 0,
  HAUL: 1,
  EXPLORE: 2,
  TRANSFER: 3, // Inter-base resource transfer
  TRADE_DELIVERY: 4, // Market sale delivery to faction base
  CONSTRUCT: 5, // Engineer: build a structure at a construction site
} as const;

export const TASK_STATUS = {
  PENDING: 0,
  CLAIMED: 1,
  IN_PROGRESS: 2,
  COMPLETED: 3,
  FAILED: 4,
} as const;

export interface Task {
  taskId: number;
  taskType: number;
  targetEid: number; // asteroid entity id
  targetX: number;
  targetY: number;
  targetZ: number;
  destX: number; // delivery destination
  destY: number;
  destZ: number;
  priority: number;
  status: number;
  claimedBy: number; // robot eid, -1 if unclaimed
  source: 'manual' | 'auto'; // who generated this task
  preferredRobotEid: number; // robot eid player targeted, -1 if none
}

let nextTaskId = 1;

export class TaskQueue {
  private tasks: Map<number, Task> = new Map();

  /** Robot EIDs (and task types) that completed tasks since last drain. */
  private recentCompletions: { robotEid: number; taskType: number }[] = [];

  /** Drain and return completions since last call. */
  drainCompletions(): { robotEid: number; taskType: number }[] {
    const result = this.recentCompletions;
    this.recentCompletions = [];
    return result;
  }

  addTask(
    taskType: number,
    targetEid: number,
    targetX: number,
    targetY: number,
    targetZ: number,
    destX: number = 0,
    destY: number = 0,
    destZ: number = 0,
    priority: number = 1,
    source: 'manual' | 'auto' = 'manual',
    preferredRobotEid: number = -1,
  ): number {
    const taskId = nextTaskId++;
    this.tasks.set(taskId, {
      taskId,
      taskType,
      targetEid,
      targetX,
      targetY,
      targetZ,
      destX,
      destY,
      destZ,
      priority,
      status: TASK_STATUS.PENDING,
      claimedBy: -1,
      source,
      preferredRobotEid,
    });
    return taskId;
  }

  getTask(taskId: number): Task | undefined {
    return this.tasks.get(taskId);
  }

  getUnclaimedTasks(): Task[] {
    const result: Task[] = [];
    for (const task of this.tasks.values()) {
      if (task.status === TASK_STATUS.PENDING) {
        result.push(task);
      }
    }
    return result;
  }

  claimTask(taskId: number, robotEid: number): boolean {
    const task = this.tasks.get(taskId);
    if (!task || task.status !== TASK_STATUS.PENDING) return false;
    task.status = TASK_STATUS.CLAIMED;
    task.claimedBy = robotEid;
    return true;
  }

  startTask(taskId: number): void {
    const task = this.tasks.get(taskId);
    if (task && task.status === TASK_STATUS.CLAIMED) {
      task.status = TASK_STATUS.IN_PROGRESS;
    }
  }

  completeTask(taskId: number): void {
    const task = this.tasks.get(taskId);
    if (task) {
      if (task.claimedBy >= 0) {
        this.recentCompletions.push({ robotEid: task.claimedBy, taskType: task.taskType });
      }
      task.status = TASK_STATUS.COMPLETED;
      task.claimedBy = -1;
    }
  }

  failTask(taskId: number): void {
    const task = this.tasks.get(taskId);
    if (task) {
      task.status = TASK_STATUS.FAILED;
      task.claimedBy = -1;
    }
  }

  releaseTask(taskId: number): void {
    const task = this.tasks.get(taskId);
    if (task && (task.status === TASK_STATUS.CLAIMED || task.status === TASK_STATUS.IN_PROGRESS)) {
      task.status = TASK_STATUS.PENDING;
      task.claimedBy = -1;
    }
  }

  cleanup(): void {
    for (const [id, task] of this.tasks) {
      if (task.status === TASK_STATUS.COMPLETED || task.status === TASK_STATUS.FAILED) {
        this.tasks.delete(id);
      }
    }
  }

  getTasksByType(taskType: number): Task[] {
    const result: Task[] = [];
    for (const task of this.tasks.values()) {
      if (
        task.taskType === taskType &&
        task.status !== TASK_STATUS.COMPLETED &&
        task.status !== TASK_STATUS.FAILED
      ) {
        result.push(task);
      }
    }
    return result;
  }

  get pendingCount(): number {
    let count = 0;
    for (const task of this.tasks.values()) {
      if (task.status === TASK_STATUS.PENDING) count++;
    }
    return count;
  }

  get totalCount(): number {
    return this.tasks.size;
  }
}
