/**
 * Robot Comms Generator — template-based message generation for the comms feed.
 *
 * Messages are short radio transmissions from robots, scaling in complexity
 * with experience (tasks completed). Rate-limited to prevent spam.
 */

import type { CultureTrait } from './culture';
import { TRAIT_METADATA, type IntelligenceTier, INTELLIGENCE_TIERS } from './culture';

// ── Rate limiting ────────────────────────────────────────────────────────────

/** Minimum ticks between comms messages (≈30s at 60 tps). */
export const COMMS_COOLDOWN_TICKS = 1800;

let lastCommsTick = -Infinity;

/** Check if enough time has passed to send a new comms message. */
export function canSendComms(tick: number): boolean {
  return tick - lastCommsTick >= COMMS_COOLDOWN_TICKS;
}

/** Mark that a comms message was sent at this tick. */
export function markCommsSent(tick: number): void {
  lastCommsTick = tick;
}

/** Reset rate-limiting state (for tests and save/load). */
export function resetCommsState(): void {
  lastCommsTick = -Infinity;
}

// ── Experience tiers (legacy, kept for backward compat) ─────────────────────

type ExperienceTier = 'novice' | 'experienced' | 'veteran';

export function getExperienceTier(tasksCompleted: number): ExperienceTier {
  if (tasksCompleted >= 50) return 'veteran';
  if (tasksCompleted >= 10) return 'experienced';
  return 'novice';
}

// ── Intelligence tier → template pool mapping ───────────────────────────────

/**
 * Map a 5-tier intelligence level to a template pool key.
 * Automaton/Responsive → novice, Adaptive → experienced,
 * Sentient → veteran, Emergent → emergent.
 */
function tierToPool(tier: IntelligenceTier): 'novice' | 'experienced' | 'veteran' | 'emergent' {
  switch (tier) {
    case INTELLIGENCE_TIERS.AUTOMATON:
    case INTELLIGENCE_TIERS.RESPONSIVE:
      return 'novice';
    case INTELLIGENCE_TIERS.ADAPTIVE:
      return 'experienced';
    case INTELLIGENCE_TIERS.SENTIENT:
      return 'veteran';
    case INTELLIGENCE_TIERS.EMERGENT:
      return 'emergent';
    default:
      return 'novice';
  }
}

