// ── Template selection ───────────────────────────────────────────────────────

/** Simple seeded pick from an array. */
function pick<T>(arr: T[], seed: number): T {
  return arr[Math.abs(seed) % arr.length];
}

function fillTemplate(template: string, vars: Record<string, string | number>): string {
  let result = template;
  for (const [key, val] of Object.entries(vars)) {
    result = result.replaceAll(`{${key}}`, String(val));
  }
  return result;
}

/** Resolve pool key: use intelligence tier when provided, else legacy experience tier. */
function resolvePool(tasksCompleted: number, intelligenceTier?: IntelligenceTier): 'novice' | 'experienced' | 'veteran' | 'emergent' {
  if (intelligenceTier !== undefined) return tierToPool(intelligenceTier);
  return getExperienceTier(tasksCompleted);
}

// ── Public generators ────────────────────────────────────────────────────────

export function generateMilestoneComms(
  robotName: string,
  tasksCompleted: number,
  seed: number,
  intelligenceTier?: IntelligenceTier,
): string {
  const pool = resolvePool(tasksCompleted, intelligenceTier);
  const template = pick(MILESTONE_TEMPLATES[pool], seed);
  return fillTemplate(template, { name: robotName, tasks: tasksCompleted });
}

