export function generateCultureTraitComms(
  robotName: string,
  tasksCompleted: number,
  trait: CultureTrait,
  seed: number,
  intelligenceTier?: IntelligenceTier,
): string {
  const templates = CULTURE_TRAIT_TEMPLATES[trait];
  if (!templates) {
    const info = TRAIT_METADATA[trait];
    return `${robotName}: something has changed in the fleet. ${info?.name ?? 'Unknown'} trait emerging.`;
  }
  const pool = resolvePool(tasksCompleted, intelligenceTier);
  const template = pick(templates[pool], seed);
  return fillTemplate(template, { name: robotName });
}

