import { query, hasComponent } from 'bitecs';
import type { World } from '../../core/ecs';
import {
  Position,
  RobotTag,
  RobotType,
  RobotState,
  ResearchOutput,
  BaseStationTag,
  AsteroidHealth,
  AsteroidSize,
  AsteroidRichness,
  AsteroidHusk,
} from '../components';
import { ROBOT_TYPES } from '../robotProfiles';
import type { TaskQueue } from '../taskQueue';
import { TASK_TYPES } from '../taskQueue';
import { TechState, getEfficiencyMultiplier } from '../techTree';
import { asteroidMaterialScore } from '../materialPriorities';
import type { MaterialWeights } from '../materialPriorities';

/** Base RP/s from crew observation — always active, even before buildings/robots */
export const BASE_RESEARCH_RATE = 0.04;

/** Returns current research points per second from all actively studying robots */
export function computeResearchRate(world: World, techState?: TechState, buildingResearchBonus = 0): number {
  const researchers = query(world, [RobotTag, RobotType, ResearchOutput, RobotState]);
  let rate = 0;
  for (let i = 0; i < researchers.length; i++) {
    const eid = researchers[i];
    if (RobotType.type[eid] === ROBOT_TYPES.RESEARCHER && ResearchOutput.isStudying[eid] === 1) {
      rate += ResearchOutput.pointsPerSecond[eid];
    }
  }
  const researchMult = techState ? getEfficiencyMultiplier(techState, 'research') : 1;
  return rate * researchMult + buildingResearchBonus + BASE_RESEARCH_RATE;
}

export function taskGenerationSystem(
  world: World,
  _dt: number,
  taskQueue: TaskQueue,
  asteroidEntities: number[],
  deepCoreCount: number = 0,
  rng: () => number = Math.random,
  materialWeights?: MaterialWeights,
): void {
  if (taskQueue.pendingCount < 5 && asteroidEntities.length > 0) {
    // Find the nearest base position for distance weighting
    const allBases = query(world, [BaseStationTag, Position]);
    let baseX = 0,
      baseY = 0,
      baseZ = 0;
    if (allBases.length > 0) {
      baseX = Position.x[allBases[0]];
      baseY = Position.y[allBases[0]];
      baseZ = Position.z[allBases[0]];
    }

    const maxNew = Math.min(5 - taskQueue.pendingCount, 10);
    for (let i = 0; i < maxNew; i++) {
      // Weighted asteroid selection: pick 5 random candidates, choose the best.
      // Score combines proximity (1/distance²) and material utility (from player weights).
      let bestEid = -1;
      let bestScore = -Infinity;
      const candidates = Math.min(5, asteroidEntities.length);
      for (let c = 0; c < candidates; c++) {
        const idx = Math.floor(rng() * asteroidEntities.length);
        const cEid = asteroidEntities[idx];
        const dx = Position.x[cEid] - baseX;
        const dy = Position.y[cEid] - baseY;
        const dz = Position.z[cEid] - baseZ;
        const d2 = dx * dx + dy * dy + dz * dz;
        // Proximity score: closer is better (inverse squared distance)
        const proximityScore = 1 / (1 + d2);
        // Material utility: boost asteroids rich in prioritized minerals
        const materialScore = materialWeights ? asteroidMaterialScore(cEid, materialWeights) : 1.0;
        const score = proximityScore * materialScore;
        if (score > bestScore) {
          bestScore = score;
          bestEid = cEid;
        }
      }
      if (bestEid < 0) continue;

      const aEid = bestEid;
      const isHusk = hasComponent(world, aEid, AsteroidHusk);

      // Skip husks unless there are Deep Core robots to mine them
      if (isHusk && deepCoreCount === 0) continue;
      // Skip depleted non-husks and tiny asteroids
      if (!isHusk && (AsteroidHealth.current[aEid] <= 0 || AsteroidSize.radius[aEid] <= 8))
        continue;

      // Priority = estimated yield (health × richness) × material utility, clamped
      const richness = AsteroidRichness.multiplier[aEid] || 1.0;
      const materialMult = materialWeights ? asteroidMaterialScore(aEid, materialWeights) : 1.0;
      const yieldEstimate = AsteroidHealth.current[aEid] * richness * materialMult;
      const priority = Math.min(10, Math.max(1, yieldEstimate / 1000));

      taskQueue.addTask(
        TASK_TYPES.MINE,
        aEid,
        Position.x[aEid],
        Position.y[aEid],
        Position.z[aEid],
        0,
        0,
        0,
        priority,
      );
    }
  }
  taskQueue.cleanup();
}
