/**
 * Transit message handlers (main → worker).
 */
import { workerState, sendMessage } from '../state';
import { dispatchCargo, getDestination, snapshotTransit, TICKS_PER_GAME_DAY } from '../../transit';
import { Orbit } from '../../components';
import { addMessage, getInboxSnapshot } from '../../inbox/inboxStore';
import type { CargoManifest } from '../../transit';

let nextInboxId = 93500; // separate range from transit phase arrival messages

export function handleDispatchCargo(payload: {
  destinationId: string;
  cargo: CargoManifest;
}): void {
  const s = workerState;
  if (s.baseEidGlobal < 0) return;

  // Player's orbital angle — use the base station's orbit angle if it has one,
  // otherwise approximate from position.
  const playerAngle = Orbit.angle[s.baseEidGlobal] || 0;

  const result = dispatchCargo(
    s.transitState,
    payload.destinationId,
    payload.cargo,
    s.baseEidGlobal,
    playerAngle,
    s.tick,
  );

  if (!result.ok) {
    sendMessage({
      type: 'sim:error',
      payload: { message: `Dispatch failed: ${result.error}`, tick: s.tick },
    });
    return;
  }

  const shipment = result.shipment!;
  const dest = getDestination(payload.destinationId);
  const destName = dest?.name ?? payload.destinationId;
  const transitDays = Math.round(
    (shipment.arrivalTick - shipment.departureTick) / TICKS_PER_GAME_DAY,
  );

  // Build cargo summary
  const cargoLines: string[] = [];
  for (const [resource, amount] of Object.entries(shipment.cargo)) {
    if ((amount as number) > 0) cargoLines.push(`${amount} ${resource}`);
  }
  const cargoSummary = cargoLines.join(', ');

  // ARIA notification for departure with destination flavor
  const flavorLine = dest?.dispatchFlavor ? ` ${dest.dispatchFlavor}` : '';

  addMessage({
    id: nextInboxId++,
    factionId: null,
    senderName: 'ARIA',
    type: 'aria_auto',
    subject: `Cargo dispatched to ${destName}`,
    body: `Shipment en route to ${destName}. Cargo: ${cargoSummary}. Estimated transit time: ${transitDays} game-days. Expected payment on arrival: ${shipment.payment.toFixed(1)} credits.${flavorLine}`,
    priority: 'normal',
    tick: s.tick,
    triaged: true,
    triageResult: 'relevant',
    read: false,
  });
  sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });

  // Immediately broadcast updated transit state
  const playerAngleForSnapshot = Orbit.angle[s.baseEidGlobal] || 0;
  sendMessage({
    type: 'sim:transit_state',
    payload: { ...snapshotTransit(s.transitState, playerAngleForSnapshot), tick: s.tick },
  });
}
