/**
 * Faction Serialization
 *
 * Serialize, deserialize, and snapshot faction system state.
 */

import {
  FACTION_DEFS,
  FACTION_COUNT,
  makeDefaultPairRecord,
  dispositionLabel,
} from './factionDefs.js';
import type {
  FactionId,
  FactionState,
  FactionSystemState,
  FactionBase,
  FactionTradeWindow,
  FactionPairKey,
  Disposition,
} from './factionDefs.js';

// ── Snapshot ───────────────────────────────────────────────────────────────────

export interface FactionSnapshot {
  id: FactionId;
  name: string;
  color: string;
  tagline: string;
  base: FactionBase;
  disposition: Disposition;
  dispositionLabel: string;
  /** Change in disposition since last broadcast (for delta flash UI) */
  dispositionDelta: number;
  robotCount: number;
  resources: { iron: number; carbon: number; silicon: number };
  goal: FactionState['goal'];
  contestingAsteroid: number;
  recentEvents: Array<{ text: string; tick: number }>;
  /** Territory claim radius around the faction base (world units) */
  territoryRadius: number;
  /** Active trade window, or null if none */
  tradeWindow: FactionTradeWindow | null;
}

export interface InterFactionSnapshot {
  /** Pairwise dispositions keyed by "low-high" faction IDs */
  dispositions: Record<FactionPairKey, number>;
}

// ── Serialization ─────────────────────────────────────────────────────────────

export interface SerializedFactionState {
  id: FactionId;
  disposition: Disposition;
  resources: { iron: number; carbon: number; silicon: number };
  robotCount: number;
  goal: 'mine' | 'expand' | 'study_anomaly' | 'idle';
  contestingAsteroid: number;
  decisionTimer: number;
  territoryRadius: number;
  recentEvents: Array<{ text: string; tick: number }>;
  lastDispositionEventTick?: number;
  tradeWindow?: FactionTradeWindow | null;
  lastTradeWindowTick?: number;
}

export interface SerializedFactionSystemState {
  factions: SerializedFactionState[];
  interFactionDispositions?: Record<FactionPairKey, number>;
  lastDisputeTick?: Record<FactionPairKey, number>;
}

export function serializeFactionSystem(state: FactionSystemState): SerializedFactionSystemState {
  return {
    factions: state.factions.map((f) => ({
      id: f.id,
      disposition: f.disposition,
      resources: { ...f.resources },
      robotCount: f.robotCount,
      goal: f.goal,
      contestingAsteroid: f.contestingAsteroid,
      decisionTimer: f.decisionTimer,
      territoryRadius: f.territoryRadius,
      recentEvents: f.recentEvents.slice(-20), // keep last 20 events
      lastDispositionEventTick: f.lastDispositionEventTick,
      tradeWindow: f.tradeWindow ? { ...f.tradeWindow } : null,
      lastTradeWindowTick: f.lastTradeWindowTick,
    })),
    interFactionDispositions: { ...state.interFactionDispositions },
    lastDisputeTick: { ...state.lastDisputeTick },
  };
}

export function deserializeFactionSystem(
  data: SerializedFactionSystemState,
  beltInnerRadius: number,
  beltOuterRadius: number,
): FactionSystemState {
  const midR = (beltInnerRadius + beltOuterRadius) * 0.55;
  const angleStep = (2 * Math.PI) / FACTION_COUNT;
  const angleOffset = Math.PI / 3;

  // Restore saved factions and add any new ones missing from old saves
  const savedById = new Map(data.factions.map((f) => [f.id, f]));
  const factions: FactionState[] = FACTION_DEFS.map((def) => {
    const angle = angleOffset + def.id * angleStep;
    const base = { x: Math.cos(angle) * midR, y: 0, z: Math.sin(angle) * midR };
    const saved = savedById.get(def.id);
    if (saved) {
      return {
        id: saved.id,
        base,
        disposition: saved.disposition,
        resources: { ...saved.resources },
        robotCount: saved.robotCount,
        goal: saved.goal,
        contestingAsteroid: saved.contestingAsteroid,
        decisionTimer: saved.decisionTimer,
        territoryRadius: saved.territoryRadius,
        recentEvents: saved.recentEvents,
        lastDispositionEventTick: saved.lastDispositionEventTick ?? -Infinity,
        tradeWindow: saved.tradeWindow ?? null,
        lastTradeWindowTick: saved.lastTradeWindowTick ?? -Infinity,
      };
    }
    // New faction not in old save — create with defaults
    return {
      id: def.id,
      base,
      resources: { iron: 500, carbon: 200, silicon: 150 },
      robotCount: 5 + def.id * 2,
      disposition: 0,
      goal: 'mine' as const,
      contestingAsteroid: -1,
      decisionTimer: 60 * (10 + def.id * 7),
      territoryRadius: 8000 + (def.id % 3) * 2000,
      recentEvents: [],
      lastDispositionEventTick: -Infinity,
      tradeWindow: null,
      lastTradeWindowTick: -Infinity,
    };
  });

  // Merge saved inter-faction data with defaults for new pairs
  const defaultDispositions = makeDefaultPairRecord(0);
  const defaultDisputeTicks = makeDefaultPairRecord(-Infinity);
  if (data.interFactionDispositions) {
    for (const [k, v] of Object.entries(data.interFactionDispositions)) {
      if (k in defaultDispositions) (defaultDispositions as Record<string, number>)[k] = v;
    }
  }
  if (data.lastDisputeTick) {
    for (const [k, v] of Object.entries(data.lastDisputeTick)) {
      if (k in defaultDisputeTicks) (defaultDisputeTicks as Record<string, number>)[k] = v;
    }
  }

  return {
    factions,
    initialized: true,
    interFactionDispositions: defaultDispositions,
    lastDisputeTick: defaultDisputeTicks,
    lastBroadcastDispositions: factions.map((f) => f.disposition),
  };
}

export function snapshotFactions(state: FactionSystemState): FactionSnapshot[] {
  const snapshots = state.factions.map((f, i) => {
    const def = FACTION_DEFS[f.id];
    const prevDisp = state.lastBroadcastDispositions[i] ?? 0;
    const delta = Math.round(f.disposition - prevDisp);
    return {
      id: f.id,
      name: def.name,
      color: def.color,
      tagline: def.tagline,
      base: { ...f.base },
      disposition: f.disposition,
      dispositionLabel: dispositionLabel(f.disposition),
      dispositionDelta: delta,
      robotCount: f.robotCount,
      resources: { ...f.resources },
      goal: f.goal,
      contestingAsteroid: f.contestingAsteroid,
      recentEvents: [...f.recentEvents],
      territoryRadius: f.territoryRadius,
      tradeWindow: f.tradeWindow ? { ...f.tradeWindow } : null,
    };
  });
  // Update last broadcast dispositions for next delta calculation
  state.lastBroadcastDispositions = state.factions.map((f) => f.disposition);
  return snapshots;
}

export function snapshotInterFaction(state: FactionSystemState): InterFactionSnapshot {
  return {
    dispositions: { ...state.interFactionDispositions },
  };
}
