/**
 * Automation tick phase: auto-queues, supply chains, sectors, and logistics.
 */
import { workerState, runSystem } from '../state';
import { tickAutoQueues, tickSupplyChain, tickSectors } from '../../automation';
import { tickLogistics } from '../../logistics';
import { getAsteroidPos, getAsteroidHealth, getAnomalyFlag, getAsteroidMinerals, getRawStorage } from './helpers';

export function tickAutomationPhase(): void {
  const s = workerState;

  runSystem('autoQueues', () => {
    tickAutoQueues(
      s.autoQueueState,
      s.asteroidEntities,
      getAsteroidPos,
      getAsteroidHealth,
      getAsteroidMinerals,
      getAnomalyFlag,
      s.taskQueue!,
      s.eventRng,
    );
  });

  if (s._unlockedTechIds.has('automated_logistics')) {
    runSystem('supplyChain', () => {
      tickSupplyChain(
        s.supplyChainState,
        getRawStorage(),
        s.asteroidEntities,
        getAsteroidPos,
        getAsteroidHealth,
        getAsteroidMinerals,
        s.taskQueue!,
      );
    });
  }

  if (s._unlockedTechIds.has('sector_mapping')) {
    runSystem('sectors', () => {
      tickSectors(
        s.sectorState,
        s.asteroidEntities,
        getAsteroidPos,
        getAsteroidHealth,
        getAnomalyFlag,
        s.taskQueue!,
        s.eventRng,
      );
    });
  }

  runSystem('logistics', () => {
    tickLogistics(s.logisticsState, s.tick, s.taskQueue!);
  });
}
