import {
  Position,
  Inventory,
  RobotState,
  TaskRef,
  PathTarget,
  Storage,
} from '../components';
import type { TaskQueue } from '../taskQueue';
import { ROBOT_STATES } from '../robotCreation';
import { transferInventoryToStorage } from '../robotInventory';
import { MINERAL_FIELDS } from '../minerals';
import { distanceTo, BASE_PROXIMITY } from './types';

export function handleTransferringRobot(
  eid: number,
  taskQueue: TaskQueue,
  allBases: ArrayLike<number>,
  haulerCapMult: number,
): void {
  const taskId = TaskRef.taskId[eid];
  const task = taskId >= 0 ? taskQueue.getTask(taskId) : undefined;
  if (!task) {
    RobotState.subState[eid] = 0;
    RobotState.state[eid] = ROBOT_STATES.IDLE;
    return;
  }

  if (RobotState.subState[eid] === 0) {
    // Phase 0: at source base — load resources
    const distToSrc = distanceTo(eid, task.targetX, task.targetY, task.targetZ);
    if (distToSrc < BASE_PROXIMITY) {
      // Find source base entity (nearest to target position)
      let srcBeid = -1;
      let minD2 = Infinity;
      for (let b = 0; b < allBases.length; b++) {
        const beid = allBases[b];
        const d2 =
          (Position.x[beid] - task.targetX) ** 2 +
          (Position.y[beid] - task.targetY) ** 2 +
          (Position.z[beid] - task.targetZ) ** 2;
        if (d2 < minD2) {
          minD2 = d2;
          srcBeid = beid;
        }
      }

      if (srcBeid >= 0) {
        // Load up to robot capacity from source storage (all resource types)
        const cap = Inventory.capacity[eid] * haulerCapMult;
        let totalAvail = 0;
        for (const m of MINERAL_FIELDS) totalAvail += Storage[m][srcBeid];

        if (totalAvail > 0) {
          const ratio = Math.min(cap, totalAvail) / totalAvail;
          for (const m of MINERAL_FIELDS) {
            const load = Storage[m][srcBeid] * ratio;
            Storage[m][srcBeid] -= load;
            Inventory[m][eid] = load;
          }
          Inventory.used[eid] = Math.min(cap, totalAvail);
        }
      }

      // Move to destination
      RobotState.subState[eid] = 1;
      PathTarget.x[eid] = task.destX;
      PathTarget.y[eid] = task.destY;
      PathTarget.z[eid] = task.destZ;
      RobotState.state[eid] = ROBOT_STATES.MOVING_TO;
    }
  } else {
    // Phase 1: at destination base — unload resources
    const distToDst = distanceTo(eid, task.destX, task.destY, task.destZ);
    if (distToDst < BASE_PROXIMITY) {
      // Find destination base entity
      let dstBeid = -1;
      let minD2 = Infinity;
      for (let b = 0; b < allBases.length; b++) {
        const beid = allBases[b];
        const d2 =
          (Position.x[beid] - task.destX) ** 2 +
          (Position.y[beid] - task.destY) ** 2 +
          (Position.z[beid] - task.destZ) ** 2;
        if (d2 < minD2) {
          minD2 = d2;
          dstBeid = beid;
        }
      }

      if (dstBeid >= 0) {
        transferInventoryToStorage(eid, dstBeid);
      }

      taskQueue.completeTask(taskId);
      TaskRef.taskId[eid] = -1;
      RobotState.subState[eid] = 0;
      RobotState.state[eid] = ROBOT_STATES.IDLE;
    }
  }
}
