import { Inventory, Storage } from './components';
import { MINERAL_FIELDS } from './minerals';

/** Transfer all inventory from robot to a base station's storage and clear the robot's inventory. */
export function transferInventoryToStorage(robotEid: number, baseEid: number): void {
  for (const m of MINERAL_FIELDS) {
    Storage[m][baseEid] += Inventory[m][robotEid];
    Inventory[m][robotEid] = 0;
  }
  Inventory.used[robotEid] = 0;
}
