/**
 * World initialization: handles sim:init message.
 * Creates ECS world, generates asteroid field, spawns initial entities.
 */
import { createWorld } from 'bitecs';
import { SpatialGrid } from '../spatialGrid';
import { TaskQueue } from '../taskQueue';
import { generateInitialField, DEFAULT_FIELD_CONFIG } from '../asteroidGen';
import type { FieldConfig } from '../asteroidGen';
import { createTechState } from '../techTree';
import { createRefineryState } from '../refining';
import { createFactoryState } from '../robotFactory';
import { createBaseBuildingState } from '../buildings';
import { createAutoQueueState, createSupplyChainState, createSectorState } from '../automation';
import { createLogisticsState } from '../logistics';
import { createMegastructureState } from '../megastructures';
import { createRobot, createBaseStation } from '../robotSystems';
import { ROBOT_TYPES } from '../robotProfiles';
import { createFactionSystem } from '../factions/factionSystem';
import { mulberry32 } from '../prng';
import { Storage } from '../components';
import { legacyMineralMultiplier } from '../legacy';
import { getDifficultySettings } from '../difficulty';
import type { DifficultyMode } from '../difficulty';
import { workerState, sendMessage, refreshUnlockedIds } from './state';
import { resetChorusTimer } from '../chorusClient';

/**
 * Validate the sim:init payload at the worker boundary.
 * TypeScript types do not protect at runtime — this guard catches
 * malformed payloads before they cause silent undefined behavior.
 *
 * @returns null if valid, or an error string describing the first failing field.
 */
function validateSimInitPayload(payload: unknown): string | null {
  if (payload === null || typeof payload !== 'object') {
    return `payload must be a non-null object, got ${payload === null ? 'null' : typeof payload}`;
  }
  const p = payload as Record<string, unknown>;
  if (typeof p['seed'] !== 'number' || !isFinite(p['seed'])) {
    return `payload.seed must be a finite number, got ${JSON.stringify(p['seed'])}`;
  }
  return null;
}

// Starting mineral stockpile so new players can immediately experiment with building.
const STARTING_MINERALS = {
  iron: 150,
  carbon: 60,
  silicate: 40,
  ice: 40,
  nickel: 25,
  cobalt: 10,
  platinum: 3,
};

export function handleSimInit(payload: { seed: number; legacyExpeditionCount?: number; difficultyMode?: DifficultyMode }): void {
  const validationError = validateSimInitPayload(payload);
  if (validationError) {
    sendMessage({
      type: 'sim:worker_error',
      payload: {
        message: `sim:init validation failed: ${validationError}`,
        tick: workerState.tick,
        system: 'handleSimInit:validation',
      },
    });
    return;
  }

  const s = workerState;

  s.world = createWorld();
  s.grid = new SpatialGrid(500);
  s.taskQueue = new TaskQueue();

  // Reset Phase 3 state
  s.techState = createTechState();
  s.refineryState = createRefineryState();
  s.factoryState = createFactoryState();
  s.factoryState.built = true; // factory available from start; robot_factory tech gives bonus
  s.buildingState = createBaseBuildingState();
  s._unlockedTechIds.clear();
  refreshUnlockedIds(); // sync Set with pre-unlocked techs (e.g. researcher_bots)

  // Reset Phase 4 automation state
  s.autoQueueState = createAutoQueueState();
  s.supplyChainState = createSupplyChainState();
  s.sectorState = createSectorState();

  // Reset Phase 5 logistics (re-initialized after base creation)
  s.logisticsState = createLogisticsState(-1);

  // Reset dust grid
  s.dustGrid.clear();

  // Reset megastructures
  s.megastructureState = createMegastructureState();
  s.megaRobotCapBonus = 0;
  s.megaSensorRangeMultiplier = 1;
  s.megaEnergyUnlimited = false;

  // Reset E_f (Environmental Flux) chorus state
  s.efState = null;
  s.efStatePrev = null;
  s.efValue = 0;
  s.efChorusLoreShown = false;
  resetChorusTimer();

  // Reset narrative event engine
  s.eventEngine.reset();
  s.eventRng = mulberry32(payload.seed ^ 0xdeadbeef);

  // Reset entity system
  s.entitySystem.reset();
  s.entitySystem.seed(payload.seed);

  // Apply difficulty multipliers
  const diff = getDifficultySettings(payload.difficultyMode ?? 'normal');
  s.difficultyMode = diff.mode;
  s.factionAggressionMultiplier = diff.factionAggression;

  const config: FieldConfig = {
    ...DEFAULT_FIELD_CONFIG,
    worldSeed: payload.seed,
    baseAsteroidDensity: DEFAULT_FIELD_CONFIG.baseAsteroidDensity * diff.mineralDensity,
    anomalyChance: diff.anomalyChance,
  };

  // Initialize faction system
  s.factionSystemState = createFactionSystem(config.beltInnerRadius, config.beltOuterRadius);
  s.fieldConfig = config;

  s.asteroidEntities = generateInitialField(s.world, config, s.grid, 5);

  // Create base station in the belt
  const baseCX = Math.floor(config.beltInnerRadius / config.chunkSize);
  const baseX = baseCX * config.chunkSize + config.chunkSize * 0.5;
  const baseEid = createBaseStation(s.world, baseX, 0, config.chunkSize * 0.5, s.grid);
  s.baseEidGlobal = baseEid;
  s.logisticsState = createLogisticsState(baseEid);

  // Seed starting minerals — legacy players get a bonus multiplier
  const mult = legacyMineralMultiplier(payload.legacyExpeditionCount ?? 0);
  Storage.iron[baseEid] = Math.floor(STARTING_MINERALS.iron * mult * diff.startingIronMultiplier);
  Storage.carbon[baseEid] = Math.floor(STARTING_MINERALS.carbon * mult);
  Storage.silicate[baseEid] = Math.floor(STARTING_MINERALS.silicate * mult);
  Storage.ice[baseEid] = Math.floor(STARTING_MINERALS.ice * mult);
  Storage.nickel[baseEid] = Math.floor(STARTING_MINERALS.nickel * mult);
  Storage.cobalt[baseEid] = Math.floor(STARTING_MINERALS.cobalt * mult);
  Storage.platinum[baseEid] = Math.floor(STARTING_MINERALS.platinum * mult);

  // Spawn initial robots near the base
  const initialStats = { tasksCompleted: 0, asteroidsNamed: 0, anomaliesStudied: 0, spawnTick: 0, taskHint: -1, knowledgeBoostUntil: 0, mourningUntil: 0, lastTaskTypes: [] as number[] };
  for (let i = 0; i < 3; i++) {
    const eid = createRobot(
      s.world,
      ROBOT_TYPES.MINER,
      baseX + (i - 1) * 50,
      20,
      config.chunkSize * 0.5 + 50,
      s.grid,
    );
    if (eid >= 0) s.cultureState.robotStats.set(eid, { ...initialStats });
  }
  for (let i = 0; i < 2; i++) {
    const eid = createRobot(
      s.world,
      ROBOT_TYPES.SCOUT,
      baseX + (i - 0.5) * 80,
      -20,
      config.chunkSize * 0.5 - 50,
      s.grid,
    );
    if (eid >= 0) s.cultureState.robotStats.set(eid, { ...initialStats });
  }
  for (let i = 0; i < 2; i++) {
    const eid = createRobot(
      s.world,
      ROBOT_TYPES.HAULER,
      baseX + (i - 0.5) * 60,
      0,
      config.chunkSize * 0.5 + 100,
      s.grid,
    );
    if (eid >= 0) s.cultureState.robotStats.set(eid, { ...initialStats });
  }

  sendMessage({ type: 'sim:ready' });
}
