/**
 * Robot tick phase: task generation, robot AI, movement, and death detection.
 */
import { query, hasComponent, removeEntity } from 'bitecs';
import { RobotTag, RobotType, RobotState, Position, BaseStationTag, TaskRef, Velocity, AsteroidTag, AsteroidHealth, PathTarget } from '../../components';
import { ROBOT_STATES } from '../../robotCreation';
import { workerState, runSystem, FIXED_DT, sendMessage } from '../state';
import { robotAISystem, movementSystem, taskGenerationSystem, constructionTaskGenerationSystem } from '../../robotSystems';
import { TASK_TYPES } from '../../taskQueue';
import { computeBuildingEffects } from '../../buildings';
import { getEfficiencyMultiplier, isTechUnlocked } from '../../techTree';
import type { CultureEffects } from '../../robotAI';
import { migrateRobotToLegacy, getIntelligenceTier, DRIFT_HISTORY_LENGTH } from '../../culture';
import { getActiveIsolationTraits, applyDialect } from '../../colonyDialect';
import type { IntelligenceTier } from '../../culture';
import { generateReplacementMessage } from '../../inbox/messageGenerator';
import { addMessage, getInboxSnapshot } from '../../inbox/inboxStore';
import { onAnomalyDiscovered } from './helpers';
import { canSendComms, markCommsSent, generateMilestoneComms, generateDeathComms, generateDirectiveDriftComms, generateMourningComms, generateGroupthinkComms, generateSoftAutonomyComms, MILESTONE_THRESHOLDS } from '../../commsGenerator';

export function tickRobotPhase(deepCoreCount: number, allRobots: ArrayLike<number>): void {
  const s = workerState;

  runSystem('taskGeneration', () => {
    taskGenerationSystem(
      s.world!,
      FIXED_DT,
      s.taskQueue!,
      s.asteroidEntities,
      deepCoreCount,
      s.eventRng,
      s.materialWeights,
    );
  });
  // Compute intelligence tiers for all robots
  const isResearched = (techId: string) => isTechUnlocked(s.techState, techId);
  const intelligenceTiers = new Map<number, IntelligenceTier>();
  for (let ri = 0; ri < allRobots.length; ri++) {
    const eid = allRobots[ri];
    const stats = s.cultureState.robotStats.get(eid);
    intelligenceTiers.set(eid, getIntelligenceTier(stats?.tasksCompleted ?? 0, isResearched));
  }

  const cultureEffects: CultureEffects = {
    activeTraits: s.cultureState.traits,
    autonomyScore: s.cultureState.autonomyScore,
    fleetCohesion: s.cultureState.fleetCohesion,
    isolationScore: s.cultureState.isolationScore,
    efficiencyMultipliers: s.cultureState.efficiencyMultipliers,
    glitchFlags: s.cultureState.glitchFlags,
    glitchRng: s.eventRng,
    robotStats: s.cultureState.robotStats,
    directiveDriftEids: [],
    glitchedEids: [],
    currentTick: s.tick,
    intelligenceTiers,
    efEfficiencyMult: s.efState === 'chorus' ? 1.05 : 1.0,
    activeIsolationTraitIds: new Set(
      getActiveIsolationTraits(s.cultureState.isolationScore).map((t) => t.id),
    ),
  };
  runSystem('robotAI', () => {
    const buildingEffects = s.buildingState ? computeBuildingEffects(s.buildingState) : undefined;
    const energyMult = getEfficiencyMultiplier(s.techState, 'energy_output');
    const chargeBonus = (buildingEffects?.chargeRateBonus ?? 0) * energyMult;
    robotAISystem(s.world!, FIXED_DT, s.taskQueue!, s.discoveredAnomalies, onAnomalyDiscovered, s.techState, cultureEffects, s.dustGrid, s.megaEnergyUnlimited, s.megaSensorRangeMultiplier, chargeBonus, s.buildingState);
  });

  // Generate construction tasks for buildings that need to be built
  runSystem('constructionTaskGeneration', () => {
    constructionTaskGenerationSystem(s.taskQueue!, s.buildingState);
  });

  const completions = s.taskQueue!.drainCompletions();
  const autoRedistribute = s.cultureState.traits.has('AUTONOMOUS_COLLECTIVE');
  const cohesiveFleetActive = s.cultureState.traits.has('COHESIVE_FLEET');
  for (const { robotEid, taskType } of completions) {
    const stats = s.cultureState.robotStats.get(robotEid);
    if (stats) {
      stats.tasksCompleted++;
      // Track task type history for drift specialization
      stats.lastTaskTypes.push(taskType);
      if (stats.lastTaskTypes.length > DRIFT_HISTORY_LENGTH) {
        stats.lastTaskTypes.splice(0, stats.lastTaskTypes.length - DRIFT_HISTORY_LENGTH);
      }
      // Check for milestone comms
      if (
        (MILESTONE_THRESHOLDS as readonly number[]).includes(stats.tasksCompleted) &&
        canSendComms(s.tick)
      ) {
        const name = s.cultureState.robotNames.get(robotEid) ?? `Robot-${robotEid}`;
        const msg = generateMilestoneComms(name, stats.tasksCompleted, robotEid ^ s.tick);
        markCommsSent(s.tick);
        sendMessage({
          type: 'sim:comms_message',
          payload: { robotEid, robotName: name, message: applyDialect(msg, s.cultureState.isolationScore), category: 'milestone', tick: s.tick },
        });
      }
    }
    // COHESIVE_FLEET: knowledge cascade — anomaly study completion boosts nearby robots
    if (cohesiveFleetActive && taskType === TASK_TYPES.EXPLORE) {
      const KNOWLEDGE_RADIUS_SQ = 1200 * 1200;
      const KNOWLEDGE_BOOST_DURATION = 2000; // ticks
      const rx = Position.x[robotEid];
      const ry = Position.y[robotEid];
      const rz = Position.z[robotEid];
      for (let ri = 0; ri < allRobots.length; ri++) {
        const other = allRobots[ri];
        if (other === robotEid) continue;
        const dx = Position.x[other] - rx;
        const dy = Position.y[other] - ry;
        const dz = Position.z[other] - rz;
        if (dx * dx + dy * dy + dz * dz < KNOWLEDGE_RADIUS_SQ) {
          const otherStats = s.cultureState.robotStats.get(other);
          if (otherStats) otherStats.knowledgeBoostUntil = s.tick + KNOWLEDGE_BOOST_DURATION;
        }
      }
    }
    // Auto-redistribution: share task knowledge with nearby idle robots
    if (autoRedistribute) {
      const rx = Position.x[robotEid];
      const ry = Position.y[robotEid];
      const rz = Position.z[robotEid];
      const REDISTRIBUTION_RADIUS_SQ = 1500 * 1500;
      for (let ri = 0; ri < allRobots.length; ri++) {
        const other = allRobots[ri];
        if (other === robotEid) continue;
        if (RobotState.state[other] !== ROBOT_STATES.IDLE) continue;
        const dx = Position.x[other] - rx;
        const dy = Position.y[other] - ry;
        const dz = Position.z[other] - rz;
        if (dx * dx + dy * dy + dz * dz < REDISTRIBUTION_RADIUS_SQ) {
          const otherStats = s.cultureState.robotStats.get(other);
          if (otherStats) otherStats.taskHint = taskType;
        }
      }
    }
  }

  // Directive drift comms
  for (const driftEid of cultureEffects.directiveDriftEids) {
    if (canSendComms(s.tick)) {
      const name = s.cultureState.robotNames.get(driftEid) ?? `Robot-${driftEid}`;
      const driftStats = s.cultureState.robotStats.get(driftEid);
      const msg = generateDirectiveDriftComms(name, driftStats?.tasksCompleted ?? 0, driftEid ^ s.tick);
      markCommsSent(s.tick);
      sendMessage({
        type: 'sim:comms_message',
        payload: { robotEid: driftEid, robotName: name, message: applyDialect(msg, s.cultureState.isolationScore), category: 'directive_drift', tick: s.tick },
      });
    }
  }

  // COHESIVE_FLEET: groupthink cascade — when a robot glitches at high cohesion,
  // nearby robots may also glitch. Each hop halves the probability.
  if (cohesiveFleetActive && s.cultureState.fleetCohesion >= 85 && cultureEffects.glitchedEids.length > 0) {
    const GROUPTHINK_RADIUS_SQ = 1000 * 1000;
    const cascadeQueue: Array<{ eid: number; probability: number }> = [];
    for (const srcEid of cultureEffects.glitchedEids) {
      cascadeQueue.push({ eid: srcEid, probability: 0.3 });
    }
    const alreadyGlitched = new Set(cultureEffects.glitchedEids);
    while (cascadeQueue.length > 0) {
      const { eid: srcEid, probability } = cascadeQueue.shift()!;
      const sx = Position.x[srcEid];
      const sy = Position.y[srcEid];
      const sz = Position.z[srcEid];
      for (let ri = 0; ri < allRobots.length; ri++) {
        const other = allRobots[ri];
        if (alreadyGlitched.has(other)) continue;
        if (RobotState.state[other] === ROBOT_STATES.IDLE ||
            RobotState.state[other] === ROBOT_STATES.BROKEN ||
            RobotState.state[other] === ROBOT_STATES.CHARGING ||
            RobotState.state[other] === ROBOT_STATES.RETURNING) continue;
        const dx = Position.x[other] - sx;
        const dy = Position.y[other] - sy;
        const dz = Position.z[other] - sz;
        if (dx * dx + dy * dy + dz * dz >= GROUPTHINK_RADIUS_SQ) continue;
        if (s.eventRng() < probability) {
          // Glitch this robot
          const taskId = TaskRef.taskId[other];
          if (taskId >= 0) {
            s.taskQueue!.failTask(taskId);
            TaskRef.taskId[other] = -1;
          }
          Velocity.x[other] = 0;
          Velocity.y[other] = 0;
          Velocity.z[other] = 0;
          RobotState.state[other] = ROBOT_STATES.IDLE;
          RobotState.stateTimer[other] = 0;
          alreadyGlitched.add(other);
          // Chain: next hop at half probability
          if (probability * 0.5 >= 0.01) {
            cascadeQueue.push({ eid: other, probability: probability * 0.5 });
          }
        }
      }
    }
    // Groupthink comms
    if (alreadyGlitched.size > cultureEffects.glitchedEids.length && canSendComms(s.tick)) {
      const msg = generateGroupthinkComms(alreadyGlitched.size, s.tick);
      markCommsSent(s.tick);
      sendMessage({
        type: 'sim:comms_message',
        payload: { robotEid: cultureEffects.glitchedEids[0], robotName: 'Fleet', message: applyDialect(msg, s.cultureState.isolationScore), category: 'groupthink', tick: s.tick },
      });
    }
  }

  // ISOLATED_CULTURE: soft autonomy — distant robots may self-assign to nearby asteroids
  if (
    s.cultureState.traits.has('ISOLATED_CULTURE') &&
    s.cultureState.isolationScore >= 75 &&
    s.tick > 0 &&
    s.tick % 1000 === 0
  ) {
    const softAutonomyBases = query(s.world!, [BaseStationTag, Position]);
    const asteroidEids = query(s.world!, [AsteroidTag, Position, AsteroidHealth]);
    for (let ri = 0; ri < allRobots.length; ri++) {
      const eid = allRobots[ri];
      if (RobotState.state[eid] !== ROBOT_STATES.IDLE) continue;
      // Find nearest base
      let nearestBaseDist = Infinity;
      for (let b = 0; b < softAutonomyBases.length; b++) {
        const beid = softAutonomyBases[b];
        const dx = Position.x[eid] - Position.x[beid];
        const dy = Position.y[eid] - Position.y[beid];
        const dz = Position.z[eid] - Position.z[beid];
        const d = Math.sqrt(dx * dx + dy * dy + dz * dz);
        if (d < nearestBaseDist) nearestBaseDist = d;
      }
      if (nearestBaseDist <= 4000) continue;
      // 5% chance per 1000-tick check
      if (s.eventRng() >= 0.05) continue;
      // Find nearest unworked asteroid (health > 0)
      let bestAsteroid = -1;
      let bestDist = Infinity;
      for (let ai = 0; ai < asteroidEids.length; ai++) {
        const aeid = asteroidEids[ai];
        if (AsteroidHealth.current[aeid] <= 0) continue;
        const dx = Position.x[eid] - Position.x[aeid];
        const dy = Position.y[eid] - Position.y[aeid];
        const dz = Position.z[eid] - Position.z[aeid];
        const d = dx * dx + dy * dy + dz * dz;
        if (d < bestDist) {
          bestDist = d;
          bestAsteroid = aeid;
        }
      }
      if (bestAsteroid >= 0) {
        // Self-assign: move to the asteroid
        RobotState.state[eid] = ROBOT_STATES.MOVING_TO;
        PathTarget.x[eid] = Position.x[bestAsteroid];
        PathTarget.y[eid] = Position.y[bestAsteroid];
        PathTarget.z[eid] = Position.z[bestAsteroid];
        // Comms
        if (canSendComms(s.tick)) {
          const name = s.cultureState.robotNames.get(eid) ?? `Robot-${eid}`;
          const robotStats = s.cultureState.robotStats.get(eid);
          const msg = generateSoftAutonomyComms(name, robotStats?.tasksCompleted ?? 0, eid ^ s.tick);
          markCommsSent(s.tick);
          sendMessage({
            type: 'sim:comms_message',
            payload: { robotEid: eid, robotName: name, message: applyDialect(msg, s.cultureState.isolationScore), category: 'soft_autonomy', tick: s.tick },
          });
        }
      }
    }
  }

  runSystem('movement', () => {
    const bx = s.baseEidGlobal >= 0 ? Position.x[s.baseEidGlobal] : 0;
    const bz = s.baseEidGlobal >= 0 ? Position.z[s.baseEidGlobal] : 0;
    movementSystem(s.world!, FIXED_DT, s.techState, bx, bz);
  });

  const DEATH_RADIUS_SQ = 500 * 500;
  const allBases = query(s.world!, [BaseStationTag, Position]);
  for (let ri = 0; ri < allRobots.length; ri++) {
    const eid = allRobots[ri];
    if (RobotState.state[eid] !== ROBOT_STATES.BROKEN) continue;
    let nearBase = false;
    for (let b = 0; b < allBases.length; b++) {
      const beid = allBases[b];
      const dx = Position.x[eid] - Position.x[beid];
      const dy = Position.y[eid] - Position.y[beid];
      const dz = Position.z[eid] - Position.z[beid];
      if (dx * dx + dy * dy + dz * dz < DEATH_RADIUS_SQ) {
        nearBase = true;
        break;
      }
    }
    if (!nearBase) {
      const deadName = s.cultureState.robotNames.get(eid) ?? `Robot-${eid}`;
      const legacy = migrateRobotToLegacy(s.cultureState, eid, s.tick, RobotType.type[eid]);
      if (s.cultureState.fleetCohesion >= 30) {
        const msg = generateReplacementMessage(legacy, s.tick);
        addMessage(msg);
        sendMessage({ type: 'sim:inbox_snapshot', payload: getInboxSnapshot(s.tick) });
      }
      // COHESIVE_FLEET: collective mourning — nearby robots suffer efficiency penalty
      if (cohesiveFleetActive) {
        const MOURNING_DURATION = 3000; // ticks
        const mourningRadius = s.cultureState.fleetCohesion >= 90 ? 4000 : 2000;
        const mourningRadiusSq = mourningRadius * mourningRadius;
        const deadX = Position.x[eid];
        const deadY = Position.y[eid];
        const deadZ = Position.z[eid];
        for (let oi = 0; oi < allRobots.length; oi++) {
          const other = allRobots[oi];
          if (other === eid) continue;
          const dx = Position.x[other] - deadX;
          const dy = Position.y[other] - deadY;
          const dz = Position.z[other] - deadZ;
          if (dx * dx + dy * dy + dz * dz < mourningRadiusSq) {
            const otherStats = s.cultureState.robotStats.get(other);
            if (otherStats) otherStats.mourningUntil = s.tick + MOURNING_DURATION;
          }
        }
        // Mourning comms
        if (canSendComms(s.tick)) {
          const mournerName = s.cultureState.robotNames.get(allRobots[0] === eid && allRobots.length > 1 ? allRobots[1] : allRobots[0]) ?? 'Fleet';
          const msg = generateMourningComms(mournerName, deadName, eid ^ s.tick);
          markCommsSent(s.tick);
          sendMessage({
            type: 'sim:comms_message',
            payload: { robotEid: allRobots[0] === eid && allRobots.length > 1 ? allRobots[1] : allRobots[0], robotName: mournerName, message: applyDialect(msg, s.cultureState.isolationScore), category: 'mourning', tick: s.tick },
          });
        }
      }
      // Death comms — find a nearby robot to react
      if (canSendComms(s.tick)) {
        const deadX = Position.x[eid];
        const deadZ = Position.z[eid];
        let closestEid = -1;
        let closestDist = Infinity;
        for (let oi = 0; oi < allRobots.length; oi++) {
          const other = allRobots[oi];
          if (other === eid) continue;
          const dx = Position.x[other] - deadX;
          const dz = Position.z[other] - deadZ;
          const d = dx * dx + dz * dz;
          if (d < closestDist) {
            closestDist = d;
            closestEid = other;
          }
        }
        if (closestEid >= 0) {
          const observerName = s.cultureState.robotNames.get(closestEid) ?? `Robot-${closestEid}`;
          const observerStats = s.cultureState.robotStats.get(closestEid);
          const deathMsg = generateDeathComms(observerName, observerStats?.tasksCompleted ?? 0, deadName, closestEid ^ s.tick);
          markCommsSent(s.tick);
          sendMessage({
            type: 'sim:comms_message',
            payload: { robotEid: closestEid, robotName: observerName, message: applyDialect(deathMsg, s.cultureState.isolationScore), category: 'death', tick: s.tick },
          });
        }
      }
      s.grid!.remove(eid);
      removeEntity(s.world!, eid);
    }
  }
}
