import {
  Position,
  Energy,
  ResearchOutput,
  RobotState,
  TaskRef,
  PathTarget,
} from '../components';
import type { RobotProfile } from '../robotProfiles';
import type { TaskQueue } from '../taskQueue';
import { ROBOT_STATES } from '../robotCreation';

export function handleStudyingRobot(
  eid: number,
  dt: number,
  taskQueue: TaskQueue,
  profile: RobotProfile,
  baseEid: number,
): void {
  // Researcher robot: study a nearby asteroid to generate research points.
  // ResearchOutput.isStudying is set; the research system reads pointsPerSecond
  // and accumulates into TechState.researchRate externally.
  // Stop studying when: energy low, no task, or state timer expires.
  const taskId = TaskRef.taskId[eid];
  const task = taskId >= 0 ? taskQueue.getTask(taskId) : undefined;
  if (!task) {
    ResearchOutput.isStudying[eid] = 0;
    RobotState.state[eid] = ROBOT_STATES.IDLE;
    return;
  }

  RobotState.stateTimer[eid] += dt;
  Energy.current[eid] -= profile.energyConsumptionRate * profile.maxThrust * 0.3 * dt;

  // Study for 30 seconds per asteroid, then return for charging
  if (RobotState.stateTimer[eid] >= 30 || Energy.current[eid] / Energy.max[eid] < 0.2) {
    ResearchOutput.isStudying[eid] = 0;
    taskQueue.completeTask(taskId);
    TaskRef.taskId[eid] = -1;
    RobotState.stateTimer[eid] = 0;

    if (baseEid >= 0) {
      RobotState.state[eid] = ROBOT_STATES.RETURNING;
      PathTarget.x[eid] = Position.x[baseEid];
      PathTarget.y[eid] = Position.y[baseEid];
      PathTarget.z[eid] = Position.z[baseEid];
    } else {
      RobotState.state[eid] = ROBOT_STATES.IDLE;
    }
  }
}
